insert into public.modules (id,course_id,titulo,ordem) values ('b5ffd0d0-d2a0-4b79-8634-f35fa5ae3df9','0e0e1cfc-88ed-4c7e-8dba-74a7d2104e81','Introdução ao Mundo dos Eventos',1);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('e6ced36e-344e-4206-832a-d9897aa4aaf5','b5ffd0d0-d2a0-4b79-8634-f35fa5ae3df9','O profissional de eventos: perfil e habilidades','texto','<p><strong>Para começar:</strong> Todo evento que dá certo — de um casamento a um grande festival — tem por trás alguém que soube unir planejamento, técnica e jogo de cintura. Antes de aprender som, luz ou produção, você precisa entender o PERFIL de quem vive de eventos. Aqui estão as competências que sustentam a carreira — e, principalmente, como cada uma aparece no dia a dia.</p><ul><li><strong>Criatividade:</strong> Um profissional de eventos precisa ser criativo para desenvolver conceitos originais e ideias inovadoras que tornem o evento memorável e único.</li><li><strong>Habilidades de Comunicação:</strong> Boas habilidades de comunicação são essenciais para se comunicar com fornecedores, parceiros, colegas de equipe e participantes do evento de maneira clara e eficaz.</li><li><strong>Organização:</strong> A capacidade de manter vários aspectos do evento organizados, como cronogramas, orçamentos, detalhes logísticos e documentação, isso é básico e fundamental.</li><li><strong>Gestão de Tempo:</strong> Os eventos envolvem muitas tarefas e prazos. Um profissional de eventos precisa ser eficiente na gestão do tempo para garantir que tudo seja concluído a tempo.</li><li><strong>Adaptabilidade:</strong> Os eventos muitas vezes têm reviravoltas e mudanças de última hora. A capacidade de se adaptar a situações imprevistas e tomar decisões rápidas é crucial.</li><li><strong>Relações Interpessoais:</strong> Um profissional de eventos precisa desenvolver e manter boas relações com fornecedores, colegas, clientes e outros stakeholders para garantir uma colaboração eficaz.</li><li><strong>Atenção aos Detalhes:</strong> Pequenos detalhes podem fazer uma grande diferença em um evento. Um profissional atento a detalhes garante que nada seja deixado de lado.</li><li><strong>Habilidade de Negociação:</strong> Negociar com fornecedores, locais e outros parceiros é uma parte importante do processo de planejamento de eventos para garantir as melhores condições possíveis.</li><li><strong>Gerenciamento de Estresse:</strong> Eventos podem ser estressantes, especialmente durante a fase de execução. Um profissional de eventos deve ser capaz de lidar com pressão e permanecer calmo sob situações desafiadoras.</li><li><strong>Conhecimento Técnico:</strong> Ter um entendimento básico de tecnologia, equipamentos de áudio e vídeo, configurações de palco e outros aspectos técnicos pode ser crucial, dependendo do tipo de evento.</li><li><strong>Pensamento Estratégico:</strong> Capacidade de pensar a longo prazo e desenvolver estratégias que estejam alinhadas com os objetivos do evento e da organização.</li><li><strong>Trabalho em Equipe:</strong> Muitos eventos envolvem colaboração entre diferentes equipes e departamentos. Ser um bom membro da equipe é essencial.</li><li><strong>Empatia:</strong> Compreender as necessidades e expectativas dos participantes e criar uma experiência positiva é importante para o sucesso do evento.</li><li><strong>Liderança:</strong> Para eventos maiores, a capacidade de liderar uma equipe e coordenar várias partes móveis é fundamental.</li><li><strong>Energia e Entusiasmo:</strong> Trabalhar em eventos pode ser cansativo, mas um profissional energético e entusiasmado pode ajudar a manter a atmosfera positiva.</li></ul><p><strong>Na prática:</strong> Em um dia de evento, essas competências entram em ação juntas: de manhã você confere o checklist de equipamentos (Organização); na montagem, alinha a equipe pelo rádio (Comunicação); surge um imprevisto de energia (Adaptabilidade + Gerenciamento de Estresse); e, na hora do show, tudo flui no tempo certo (Gestão de Tempo). É a soma das habilidades que faz o profissional.</p><h4>Resumo</h4><ul><li>O profissional de eventos é um ''maestro'' de várias habilidades.</li><li>As competências técnicas (som, luz, vídeo) vêm depois — primeiro, o perfil.</li><li>Ninguém nasce com todas: elas se desenvolvem com prática e atitude.</li></ul>',15,1,true,true);
