insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('a594a9d9-7493-404f-aa1d-5c5609419488','b5ffd0d0-d2a0-4b79-8634-f35fa5ae3df9','Os elementos de um evento','texto','<p><strong>Para começar:</strong> Um evento é a soma de vários elementos que trabalham juntos. Conhecer cada um ajuda você a entender onde sua função se encaixa dentro da produção.</p><ul><li><strong>Escritório:</strong> gestão administrativa, contratos e documentação.</li><li><strong>Produção:</strong> coordena toda a operação e a equipe.</li><li><strong>Transporte:</strong> logística de equipamentos, equipe e artistas.</li><li><strong>Estrutura:</strong> palco, tendas, grades, piso e montagem física.</li><li><strong>Som:</strong> sonorização do evento (PA, monitores, microfones).</li><li><strong>Luz:</strong> iluminação de palco e ambiente.</li><li><strong>Vídeo:</strong> telões, projeção e imagem (VJ).</li><li><strong>Efeito:</strong> efeitos especiais e pirotecnia.</li><li><strong>Alimentos e Bebidas:</strong> catering, bar e alimentação da equipe e do público.</li><li><strong>Segurança:</strong> controle de acesso, brigada e prevenção.</li><li><strong>Objetivos e Conceito:</strong> definir claramente o objetivo (promover marca, arrecadar fundos, etc.) e criar um conceito/tema que orienta todo o evento.</li><li><strong>Planejamento e Orçamento:</strong> plano detalhado da pré-produção ao pós-evento, com orçamento realista cobrindo todas as despesas.</li><li><strong>Local e Logística:</strong> escolher um local adequado (capacidade, localização, instalações) e gerenciar a logística: montagem, decoração, mobiliário e equipamentos audiovisuais.</li></ul><p><strong>Na prática:</strong> Em um show, por exemplo, Estrutura monta o palco, Som e Luz instalam os equipamentos, Vídeo cuida do telão, Efeito prepara a pirotecnia, A&amp;B abastece os bastidores e Segurança controla o acesso — tudo coordenado pela Produção.</p><h4>Resumo</h4><ul><li>Um evento é a soma de vários elementos interligados.</li><li>Som, Luz, Vídeo e Efeito são as áreas técnicas principais.</li><li>A Produção coordena todos os elementos para o evento fluir.</li></ul>',15,3,true,false);
