insert into public.modules (id,course_id,titulo,ordem) values ('ae7bf819-bf25-4ee8-90f3-9dc852c6dd96','0e0e1cfc-88ed-4c7e-8dba-74a7d2104e81','Interpessoalidade e Postura Profissional',2);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('810855c1-1295-4a9d-b334-a8f02e763d99','ae7bf819-bf25-4ee8-90f3-9dc852c6dd96','Postura profissional','texto','<p><strong>Para começar:</strong> No meio de eventos, sua postura fala antes de você. Pontualidade, respeito e atitude profissional constroem (ou destroem) sua reputação na área — onde todo mundo se conhece e indica quem é bom.</p><ul><li><strong>Postura Profissional:</strong> No ambiente de trabalho, a postura profissional se manifesta através de atitudes como pontualidade, vestimenta adequada, ética de trabalho sólida, respeito pelos colegas e cumprimento de tarefas com eficiência e responsabilidade.</li><li><strong>Postura Social:</strong> Ter uma boa postura social envolve demonstrar respeito, empatia e consideração pelos outros. Isso inclui escutar ativamente, fazer contato visual, utilizar uma linguagem corporal aberta e mostrar interesse genuíno nas conversas e interações.</li></ul><p><strong>Na prática:</strong> O profissional de postura forte chega no horário, cumprimenta a equipe, respeita a hierarquia da produção, cuida do equipamento (seu e dos outros) e entrega o que prometeu. Pequenas atitudes geram novas chamadas para trabalhar.</p><h4>Resumo</h4><ul><li>Postura não é só aparência: é atitude e comportamento.</li><li>Postura profissional: pontualidade, ética e responsabilidade.</li><li>Postura social: respeito, empatia e boa comunicação.</li></ul>',12,1,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('503a135f-0e50-4cfa-b7cd-0a22644a2200','810855c1-1295-4a9d-b334-a8f02e763d99','Quiz — Postura profissional');
