insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('117480f9-7a41-4b7a-91ca-8a15cb5d2209','ae7bf819-bf25-4ee8-90f3-9dc852c6dd96','Apresentação e vestimenta técnica','texto','<p><strong>Para começar:</strong> No bastidor, a roupa não é estética — é segurança e identidade de equipe. A vestimenta técnica protege você de riscos elétricos, calor e quedas, e ainda mostra que você faz parte da produção.</p><ul><li><strong>Calçado:</strong> fechado, amarrado e com sola de borracha (proteção contra choque e quedas).</li><li><strong>Calça:</strong> cobrindo completamente as pernas, de tecido não inflamável.</li><li><strong>Camiseta:</strong> de manga, preta, sem marcas ou logos que não sejam da equipe.</li><li><strong>Critérios técnicos:</strong> a roupa deve considerar condutibilidade, inflamabilidade e influências eletromagnéticas, de acordo com as normas técnicas.</li></ul><p><strong>Na prática:</strong> Antes de subir ao palco ou mexer em energia, confira: calçado de borracha amarrado, calça comprida não inflamável e camiseta de manga preta. Nada de bermuda, chinelo ou regata — além de inseguro, passa imagem amadora.</p><h4>Resumo</h4><ul><li>A vestimenta técnica é item de segurança, não só visual.</li><li>Calçado de borracha, calça não inflamável e camiseta de manga preta.</li><li>Seguir as normas técnicas protege você e a equipe.</li></ul>',12,2,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('5f26e7ec-6c36-4cba-8b1d-681ddb4de1b2','117480f9-7a41-4b7a-91ca-8a15cb5d2209','Quiz — Apresentação e vestimenta técnica');
