insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('ce085ba9-0b00-414d-b41e-8f1de2a46e77','ae7bf819-bf25-4ee8-90f3-9dc852c6dd96','Comunicação eficaz com a equipe e artistas','texto','<p><strong>Para começar:</strong> Em um evento, uma informação mal passada vira atraso, retrabalho ou acidente. Saber se comunicar com clareza — e ouvir — é o que mantém a engrenagem girando.</p><p><strong>Na prática:</strong> Comunicação eficaz no bastidor é: falar curto e claro pelo rádio, confirmar se a mensagem foi entendida (''copiou?''), adaptar o tom para artista, produtor ou colega, e ouvir com atenção antes de responder.</p><h4>Resumo</h4><ul><li>Comunicar é expressar com clareza E ouvir bem.</li><li>Boas pessoas comunicativas adaptam a mensagem ao público.</li><li>Comunicação eficaz evita erros, atrasos e conflitos.</li></ul>',10,3,true,false);
