insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('605f0b3a-75e7-4ded-a04c-02e872f007e9','ae7bf819-bf25-4ee8-90f3-9dc852c6dd96','Lidando com pressão e estresse','texto','<p><strong>Para começar:</strong> Evento é prazo curto, imprevisto e adrenalina. Saber manter a calma sob pressão é o que separa o profissional do amador — e protege sua saúde na carreira.</p><ul><li><strong>Mantenha a calma:</strong> Tente manter a calma e o controle emocional, mesmo quando a pressão aumenta. Respirar profundamente e pausar por um momento antes de responder pode ajudar a evitar reações impulsivas.</li><li><strong>Priorize e organize:</strong> Identifique as tarefas mais importantes e priorize-as. Uma lista organizada de tarefas ajuda a focar naquilo que realmente precisa ser feito, reduzindo o sentimento de sobrecarga.</li><li><strong>Divida as tarefas:</strong> Se possível, divida as tarefas em etapas menores e mais gerenciáveis. Isso torna o trabalho menos avassalador e permite medir o progresso.</li><li><strong>Defina limites:</strong> Saiba até onde pode esticar suas capacidades. Defina limites realistas e saiba quando pedir ajuda ou quando é hora de pausar e descansar.</li><li><strong>Gerencie o tempo:</strong> Use técnicas de gerenciamento de tempo, como a técnica Pomodoro, para trabalhar de forma focada por períodos de tempo definidos, seguidos por pausas curtas.</li><li><strong>Mantenha a perspectiva:</strong> Lembre-se de que a situação atual de pressão e estresse é temporária. Manter uma perspectiva mais ampla pode ajudar a reduzir a sensação de sobrecarga.</li><li><strong>Pratique a automotivação:</strong> Mantenha-se motivado, lembrando-se dos objetivos que deseja alcançar e das recompensas que vêm com o sucesso.</li><li><strong>Cuide de si mesmo:</strong> Priorize o autocuidado. Isso inclui comer bem, dormir o suficiente, fazer exercícios físicos e dedicar tempo para atividades que o relaxem e o revigorem.</li><li><strong>Pratique a resiliência:</strong> A resiliência é a capacidade de se recuperar rapidamente de adversidades. Encare os desafios como oportunidades de crescimento e aprendizado.</li><li><strong>Peça ajuda:</strong> Não tenha medo de pedir ajuda quando necessário. Isso pode ser tanto em relação às tarefas quanto ao apoio emocional.</li><li><strong>Pratique a resolução de problemas:</strong> Aborde os problemas de maneira sistemática, identificando soluções possíveis e avaliando as consequências de cada opção.</li><li><strong>Pratique técnicas de relaxamento:</strong> Técnicas como meditação, ioga ou simplesmente respirar profundamente podem ajudar a acalmar a mente e reduzir o estresse.</li><li><strong>Desenvolva habilidades de comunicação:</strong> Comunique-se de forma aberta com colegas e superiores sobre a sua carga de trabalho e limites. Isso pode levar a um ambiente de trabalho mais compreensivo.</li><li><strong>Celebre as pequenas vitórias:</strong> Reconheça e celebre seus progressos, mesmo que sejam pequenos. Isso pode criar um senso de realização e motivação.</li><li><strong>Busque apoio profissional:</strong> Se o estresse e a pressão se tornarem esmagadores, considere buscar o apoio de um profissional de saúde mental para orientação.</li></ul><p><strong>Na prática:</strong> Faltam 10 minutos para abrir a casa e um equipamento falha. Em vez de entrar em pânico: respire, priorize o que é essencial agora, divida a tarefa, peça ajuda e resolva passo a passo. Depois, celebre que deu certo.</p><h4>Resumo</h4><ul><li>Pressão faz parte de eventos — calma e prioridade são chave.</li><li>Dividir tarefas e pedir ajuda reduz a sobrecarga.</li><li>Autocuidado e resiliência sustentam a carreira a longo prazo.</li></ul>',12,6,true,false);
