insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('b2244804-287f-403f-813f-8fd98e4fdb60','ae7bf819-bf25-4ee8-90f3-9dc852c6dd96','Trabalho em equipe e resolução de conflitos','texto','<p><strong>Para começar:</strong> Onde há gente trabalhando junto sob pressão, conflitos surgem — é natural. O que define o profissional é saber resolver de forma construtiva, sem brigar nem guardar mágoa.</p><ul><li><strong>Promova a comunicação aberta:</strong> Crie um ambiente onde todos os membros da equipe se sintam à vontade para expressar suas opiniões e preocupações. Uma comunicação aberta pode evitar o acúmulo de tensões.</li><li><strong>Pratique a escuta ativa:</strong> Ao resolver conflitos, ouça atentamente todas as partes envolvidas. Demonstrar que você está genuinamente interessado em entender as perspectivas dos outros pode reduzir as emoções negativas.</li><li><strong>Identifique as causas:</strong> Compreenda as razões subjacentes do conflito. Muitas vezes, os conflitos são causados por mal-entendidos, diferenças de opinião ou objetivos conflitantes.</li><li><strong>Envolva um mediador neutro:</strong> Se um conflito estiver afetando negativamente a dinâmica da equipe, considere envolver um mediador neutro para facilitar a discussão e encontrar uma solução imparcial. Foque em soluções, não em culpados: Em vez de procurar culpados, concentre-se em encontrar soluções. O objetivo deve ser resolver o problema e melhorar a colaboração futura.</li><li><strong>Procure interesses comuns:</strong> Identifique os pontos em que os interesses das partes envolvidas se alinham. Isso pode ajudar a encontrar soluções que beneficiem a todos.</li><li><strong>Evite reações emocionais exageradas:</strong> Mantenha a calma e evite reações emocionais intensas. Uma abordagem racional e controlada ajuda a manter o foco na resolução do conflito.</li><li><strong>Estabeleça acordos claros:</strong> Quando uma solução for encontrada, coloque-a por escrito de forma clara e concisa. Isso ajuda a evitar futuros mal-entendidos.</li><li><strong>Aprenda com os conflitos:</strong> Veja os conflitos como oportunidades de aprendizado. Eles podem revelar lacunas na comunicação, processos ou expectativas, permitindo que a equipe melhore e evolua.</li><li><strong>Desenvolva habilidades de inteligência emocional:</strong> A inteligência emocional envolve a capacidade de entender e gerenciar emoções, tanto suas quanto as dos outros. Essas habilidades são essenciais para resolver conflitos de maneira eficaz.</li><li><strong>Crie regras de convivência:</strong> Em equipes de longo prazo, é útil estabelecer regras básicas para a convivência e resolução de conflitos. Isso pode incluir diretrizes para a comunicação respeitosa e a abordagem de desacordos.</li><li><strong>Reavalie periodicamente:</strong> Após a resolução de um conflito, verifique periodicamente se as soluções estão funcionando e se as relações melhoraram. Caso contrário, ajuste as abordagens conforme necessário.</li></ul><p><strong>Na prática:</strong> Dois técnicos discordam sobre a ordem da montagem. Em vez de bater de frente: ouça os dois lados, identifique a real causa, foque na solução (não em quem está certo) e registre o combinado. O evento agradece.</p><h4>Resumo</h4><ul><li>Conflitos são naturais e podem ser oportunidades de melhoria.</li><li>Escuta ativa e foco na solução resolvem a maioria deles.</li><li>Inteligência emocional é a base para lidar com conflitos.</li></ul>',12,7,true,false);
