insert into public.modules (id,course_id,titulo,ordem) values ('91d18374-4088-4431-b97e-3bd800bac39c','0e0e1cfc-88ed-4c7e-8dba-74a7d2104e81','Funções e Atividades',3);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('1bf721ea-14a6-44da-add7-a6c0b080c99f','91d18374-4088-4431-b97e-3bd800bac39c','Funções e atividades em um evento','texto','<p><strong>Para começar:</strong> Cada pessoa em um evento tem um papel claro. Conhecer as funções ajuda você a saber com quem falar, a quem reportar e onde quer chegar na carreira.</p><ul><li><strong>Produtor:</strong> organiza e coordena a equipe, filtra as informações e toma as decisões da operação.</li><li><strong>Técnico de Som:</strong> responsável por todo o processo de sonorização do espetáculo (PA, monitores, microfones).</li><li><strong>Técnico de Iluminação:</strong> responsável por todo o processo de iluminação de palco e ambiente.</li><li><strong>Técnico de Vídeo (VJ):</strong> responsável por todo o processo de imagem: telões, projeção e conteúdo visual.</li><li><strong>Técnico de Pirotecnia / Efeito:</strong> responsável por todo o processo de efeitos especiais e pirotecnia, sempre com segurança.</li><li><strong>Segurança:</strong> controle de acesso, organização do público e prevenção de incidentes.</li><li><strong>Bombeiro / Brigadista:</strong> responsável pela prevenção e combate a incêndio e pela resposta a emergências.</li><li><strong>Carregador / Roadie:</strong> responsável por carga, descarga e movimentação de equipamentos com segurança.</li></ul><p><strong>Na prática:</strong> Em um show, o Produtor coordena tudo; Som, Luz e Vídeo cuidam da parte técnica; Efeito prepara a pirotecnia; Roadies montam e desmontam; e a Segurança/Brigada garante que público e equipe estejam protegidos.</p><h4>Resumo</h4><ul><li>Cada função tem uma responsabilidade clara e complementar.</li><li>As áreas técnicas: Som, Luz, Vídeo e Efeito.</li><li>Conhecer as funções ajuda a planejar sua trilha de carreira.</li></ul>',15,1,true,false);
