insert into public.modules (id,course_id,titulo,ordem) values ('d1daa44a-8d0c-4271-a8eb-c6833ecfd8a0','0e0e1cfc-88ed-4c7e-8dba-74a7d2104e81','Encerramento — Nível Trainee',4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('d4c70113-71dc-402d-b715-34c24ffe03ba','d1daa44a-8d0c-4271-a8eb-c6833ecfd8a0','Conclusão: o profissional de eventos completo','texto','<p><strong>Para começar:</strong> Você chegou ao fim do nível Trainee! Aqui a gente amarra tudo o que viu e prepara o próximo passo.</p><p><strong>Na prática:</strong> Você já entende o perfil do profissional, como um evento se organiza, seus elementos, a postura e as habilidades interpessoais, e as funções de cada um. Essa base é o alicerce para a parte técnica que vem a seguir.</p><h4>Resumo</h4><ul><li>O trabalho em equipe é a espinha dorsal de qualquer evento.</li><li>Resiliência e autogestão sustentam a carreira.</li><li>Próximo passo: nível JUNIOR — Segurança, Elétrica, Eletrônica, Som, Luz, Vídeo, Produção e Efeito.</li></ul>',8,1,true,false);
