  ('1320b04f-ec96-47e3-905c-46a6f7bce71e','Junior — Profissões de Evento','junior-profissoes-de-evento','Curso Junior — Profissões de Evento — SMU PRO','junior','outros','{}','free',902,43,false,false,2);
insert into public.modules (id,course_id,titulo,ordem) values ('8104a9c8-c09c-416a-bcd6-16948d17d0be','1320b04f-ec96-47e3-905c-46a6f7bce71e','Segurança do Trabalho',1);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('bc478c33-936d-427f-97f7-1890d50a9938','8104a9c8-c09c-416a-bcd6-16948d17d0be','EPIs para Montagem e Operação de Palcos','texto','<p><strong>Para começar:</strong> Trabalhar na montagem, operação e desmontagem de palcos expõe o técnico a quedas, impactos, ruído, eletricidade e produtos químicos. Esta aula apresenta os Equipamentos de Proteção Individual (EPIs) que tornam esse trabalho seguro. Conhecer e usar o EPI certo é a primeira linha de defesa contra acidentes em eventos.</p><p>O EPI é todo dispositivo de uso individual destinado a proteger o trabalhador contra riscos que podem ameaçar sua saúde e segurança. Em eventos, a escolha do EPI deve ser feita conforme os riscos específicos de cada tarefa (altura, eletricidade, ruído, poeira) e seguir as normas de segurança aplicáveis. Além de escolher corretamente, é essencial usar, conservar e fazer a manutenção do equipamento para que ele cumpra sua função.</p><ul><li><strong>Capacete de Segurança:</strong> Protege a cabeça contra impactos de objetos que possam cair ou golpear. Indispensável em áreas de montagem com trabalho em altura acima das pessoas.</li><li><strong>Cinto de Segurança com Talabarte:</strong> Indispensável para trabalhos em altura. O cinto (tipo paraquedista) mantém o trabalhador preso a uma estrutura segura e o talabarte interrompe a queda, limitando o impacto.</li><li><strong>Luvas de Proteção:</strong> Oferecem proteção às mãos contra cortes, abrasões e objetos pontiagudos durante o manuseio de estruturas, cabos e ferramentas.</li><li><strong>Botas de Segurança:</strong> Com solado antiderrapante e biqueira de proteção (geralmente de composite ou aço), protegem os pés contra impactos e queda de objetos pesados.</li><li><strong>Óculos de Proteção:</strong> Protegem os olhos contra partículas, poeira, detritos e objetos voadores que podem causar lesões oculares durante cortes, lixamento ou montagem.</li><li><strong>Protetores Auriculares:</strong> Reduzem a exposição a ruídos excessivos de equipamentos de som e ferramentas, ajudando a prevenir a perda auditiva (PAIR). Podem ser tipo plug (inserção) ou concha (abafador).</li><li><strong>Máscara Respiratória:</strong> Em trabalhos com poeira, produtos químicos ou materiais tóxicos, protege as vias respiratórias. O tipo de filtro deve ser adequado ao contaminante.</li><li><strong>Vestimenta de Segurança:</strong> Roupas resistentes e adequadas protegem o corpo contra respingos químicos, faíscas e outros perigos durante a montagem.</li><li><strong>Protetor Solar e Chapéu:</strong> Em eventos ao ar livre, protegem contra a exposição excessiva ao sol durante longas jornadas de montagem.</li><li><strong>EPIs Elétricos:</strong> Em atividades elétricas, como montagem de iluminação, usam-se luvas isolantes e outros EPIs específicos para eletricidade, conforme o nível de tensão envolvido.</li><li><strong>Máscara de Solda:</strong> Protege o rosto e os olhos contra a radiação e faíscas em serviços de soldagem na montagem de estruturas metálicas.</li><li><strong>Vestimenta Refletiva:</strong> Em locais com baixa visibilidade, como ambientes escuros ou trabalho noturno, aumenta a visibilidade do trabalhador e reduz o risco de atropelamento ou colisão.</li></ul><p><strong>Na prática:</strong> Na montagem de um festival ao ar livre, a equipe de estrutura ergue uma treliça de iluminação a 8 metros de altura. Os montadores que sobem usam capacete, botas com biqueira, luvas e cinto de segurança tipo paraquedista com talabarte duplo, sempre conectados a um ponto de ancoragem. No solo, quem opera a serra para cortar madeira do palco usa óculos de proteção e protetor auricular, e à noite todos vestem colete refletivo porque empilhadeiras circulam no escuro. Cada tarefa tem seu conjunto de EPI, definido pelo risco daquela função.</p><h4>Resumo</h4><ul><li>O EPI é a primeira linha de defesa contra quedas, impactos, ruído, eletricidade e poeira</li><li>A escolha do EPI depende do risco específico de cada tarefa</li><li>Usar, inspecionar e conservar o equipamento é tão importante quanto tê-lo</li></ul>',16,1,true,true);
