insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('090e5c3e-7a65-48b3-9be0-f0844f79604a','a4ad29c7-35f1-4a79-b372-9b83b162da81','O que define qual conjunto de EPI deve ser usado em cada tarefa?','A escolha do EPI deve ser feita conforme os riscos específicos do trabalho e as normas de segurança aplicáveis.',4,1);
