insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0471f986-c966-48b5-869a-b016b96a0957','2b57caba-a9e6-462d-91c5-e073bffe04e0','O que deve ser feito antes do evento para evitar problemas durante a apresentação?','Testes prévios garantem que tudo esteja funcionando e ajudam a evitar problemas durante a apresentação.',4,1);
