insert into public.modules (id,course_id,titulo,ordem) values ('5f8eac47-c30d-47f9-9301-8a452bb431c3','1320b04f-ec96-47e3-905c-46a6f7bce71e','Elétrica I',2);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('37765f96-9ead-484d-9152-eec637d3bc22','5f8eac47-c30d-47f9-9301-8a452bb431c3','O que é eletricidade: fluxo e corrente','texto','<p><strong>Para começar:</strong> Tudo o que liga num evento — som, luz, LED, vídeo — depende de eletricidade. Antes de mexer em qualquer cabo ou tomada, o técnico precisa entender o que de fato está ''correndo'' por dentro daquele fio. Esta aula é a base de todo o resto.</p><p>Eletricidade é o movimento de cargas elétricas dentro de um condutor (normalmente elétrons em um fio metálico). Quando esse movimento é ordenado, dizemos que existe corrente elétrica, e é ela que transporta energia de um ponto a outro do circuito. Nesta aula você entende o conceito de fluxo elétrico e como ele se mede em Ampere.</p><ul><li><strong>Fluxo elétrico:</strong> É a medida da quantidade de carga elétrica que atravessa uma determinada área num intervalo de tempo. É análogo ao fluxo de água em um cano ou ao fluxo de calor: descreve a taxa de movimento das cargas através de um condutor, como um fio elétrico.</li><li><strong>Corrente elétrica:</strong> É o fluxo ordenado de cargas elétricas (geralmente elétrons) através de um condutor. É a corrente que efetivamente transporta a energia elétrica de um ponto a outro do circuito e alimenta os equipamentos.</li><li><strong>Unidade: Ampere (A):</strong> A corrente é medida em ampere (A). Um ampere equivale a um coulomb de carga passando por um ponto do condutor a cada segundo (1 A = 1 C/s). Quanto maior o Ampere, maior a quantidade de carga fluindo por segundo.</li><li><strong>Corrente contínua (CC) x alternada (CA):</strong> Na corrente contínua o fluxo segue sempre no mesmo sentido (ex.: bateria). Na corrente alternada o sentido se inverte muitas vezes por segundo — é o tipo que chega nas tomadas e na rede elétrica que alimenta os eventos.</li><li><strong>Por que importa em eventos:</strong> Equipamentos são especificados em potência (W) mas a fiação, os disjuntores e o gerador trabalham em corrente (A). Saber ler a corrente é o que evita cabo subdimensionado, aquecimento e disjuntor desarmando no meio do show.</li></ul><p><strong>Na prática:</strong> Um refletor de LED informa que ''puxa'' 2,5 A. Se você ligar oito refletores iguais no mesmo circuito, a corrente total é 8 x 2,5 = 20 A. Um circuito protegido por um disjuntor de 16 A não aguentaria essa carga e desarmaria — por isso o técnico distribui os refletores em mais de um circuito.</p><h4>Resumo</h4><ul><li>Corrente elétrica é o fluxo ordenado de cargas (elétrons) num condutor e é o que transporta energia.</li><li>A unidade da corrente é o Ampere (A): 1 A = 1 coulomb por segundo.</li><li>Eventos usam corrente alternada (CA) na rede e nas tomadas; bateria fornece corrente contínua (CC).</li></ul>',12,1,true,false);
