insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e7d7e04c-6958-4e3f-ab40-effea3c2860e','45681604-e9a7-48cd-9c4e-6f99a3d5fc21','Qual é a unidade de medida da corrente elétrica?','A corrente elétrica é medida em Ampere (A). Um ampere corresponde a um coulomb de carga passando por um ponto a cada segundo.',1,1);
