insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e15e0ea1-5b3b-4f8c-aeeb-97d68fe7adba','45681604-e9a7-48cd-9c4e-6f99a3d5fc21','Que tipo de corrente chega nas tomadas que alimentam os equipamentos de um evento?','A rede elétrica e as tomadas fornecem corrente alternada (CA), que inverte o sentido muitas vezes por segundo. Baterias fornecem corrente contínua (CC).',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e15e0ea1-5b3b-4f8c-aeeb-97d68fe7adba','Corrente contínua (CC)',false,1);
