insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('16a8f29d-5843-42a1-9ed1-1109ddc670ee','45681604-e9a7-48cd-9c4e-6f99a3d5fc21','Oito refletores de 2,5 A cada, no mesmo circuito, somam que corrente total?','Basta somar as correntes de equipamentos no mesmo circuito: 8 x 2,5 A = 20 A. Isso excede um disjuntor de 16 A, que desarmaria.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('16a8f29d-5843-42a1-9ed1-1109ddc670ee','2,5 A',false,1);
