insert into public.quiz_options (question_id,texto,correta,ordem) values ('16a8f29d-5843-42a1-9ed1-1109ddc670ee','20 A',true,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('16a8f29d-5843-42a1-9ed1-1109ddc670ee','16 A',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('7ec36224-e579-4743-b4e0-c1aec71424ed','5f8eac47-c30d-47f9-9301-8a452bb431c3','Tensão (Volt): a força que empurra a corrente','texto','<p><strong>Para começar:</strong> Se a corrente é a ''água correndo'', a tensão é a ''pressão'' que faz essa água andar. Conhecer a tensão disponível no local (110 V, 220 V, trifásico) é o primeiro dado que o técnico levanta antes de planejar a energia de um palco.</p><p>A tensão elétrica, também chamada de diferença de potencial, é a grandeza que mede a energia elétrica por unidade de carga em um circuito. Ela é a força motriz que impulsiona os elétrons pelo condutor, permitindo o fluxo de corrente. Sem diferença de tensão entre dois pontos, não há corrente.</p><ul><li><strong>Tensão (diferença de potencial):</strong> Mede a quantidade de energia elétrica por unidade de carga entre dois pontos do circuito. É a força que ''empurra'' os elétrons: eles fluem do ponto de maior potencial para o de menor potencial, criando a corrente.</li><li><strong>Unidade: Volt (V):</strong> A tensão é medida em volts (V) e representada pela letra ''V''. Quanto maior a tensão entre dois pontos, maior a força disponível para movimentar as cargas.</li><li><strong>De onde vem a tensão:</strong> É gerada por fontes de energia como baterias, geradores e fontes de alimentação. Pode ser aumentada ou diminuída por transformadores, que elevam ou reduzem a tensão de um circuito.</li><li><strong>Tensões padrão (atenção à região):</strong> A tensão disponível varia conforme o local: 110 V, 127 V, 220 V, 230 V etc. O técnico precisa confirmar qual tensão existe na área do palco antes de conectar qualquer equipamento, pois ligar um aparelho na tensão errada pode danificá-lo.</li><li><strong>Relação com corrente e resistência:</strong> Pela Lei de Ohm, V = I · R: a tensão é igual à corrente multiplicada pela resistência. Essa relação conecta tensão, corrente e resistência — assunto da próxima aula.</li></ul><p><strong>Na prática:</strong> Ao chegar num evento, o técnico mede a tomada com um multímetro e confirma 220 V. Um equipamento importado marcado apenas ''120 V'' não pode ser ligado direto nessa tomada — seria preciso um transformador para reduzir a tensão de 220 V para 120 V, evitando queimar o aparelho.</p><h4>Resumo</h4><ul><li>Tensão é a diferença de potencial: a força que empurra os elétrons pelo circuito, medida em Volt (V).</li><li>Os elétrons fluem do maior para o menor potencial; sem diferença de tensão não há corrente.</li><li>A tensão da rede varia por região (110/127/220/230 V) e deve sempre ser confirmada antes de energizar.</li></ul>',12,2,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('fad08def-5b3a-4ba8-8e21-bf85fe53e723','7ec36224-e579-4743-b4e0-c1aec71424ed','Quiz — Tensão (Volt): a força que empurra a corrente');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('3f063a61-bf78-4e89-b023-959100d5fd1d','fad08def-5b3a-4ba8-8e21-bf85fe53e723','Em que unidade se mede a tensão elétrica?','A tensão (diferença de potencial) é medida em Volt (V) e representada pela letra V.',1,1);
