insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('645ae664-1e25-481d-8395-f0002df08da2','fad08def-5b3a-4ba8-8e21-bf85fe53e723','O que a tensão elétrica representa em um circuito?','A tensão é a diferença de potencial — a força motriz que impulsiona os elétrons pelo condutor, permitindo o fluxo de corrente.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('645ae664-1e25-481d-8395-f0002df08da2','O fluxo de cargas',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('645ae664-1e25-481d-8395-f0002df08da2','A força que empurra os elétrons (diferença de potencial)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('645ae664-1e25-481d-8395-f0002df08da2','A oposição à corrente',false,3);
