insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e7916f51-0827-41d4-858f-553e7458cb36','fad08def-5b3a-4ba8-8e21-bf85fe53e723','Por que o técnico deve confirmar a tensão da rede antes de ligar um equipamento?','A tensão varia por região (110/127/220/230 V). Conectar um equipamento a uma tensão diferente da que ele suporta pode queimá-lo; por isso se confirma a tensão antes.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e7916f51-0827-41d4-858f-553e7458cb36','Porque a tensão é sempre 220 V',false,1);
