insert into public.quiz_options (question_id,texto,correta,ordem) values ('e7916f51-0827-41d4-858f-553e7458cb36','Porque a tensão não influencia o equipamento',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e7916f51-0827-41d4-858f-553e7458cb36','Porque a tensão só importa para a iluminação',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('f367b1ff-b28d-4aa9-a26c-c388fd5d5d53','5f8eac47-c30d-47f9-9301-8a452bb431c3','Resistência (Ohm) e a Lei de Ohm','texto','<p><strong>Para começar:</strong> Por que um cabo fino esquenta e um grosso não? Por que parte da energia ''vira calor''? A resposta está na resistência. E a Lei de Ohm é a fórmula que amarra tensão, corrente e resistência — o cálculo mais importante da elétrica básica.</p><p>Resistência elétrica é a propriedade dos materiais de se opor à passagem da corrente. Ela limita quanta corrente pode fluir e transforma parte da energia elétrica em calor. Entender resistência ajuda o técnico a escolher cabos certos e a evitar aquecimento perigoso na operação.</p><ul><li><strong>Resistência elétrica:</strong> É a propriedade do material que se opõe ao fluxo de corrente. Ela limita a quantidade de corrente que passa e converte parte da energia elétrica em calor. É representada pela letra ''R''.</li><li><strong>Unidade: Ohm (Ω):</strong> A resistência é medida em ohms (Ω), em homenagem ao físico alemão Georg Simon Ohm, que formulou a lei que relaciona tensão, corrente e resistência.</li><li><strong>Fatores que influenciam a resistência:</strong> Dependem do material do condutor, das dimensões físicas (comprimento e área da seção transversal), da temperatura e de outras características. Cabos mais longos e finos têm mais resistência; cabos mais grossos têm menos.</li><li><strong>Lei de Ohm: V = I · R:</strong> A tensão aplicada é igual à corrente multiplicada pela resistência. Reorganizando: I = V / R e R = V / I. Quanto maior a resistência, menor a corrente para uma mesma tensão — e vice-versa.</li><li><strong>Resistência vira calor:</strong> Como a resistência transforma energia em calor, um cabo subdimensionado (resistência alta para a corrente que passa) esquenta. Por isso se escolhe a bitola do cabo de acordo com a corrente que ele vai transportar.</li><li><strong>Resistores:</strong> Componentes feitos para introduzir uma resistência definida no circuito, controlando a corrente e a tensão em diferentes partes do sistema.</li></ul><p><strong>Na prática:</strong> Um equipamento de 220 V tem resistência de 44 Ω. Pela Lei de Ohm, a corrente é I = V / R = 220 / 44 = 5 A. Com esse valor o técnico já sabe que precisa de um circuito e de um cabo que suportem pelo menos 5 A, com margem de segurança acima disso.</p><h4>Resumo</h4><ul><li>Resistência (R) é a oposição ao fluxo de corrente, medida em Ohm (Ω), e transforma energia em calor.</li><li>A Lei de Ohm relaciona as três grandezas: V = I · R (logo I = V/R e R = V/I).</li><li>Mais resistência significa menos corrente para a mesma tensão; cabo subdimensionado esquenta.</li></ul>',13,3,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('173264d0-8904-4024-88d3-48895e770ae9','f367b1ff-b28d-4aa9-a26c-c388fd5d5d53','Quiz — Resistência (Ohm) e a Lei de Ohm');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5794a1d8-36a3-4dc2-b3e4-500628410c0d','173264d0-8904-4024-88d3-48895e770ae9','Qual é a fórmula da Lei de Ohm?','A Lei de Ohm é V = I · R: a tensão é igual à corrente multiplicada pela resistência. Dela se obtém I = V/R e R = V/I.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5794a1d8-36a3-4dc2-b3e4-500628410c0d','P = V · I',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5794a1d8-36a3-4dc2-b3e4-500628410c0d','V = I · R',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5794a1d8-36a3-4dc2-b3e4-500628410c0d','I = P · V',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5794a1d8-36a3-4dc2-b3e4-500628410c0d','R = V · I',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c8966c47-4bb8-4fb0-a234-20fb2be08c80','173264d0-8904-4024-88d3-48895e770ae9','Em que unidade se mede a resistência elétrica?','A resistência é medida em Ohm (Ω), nome em homenagem a Georg Simon Ohm.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('c8966c47-4bb8-4fb0-a234-20fb2be08c80','Volt (V)',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('c8966c47-4bb8-4fb0-a234-20fb2be08c80','Watt (W)',false,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('c8966c47-4bb8-4fb0-a234-20fb2be08c80','Ohm (Ω)',true,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('c8966c47-4bb8-4fb0-a234-20fb2be08c80','Ampere (A)',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0a09602c-b411-46e7-bb66-343d901f3a6e','173264d0-8904-4024-88d3-48895e770ae9','Para uma mesma tensão, o que acontece com a corrente se a resistência aumenta?','Por I = V/R, aumentando a resistência (R) com a tensão (V) fixa, a corrente (I) diminui. Mais resistência, menos corrente.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('0a09602c-b411-46e7-bb66-343d901f3a6e','A corrente aumenta',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('0a09602c-b411-46e7-bb66-343d901f3a6e','A corrente diminui',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('0a09602c-b411-46e7-bb66-343d901f3a6e','A corrente não muda',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('0a09602c-b411-46e7-bb66-343d901f3a6e','A tensão é que diminui',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('d0c3a118-bbb8-4d85-9ddb-a1ff909c4347','173264d0-8904-4024-88d3-48895e770ae9','Um equipamento de 220 V tem resistência de 44 Ω. Qual a corrente?','I = V/R = 220/44 = 5 A. Com isso o técnico dimensiona cabo e circuito para suportar ao menos 5 A com margem.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d0c3a118-bbb8-4d85-9ddb-a1ff909c4347','2 A',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d0c3a118-bbb8-4d85-9ddb-a1ff909c4347','5 A',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d0c3a118-bbb8-4d85-9ddb-a1ff909c4347','10 A',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d0c3a118-bbb8-4d85-9ddb-a1ff909c4347','44 A',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('289c3d80-ceb3-418a-9ebc-342d3b2f83b8','5f8eac47-c30d-47f9-9301-8a452bb431c3','Potência (Watt) e cálculo de consumo','texto','<p><strong>Para começar:</strong> Toda ficha técnica de equipamento traz a potência em Watts. É esse número que o técnico soma para saber o consumo total do evento e dimensionar gerador, cabos e disjuntores. Errar essa conta é arriscar sobrecarga e parada do show.</p><p>Potência elétrica é a taxa com que a energia elétrica é transferida, consumida ou dissipada em um circuito — ou seja, quanta energia o equipamento usa por unidade de tempo. É a grandeza-chave para entender consumo e calcular custos e capacidade de fornecimento.</p><ul><li><strong>Potência elétrica:</strong> É a taxa na qual a energia elétrica é transferida ou convertida em um circuito — a quantidade de energia consumida, produzida ou dissipada por unidade de tempo.</li><li><strong>Unidade: Watt (W):</strong> A potência se mede em watts (W), em homenagem a James Watt. 1.000 W equivalem a 1 quilowatt (kW). É comum somar a potência dos equipamentos em kW para dimensionar a energia do evento.</li><li><strong>Fórmula principal: P = V · I:</strong> A potência é o produto da tensão pela corrente. Logo, ela é diretamente proporcional tanto à tensão quanto à corrente do circuito.</li><li><strong>Outras formas (com a Lei de Ohm):</strong> A potência também pode ser escrita como P = I² · R (em função da corrente e da resistência) ou P = V² / R (em função da tensão e da resistência).</li><li><strong>Calcular a corrente a partir da potência:</strong> Reorganizando P = V · I, obtém-se I = P / V. É a conta que o técnico usa para descobrir quantos amperes um equipamento puxa, conhecendo sua potência e a tensão da rede.</li><li><strong>Energia x potência: o kWh:</strong> O consumo de energia ao longo do tempo é medido em quilowatt-hora (kWh): a energia usada em uma hora a uma taxa constante de 1 kW. É a unidade que aparece na conta de luz.</li></ul><p><strong>Na prática:</strong> Um sistema de som soma 4.400 W de potência e a tensão da rede é 220 V. A corrente é I = P / V = 4.400 / 220 = 20 A. Sabendo disso, o técnico já planeja cabos e disjuntor para suportar 20 A com folga, distribuindo a carga se necessário.</p><h4>Resumo</h4><ul><li>Potência é a energia usada por unidade de tempo, medida em Watt (W); 1.000 W = 1 kW.</li><li>A fórmula central é P = V · I, de onde se tira I = P / V para achar a corrente.</li><li>Energia consumida ao longo do tempo é medida em quilowatt-hora (kWh) — a unidade da conta de luz.</li></ul>',14,4,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('de180f31-7cce-48d1-9d4f-641e1bb0a17c','289c3d80-ceb3-418a-9ebc-342d3b2f83b8','Quiz — Potência (Watt) e cálculo de consumo');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('35a1345a-8421-4a54-9624-6bfd9cf3eb96','de180f31-7cce-48d1-9d4f-641e1bb0a17c','Qual é a fórmula da potência elétrica?','A potência é o produto da tensão pela corrente: P = V · I. Por isso ela é proporcional tanto à tensão quanto à corrente.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('35a1345a-8421-4a54-9624-6bfd9cf3eb96','P = V / I',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('35a1345a-8421-4a54-9624-6bfd9cf3eb96','P = V · I',true,2);
