insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('007cb69d-82bb-4cee-8424-485b4dcf7a17','de180f31-7cce-48d1-9d4f-641e1bb0a17c','Em que unidade se mede a potência elétrica?','A potência se mede em Watt (W), em homenagem a James Watt. 1.000 W = 1 kW.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('007cb69d-82bb-4cee-8424-485b4dcf7a17','Volt (V)',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('007cb69d-82bb-4cee-8424-485b4dcf7a17','Ampere (A)',false,2);
