insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('2ae879a1-ff97-43f8-8d83-d56739f271fb','de180f31-7cce-48d1-9d4f-641e1bb0a17c','Um equipamento de 4.400 W em 220 V puxa que corrente?','Usando I = P/V = 4.400/220 = 20 A. Essa conta converte potência em corrente para dimensionar cabos e disjuntores.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('2ae879a1-ff97-43f8-8d83-d56739f271fb','10 A',false,1);
