insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('616746ca-8644-4d63-80e5-3ef2cac4f8c3','de180f31-7cce-48d1-9d4f-641e1bb0a17c','O que a unidade quilowatt-hora (kWh) representa?','O kWh mede a energia consumida ao longo do tempo (1 kW durante 1 hora). É a unidade que aparece na conta de luz.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('616746ca-8644-4d63-80e5-3ef2cac4f8c3','A força que empurra a corrente',false,1);
