insert into public.quiz_options (question_id,texto,correta,ordem) values ('616746ca-8644-4d63-80e5-3ef2cac4f8c3','A energia consumida ao longo do tempo',true,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('616746ca-8644-4d63-80e5-3ef2cac4f8c3','A corrente instantânea',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('ef8daa53-1ba9-4f38-8676-2c2688d861bd','5f8eac47-c30d-47f9-9301-8a452bb431c3','Fontes de energia: companhia, auxiliar e backup','texto','<p><strong>Para começar:</strong> Nem todo local tem rede elétrica suficiente para um show. O técnico precisa conhecer as três fontes — rede da companhia, geradores e sistemas de backup — para garantir que o evento aconteça em qualquer lugar e não pare se faltar energia.</p><p>A energia de um evento pode vir de três caminhos que se complementam: a rede da companhia elétrica, a energia auxiliar (geradores) e os sistemas de backup. Cada uma tem seu papel, e em eventos de grande porte elas trabalham juntas para garantir continuidade.</p><ul><li><strong>Companhia elétrica: geração:</strong> A eletricidade é produzida em usinas a partir de fontes como carvão, gás natural, nuclear, hidrelétrica, solar e eólica, cada uma com vantagens e desvantagens de custo, disponibilidade e impacto ambiental.</li><li><strong>Companhia elétrica: distribuição e medição:</strong> Depois de gerada, a energia passa por linhas de transmissão e subestações até a rede de distribuição, que a leva às instalações. O consumo é medido em quilowatt-hora (kWh).</li><li><strong>Quadro de distribuição (Main Power):</strong> A energia entra na instalação por um quadro de distribuição, onde disjuntores e fusíveis protegem o sistema contra sobrecargas e curtos-circuitos, dividindo a energia em circuitos para áreas específicas.</li><li><strong>Energia auxiliar: geradores:</strong> Quando a rede do local é insuficiente ou inexistente, usa-se um gerador — equipamento que converte energia mecânica (motor a diesel) em energia elétrica, criando um sistema elétrico independente e móvel para som, luz, LED, vídeo e áreas de apoio.</li><li><strong>Backup: baterias e UPS:</strong> Para evitar paradas em falhas da rede, usam-se sistemas de reserva: baterias (íon-lítio, chumbo-ácido) e UPS (sistema de alimentação ininterrupta), que assumem o fornecimento aos equipamentos críticos quando a energia principal cai.</li><li><strong>Backup: geradores a combustível e sistemas híbridos:</strong> Geradores a diesel sustentam o fornecimento por períodos prolongados em instalações críticas como eventos. Sistemas híbridos combinam baterias, geradores e painéis solares para dar redundância e flexibilidade.</li><li><strong>Boas práticas do backup:</strong> Avaliar as necessidades e priorizar os equipamentos críticos, escolher a tecnologia adequada, instalar com profissionais qualificados, testar regularmente e fazer manutenção (baterias carregadas, geradores em ordem).</li></ul><p><strong>Na prática:</strong> Num festival ao ar livre sem rede suficiente, a produção instala dois geradores a diesel: um alimenta som e luz, o outro fica como redundância. A mesa de som e os equipamentos mais sensíveis ainda recebem um UPS, que segura o sinal por alguns segundos se houver troca de fonte, evitando que o show pare por uma falha momentânea.</p><h4>Resumo</h4><ul><li>A energia do evento pode vir da companhia elétrica, de geradores (auxiliar) e de sistemas de backup.</li><li>O quadro de distribuição (Main Power) recebe a energia e a protege com disjuntores e fusíveis.</li><li>Backup (baterias, UPS, geradores redundantes) garante continuidade para os equipamentos críticos.</li></ul>',15,5,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('2e861264-7fc3-49f0-ad1a-76aad27743c3','ef8daa53-1ba9-4f38-8676-2c2688d861bd','Quiz — Fontes de energia: companhia, auxiliar e backup');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c84ece0c-f8a4-47a6-8515-fd2e64299b96','2e861264-7fc3-49f0-ad1a-76aad27743c3','O que faz o quadro de distribuição (Main Power)?','O quadro de distribuição recebe a energia da rede ou do gerador e a divide em circuitos, protegendo o sistema contra sobrecargas e curtos com disjuntores e fusíveis.',1,1);
