insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('7a67b7b9-755b-406d-b25a-41db14fc4dbd','2e861264-7fc3-49f0-ad1a-76aad27743c3','O que é um gerador de energia usado em eventos?','O gerador converte energia mecânica, normalmente de um motor a diesel, em energia elétrica, criando um sistema independente e móvel para o evento.',2,1);
