insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('f8fff903-911f-45d2-9673-ead32fd66933','2e861264-7fc3-49f0-ad1a-76aad27743c3','Para que serve um sistema de backup (baterias/UPS) num evento?','O backup (baterias, UPS, gerador redundante) assume o fornecimento aos equipamentos críticos em caso de interrupção, garantindo continuidade do evento.',3,1);
