insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('903f571b-900c-4da5-8227-0f535d1a14bd','2e861264-7fc3-49f0-ad1a-76aad27743c3','Em que unidade a companhia elétrica mede o consumo de energia?','O consumo é medido em quilowatt-hora (kWh), que representa a energia usada em uma hora a uma taxa constante de 1 kW.',4,1);
