insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('92804f12-1a30-4cc0-b823-8fad45b6bc12','5f8eac47-c30d-47f9-9301-8a452bb431c3','Dimensionamento de carga e gerador','texto','<p><strong>Para começar:</strong> Dimensionar a carga é a tarefa que separa o evento que funciona do que dá problema. É somar tudo o que consome energia, converter em corrente e escolher gerador, cabos e disjuntores certos — com margem de segurança para os picos.</p><p>Dimensionar a parte elétrica de um palco é determinar quanta energia será necessária e como distribuí-la para alimentar iluminação, som, vídeo e demais equipamentos. O processo é metódico: levantar potências, somar, converter em corrente, escolher a distribuição e os dispositivos de proteção — sempre com folga.</p><ul><li><strong>1. Levantar os requisitos:</strong> Listar todos os equipamentos do palco (luzes, alto-falantes, amplificadores, projetores, máquinas de efeito) e anotar potência (W), tensão (V) e/ou corrente (A) de cada um.</li><li><strong>2. Calcular a demanda total:</strong> Somar as potências (ou correntes) de todos os dispositivos para obter a demanda total de energia do evento.</li><li><strong>3. Determinar a tensão:</strong> Confirmar a tensão disponível na área do palco (110 V, 220 V, 230 V...), pois ela varia conforme a região.</li><li><strong>4. Calcular a corrente:</strong> Usar I = P / V, onde I é a corrente (A), P a potência (W) e V a tensão (V). É a conta que transforma a potência total em corrente para dimensionar cabos e proteções.</li><li><strong>5. Distribuir e separar circuitos:</strong> Distribuir as cargas de forma uniforme em várias tomadas/circuitos para evitar sobrecarga. Equipamentos de alta potência (como iluminação) geralmente exigem circuitos dedicados.</li><li><strong>6. Margem de segurança do gerador:</strong> O gerador nunca deve operar no limite. Como boa prática, trabalha-se com 20% a 30% de capacidade livre, garantindo estabilidade e absorvendo os picos de consumo.</li><li><strong>7. Proteção, infraestrutura e documentação:</strong> Usar disjuntores e fusíveis, caixas de distribuição e cabos adequados; planejar o roteamento de cabos para evitar tropeços; documentar todas as conexões. Em demandas complexas, consultar eletricista ou engenheiro qualificado.</li></ul><p><strong>Na prática:</strong> Um palco soma 13.200 W de equipamentos em 220 V. A corrente é I = P/V = 13.200/220 = 60 A. Para essa carga não rodar no limite, o gerador deve ter folga de 20% a 30%: 60 A representariam no máximo 70% a 80% da sua capacidade, ou seja, escolhe-se um gerador dimensionado para algo em torno de 75 a 80 A (ou a potência equivalente), e a iluminação fica em circuito dedicado.</p><h4>Resumo</h4><ul><li>Dimensionar carga é somar as potências, converter em corrente (I = P/V) e escolher cabos, gerador e proteções.</li><li>Distribua as cargas de forma uniforme e use circuitos dedicados para equipamentos de alta potência.</li><li>O gerador nunca opera no limite: trabalhe com 20% a 30% de capacidade livre para os picos.</li></ul>',16,6,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('5464aa30-5f48-4bb1-9193-eb325f75d598','92804f12-1a30-4cc0-b823-8fad45b6bc12','Quiz — Dimensionamento de carga e gerador');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0a11253b-606b-4d75-b6a5-d1ee27455b2b','5464aa30-5f48-4bb1-9193-eb325f75d598','Qual fórmula converte a potência total em corrente para dimensionar a parte elétrica?','Reorganizando P = V · I, obtém-se I = P / V. É a conta usada para descobrir a corrente a partir da potência e da tensão.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('0a11253b-606b-4d75-b6a5-d1ee27455b2b','I = P · V',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('0a11253b-606b-4d75-b6a5-d1ee27455b2b','I = P / V',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('0a11253b-606b-4d75-b6a5-d1ee27455b2b','I = V / P',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('0a11253b-606b-4d75-b6a5-d1ee27455b2b','I = V · R',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('598889fc-2aa5-4638-9121-4eda50664910','5464aa30-5f48-4bb1-9193-eb325f75d598','Qual é a margem de segurança recomendada para não operar o gerador no limite?','A boa prática é manter 20% a 30% de capacidade livre no gerador, garantindo estabilidade e absorvendo picos de consumo.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('598889fc-2aa5-4638-9121-4eda50664910','0% a 5% de folga',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('598889fc-2aa5-4638-9121-4eda50664910','20% a 30% de capacidade livre',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('598889fc-2aa5-4638-9121-4eda50664910','50% a 60% de folga',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('598889fc-2aa5-4638-9121-4eda50664910','Não há margem; pode operar no limite',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('57e1b880-1748-43f8-89ae-3b4707b55f91','5464aa30-5f48-4bb1-9193-eb325f75d598','Um palco de 13.200 W em 220 V exige que corrente?','I = P/V = 13.200/220 = 60 A. A partir daí dimensiona-se o gerador com folga e separam-se os circuitos de alta potência.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('57e1b880-1748-43f8-89ae-3b4707b55f91','30 A',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('57e1b880-1748-43f8-89ae-3b4707b55f91','44 A',false,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('57e1b880-1748-43f8-89ae-3b4707b55f91','60 A',true,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('57e1b880-1748-43f8-89ae-3b4707b55f91','132 A',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('886e9d71-00cd-463e-9db7-bbb227ea7328','5464aa30-5f48-4bb1-9193-eb325f75d598','Por que equipamentos de iluminação costumam ficar em circuitos dedicados?','Equipamentos de alta potência, como iluminação, geralmente exigem circuitos dedicados para distribuir a carga e evitar sobrecargas.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('886e9d71-00cd-463e-9db7-bbb227ea7328','Porque consomem pouca energia',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('886e9d71-00cd-463e-9db7-bbb227ea7328','Porque são de alta potência e evitam sobrecarregar circuitos compartilhados',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('886e9d71-00cd-463e-9db7-bbb227ea7328','Porque não precisam de proteção',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('886e9d71-00cd-463e-9db7-bbb227ea7328','Porque a luz não usa corrente',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('3bb0d3a4-b779-4685-93ff-1b67a65bbc46','5f8eac47-c30d-47f9-9301-8a452bb431c3','Gerenciamento e segurança da rede elétrica','texto','<p><strong>Para começar:</strong> Montar a energia é metade do trabalho; gerenciá-la com segurança durante o evento é a outra. Main Power, balanceamento de fases, aterramento e monitoramento são o que mantém o show estável do início ao fim, sem riscos para equipamentos e pessoas.</p><p>A rede elétrica é um dos sistemas mais críticos de uma produção: som, luz, vídeo, LED e efeitos dependem de uma distribuição organizada, segura e estável. Por isso o gerenciamento começa no planejamento da carga total e segue durante toda a operação, com foco em proteção, balanceamento e monitoramento.</p><ul><li><strong>Planejamento da carga total:</strong> Primeiro passo do gerenciamento: levantar o consumo de todos os equipamentos e organizar como a energia será distribuída entre palco, iluminação, house mix, backstage, camarins e áreas de apoio.</li><li><strong>Main Power (distribuição principal):</strong> Quadro principal onde a energia da rede ou do gerador é recebida e distribuída. Funciona como centro de controle, normalmente com disjuntores principais, barramentos, saídas trifásicas e monofásicas, medidores de corrente e tensão e proteções contra sobrecarga e curto-circuito.</li><li><strong>Subquadros e racks:</strong> A partir do Main Power, a energia segue para subquadros e racks de distribuição, que alimentam os equipamentos específicos de cada área técnica.</li><li><strong>Balanceamento de fases:</strong> Em sistemas trifásicos (comuns em eventos), distribuir a carga de forma equilibrada entre as três fases. O desequilíbrio pode causar aquecimento de cabos, queda de tensão, desarme de disjuntores e instabilidade nos equipamentos.</li><li><strong>Proteção e cabos:</strong> Cada circuito deve ter disjuntor adequado contra sobrecarga e curto-circuito, e os cabos devem ser dimensionados para suportar a corrente que vão transportar, evitando aquecimento e risco de incêndio.</li><li><strong>Aterramento, organização e identificação:</strong> Todo sistema precisa de aterramento adequado para segurança de equipamentos e pessoas. Cabos devem ser organizados e protegidos de pessoas, veículos e intempéries; quadros, cabos e conexões devem ser claramente identificados.</li><li><strong>Monitoramento durante o evento:</strong> A equipe acompanha constantemente consumo de corrente, estabilidade da tensão, temperatura de cabos e conectores e funcionamento dos disjuntores, identificando problemas cedo e evitando falhas.</li></ul><p><strong>Na prática:</strong> Num evento trifásico, o técnico percebe no Main Power que a fase A está com 80 A e as fases B e C com 30 A cada. Esse desequilíbrio aquece o cabo da fase A e pode derrubar o disjuntor. Ele redistribui circuitos entre as fases até deixá-las próximas (cerca de 45 a 50 A cada), restabelecendo o balanceamento e a estabilidade do sistema.</p><h4>Resumo</h4><ul><li>O gerenciamento começa no planejamento da carga e centraliza a energia no Main Power, com proteções e medidores.</li><li>Em sistemas trifásicos é essencial balancear as fases para evitar aquecimento, queda de tensão e desarme.</li><li>Segurança exige aterramento, cabos dimensionados, identificação e monitoramento contínuo durante o evento.</li></ul>',16,7,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('40f1d910-8683-4aba-a230-467d6f3ae214','3bb0d3a4-b779-4685-93ff-1b67a65bbc46','Quiz — Gerenciamento e segurança da rede elétrica');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5734d346-4356-436f-a1f1-7685fc2190cb','40f1d910-8683-4aba-a230-467d6f3ae214','O que é o Main Power em uma produção de eventos?','O Main Power é o quadro principal de distribuição: recebe a energia da rede ou do gerador e a distribui de forma organizada e protegida para os setores do evento.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5734d346-4356-436f-a1f1-7685fc2190cb','O gerador a diesel',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5734d346-4356-436f-a1f1-7685fc2190cb','O quadro principal que recebe e distribui a energia, funcionando como centro de controle',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5734d346-4356-436f-a1f1-7685fc2190cb','O cabo de aterramento',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5734d346-4356-436f-a1f1-7685fc2190cb','O medidor da companhia elétrica',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('fe25043a-62f4-4028-a5b6-aa419ac7b1c4','40f1d910-8683-4aba-a230-467d6f3ae214','Por que é importante balancear as fases em um sistema trifásico?','O desequilíbrio de fases sobrecarrega uma das fases, causando aquecimento de cabos, queda de tensão, desarme de disjuntores e instabilidade. Balancear distribui a carga entre as três fases.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('fe25043a-62f4-4028-a5b6-aa419ac7b1c4','Para aumentar a tensão da rede',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('fe25043a-62f4-4028-a5b6-aa419ac7b1c4','Para distribuir a carga igualmente e evitar aquecimento, queda de tensão e desarme',true,2);
