insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('010ebac1-f31a-4af1-afd0-716a7735e3f7','40f1d910-8683-4aba-a230-467d6f3ae214','O que a equipe técnica deve monitorar durante o evento?','Durante a operação, monitora-se continuamente corrente, tensão, temperatura de cabos/conectores e os disjuntores, para identificar problemas cedo e evitar falhas.',4,1);
