insert into public.modules (id,course_id,titulo,ordem) values ('8817f174-7b84-4709-88c8-fbc71ba8e2e1','1320b04f-ec96-47e3-905c-46a6f7bce71e','Eletrônica I',3);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('2f994f98-a621-4c52-8870-9d38d0c22aaa','8817f174-7b84-4709-88c8-fbc71ba8e2e1','Fundamentos de Eletrônica para o Técnico de Eventos','texto','<p><strong>Para começar:</strong> Antes de montar qualquer som, luz ou vídeo, você precisa entender o que está correndo dentro dos cabos: a eletricidade. Nesta aula você vai dominar os conceitos básicos que sustentam todo o resto do módulo. Sem essa base, qualquer falha vira mistério.</p><p>A eletrônica estuda o comportamento e o controle dos elétrons em dispositivos e sistemas. No mundo dos eventos, ela está por trás de absolutamente tudo: mesas de som, moving lights, painéis de LED, intercom e até o no-break que protege o sistema. Entender corrente, tensão e os componentes básicos é o primeiro passo para trabalhar com segurança e diagnosticar problemas.</p><ul><li><strong>Corrente elétrica:</strong> É o fluxo de elétrons através de um circuito. Medida em Ampères (A). Quanto maior a corrente, maior o ''volume'' de energia passando — é por isso que cabos e disjuntores têm limite de Ampères que não pode ser ultrapassado.</li><li><strong>Tensão (voltagem):</strong> É a diferença de potencial elétrico entre dois pontos do circuito, medida em Volts (V). É a ''força'' que empurra os elétrons. No Brasil, as tomadas costumam ser 127 V ou 220 V — confundir as duas pode queimar equipamento.</li><li><strong>Resistência e Lei de Ohm:</strong> Resistência (medida em Ohms, Ω) limita o fluxo de corrente. A Lei de Ohm relaciona os três: V = I × R (tensão = corrente × resistência). É a fórmula mais básica da eletrônica e ajuda a entender por que um cabo fino esquenta ao puxar muita corrente.</li><li><strong>Resistor:</strong> Componente que limita o fluxo de corrente no circuito. Unidade: Ohms (Ω). Está dentro de praticamente todo equipamento eletrônico.</li><li><strong>Diodo:</strong> Permite a passagem de corrente em apenas uma direção. Usado em retificadores e circuitos de proteção. O LED (diodo emissor de luz) é um tipo de diodo — base dos painéis e refletores modernos.</li><li><strong>Capacitor:</strong> Armazena e libera carga elétrica. Usado para filtrar sinais e suavizar variações de tensão, ajudando a estabilizar a alimentação dos equipamentos.</li><li><strong>Transistor:</strong> Amplifica ou controla o fluxo de corrente. Pode funcionar como chave eletrônica ou amplificador. É a base dos amplificadores de áudio e de toda a eletrônica digital.</li><li><strong>Circuito série x paralelo:</strong> Em série, os componentes ficam em uma única rota: a corrente é a mesma, mas a tensão se divide. Em paralelo, ficam em pontos comuns: a tensão é a mesma, mas a corrente se divide. Saber a diferença ajuda a entender distribuição de energia e ligação de caixas acústicas.</li></ul><p><strong>Na prática:</strong> Num show, o técnico vai ligar um rack de amplificadores. Ele confere se a tomada é 220 V (e não 127 V) antes de plugar, porque o amplificador está configurado para 220 V. Em seguida calcula mentalmente a corrente total que aquele rack vai puxar, para não estourar o disjuntor da régua de AC. Esse raciocínio simples — tensão certa e corrente dentro do limite — evita queimar equipamento e parar o evento.</p><h4>Resumo</h4><ul><li>Corrente (A) é o fluxo de elétrons; tensão (V) é a força que os empurra; resistência (Ω) limita esse fluxo, e a Lei de Ohm (V = I × R) relaciona os três.</li><li>Resistor, diodo, capacitor e transistor são os componentes básicos presentes em todo equipamento de evento.</li><li>Em circuito série a tensão se divide; em paralelo a corrente se divide — isso afeta como a energia é distribuída no evento.</li></ul>',25,1,true,false);
