insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('aa955611-49c1-4624-be62-a18b1cb74cec','8fecf1a2-a810-4901-bd51-25ec02d279ab','Qual unidade mede a corrente elétrica?','A corrente, que é o fluxo de elétrons, é medida em Ampères (A). Volts medem tensão e Ohms medem resistência.',1,1);
