insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('f4f7611c-8f4b-4d44-aa7a-ec6c6db0aba6','8fecf1a2-a810-4901-bd51-25ec02d279ab','A Lei de Ohm é expressa por qual fórmula?','A Lei de Ohm é V = I × R: a tensão é igual à corrente multiplicada pela resistência.',2,1);
