insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('629db535-68b2-4ea3-9367-db4c3790cac0','8fecf1a2-a810-4901-bd51-25ec02d279ab','Num circuito em paralelo, o que acontece com a tensão e a corrente?','Em paralelo os componentes ligam-se a pontos comuns: a tensão é a mesma em todos, e a corrente é que se divide entre os caminhos.',3,1);
