insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('bb56eefe-064f-45c1-9d68-3eb0311287f4','8fecf1a2-a810-4901-bd51-25ec02d279ab','Qual componente permite a passagem de corrente em apenas uma direção?','O diodo conduz corrente em apenas um sentido, sendo usado em retificadores e proteção. O LED é um tipo de diodo.',4,1);
