insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('8d6ed876-177e-41f9-a2e7-d524a11d1857','af163990-652e-4309-a294-1eda7144b50b','Para que serve o no-break (UPS) em um evento?','O no-break (UPS) mantém equipamentos críticos energizados durante quedas, evitando travamentos e perda de programação.',2,1);
