insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('06eb1972-4a3a-4bee-9994-dedc9c2ed905','af163990-652e-4309-a294-1eda7144b50b','Qual a vantagem do alicate amperímetro?','O alicate amperímetro ''abraça'' o cabo e mede a corrente com o circuito em funcionamento, sem precisar desconectá-lo.',3,1);
