insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('642fef5f-d6ca-4ee1-9dce-27a88890e01a','af163990-652e-4309-a294-1eda7144b50b','Qual a função do flight case?','O flight case é uma caixa rígida que protege os equipamentos contra impactos e umidade no transporte e na montagem.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('642fef5f-d6ca-4ee1-9dce-27a88890e01a','Distribuir energia elétrica',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('642fef5f-d6ca-4ee1-9dce-27a88890e01a','Transportar e proteger equipamentos contra impactos',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('642fef5f-d6ca-4ee1-9dce-27a88890e01a','Controlar a iluminação',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('642fef5f-d6ca-4ee1-9dce-27a88890e01a','Medir frequências de RF',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('3e231aad-110c-4935-b3ba-af1e0d2d0740','8817f174-7b84-4709-88c8-fbc71ba8e2e1','Cabos: Alimentação AC e Transmissão de Sinais','texto','<p><strong>Para começar:</strong> O cabo certo no lugar certo é metade do trabalho do técnico de eventos. Cada tipo de cabo carrega um tipo de informação — energia, áudio, vídeo, dados ou luz. Nesta aula você aprende a reconhecer e escolher o cabo adequado para cada aplicação.</p><p>Os cabos se dividem em dois grandes grupos: os de alimentação AC (corrente alternada), que levam energia, e os de sinal, que transportam áudio, vídeo e dados. Escolher errado pode significar ruído, perda de qualidade, falha de imagem ou até risco elétrico. Conhecer cada tipo é fundamental no dia a dia.</p><ul><li><strong>Cabo de alimentação padrão (NBR 14136):</strong> Cabo de energia elétrica com plugues e tomadas normalizados no Brasil. É o cabo de força comum dos equipamentos.</li><li><strong>Cabos AC industriais, de extensão e de distribuição:</strong> Cabos mais robustos para ambientes exigentes; de extensão levam energia a distâncias maiores; de distribuição são mais grossos e alimentam vários equipamentos a partir de uma única fonte.</li><li><strong>Cabo XLR (áudio balanceado):</strong> Padrão profissional para áudio balanceado, usado em microfones, caixas e mesas de mixagem. O sinal balanceado (3 vias) reduz ruído em cabos longos — por isso é o preferido em eventos.</li><li><strong>Cabo Jack / P10 (TRS e TS):</strong> Cabo de áudio com plugue P10. TS (mono, não balanceado) é usado em guitarras e instrumentos; TRS pode levar áudio estéreo (fones) ou áudio balanceado (mono). Comum em instrumentos musicais e ligações de mesa.</li><li><strong>Cabo coaxial:</strong> Núcleo condutor central com blindagem metálica que minimiza interferências. Transmite sinais de áudio, vídeo e dados — usado, por exemplo, em vídeo SDI e sinais de RF/antena.</li><li><strong>Cabo HDMI:</strong> Transmite áudio e vídeo de alta definição num único cabo, entre TVs, players, consoles e telões. Tem limite prático de distância — em runs longos usa-se SDI (coaxial) ou conversores.</li><li><strong>Cabo VGA:</strong> Vídeo analógico para monitores e projetores antigos. Em desuso, mas ainda aparece em equipamentos legados.</li><li><strong>Cabo Ethernet (rede):</strong> Conexões de rede e dados em LAN. Em eventos, é a base de protocolos modernos de áudio (ex.: Dante) e de iluminação em rede (Art-Net/sACN).</li><li><strong>Cabo USB:</strong> Transmite dados e energia entre computadores, smartphones e periféricos; muito usado para interfaces de áudio e controladoras.</li><li><strong>Cabo DMX:</strong> Cabo digital que controla equipamentos de iluminação de palco pelo protocolo DMX. Atenção: parece XLR mas é específico para dados de luz — não deve ser confundido com cabo de microfone.</li><li><strong>Cabo óptico (fibra óptica):</strong> Transmite sinais por pulsos de luz, ideal para longas distâncias e áudio de alta qualidade, imune a interferência eletromagnética.</li></ul><p><strong>Na prática:</strong> Na montagem de um telão, o técnico precisa levar a imagem do switcher (mesa de corte) até um painel a 30 metros do palco. Ele sabe que um HDMI comum não aguenta essa distância sem perder o sinal, então usa cabo SDI (coaxial) com conectores BNC, que mantém a imagem estável no longo percurso. Cabo certo para a distância certa.</p><h4>Resumo</h4><ul><li>Cabos se dividem em alimentação AC (energia) e sinal (áudio, vídeo, dados, luz).</li><li>XLR é o padrão de áudio balanceado; DMX controla luz; HDMI/SDI levam vídeo; Ethernet leva dados e protocolos de rede.</li><li>A escolha depende do tipo de sinal, da distância e da compatibilidade — cabo errado gera ruído, perda de sinal ou falha.</li></ul>',28,3,true,false);
