insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c00adf8e-87cf-439b-8e31-ea235c10e255','4b254d02-71e3-482f-baca-afde85036383','Qual cabo é usado para controlar equipamentos de iluminação de palco?','O cabo DMX transporta o protocolo Digital Multiplex, usado para controlar moving lights, refletores e outros equipamentos de luz.',2,1);
