insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('6f574153-f6af-479d-98c0-a72d3e2f3749','4b254d02-71e3-482f-baca-afde85036383','Para levar vídeo a uma distância longa (dezenas de metros), qual opção é mais indicada que o HDMI comum?','O HDMI comum tem limite prático de distância; SDI (coaxial) e fibra óptica mantêm o sinal estável em runs longos.',3,1);
