insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('8545dea6-b3bf-4a34-89e7-57f4279c58a2','4b254d02-71e3-482f-baca-afde85036383','Qual cabo transmite sinais por pulsos de luz e é imune a interferência eletromagnética?','A fibra óptica transmite por luz, sendo ideal para longas distâncias e imune à interferência eletromagnética.',4,1);
