insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('7fc3caa0-049b-4a6f-9313-43b86a36111c','8817f174-7b84-4709-88c8-fbc71ba8e2e1','Conectores de Áudio, Vídeo, Energia e Iluminação','texto','<p><strong>Para começar:</strong> Se o cabo é a estrada, o conector é a porta de entrada. Plugar o conector errado — ou de forma malfeita — gera ruído, mau contato e falhas no meio do show. Nesta aula você aprende a reconhecer os conectores certos para áudio, vídeo, energia e luz.</p><p>Cada categoria de sinal tem seus conectores típicos. Um técnico precisa identificá-los de olhos fechados, porque na correria da montagem é o conector que define se o sinal vai passar limpo ou com problema. Vamos organizar os principais por família.</p><ul><li><strong>Conector NBR 14136 (plugue e tomada padrão):</strong> Padrão brasileiro de energia elétrica em residências e locais comerciais. É o plugue de força comum dos equipamentos no Brasil.</li><li><strong>Conector IEC (C13/C14, C19/C20):</strong> Conectores de força encontrados em computadores, amplificadores e equipamentos de áudio/vídeo. O C13/C14 é o famoso ''rabicho'' de fonte; o C19/C20 aguenta correntes maiores.</li><li><strong>Conector PowerCON:</strong> Conector de energia travado, comum em equipamentos profissionais de iluminação, áudio e vídeo. A trava evita que o cabo se solte durante o evento — mais seguro que o plugue comum.</li><li><strong>Conector XLR (áudio):</strong> Conector de 3 pinos, travado, para áudio balanceado em microfones, caixas e mesas. A trava e os 3 pinos garantem conexão firme e baixo ruído.</li><li><strong>Conector P10 / TRS (Jack):</strong> Plugue de áudio para instrumentos, fones e ligações de mesa. TS (mono) e TRS (estéreo ou balanceado). Muito comum em guitarras e teclados.</li><li><strong>Conector RCA:</strong> Conectores coloridos encontrados em aparelhos de som e TVs domésticas, para áudio e vídeo de nível de consumo. Aparece em equipamentos mais simples.</li><li><strong>Conector SpeakON:</strong> Conector travado para ligar amplificadores a caixas acústicas (sistemas de PA). Suporta alta potência com segurança e substitui ligações antigas a P10 ou bornes.</li><li><strong>Conector HDMI / DisplayPort:</strong> HDMI leva áudio e vídeo de alta definição num só conector; DisplayPort é similar, usado em vídeo de alta qualidade entre computadores e telas.</li><li><strong>Conector VGA / DVI:</strong> VGA é vídeo analógico (monitores e projetores antigos); DVI é vídeo digital entre computadores e monitores. Ambos em desuso, mas presentes em equipamentos legados.</li><li><strong>Conector BNC:</strong> Conector tipo baioneta usado em vídeo profissional (SDI), câmeras e equipamentos de transmissão. Trava com um quarto de volta, garantindo contato firme.</li><li><strong>Conector DMX (XLR de dados):</strong> Conector usado para controlar iluminação pelo protocolo DMX. Fisicamente parecido com o XLR de áudio (geralmente 3 ou 5 pinos), mas dedicado a dados de luz.</li></ul><p><strong>Na prática:</strong> Ao ligar as caixas de PA, o técnico usa cabos com SpeakON em vez de P10. O SpeakON trava ao girar, suporta a alta potência do amplificador sem aquecer e não corre risco de soltar com a vibração do grave. Resultado: ligação firme e segura mesmo no pico do show.</p><h4>Resumo</h4><ul><li>Energia: NBR 14136, IEC (C13/C14, C19/C20) e PowerCON (travado, profissional).</li><li>Áudio: XLR (balanceado), P10/TRS (instrumentos) e SpeakON (caixas de potência).</li><li>Vídeo: HDMI, DisplayPort, VGA/DVI (legado) e BNC (SDI profissional); DMX para iluminação.</li></ul>',26,4,true,false);
