insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('ee4d475a-c69d-448e-a388-0de7f129af3b','9214275c-4915-4cde-859d-f73bc552182f','Sobre o conector DMX, é correto afirmar que:','O conector DMX é dedicado a dados de iluminação (protocolo DMX). Apesar de parecer um XLR, não deve ser usado como cabo de áudio.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('ee4d475a-c69d-448e-a388-0de7f129af3b','É idêntico em função ao XLR de áudio',false,1);
