insert into public.quiz_options (question_id,texto,correta,ordem) values ('ee4d475a-c69d-448e-a388-0de7f129af3b','Substitui o cabo HDMI',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('c221de8e-0715-4f04-9df9-e333fbdd61f6','8817f174-7b84-4709-88c8-fbc71ba8e2e1','Transmissão Sem Fio: RF, Infravermelho e Interferências','texto','<p><strong>Para começar:</strong> Microfones sem fio, intercom, controle remoto: cada vez mais o sinal viaja pelo ar. Mas o ar é um espaço disputado, cheio de interferências. Nesta aula você entende como a transmissão sem fio funciona e como evitar que ela falhe no pior momento.</p><p>Uma transmissão sem fio leva áudio, vídeo ou dados de um emissor a um receptor sem cabos, usando ondas eletromagnéticas. As duas tecnologias mais presentes em eventos são RF (radiofrequência) e IR (infravermelho). E onde há muitos sinais no ar, surge o grande inimigo: a interferência.</p><ul><li><strong>Como funciona o sem fio (modulação):</strong> O sinal original é combinado com uma onda portadora de frequência mais alta — processo chamado modulação. Isso permite que ele seja transportado pelo ar como onda eletromagnética e recuperado no destino (demodulação).</li><li><strong>Transmissão, propagação e recepção:</strong> Após modulado, o sinal vira onda eletromagnética enviada por uma antena; ela se propaga à velocidade da luz, podendo atravessar obstáculos dependendo da frequência. A antena receptora capta a onda e a converte de volta em sinal elétrico.</li><li><strong>RF (radiofrequência):</strong> Faixa do espectro eletromagnético entre o áudio e as micro-ondas, de alguns kHz a centenas de GHz. Atravessa obstáculos e alcança longas distâncias — base de microfones sem fio, intercom, Wi-Fi, rádio e TV. O uso é regulamentado por órgãos governamentais (no Brasil, a Anatel) para evitar conflitos de frequência.</li><li><strong>IR (infravermelho):</strong> Radiação eletromagnética além da luz visível, com comprimento de onda maior. Exige geralmente linha de visada direta e tem curto alcance. Usado em controles remotos, automação e sensores; também em imagem térmica (visualizar calor).</li><li><strong>RF x IR — quando usar cada um:</strong> RF atravessa paredes e cobre longas distâncias, mas disputa espaço no espectro e sofre interferência. IR não atravessa obstáculos e precisa de mira direta, mas é imune a interferência de RF — bom para controles ponto a ponto.</li><li><strong>Interferência de RF (RFI):</strong> Presença indesejada de sinais de RF que atrapalham o funcionamento de equipamentos. Vem de outros transmissores, celulares, lâmpadas LED/dimmers, motores e dispositivos sem fio. Pode causar chiado, queda de sinal e até falha total do microfone.</li><li><strong>Como reduzir interferência:</strong> Blindagem eletromagnética dos equipamentos sensíveis; filtragem de frequências indesejadas; aterramento adequado; posicionamento (afastar de fontes de ruído e usar antenas direcionais); usar frequências diferentes das fontes de interferência; e recursos automáticos como controle de potência e correção de erro.</li></ul><p><strong>Na prática:</strong> Antes de um evento com 8 microfones sem fio, o técnico usa o analisador de espectro (ou a função de scan do receptor) para mapear quais frequências estão livres naquele local. Ele afasta a antena receptora de painéis de LED (fonte de RFI), coordena os canais em frequências diferentes e faz um teste andando pelo palco. Assim evita que dois microfones briguem pela mesma frequência e que o LED ''suje'' o sinal durante a apresentação.</p><h4>Resumo</h4><ul><li>Sem fio transporta sinais pelo ar via ondas eletromagnéticas (modulação no envio, demodulação na recepção).</li><li>RF atravessa obstáculos e alcança longe (microfones, intercom, Wi-Fi); IR precisa de mira direta e curto alcance (controles).</li><li>A interferência de RF (RFI) vem de outros equipamentos; mitiga-se com blindagem, aterramento, posicionamento e escolha de frequências.</li></ul>',27,5,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('dc5e3a57-0722-4665-9040-42e1ac3a432e','c221de8e-0715-4f04-9df9-e333fbdd61f6','Quiz — Transmissão Sem Fio: RF, Infravermelho e Interferências');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('4914ec45-566a-4e69-87d3-b500ff2e07f9','dc5e3a57-0722-4665-9040-42e1ac3a432e','O que significa a sigla RF?','RF significa Radiofrequência — a faixa do espectro eletromagnético usada para comunicações sem fio como microfones, Wi-Fi e rádio.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('4914ec45-566a-4e69-87d3-b500ff2e07f9','Receptor Fixo',false,1);
