insert into public.quiz_options (question_id,texto,correta,ordem) values ('4914ec45-566a-4e69-87d3-b500ff2e07f9','Recepção Frontal',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('dff63a1e-733b-40c2-a1bd-a1b9a0278adf','dc5e3a57-0722-4665-9040-42e1ac3a432e','Uma diferença prática entre IR e RF é que o infravermelho (IR):','O IR normalmente precisa de mira direta (linha de visada) e cobre curtas distâncias, ao contrário do RF que atravessa obstáculos.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('dff63a1e-733b-40c2-a1bd-a1b9a0278adf','Atravessa paredes facilmente',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('dff63a1e-733b-40c2-a1bd-a1b9a0278adf','Geralmente exige linha de visada direta e tem curto alcance',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('dff63a1e-733b-40c2-a1bd-a1b9a0278adf','Tem alcance maior que o RF',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('dff63a1e-733b-40c2-a1bd-a1b9a0278adf','Sofre mais interferência de outros rádios',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('8ba2ad92-6c7b-4a44-bf4f-d88a7861396b','dc5e3a57-0722-4665-9040-42e1ac3a432e','O que é a interferência de radiofrequência (RFI)?','A RFI é a presença de sinais de RF indesejados (de celulares, LED, dimmers, outros rádios) que prejudicam a recepção dos equipamentos.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('8ba2ad92-6c7b-4a44-bf4f-d88a7861396b','Um tipo de cabo balanceado',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('8ba2ad92-6c7b-4a44-bf4f-d88a7861396b','A presença indesejada de sinais de RF que atrapalham os equipamentos',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('8ba2ad92-6c7b-4a44-bf4f-d88a7861396b','Uma estrutura de fixação de palco',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('8ba2ad92-6c7b-4a44-bf4f-d88a7861396b','Um conector de energia',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('aebf6ecb-5710-40fd-9d0d-8e222579c817','dc5e3a57-0722-4665-9040-42e1ac3a432e','Qual NÃO é uma forma adequada de reduzir interferência de RF?','Concentrar tudo na mesma frequência aumenta o conflito. O correto é coordenar canais em frequências diferentes, além de afastar fontes de ruído, aterrar e blindar.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('aebf6ecb-5710-40fd-9d0d-8e222579c817','Usar frequências diferentes das fontes de interferência',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('aebf6ecb-5710-40fd-9d0d-8e222579c817','Afastar antenas de fontes de ruído como LED e dimmers',false,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('aebf6ecb-5710-40fd-9d0d-8e222579c817','Concentrar todos os canais na mesma frequência',true,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('aebf6ecb-5710-40fd-9d0d-8e222579c817','Garantir aterramento adequado e blindagem',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('a4234fea-de7d-4e22-afa7-fee330a48b3d','8817f174-7b84-4709-88c8-fbc71ba8e2e1','Estruturas de Fixação e Segurança no Palco','texto','<p><strong>Para começar:</strong> Tudo o que sobe no palco precisa ficar firme — e seguro acima da cabeça das pessoas. Refletores, caixas, telões e cenários ficam suspensos por estruturas que não admitem erro. Nesta aula você conhece as principais estruturas de fixação e o que jamais pode ser negligenciado na segurança.</p><p>A estrutura de fixação garante estabilidade e, principalmente, segurança dos elementos suspensos e apoiados no palco. Como o técnico de eventos trabalha próximo a essas montagens, precisa reconhecer cada estrutura e entender que segurança vem sempre em primeiro lugar.</p><ul><li><strong>Grid (grelha):</strong> Estrutura de trusses (barras metálicas) suspensa no alto do palco, usada para fixar iluminação, alto-falantes, telões e outros elementos em diferentes alturas e posições.</li><li><strong>Varas de teatro (bambolinas):</strong> Varas horizontais no grid às quais se prendem iluminação, cenários e cortinas, que podem subir e descer conforme a necessidade da cena.</li><li><strong>Torres de iluminação:</strong> Estruturas autônomas (de chão) que sustentam refletores, moving lights e gobos, posicionadas em pontos do palco para direcionar a luz.</li><li><strong>Pontos de ancoragem:</strong> Pontos da estrutura projetados e testados para suportar cargas suspensas, usados para fixar equipamentos com segurança. A resistência de cada ponto é verificada antes do uso.</li><li><strong>Sistemas de fly:</strong> Conjunto de cabos e polias que permite suspender e mover equipamentos de forma controlada, ajustando a altura de cenários e iluminação com eficiência.</li><li><strong>Estruturas de solo:</strong> Fixações de chão: suportes (tripés) para caixas de som, racks para áudio e vídeo e pedestais diversos. Alternativa quando não se usa suspensão.</li><li><strong>Suportes de parede:</strong> Para equipamentos leves, como monitores e telas pequenas, comuns em salas de controle e áreas de exibição.</li><li><strong>Trilhos e barras de fixação:</strong> Trilhos ou barras onde os equipamentos são montados ou deslizados para ajustar a posição de forma rápida e flexível.</li><li><strong>Segurança em primeiro lugar:</strong> Toda estrutura de fixação deve ser projetada, instalada e testada por profissionais experientes, seguindo as normas de segurança para eventos ao vivo. É essencial considerar o peso dos equipamentos, a distribuição de carga, a estabilidade e a capacidade de carga das fixações. Cargas suspensas exigem cabos de segurança secundários.</li></ul><p><strong>Na prática:</strong> Ao pendurar um moving light na truss do grid, o técnico não confia só na garra (clamp). Ele passa também um cabo de aço de segurança (safety) ligando o equipamento à estrutura. Se a garra falhar, o safety segura o refletor e evita uma queda perigosa sobre o público ou a equipe. Nunca um equipamento suspenso fica sem essa redundância.</p><h4>Resumo</h4><ul><li>Estruturas suspensas (grid/truss, bambolinas, sistemas de fly) e de chão (torres, racks, tripés) sustentam os equipamentos do palco.</li><li>Pontos de ancoragem são testados quanto à resistência e definem onde se pode suspender carga com segurança.</li><li>Segurança é prioridade: respeitar capacidade de carga, usar cabos de segurança e contar com profissionais habilitados.</li></ul>',24,6,true,false);
