insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('ebf85e29-9440-4cc2-b4c3-f96af7c1a7b2','736ab864-8b78-4efd-ab73-3bb9146a372d','Por que se usa um cabo de segurança (safety) em equipamentos suspensos?','O cabo de segurança é uma redundância: se a garra/fixação principal falhar, ele segura o equipamento e evita a queda.',2,1);
