insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('05dbb1f9-7ea6-46a7-804a-7618c2b2c7ef','736ab864-8b78-4efd-ab73-3bb9146a372d','Os pontos de ancoragem se caracterizam por:','Pontos de ancoragem são projetados e testados quanto à resistência, definindo onde se pode fixar cargas suspensas de forma segura.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('05dbb1f9-7ea6-46a7-804a-7618c2b2c7ef','Serem usados apenas para cabos de áudio',false,1);
