insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('518ab3b1-84d2-44c8-92fb-16f51cfb89bb','736ab864-8b78-4efd-ab73-3bb9146a372d','Qual é uma estrutura de fixação de solo (não suspensa)?','A torre de iluminação é uma estrutura autônoma de chão. Bambolinas, sistemas de fly e grid são suspensos.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('518ab3b1-84d2-44c8-92fb-16f51cfb89bb','Bambolinas',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('518ab3b1-84d2-44c8-92fb-16f51cfb89bb','Sistema de fly',false,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('518ab3b1-84d2-44c8-92fb-16f51cfb89bb','Torre de iluminação',true,3);
