insert into public.modules (id,course_id,titulo,ordem) values ('bd2fd591-2a6a-42c5-8f91-d28998e0d63a','1320b04f-ec96-47e3-905c-46a6f7bce71e','Luz I',4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('7891f0c9-ac8c-44e2-a00b-2ccb3c854da8','bd2fd591-2a6a-42c5-8f91-d28998e0d63a','Fundamentos da iluminação: o que a luz faz num evento','texto','<p><strong>Para começar:</strong> Iluminar não é só clarear o ambiente. É criar atmosfera, destacar o que importa e transmitir emoção. Nesta aula você vai entender os conceitos básicos que estão por trás de qualquer projeto de luz.</p><p>Antes de mexer em qualquer equipamento, o técnico precisa dominar o vocabulário da luz. São poucos conceitos, mas eles aparecem o tempo todo no dia a dia de um evento.</p><ul><li><strong>O que é iluminação:</strong> Uso controlado da luz para criar efeitos visuais desejados em palcos, eventos, espaços arquitetônicos e estúdios. Vai além de fornecer claridade: cria atmosfera, destaca elementos e transmite emoções.</li><li><strong>Fonte de luz:</strong> É a fonte física que emite a luz (lâmpada incandescente, LED, fluorescente, etc.). A escolha da fonte afeta a temperatura de cor, a intensidade e outras características da iluminação.</li><li><strong>Intensidade luminosa:</strong> Refere-se ao brilho ou quantidade de luz emitida. É medida em lúmens (lm). Quanto maior a intensidade, mais iluminado o ambiente ou objeto aparece. No controle de palco, a intensidade de cada aparelho costuma ser ajustada em porcentagem (0 a 100%).</li><li><strong>Direção da luz:</strong> De onde a luz incide sobre o objeto ou cena. É decisiva para criar sombras e realçar características. A luz pode vir de cima, de baixo, lateralmente (luz de lateral/sidelight) ou de ângulos específicos para alcançar o efeito desejado.</li><li><strong>Ângulo de feixe:</strong> Abertura do feixe emitido pela fonte. Feixes estreitos (spot) concentram a luz em uma área menor; feixes amplos (flood) espalham a luz por uma área maior.</li><li><strong>Difusão e foco:</strong> A luz pode ser direcionada e moldada com refletores, lentes e acessórios. A difusão suaviza a luz (deixa mais espalhada e sem bordas duras); o foco direciona a luz para um ponto específico.</li><li><strong>Segurança como base:</strong> Em eventos ao vivo, iluminação adequada é essencial para a segurança de artistas e equipe: todos precisam enxergar para se mover e trabalhar sem riscos. Acessos, escadas e bastidores nunca devem ficar no escuro total.</li></ul><p><strong>Na prática:</strong> Num show em uma casa de eventos média, o lighting designer pede uma ''luz de boas-vindas'' enquanto o público entra: luz ampla, suave e quente cobrindo o palco. Ao começar o show, ele troca para feixes estreitos e direcionados sobre o vocalista. Mesma sala, mesmos aparelhos, dois efeitos completamente diferentes só mudando direção, ângulo de feixe e difusão.</p><h4>Resumo</h4><ul><li>Iluminar é controlar a luz para criar atmosfera, destacar e emocionar, não apenas clarear</li><li>Os conceitos-base são: fonte, intensidade (lúmens), direção, ângulo de feixe e difusão/foco</li><li>Segurança vem primeiro: ninguém trabalha ou se desloca no escuro total</li></ul>',25,1,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('52efaf97-3b72-49f0-ab25-70b0ad77bfea','7891f0c9-ac8c-44e2-a00b-2ccb3c854da8','Quiz — Fundamentos da iluminação: o que a luz faz num evento');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('df5dcbe3-91d4-4a91-9104-4dc9c9ef3492','52efaf97-3b72-49f0-ab25-70b0ad77bfea','Em que unidade se mede a intensidade luminosa (quantidade de luz emitida)?','A intensidade luminosa é medida em lúmens (lm). Kelvin mede temperatura de cor e watts medem consumo de energia, não a quantidade de luz.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('df5dcbe3-91d4-4a91-9104-4dc9c9ef3492','Kelvin (K)',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('df5dcbe3-91d4-4a91-9104-4dc9c9ef3492','Lúmens (lm)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('df5dcbe3-91d4-4a91-9104-4dc9c9ef3492','Watts (W)',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('df5dcbe3-91d4-4a91-9104-4dc9c9ef3492','Graus (°)',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('9dbbe135-7bfd-4c92-85fc-1bc9e88166dc','52efaf97-3b72-49f0-ab25-70b0ad77bfea','Qual a principal diferença entre um feixe estreito e um feixe amplo?','Feixes estreitos (spot) concentram a luz numa área pequena; feixes amplos (flood) espalham a luz por uma área maior. É o ângulo de feixe que define isso.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('9dbbe135-7bfd-4c92-85fc-1bc9e88166dc','O estreito é sempre mais quente',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('9dbbe135-7bfd-4c92-85fc-1bc9e88166dc','O estreito concentra a luz numa área menor; o amplo espalha por área maior',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('9dbbe135-7bfd-4c92-85fc-1bc9e88166dc','O amplo só existe em LED',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('9dbbe135-7bfd-4c92-85fc-1bc9e88166dc','Não há diferença prática',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('18d15ca2-e83e-46d9-b84a-23e18bfc48b3','52efaf97-3b72-49f0-ab25-70b0ad77bfea','Por que a iluminação de segurança é considerada essencial num evento ao vivo?','Em eventos ao vivo a luz adequada garante que artistas e equipe técnica se movam e executem tarefas com clareza e sem riscos. Acessos e bastidores não podem ficar no escuro total.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('18d15ca2-e83e-46d9-b84a-23e18bfc48b3','Para economizar energia',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('18d15ca2-e83e-46d9-b84a-23e18bfc48b3','Para que artistas e equipe enxerguem e se movam sem riscos',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('18d15ca2-e83e-46d9-b84a-23e18bfc48b3','Apenas por exigência estética',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('18d15ca2-e83e-46d9-b84a-23e18bfc48b3','Para deixar o palco mais escuro',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('25e6d5e3-1696-48fb-ba10-dd5fdf3461c1','bd2fd591-2a6a-42c5-8f91-d28998e0d63a','Temperatura de cor e o uso das cores na luz','texto','<p><strong>Para começar:</strong> A mesma cena pode parecer aconchegante ou fria dependendo da cor da luz. Nesta aula você vai entender temperatura de cor em Kelvin e como as cores comunicam emoções no palco.</p><p>Cor é uma das ferramentas mais poderosas do iluminador. Ela define o clima da cena antes mesmo de o público perceber. Vamos separar dois assuntos: a temperatura de cor da fonte e o significado das cores aplicadas.</p><ul><li><strong>Temperatura de cor:</strong> Medida da aparência da cor da luz branca emitida por uma fonte, expressa em Kelvin (K). Atenção ao que parece contraintuitivo: fontes mais quentes (amareladas) têm temperatura de cor mais BAIXA, e fontes mais frias (azuladas) têm temperatura de cor mais ALTA.</li><li><strong>Referências práticas de Kelvin:</strong> Como guia padrão do mercado: luz quente/amarelada fica em torno de 2700–3200 K (clima intimista, aconchegante); luz neutra em torno de 4000 K; luz fria/branca-azulada a partir de 5600–6500 K (clima moderno, clínico, de dia claro). Misturar fontes de Kelvin muito diferentes na mesma cena costuma deixar a luz ''suja''.</li><li><strong>Cor por filtros e por LED:</strong> As fontes podem emitir cores diferentes. Em aparelhos convencionais usa-se gelatina (filtro de cor) na frente da lente; em aparelhos de LED a cor é gerada eletronicamente pela mistura dos diodos (RGB / RGBW / RGBA). A combinação de cores cria efeitos dramáticos e atmosferas específicas.</li><li><strong>Cores quentes e seus significados:</strong> Vermelho: paixão, energia, amor, ação, atenção, perigo. Laranja: entusiasmo, vitalidade, determinação, calor, simpatia. Amarelo: alegria, felicidade, criatividade, clareza, otimismo, energia positiva. Rosa: ternura, romance, suavidade, compaixão.</li><li><strong>Cores frias e neutras e seus significados:</strong> Azul: calma, serenidade, confiança, estabilidade, profundidade. Verde: natureza, renovação, crescimento, saúde, equilíbrio. Roxo: realeza, espiritualidade, mistério, luxo, criatividade. Branco: pureza, paz, simplicidade, limpeza. Preto/ausência de luz: mistério, elegância, formalidade.</li><li><strong>Cor é cultural e subjetiva:</strong> Essas associações não são universais: variam conforme cultura, contexto e experiência pessoal. O preto, por exemplo, significa luto em algumas culturas e elegância em outras. Use as cores como ferramenta de comunicação, mas considere o público e o tema do evento.</li></ul><p><strong>Na prática:</strong> Numa formatura, a entrada dos formandos pede luz quente em ~3000 K com âmbar e dourado para um clima solene e acolhedor. Na hora da festa, o técnico vira tudo para azul e magenta saturados com a luz fria por trás, e a mesma sala vira balada. A escolha de Kelvin e de cor mudou completamente a leitura emocional do momento.</p><h4>Resumo</h4><ul><li>Temperatura de cor é medida em Kelvin: quente é Kelvin baixo, frio é Kelvin alto</li><li>Cor pode vir de gelatina (convencional) ou da mistura de LEDs (RGB/RGBW)</li><li>O significado das cores comunica emoção, mas é cultural e subjetivo</li></ul>',25,2,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('5555715f-ce50-4198-990c-bb645619bc0a','25e6d5e3-1696-48fb-ba10-dd5fdf3461c1','Quiz — Temperatura de cor e o uso das cores na luz');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('50197026-a9c8-4d26-b0f6-faa5b061a7be','5555715f-ce50-4198-990c-bb645619bc0a','Uma luz bem amarelada e aconchegante corresponde a qual faixa de temperatura de cor?','Luz quente/amarelada tem temperatura de cor BAIXA (cerca de 2700–3200 K). Kelvin alto (5600–6500 K) corresponde à luz fria e azulada.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('50197026-a9c8-4d26-b0f6-faa5b061a7be','Kelvin alto, em torno de 6500 K',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('50197026-a9c8-4d26-b0f6-faa5b061a7be','Kelvin baixo, em torno de 2700–3200 K',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('50197026-a9c8-4d26-b0f6-faa5b061a7be','Não tem relação com Kelvin',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('50197026-a9c8-4d26-b0f6-faa5b061a7be','Sempre exatamente 4000 K',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('b83d5d63-1a0e-4c0e-b5be-f5f7a652aefa','5555715f-ce50-4198-990c-bb645619bc0a','Num refletor de LED, como a cor é normalmente produzida?','No LED a cor é gerada eletronicamente pela mistura dos diodos coloridos (RGB, RGBW, RGBA). Já nos convencionais usa-se gelatina (filtro de cor) na frente da lente.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('b83d5d63-1a0e-4c0e-b5be-f5f7a652aefa','Trocando a lâmpada por uma colorida',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('b83d5d63-1a0e-4c0e-b5be-f5f7a652aefa','Misturando eletronicamente os diodos (RGB/RGBW)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('b83d5d63-1a0e-4c0e-b5be-f5f7a652aefa','Pintando a lente',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('b83d5d63-1a0e-4c0e-b5be-f5f7a652aefa','Aumentando os watts',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('a1e8a640-6e8b-4ece-bf42-c808eaf46adb','5555715f-ce50-4198-990c-bb645619bc0a','O que é correto afirmar sobre o significado das cores na iluminação?','As associações de cor não são universais: dependem de cultura, contexto e individualidade. O técnico deve considerar o público e o tema ao escolher as cores.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('a1e8a640-6e8b-4ece-bf42-c808eaf46adb','É universal e igual para todos',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('a1e8a640-6e8b-4ece-bf42-c808eaf46adb','Varia conforme cultura, contexto e experiência pessoal',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('a1e8a640-6e8b-4ece-bf42-c808eaf46adb','Só importa em teatro',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('a1e8a640-6e8b-4ece-bf42-c808eaf46adb','Nunca muda o clima da cena',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('9ff3635c-3e90-4f51-bd6a-816b7c2fec17','5555715f-ce50-4198-990c-bb645619bc0a','Por que geralmente se evita misturar fontes de Kelvin muito diferentes na mesma cena de luz branca?','Misturar temperaturas de cor muito diferentes no branco deixa a luz visualmente inconsistente e ''suja''. O ideal é manter coerência de Kelvin dentro da mesma cena.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('9ff3635c-3e90-4f51-bd6a-816b7c2fec17','Porque gasta mais energia',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('9ff3635c-3e90-4f51-bd6a-816b7c2fec17','Porque a luz tende a ficar ''suja'' e inconsistente',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('9ff3635c-3e90-4f51-bd6a-816b7c2fec17','Porque queima os aparelhos',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('9ff3635c-3e90-4f51-bd6a-816b7c2fec17','Porque é proibido por norma',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('7ff793e3-ec3c-49bb-952a-0bca4dfe2ce8','bd2fd591-2a6a-42c5-8f91-d28998e0d63a','O papel do técnico de iluminação','texto','<p><strong>Para começar:</strong> Por trás de cada cena bem iluminada existe um técnico que montou, configurou, operou e resolveu problemas em tempo real. Nesta aula você vai entender exatamente o que se espera dessa função.</p><p>O técnico de iluminação atua em eventos, teatro, TV, cinema e produções afins. Suas responsabilidades variam conforme o porte do evento, mas há um núcleo de funções que se repete sempre.</p><ul><li><strong>Instalação e configuração:</strong> Montar e configurar todos os equipamentos de iluminação necessários: luzes, cabos, suportes (treliças/clamps), consoles e periféricos. É a base de tudo e onde a maioria dos erros é prevenida.</li><li><strong>Operação dos equipamentos:</strong> Durante o evento, operar os aparelhos conforme as necessidades do diretor, do designer de iluminação ou da equipe, seguindo o roteiro de cenas.</li><li><strong>Programação de luzes:</strong> Programar as luzes conforme os requisitos do evento, criando diferentes cenários (cenas/memórias) e efeitos sob demanda. Em muitos casos isso é feito antecipadamente na passagem de som/luz.</li><li><strong>Manutenção e reparo:</strong> Fazer a manutenção regular dos equipamentos para garantir que tudo funcione, e executar reparos quando necessário. Aparelho que não acende na hora do show quase sempre é falha que poderia ter sido pega na manutenção.</li><li><strong>Colaboração com a equipe:</strong> Trabalhar em estreita colaboração com diretores, designers de iluminação, técnicos de som e demais membros da produção, para que a luz atenda às necessidades do evento.</li><li><strong>Segurança elétrica e estrutural:</strong> Garantir que instalações elétricas e equipamentos estejam em conformidade com os padrões de segurança. Inclui carga elétrica adequada, aterramento, fixação correta dos aparelhos em altura e travas de segurança (safety).</li><li><strong>Resolução de problemas ao vivo:</strong> Em evento ao vivo surgem imprevistos. O técnico precisa identificar e resolver rapidamente para minimizar o impacto: cabo solto, aparelho que apagou, canal travado. Calma e método valem mais que pressa.</li></ul><p><strong>Na prática:</strong> Faltam dez minutos para abrir a casa e um refletor frontal não acende. Em vez de entrar em pânico, o técnico segue o método: confere se o aparelho está endereçado, testa o cabo de energia, testa o cabo DMX, e descobre que um conector DMX se soltou na treliça. Reconecta, testa a cena, e o show abre no horário. Resolução de problemas é rotina, não exceção.</p><h4>Resumo</h4><ul><li>O técnico instala, configura, opera, programa e mantém os equipamentos de luz</li><li>Segurança elétrica e estrutural é responsabilidade central da função</li><li>Resolver problemas ao vivo com método e rapidez faz parte da rotina</li></ul>',20,3,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('5ef76b7e-00af-429c-b154-3e59b5284fee','7ff793e3-ec3c-49bb-952a-0bca4dfe2ce8','Quiz — O papel do técnico de iluminação');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('eaebc3c9-d26c-4e9b-bd5d-d4a1e0f8d02b','5ef76b7e-00af-429c-b154-3e59b5284fee','Qual destas é uma responsabilidade central do técnico de iluminação?','O técnico é responsável por instalar, configurar, operar, programar e manter os equipamentos de iluminação, sempre em colaboração com a equipe de produção.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('eaebc3c9-d26c-4e9b-bd5d-d4a1e0f8d02b','Escrever o roteiro artístico do show',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('eaebc3c9-d26c-4e9b-bd5d-d4a1e0f8d02b','Instalar, configurar e operar os equipamentos de luz',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('eaebc3c9-d26c-4e9b-bd5d-d4a1e0f8d02b','Definir o cachê dos artistas',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('eaebc3c9-d26c-4e9b-bd5d-d4a1e0f8d02b','Cuidar apenas do áudio',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('85b0a7bb-d4d9-4967-a870-df05db4cba61','5ef76b7e-00af-429c-b154-3e59b5284fee','Durante o evento ao vivo um refletor apaga. Qual é a melhor postura?','O técnico precisa identificar e resolver imprevistos rapidamente para minimizar o impacto. Um diagnóstico metódico (energia, DMX, endereço) é o caminho.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('85b0a7bb-d4d9-4967-a870-df05db4cba61','Ignorar e seguir o show',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('85b0a7bb-d4d9-4967-a870-df05db4cba61','Diagnosticar com método: energia, cabo DMX, endereçamento',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('85b0a7bb-d4d9-4967-a870-df05db4cba61','Desligar todo o sistema',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('85b0a7bb-d4d9-4967-a870-df05db4cba61','Esperar acabar o evento para olhar',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('18b97b7f-41d3-46f4-ae47-b1ed53b2576f','5ef76b7e-00af-429c-b154-3e59b5284fee','A segurança elétrica e estrutural no trabalho do técnico inclui principalmente:','Garantir conformidade com padrões de segurança envolve carga elétrica correta, aterramento e fixação segura dos aparelhos em altura, com cabos de segurança (safety).',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('18b97b7f-41d3-46f4-ae47-b1ed53b2576f','Apenas escolher cores bonitas',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('18b97b7f-41d3-46f4-ae47-b1ed53b2576f','Carga elétrica adequada, aterramento e fixação/travas dos aparelhos em altura',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('18b97b7f-41d3-46f4-ae47-b1ed53b2576f','Somente a marca do console',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('18b97b7f-41d3-46f4-ae47-b1ed53b2576f','Reduzir o número de cenas',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('55da8aec-531e-4f44-b366-f6b0a8a85983','bd2fd591-2a6a-42c5-8f91-d28998e0d63a','Equipamentos de iluminação: tipos de refletor e aparelhos de palco','texto','<p><strong>Para começar:</strong> PAR, Fresnel, elipsoidal, LED, moving head... cada aparelho tem um feixe e um propósito. Nesta aula você vai aprender a reconhecer os principais equipamentos e saber quando usar cada um.</p><p>Escolher o aparelho certo é metade do trabalho. Cada tipo de refletor entrega um tipo de feixe; cada aparelho de efeito cumpre uma função. Vamos do convencional ao automatizado.</p><ul><li><strong>PAR / Par Can:</strong> Aparelho robusto e versátil que emite um feixe intenso e concentrado, sem foco ajustável (o feixe é definido pela lâmpada/lente). Ótimo para banhar áreas e dar cor em grande quantidade. Hoje é muito comum o PAR de LED, que troca cor eletronicamente e consome menos energia.</li><li><strong>Fresnel:</strong> Projetor com lente Fresnel (de anéis), que permite ajustar o foco de spot (feixe fechado) a flood (feixe aberto). Gera luz suave, de bordas difusas, boa para cobrir áreas amplas com transição macia.</li><li><strong>PC (Plano-Convexo):</strong> Projetor com lente plano-convexa. Entrega um feixe mais definido e com borda um pouco mais dura que o Fresnel, também com foco ajustável. Útil para destacar áreas e objetos com mais recorte. Observação técnica: a lente do PC é plano-convexa; quem usa lentes que permitem recorte preciso com facas e gobos é o elipsoidal, descrito a seguir.</li><li><strong>Elipsoidal (recorte):</strong> Refletor de feixe preciso e definido, com facas (shutters) para recortar o formato da luz e suporte para gobos (máscaras que projetam padrões). É a ferramenta padrão para iluminar um objeto ou pessoa específica com bordas limpas. (No material-base esse recurso de feixe preciso aparece associado ao ''PC''; o aparelho de recorte propriamente dito é o elipsoidal.)</li><li><strong>Moving Head (cabeça móvel):</strong> Luminária motorizada controlada remotamente: ajusta direção (pan/tilt), cor, foco e efeitos de movimento. Existem versões spot (feixe definido, com gobo), wash (feixe aberto e suave) e beam (feixe muito fechado e potente). É o ''canivete'' do show moderno.</li><li><strong>Wash:</strong> Aparelho que emite luz ampla e uniforme, cobrindo grandes áreas com cor e intensidade homogêneas. Usado para preencher o palco ou o cenário com cor.</li><li><strong>LED:</strong> Aparelhos que usam diodos emissores de luz para gerar várias cores e efeitos com baixo consumo de energia e pouco calor. Presentes em PARs, washes, barras, painéis e moving heads.</li><li><strong>Aparelhos convencionais:</strong> Refletores tradicionais: lâmpadas PAR, refletores de tungstênio e similares. Continuam amplamente usados, em geral com luz quente e controle de intensidade por dimmer.</li></ul><p><strong>Na prática:</strong> Num show de banda, o desenho combina aparelhos: PARs de LED dão a cor de fundo do palco (wash geral), elipsoidais recortam um facho limpo sobre o vocalista no solo, e moving heads beam cortam o ar com fumaça para os refrões. Cada aparelho foi escolhido pelo tipo de feixe que entrega.</p><h4>Resumo</h4><ul><li>PAR banha e dá cor; Fresnel e PC ajustam foco; elipsoidal recorta com precisão e gobo</li><li>Moving head é motorizado (pan/tilt, cor, foco) e vem em versões spot, wash e beam</li><li>LED entrega cor variada com baixo consumo e pouco calor, em vários formatos</li></ul>',30,4,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('4326627f-f043-4d08-bcb8-28e72776ca9a','55da8aec-531e-4f44-b366-f6b0a8a85983','Quiz — Equipamentos de iluminação: tipos de refletor e aparelhos de');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('14b3388e-a3b5-4043-bd85-431e90de8711','4326627f-f043-4d08-bcb8-28e72776ca9a','Qual aparelho é o indicado para projetar um feixe recortado e limpo sobre uma pessoa, com possibilidade de gobo?','O elipsoidal tem feixe preciso, facas (shutters) para recorte e suporte para gobos, sendo a ferramenta padrão para destacar uma pessoa ou objeto com bordas limpas.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('14b3388e-a3b5-4043-bd85-431e90de8711','Par Can',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('14b3388e-a3b5-4043-bd85-431e90de8711','Wash',false,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('14b3388e-a3b5-4043-bd85-431e90de8711','Elipsoidal',true,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('14b3388e-a3b5-4043-bd85-431e90de8711','Fresnel',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('14904f70-09bd-480f-9c0c-df936ada8542','4326627f-f043-4d08-bcb8-28e72776ca9a','O que caracteriza o feixe de um PAR (Par Can)?','O PAR emite um feixe intenso e concentrado e não tem foco ajustável (o feixe depende da lâmpada/lente). É ótimo para banhar áreas e dar cor.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('14904f70-09bd-480f-9c0c-df936ada8542','Feixe com foco totalmente ajustável',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('14904f70-09bd-480f-9c0c-df936ada8542','Feixe intenso e concentrado, sem foco ajustável',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('14904f70-09bd-480f-9c0c-df936ada8542','Sempre um feixe difuso e fraco',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('14904f70-09bd-480f-9c0c-df936ada8542','Só funciona em movimento',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e894c2fa-673e-4623-b9b3-7362fe11155b','4326627f-f043-4d08-bcb8-28e72776ca9a','Um moving head se diferencia de um refletor convencional principalmente por:','O moving head é uma luminária motorizada controlada remotamente, que ajusta direção (pan/tilt), cor, foco e efeitos de movimento, ao contrário dos refletores fixos.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e894c2fa-673e-4623-b9b3-7362fe11155b','Ser sempre mais barato',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e894c2fa-673e-4623-b9b3-7362fe11155b','Ser motorizado, ajustando direção, cor, foco e movimento por controle remoto',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e894c2fa-673e-4623-b9b3-7362fe11155b','Não usar eletricidade',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e894c2fa-673e-4623-b9b3-7362fe11155b','Não poder mudar de cor',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e262f502-471e-4d72-b38f-d78274cc531f','4326627f-f043-4d08-bcb8-28e72776ca9a','Qual vantagem principal dos aparelhos de LED frente aos convencionais de tungstênio?','Os LEDs geram diversas cores e efeitos eletronicamente, com baixo consumo de energia e pouca geração de calor, dispensando a gelatina usada nos convencionais.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e262f502-471e-4d72-b38f-d78274cc531f','Esquentam muito mais',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e262f502-471e-4d72-b38f-d78274cc531f','Produzem várias cores com baixo consumo de energia e pouco calor',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e262f502-471e-4d72-b38f-d78274cc531f','Não conseguem mudar de cor',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e262f502-471e-4d72-b38f-d78274cc531f','Precisam sempre de gelatina',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('055146a4-f5dd-4bae-8256-a95dd268b84c','bd2fd591-2a6a-42c5-8f91-d28998e0d63a','Efeitos especiais e controle DMX','texto','<p><strong>Para começar:</strong> Fumaça cortada por um feixe, um strobe no refrão, dezenas de aparelhos mudando de cor ao mesmo tempo. Tudo isso depende de efeitos especiais bem usados e de um protocolo de controle: o DMX.</p><p>Esta aula fecha o módulo juntando os aparelhos de efeito ao sistema que comanda todos eles de forma sincronizada. Entender o básico de DMX é o que separa apertar botão de operar um show.</p><ul><li><strong>Estroboscópio (strobe):</strong> Produz flashes de luz intermitentes. Conforme a taxa de flash, cria efeito de congelamento do movimento ou de movimento em câmera lenta. Usar com responsabilidade: strobe intenso pode causar desconforto e há restrições para pessoas fotossensíveis.</li><li><strong>Máquinas de atmosfera:</strong> Máquinas de fumaça, de neblina (hazer) e de bolhas. Elas não são luz, mas dão corpo ao ar para que os feixes fiquem visíveis. Sem fumaça/haze, um beam no ar quase não aparece.</li><li><strong>Laser:</strong> Gera feixes concentrados e coloridos que criam padrões e efeitos visuais complexos. Exige cuidado especial de segurança e, frequentemente, regras quanto à projeção em direção ao público.</li><li><strong>Luz UV (luz negra):</strong> Emite luz ultravioleta que faz substâncias fluorescentes brilharem, criando efeitos visuais marcantes em cenários, figurinos e tinta especial.</li><li><strong>Outros recursos visuais:</strong> Projetores de imagem (exibem imagens, vídeos e padrões em superfícies), fibra óptica (pontos de luz e céu de estrelas) e luzes inteligentes programáveis sincronizadas com a música ou as ações do palco.</li><li><strong>O que é DMX:</strong> DMX (DMX512) é o protocolo padrão de controle de iluminação. Permite ajustar intensidade, cor e padrões de muitos aparelhos de forma precisa e sincronizada a partir de um console. Substitui a ideia de ''um interruptor por luz'' por um único cabo de dados controlando tudo.</li><li><strong>Endereço e canais DMX:</strong> Cada aparelho recebe um endereço DMX e ocupa um número de canais (por exemplo, um par de LED pode usar canais separados para vermelho, verde, azul e intensidade). Um universo DMX tem 512 canais. Endereçar certo é o que faz cada aparelho ''entender'' o comando dirigido a ele.</li><li><strong>Ligação e cuidados básicos:</strong> Os aparelhos DMX são ligados em cadeia (daisy chain) com cabo apropriado, geralmente saindo do console e passando de aparelho em aparelho. Boas práticas: usar cabo de boa qualidade e, em linhas longas, um terminador no último aparelho para evitar ruído no sinal.</li></ul><p><strong>Na prática:</strong> Antes da virada do ano, o técnico endereça cada moving head em um universo DMX, liga tudo em daisy chain a partir do console e coloca um terminador no último aparelho. Na contagem regressiva, uma única cena dispara: hazer enche o ar, todos os beams sobem juntos em azul e o strobe entra na batida. Dezenas de aparelhos, um comando, graças ao DMX.</p><h4>Resumo</h4><ul><li>Efeitos como strobe, fumaça/haze, laser e UV dão impacto, mas exigem cuidado de segurança</li><li>DMX512 é o protocolo padrão que controla muitos aparelhos de forma precisa e sincronizada</li><li>Cada aparelho tem endereço e ocupa canais; um universo DMX tem 512 canais</li></ul>',25,5,true,false);
