insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('f13fdcdb-9e46-4786-9b1d-21859eaff261','ffda5fda-d2a6-4f11-babc-792c5b70cdda','Quantos canais existem em um universo DMX?','Um universo DMX possui 512 canais. Cada aparelho recebe um endereço e ocupa um número de canais dentro desse universo.',2,1);
