insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('f73cead3-170b-4e9f-ae97-dde18fd225e0','ffda5fda-d2a6-4f11-babc-792c5b70cdda','Qual cuidado é importante ao usar luz estroboscópica (strobe)?','O strobe deve ser usado com responsabilidade: flashes intensos podem causar desconforto e há restrições para pessoas fotossensíveis. O mesmo cuidado de segurança vale para laser.',4,1);
