insert into public.modules (id,course_id,titulo,ordem) values ('952a9de6-e32a-413d-92b5-6b306bc3c37c','1320b04f-ec96-47e3-905c-46a6f7bce71e','Vídeo I',5);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('341e82f6-b38e-4692-873a-c73bb39f59bf','952a9de6-e32a-413d-92b5-6b306bc3c37c','A profissão de vídeo em eventos: o que faz o técnico e o VJ','texto','<p><strong>Para começar:</strong> Trabalhar com vídeo em eventos é transformar ideias em imagens em movimento que informam, entretêm e emocionam o público. Antes de tocar em qualquer equipamento, você precisa entender o papel do profissional de vídeo e onde ele atua. Nesta aula você vai conhecer a profissão, a função do VJ e por que o vídeo virou peça central de qualquer evento moderno.</p><p>O profissional de vídeo (videomaker) cria, produz e edita imagens. Dentro do evento ao vivo, uma especialização ganha destaque: o VJ (Video Jockey), que manipula visuais em tempo real durante a apresentação.</p><ul><li><strong>O que é o profissional de vídeo:</strong> É quem cria, produz e edita vídeos que informam, entretêm e inspiram. Combina criatividade, conhecimento técnico e comunicação para entregar conteúdo audiovisual de qualidade em plataformas online, TV, cinema e, principalmente para nós, eventos ao vivo.</li><li><strong>O que é um VJ (Video Jockey):</strong> É o profissional que cria e manipula conteúdo visual em tempo real durante apresentações ao vivo: shows musicais, festas, eventos culturais e performances artísticas. Assim como o DJ trabalha o som, o VJ trabalha a imagem, sincronizando-a com a música e a atmosfera do evento.</li><li><strong>Por que o vídeo importa no evento:</strong> A demanda por conteúdo audiovisual cresce em todas as frentes. No evento, a imagem amplifica a atmosfera, reforça a mensagem do palco e cria uma experiência sensorial que envolve o público. Telões e painéis viraram parte essencial da cenografia.</li><li><strong>Storytelling visual:</strong> O profissional de vídeo conta histórias com imagens. No evento, isso significa escolher e organizar o conteúdo visual de forma que a sequência de imagens faça sentido com a música, o tema e o momento da apresentação.</li><li><strong>Diferença entre produção e operação:</strong> Na produção (pré-evento) você cria e organiza o conteúdo: vídeos, loops, animações e imagens. Na operação (durante o evento) você exibe, mixa e ajusta esse conteúdo ao vivo. O técnico júnior geralmente começa apoiando a operação.</li></ul><p><strong>Na prática:</strong> Em um show de música eletrônica, enquanto o DJ toca, o VJ projeta loops de animação sincronizados com a batida nos telões atrás do palco. Quando a música muda de ritmo, ele troca o visual para acompanhar o clima — escuro e lento nas partes calmas, colorido e rápido nos drops.</p><h4>Resumo</h4><ul><li>O profissional de vídeo cria e edita imagens; o VJ as manipula ao vivo no evento.</li><li>O vídeo ao vivo serve para amplificar a atmosfera e envolver o público.</li><li>A produção acontece antes; a operação acontece durante o evento.</li></ul>',12,1,true,false);
