insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('3cad2b75-d65c-43d1-ac2f-01d34f713c33','d0dfe31e-136d-4c57-b3cc-3c854bd51fe0','O VJ é frequentemente comparado a qual outro profissional do evento?','Assim como o DJ trabalha o som ao vivo, o VJ trabalha a imagem ao vivo, sincronizada com a música.',2,1);
