insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('58b5ff64-ca7e-4619-aeba-c308834e761f','d0dfe31e-136d-4c57-b3cc-3c854bd51fe0','Qual é o objetivo principal do vídeo ao vivo em um evento?','O objetivo é criar uma experiência visual envolvente e sincronizada que amplifica a atmosfera e envolve o público.',3,1);
