insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('af2aff72-6142-4d5b-b7b8-e55e013aab60','d0dfe31e-136d-4c57-b3cc-3c854bd51fe0','Em que fase o técnico organiza vídeos, loops e imagens que serão usados?','A organização e criação do conteúdo (vídeos, loops, animações, imagens) acontece na produção, antes do evento.',4,1);
