insert into public.quiz_options (question_id,texto,correta,ordem) values ('af2aff72-6142-4d5b-b7b8-e55e013aab60','No pós-evento de faturamento',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('836dd430-7b58-4daa-906f-6c68d34f6c7c','952a9de6-e32a-413d-92b5-6b306bc3c37c','Equipamentos específicos do VJ: o kit básico de vídeo no evento','texto','<p><strong>Para começar:</strong> Um bom resultado visual depende do equipamento certo, bem conectado e protegido. Nesta aula você vai conhecer o kit básico que sustenta qualquer operação de VJ — do computador que é o coração do sistema até os cabos de backup que salvam a apresentação. Conhecer cada peça evita pânico na hora do show.</p><p>A seleção de equipamentos varia com o estilo do show, o tamanho do público e as preferências do VJ. Mas existe um conjunto básico que quase sempre aparece. Vamos percorrer peça por peça.</p><ul><li><strong>Computador:</strong> É o núcleo do equipamento do VJ. Precisa ser potente para executar o software de VJing e processar vídeo em tempo real sem travar. Placa de vídeo dedicada, memória RAM suficiente e armazenamento rápido (SSD) fazem diferença direta no desempenho.</li><li><strong>Software de VJing:</strong> Programas especializados para mixar e manipular vídeos, imagens e efeitos ao vivo. Os mais citados são Resolume, VDMX e Modul8. É neles que o conteúdo é organizado em camadas e disparado durante a apresentação.</li><li><strong>Controlador MIDI ou controlador de VJ:</strong> Interface física com botões, sliders (controles deslizantes) e pads. Cada controle é mapeado para um parâmetro do software — disparar um clipe, mudar a velocidade, aplicar um efeito —, permitindo operar com as mãos em vez de só pelo mouse.</li><li><strong>Projetor ou telas (LED x projeção):</strong> Os visuais são exibidos em telas ou superfícies. Há dois caminhos principais: telas LED, que são painéis que emitem a própria luz (mais brilho, bom para ambientes claros), e projeção, em que um projetor lança a imagem sobre uma superfície (mais barato em áreas grandes, mas perde nitidez com luz ambiente).</li><li><strong>Cabos e adaptadores de vídeo:</strong> Conectam o computador ao projetor ou às telas. Os mais comuns são HDMI, DisplayPort e VGA. O VGA é analógico e antigo; HDMI e DisplayPort são digitais e preferíveis. Adaptadores resolvem incompatibilidades entre conectores.</li><li><strong>Interface de captura de vídeo:</strong> Equipamento que leva um sinal externo — por exemplo, de uma câmera ao vivo — para dentro do software de VJing. Assim o VJ consegue incorporar imagem ao vivo do palco ou da plateia à mixagem visual.</li><li><strong>Conteúdo visual (bancos de mídia):</strong> São os vídeos, loops, imagens e animações usados para montar os visuais. O VJ pode criar o próprio conteúdo ou usar bibliotecas de mídia existentes, sempre organizadas e nomeadas para achar rápido durante o show.</li><li><strong>Controlador de iluminação DMX:</strong> Alguns VJs também comandam a luz do palco em sincronia com os visuais. O padrão de controle de iluminação em eventos é o DMX, que liga a mesa/controlador aos refletores e moving heads.</li><li><strong>Ferramentas de mapeamento de projeção:</strong> Quando se projeta em superfícies não convencionais (prédios, objetos, cenários irregulares), usam-se ferramentas de mapeamento para ajustar a imagem ao formato da superfície. É o video mapping em sua forma básica.</li><li><strong>Hub USB / hub de energia:</strong> Controladores MIDI, interfaces de captura e outros dispositivos conectam por USB. Um hub fornece portas extras e, quando alimentado, energia suficiente para todos os periféricos funcionarem juntos.</li><li><strong>Acessórios e equipamentos de proteção:</strong> Cabos extras, adaptadores e fixações garantem uma montagem estável. Estabilizadores de energia, adaptadores de voltagem e cabos de backup evitam que um problema elétrico ou um cabo solto derrube a apresentação.</li></ul><p><strong>Na prática:</strong> Na montagem de uma festa, o técnico conecta o notebook ao painel de LED por cabo HDMI, liga o controlador MIDI por USB num hub alimentado e deixa um segundo cabo HDMI já testado guardado na bag como backup. Antes do público entrar, passa o sinal de uma câmera pela interface de captura para conferir que a imagem ao vivo aparece no software.</p><h4>Resumo</h4><ul><li>O computador com software de VJing (Resolume, VDMX, Modul8) é o coração do sistema.</li><li>Exibição é por telas LED (emitem luz) ou projeção; conexão por HDMI, DisplayPort ou VGA.</li><li>Hubs, estabilizadores e cabos de backup garantem uma operação estável e sem sustos.</li></ul>',15,2,true,false);
