insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('75d7cc11-da62-4d9f-9e02-e8a8a7a19f4f','cc3bee03-1994-4ff8-8cb6-63269605fec2','Qual equipamento é considerado o núcleo do sistema do VJ?','O computador é o núcleo: ele executa o software de VJing e processa o vídeo em tempo real. Por isso precisa ser potente.',1,1);
