insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('8b780aef-6c32-42a2-91bd-e5c89a069512','cc3bee03-1994-4ff8-8cb6-63269605fec2','Qual é a diferença básica entre tela LED e projeção?','Painéis de LED emitem luz própria (mais brilho, bons com luz ambiente); a projeção depende de um projetor lançando a imagem numa superfície e perde nitidez com luz forte.',2,1);
