insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('ef207e52-ec18-4a10-a82c-f0c91d5a537f','cc3bee03-1994-4ff8-8cb6-63269605fec2','Para que serve a interface de captura de vídeo?','A interface de captura incorpora sinais externos (ex.: câmera) ao software de VJing, permitindo usar imagem ao vivo na mixagem.',3,1);
