insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('3885e7fc-1c88-44f5-a39e-469a4b36c088','952a9de6-e32a-413d-92b5-6b306bc3c37c','Fundamentos técnicos de sinal de vídeo: resolução, conexões e switcher','texto','<p><strong>Para começar:</strong> Saber ligar um cabo é o começo; entender o sinal que passa por ele é o que separa o técnico amador do profissional. Nesta aula você vai dominar os conceitos que sustentam toda operação de vídeo em evento: resolução, os sinais HDMI e SDI, e a mesa de corte (switcher) que escolhe o que vai para o telão.</p><p>Este é o conteúdo de enriquecimento técnico, padrão do mercado de vídeo para eventos, que complementa os equipamentos vistos antes. Conhecer estes fundamentos evita imagem cortada, sem sinal ou na resolução errada.</p><ul><li><strong>Resolução:</strong> É a quantidade de pixels que formam a imagem. As mais comuns em eventos são Full HD (1920x1080) e 4K (3840x2160). A regra prática: a resolução que sai do computador deve combinar com a do telão. Mandar uma resolução que a tela não suporta resulta em imagem cortada, esticada ou sem sinal.</li><li><strong>Sinal HDMI:</strong> Conexão digital que leva imagem e áudio no mesmo cabo. É o padrão mais comum em notebooks, projetores e telas. Tem limite de distância: cabos longos de HDMI (acima de ~10-15 m) podem perder o sinal sem um amplificador ou extensor.</li><li><strong>Sinal SDI:</strong> Conexão profissional (conector BNC, que rosqueia) usada em estruturas maiores. A grande vantagem sobre o HDMI é a distância: o SDI percorre dezenas de metros por cabo coaxial sem perder qualidade, ideal para ligar câmeras e palcos distantes da régia.</li><li><strong>DisplayPort e VGA:</strong> DisplayPort é digital, comum em placas de vídeo de computador, e suporta altas resoluções. VGA é analógico e antigo — ainda aparece em projetores antigos, mas só transmite vídeo (sem áudio) e perde qualidade. Sempre que possível, prefira conexões digitais.</li><li><strong>Mesa de corte / switcher:</strong> É o equipamento (ou software) que recebe várias fontes de vídeo — câmeras, notebook do VJ, slides — e decide qual delas aparece no telão a cada momento. Permite cortar de uma fonte para outra com transições limpas, sendo o centro da operação em eventos com múltiplas entradas.</li><li><strong>Conceito de fonte e saída:</strong> Fonte (input) é de onde o vídeo vem (câmera, computador, player). Saída (output) é para onde ele vai (telão, projetor, gravação, transmissão). Toda operação consiste em rotear fontes para saídas; entender esse fluxo evita ligar o cabo no lugar errado.</li><li><strong>Taxa de quadros (frame rate):</strong> É quantas imagens por segundo o vídeo exibe, medida em fps (ex.: 30 ou 60 fps). Manter a mesma taxa entre fonte, switcher e tela evita travamentos e imagem ''pulando''. É um ajuste que costuma passar despercebido até dar problema.</li><li><strong>Mapping básico:</strong> Mapping (mapeamento de projeção) é ajustar a imagem para encaixar exatamente no formato da superfície projetada, mesmo que ela seja irregular. Na forma básica, é alinhar os cantos da projeção (keystone/quatro pontos) para que a imagem fique reta e do tamanho certo na tela ou no cenário.</li></ul><p><strong>Na prática:</strong> Numa conferência, três câmeras chegam à régia por cabo SDI (porque o palco fica longe) e o notebook dos slides chega por HDMI. Tudo entra na mesa de corte, e o técnico configura a saída em Full HD 1080p a 30 fps para combinar com o telão de LED. Durante o evento, ele corta entre as câmeras e os slides usando o switcher, sempre conferindo que a resolução de saída bate com a do painel.</p><h4>Resumo</h4><ul><li>Resolução de saída deve combinar com a da tela; senão a imagem corta, estica ou some.</li><li>HDMI é digital e curto; SDI é profissional e cobre longas distâncias por cabo coaxial.</li><li>A mesa de corte (switcher) recebe várias fontes e escolhe qual vai para a saída.</li></ul>',16,3,true,false);
