insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('751dd774-4538-4681-b4e2-275bc9cef165','a45ca299-c413-4ba0-9906-56734c12356e','O que acontece se a resolução que sai do computador não combinar com a do telão?','Resolução incompatível gera imagem cortada, esticada ou ausência de sinal. A saída deve sempre combinar com a resolução da tela.',1,1);
