insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('f668cff5-b415-4635-8deb-67989998aefd','a45ca299-c413-4ba0-9906-56734c12356e','Qual a principal vantagem do sinal SDI sobre o HDMI?','O SDI (cabo coaxial, conector BNC) cobre dezenas de metros sem perda, ideal para câmeras e palcos distantes da régia; o HDMI tem alcance curto.',2,1);
