insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('1b21ec1e-6712-4ff1-ac5b-92a4ff57711c','a45ca299-c413-4ba0-9906-56734c12356e','Para que serve a mesa de corte (switcher) em um evento?','O switcher recebe várias fontes (câmeras, notebook, slides) e decide, com transições limpas, qual delas é exibida na saída a cada momento.',3,1);
