insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('f9880265-f85f-4812-91e3-f72ab2241b6f','a45ca299-c413-4ba0-9906-56734c12356e','O que é o mapping básico em projeção?','Mapping básico é ajustar/alinhar os cantos da projeção (quatro pontos / keystone) para encaixar a imagem corretamente na superfície.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('f9880265-f85f-4812-91e3-f72ab2241b6f','Apagar o conteúdo do telão',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('f9880265-f85f-4812-91e3-f72ab2241b6f','Alinhar os cantos da imagem para que ela fique reta e no tamanho certo na superfície',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('f9880265-f85f-4812-91e3-f72ab2241b6f','Aumentar o volume da trilha',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('f9880265-f85f-4812-91e3-f72ab2241b6f','Trocar o projetor por uma tela LED',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('31d41a99-6b32-42e4-9ed3-a67e53cbc5a8','952a9de6-e32a-413d-92b5-6b306bc3c37c','Atividades do VJ na prática: mixar, sincronizar e improvisar ao vivo','texto','<p><strong>Para começar:</strong> Com equipamento montado e sinal entendido, chega a hora do que o público realmente vê: a operação ao vivo. Nesta aula você vai percorrer as atividades do dia a dia do VJ — da criação do conteúdo à improvisação no calor do show — e entender que técnica e leitura de plateia andam juntas.</p><p>As atividades variam com o tipo de evento, o estilo musical e as tecnologias disponíveis. Mas o objetivo é sempre o mesmo: criar uma experiência visual envolvente e sincronizada com a música ao vivo.</p><ul><li><strong>Criação de conteúdo visual:</strong> Antes do evento, o VJ produz vídeos, animações, efeitos e imagens usando softwares de edição, animação e design. Esse material vira o banco de mídia que será disparado durante a apresentação.</li><li><strong>Mixagem de vídeos:</strong> Ao vivo, o VJ combina diferentes vídeos e visuais em camadas, criando um fluxo contínuo de imagens que se sincroniza com a música e o tema do evento. É o equivalente visual de mixar faixas de som.</li><li><strong>Manipulação em tempo real:</strong> Durante a apresentação, ajusta cores, transições, efeitos e filtros na hora, adaptando-se à atmosfera e ao ritmo. Nada é totalmente pré-gravado: a operação responde ao momento.</li><li><strong>Sincronização com a música:</strong> O VJ trabalha junto dos artistas musicais para casar os visuais com a música. Softwares permitem ajustar velocidade e ritmo dos elementos visuais conforme a trilha sonora, criando uma experiência sensorial coesa.</li><li><strong>Projeção e mapeamento:</strong> Em eventos especiais, aplica técnicas de mapeamento para que os visuais se adaptem a superfícies irregulares — edifícios, objetos tridimensionais, cenários — gerando efeitos de maior impacto.</li><li><strong>Seleção e remix de conteúdo existente:</strong> Além do material próprio, o VJ seleciona e remixa conteúdo pré-existente (videoclipes, trechos de filmes, animações) para encaixar na narrativa visual da apresentação.</li><li><strong>Interatividade:</strong> Alguns VJs incorporam elementos interativos, deixando o público influenciar os visuais por meio de sensores de movimento ou aplicativos móveis, tornando a experiência participativa.</li><li><strong>Colaboração com artistas:</strong> O VJ atua junto a DJs, músicos e artistas de palco para entregar uma experiência multimídia coesa, em que som, luz e imagem conversam entre si.</li><li><strong>Gerenciamento técnico:</strong> Além de criar, o VJ configura e opera os equipamentos de projeção, iluminação e controle necessários — montagem, testes e ajustes fazem parte do trabalho.</li><li><strong>Improvisação criativa:</strong> Marca registrada do VJing: improvisar e adaptar os visuais conforme o feedback da plateia e as mudanças do ambiente. A capacidade de reagir ao inesperado é tão importante quanto o conteúdo preparado.</li><li><strong>Acompanhar tendências:</strong> Um bom VJ se mantém atento a novas tecnologias, efeitos e estilos visuais emergentes para manter as apresentações atualizadas e envolventes.</li></ul><p><strong>Na prática:</strong> Em uma festa, o VJ percebe que a pista esfriou. Em tempo real, ele troca os loops escuros por imagens mais coloridas e acelera as transições para acompanhar uma música mais agitada que o DJ acabou de soltar. Não estava no roteiro — é pura improvisação criativa lendo a reação do público.</p><h4>Resumo</h4><ul><li>O VJ cria o conteúdo antes e o mixa, ajusta e sincroniza ao vivo durante o evento.</li><li>Sincronizar a imagem com a música e colaborar com os artistas é essencial.</li><li>A improvisação criativa — reagir à plateia em tempo real — é a marca do VJing.</li></ul>',14,4,true,false);
