insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('508a1bf8-e4c4-45e1-88f3-33919d6a9456','e9da3cd4-44f9-49e2-9541-c3f71a355ba3','Qual atividade é descrita como a marca registrada do VJing?','A capacidade de improvisar e adaptar os visuais com base no feedback da plateia e nas mudanças do ambiente é uma característica distintiva do VJing.',2,1);
