insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('34bb4035-a593-4e9b-9e50-b0004b23b0bf','e9da3cd4-44f9-49e2-9541-c3f71a355ba3','O que o VJ faz na ''manipulação em tempo real''?','Na manipulação em tempo real, o VJ ajusta parâmetros como cores, transições, efeitos e filtros ao vivo, adaptando-se à atmosfera e ao ritmo.',4,1);
