insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('b439d530-8493-4636-9034-7b20fd43e898','d3e79e3a-c851-4372-b287-e5c0b148fd99','Na prática, as fases do fluxo costumam ser agrupadas em quais três grandes momentos?','O vocabulário do dia a dia agrupa o fluxo em pré-produção, durante o evento e pós-produção.',4,1);
