insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('d8dfd0fb-ff6f-4ade-b652-df7029bfa907','01fa9b3b-b34e-4c00-88fc-7a3707012c98','Qual é a principal função de uma Ordem de Serviço de carga e descarga?','A OS estabelece diretrizes, responsabilidades, horários e áreas para a gestão de carga e descarga, e todos os envolvidos devem segui-la.',1,1);
