insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5f8d3894-7803-43d9-9ba7-f8920fa27891','01fa9b3b-b34e-4c00-88fc-7a3707012c98','A desmontagem de um evento geralmente segue qual lógica em relação à montagem?','Como boa prática de cronograma, a desmontagem costuma ocorrer na ordem inversa da montagem e em horários apertados.',4,1);
