insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0766db5f-8494-43cf-b4be-a2049cd2db07','3a9bbdd6-b797-4805-83c6-a61d7b4fc14a','Alvarás e autorizações oficiais do evento servem para quê?','Os alvarás e licenças (bombeiros, som, estrutura, uso do espaço) mantêm o evento dentro das normas legais e de segurança, evitando fiscalização ou interrupção.',4,1);
