insert into public.quiz_options (question_id,texto,correta,ordem) values ('0766db5f-8494-43cf-b4be-a2049cd2db07','Organizar o stage plot',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('0766db5f-8494-43cf-b4be-a2049cd2db07','Substituir a carteira de trabalho',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('bf89fbd8-44b2-4a79-a215-09550492e5b9','667b6c17-474d-4270-a95a-bdf74d7b843d','Gestão de Equipe na Produção de Eventos','texto','<p><strong>Para começar:</strong> Um evento é feito por muitas mãos: som, luz, palco, montagem, segurança. Fazer essas pessoas trabalharem juntas, com clareza de funções e boa comunicação, é o que chamamos de gestão de equipe. Nesta aula você vai conhecer os princípios que tornam uma equipe coesa e eficaz.</p><p>Em produções de eventos, diferentes especialistas precisam atuar em sincronia sob pressão de tempo. Mesmo o técnico júnior se beneficia de entender esses princípios: eles explicam por que comunicação, papéis claros e flexibilidade fazem tanta diferença no resultado final.</p><ul><li><strong>Comunicação clara e aberta:</strong> Estabeleça canais de comunicação claros e abertos entre os membros da equipe. Garanta que todos compreendam suas funções, responsabilidades e metas. Em evento, é o que evita o clássico ninguém me avisou.</li><li><strong>Definição de papéis e responsabilidades:</strong> Atribua funções específicas a cada membro com base em suas habilidades e conhecimentos, e assegure que todos saibam exatamente o que se espera deles. Cada pessoa sabendo seu posto evita sobreposição e tarefas esquecidas.</li><li><strong>Liderança efetiva:</strong> Lidere pelo exemplo, demonstrando comprometimento, responsabilidade e profissionalismo. Esteja disponível para orientar e apoiar quando necessário. A equipe espelha a postura de quem comanda.</li><li><strong>Motivação e engajamento:</strong> Mantenha a equipe motivada reconhecendo e recompensando os esforços. Incentive a colaboração e o compartilhamento de ideias. Gente reconhecida rende mais nas longas jornadas de evento.</li><li><strong>Gerenciamento de conflitos:</strong> Esteja preparado para lidar com conflitos entre membros. Resolva-os de maneira construtiva, buscando soluções que beneficiem a todos. Sob pressão e cansaço, atritos surgem e precisam ser tratados rápido.</li><li><strong>Planejamento e organização:</strong> Desenvolva um plano detalhado da produção, identificando tarefas e prazos. Distribua as tarefas de forma equilibrada e assegure que todos entendam a programação. É o cronograma da equipe.</li><li><strong>Acompanhamento e avaliação:</strong> Monitore regularmente o progresso das tarefas e verifique se tudo ocorre conforme o planejado. Forneça feedback construtivo para aprimorar o desempenho da equipe.</li><li><strong>Flexibilidade e adaptação:</strong> Esteja preparado para mudanças de última hora e imprevistos. Tome decisões rápidas e eficazes para contornar desafios. Em evento ao vivo, o plano sempre encontra surpresas.</li><li><strong>Valorização, desenvolvimento e inclusão:</strong> Reconheça e aproveite as habilidades individuais, permitindo que cada um contribua com suas ideias. Ofereça oportunidades de aprendizado e atualização. Crie um ambiente respeitoso e inclusivo, valorizando a diversidade e evitando qualquer discriminação.</li><li><strong>Celebração do sucesso:</strong> Celebre as conquistas e o sucesso da equipe, reconhecendo o esforço coletivo. Isso fortalece o senso de realização e a união, importante antes do próximo evento.</li></ul><p><strong>Na prática:</strong> Antes da montagem, o coordenador reúne a equipe por cinco minutos: define quem cuida de som, quem cuida de luz e quem fica na estrutura (papéis claros), passa o cronograma de tarefas e horários (planejamento) e combina o canal de rádio para avisos (comunicação). Quando um caminhão atrasa, ele remaneja duas pessoas para adiantar outra frente (flexibilidade). No fim da montagem, agradece o time pelo ritmo (celebração e motivação).</p><h4>Resumo</h4><ul><li>Gestão de equipe coordena diferentes especialistas rumo a objetivos comuns, algo crucial em eventos.</li><li>Os pilares incluem comunicação clara, papéis definidos, liderança pelo exemplo, planejamento e flexibilidade.</li><li>Reconhecer habilidades, manter ambiente inclusivo e celebrar conquistas mantêm a equipe coesa e motivada.</li></ul>',20,5,true,false);
