insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0114ba9e-ef49-41ff-a37b-7e520edabb5c','cf8366ed-1c3a-4e90-be25-b8f8a64a60a9','Qual prática fortalece o senso de realização e a união da equipe?','Celebrar o sucesso e reconhecer o esforço coletivo fortalece o senso de realização e a união da equipe.',4,1);
