insert into public.modules (id,course_id,titulo,ordem) values ('a8d57a07-f986-4337-967e-1f765e6764f9','1320b04f-ec96-47e3-905c-46a6f7bce71e','Som I',7);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('924b5f6a-bd59-45c7-bc89-06f05d1d756b','a8d57a07-f986-4337-967e-1f765e6764f9','O que é som: a onda que você vai trabalhar a vida toda','texto','<p><strong>Para começar:</strong> Antes de mexer em qualquer botão da mesa, você precisa entender o que está acontecendo no ar. Som é energia em forma de vibração, e tudo que um técnico faz é capturar, moldar e devolver essa vibração para o público. Esta aula é a base de todo o resto do módulo.</p><p>O som é uma forma de energia percebida pelo sistema auditivo e interpretada pelo cérebro. Ele nasce de vibrações de partículas em um meio (geralmente o ar) que se propagam como ondas de pressão.</p><ul><li><strong>O que é som:</strong> Som é energia mecânica criada por vibrações ou oscilações de partículas no ar (ou em outros meios). Essas vibrações se propagam como ondas sonoras até chegarem ao ouvido, que as converte em sinais elétricos para o cérebro interpretar.</li><li><strong>Compressão e rarefação:</strong> A onda sonora alterna regiões de compressão (partículas mais próximas umas das outras, alta pressão) e rarefação (partículas mais afastadas, baixa pressão). É essa variação de pressão que viaja pelo ar, não as partículas em si, que apenas vibram em torno da posição de equilíbrio.</li><li><strong>Como o som é produzido:</strong> O som pode ser gerado de muitas formas: falando, tocando instrumentos, ou por fenômenos naturais como o trovão. Qualquer fonte de energia que perturbe o meio e faça as partículas vibrarem gera som.</li><li><strong>Meios de propagação:</strong> O som viaja pelo ar, mas também pela água e por sólidos. Ele precisa de um meio material para se propagar; no vácuo (ausência de meio) não há som.</li><li><strong>As quatro características do som:</strong> Todo som pode ser descrito por: Frequência (altura, grave/agudo), Amplitude (intensidade/volume), Timbre (a ''cor'' que distingue um violino de uma guitarra) e Duração (quanto tempo o som persiste).</li><li><strong>Timbre:</strong> É a qualidade que permite distinguir dois sons de mesma frequência e amplitude vindos de fontes diferentes. É por causa do timbre que reconhecemos a diferença entre um violino e uma guitarra tocando a mesma nota no mesmo volume.</li><li><strong>Por que isso importa em eventos:</strong> No evento, o som é controlado, amplificado e processado para entregar uma experiência auditiva de qualidade ao público. Entender a onda é entender o que cada equipamento faz com ela.</li></ul><p><strong>Na prática:</strong> Bata palma uma vez numa sala. Você criou uma onda de pressão: o ar comprimiu e rarefez rapidamente, a onda se espalhou em todas as direções e chegou aos ouvidos das pessoas em volta. Se houver eco, você está ouvindo essa mesma onda voltar depois de bater nas paredes. Tudo o que a mesa de som faz é trabalhar com essa onda em forma de sinal elétrico.</p><h4>Resumo</h4><ul><li>Som é energia mecânica que se propaga como onda de pressão, alternando compressão e rarefação.</li><li>As quatro características fundamentais são frequência, amplitude, timbre e duração.</li><li>Som precisa de um meio material para viajar; não existe som no vácuo.</li></ul>',25,1,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('37ea335a-72e0-424f-a884-9b4f95489116','924b5f6a-bd59-45c7-bc89-06f05d1d756b','Quiz — O que é som: a onda que você vai trabalhar a vida toda');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('34097ba3-b2ed-4935-89d8-5e491de37946','37ea335a-72e0-424f-a884-9b4f95489116','O que se propaga quando um som viaja pelo ar?','As partículas de ar apenas vibram em torno da posição de equilíbrio; o que viaja é a variação de pressão (a onda).',1,1);
