insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('d5f5878e-448a-4c2e-a5df-12c280769dfb','37ea335a-72e0-424f-a884-9b4f95489116','Qual característica do som permite diferenciar um violino de uma guitarra tocando a mesma nota no mesmo volume?','O timbre é a qualidade que distingue sons de mesma frequência e amplitude vindos de fontes diferentes.',2,1);
