insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('edd56f2d-3ffb-43a4-b024-f946d50db511','37ea335a-72e0-424f-a884-9b4f95489116','O som pode se propagar no vácuo?','O som é uma onda mecânica e precisa de um meio (ar, água, sólido). Sem meio, não há propagação.',3,1);
