insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('20f18115-1bd3-4973-8fcb-06e42c240d66','37ea335a-72e0-424f-a884-9b4f95489116','Compressão em uma onda sonora corresponde a:','Compressão é a região onde as partículas estão mais próximas umas das outras, formando alta pressão; rarefação é o contrário.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('20f18115-1bd3-4973-8fcb-06e42c240d66','Região de baixa pressão, partículas afastadas',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('20f18115-1bd3-4973-8fcb-06e42c240d66','Região de alta pressão, partículas mais próximas',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('20f18115-1bd3-4973-8fcb-06e42c240d66','Ausência de vibração',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('20f18115-1bd3-4973-8fcb-06e42c240d66','Aumento da frequência',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('632344eb-594e-496b-9a2a-d9cf1ce6ff77','a8d57a07-f986-4337-967e-1f765e6764f9','Frequência e amplitude: altura e volume do som','texto','<p><strong>Para começar:</strong> Frequência e amplitude são os dois parâmetros que você mais vai ajustar na mesa. Um define se o som é grave ou agudo; o outro define se é alto ou baixo. Confundir esses dois conceitos é o erro mais comum de quem está começando.</p><p>Frequência e amplitude são propriedades distintas da onda. A frequência governa a altura (grave/agudo) e a amplitude governa a intensidade (volume). São coisas independentes.</p><ul><li><strong>Frequência (Hz):</strong> Frequência é a quantidade de ciclos completos que a onda realiza por segundo, medida em Hertz (Hz). 1 Hz = 1 ciclo por segundo. Ela determina a altura do som: quanto maior a frequência, mais agudo; quanto menor, mais grave.</li><li><strong>Faixa audível:</strong> O ouvido humano percebe, em média, frequências entre 20 Hz e 20.000 Hz (20 kHz). Essa capacidade varia de pessoa para pessoa e diminui com a idade, especialmente nos agudos.</li><li><strong>Graves, médios e agudos:</strong> Graves são as frequências baixas (impacto do bumbo, contrabaixo), médios são a região da voz e da maioria dos instrumentos, e agudos são as altas frequências (pratos, brilho, sibilância). Equalizar é ajustar o equilíbrio entre essas faixas.</li><li><strong>Amplitude e volume:</strong> Amplitude é a medida da intensidade da onda, ligada à energia que ela transporta. Quanto maior a amplitude, mais alto o som percebido. Ao mover um fader de volume, você está alterando a amplitude do sinal.</li><li><strong>Decibel (dB):</strong> Na prática profissional, a intensidade do som e os níveis de sinal são medidos em decibéis (dB). O dB é uma escala logarítmica: pequenos números representam grandes variações de energia. Por isso pequenos ajustes de fader já mudam muito a percepção de volume.</li><li><strong>Amplitude na forma de onda:</strong> Em um osciloscópio ou na tela da mesa, a amplitude aparece na vertical: cristas (valores positivos) e vales (valores negativos) indicam as oscilações de pressão. Uma onda mais ''alta'' na tela é um som mais intenso.</li><li><strong>Frequência ≠ amplitude:</strong> São independentes: um som grave pode ser alto ou baixo, e um som agudo também. Mudar o volume (amplitude) não muda se o som é grave ou agudo (frequência).</li></ul><p><strong>Na prática:</strong> Na passagem de som, o vocalista reclama que está ''abafado''. Isso é frequência: faltam agudos/médios, e você ajusta a equalização. Se ele reclama que está ''baixo demais'', isso é amplitude: você sobe o fader. São dois controles diferentes para dois problemas diferentes. Misturar os dois é o erro clássico de iniciante.</p><h4>Resumo</h4><ul><li>Frequência mede-se em Hertz (Hz) e define a altura: mais Hz = mais agudo, menos Hz = mais grave.</li><li>Amplitude define o volume/intensidade e, na prática, mede-se em decibéis (dB).</li><li>Frequência e amplitude são independentes: o fader muda a amplitude, a equalização muda as frequências.</li></ul>',25,2,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('bdfe0313-1260-46b3-8366-9eb7f09605d8','632344eb-594e-496b-9a2a-d9cf1ce6ff77','Quiz — Frequência e amplitude: altura e volume do som');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('ba9ad156-f0d1-41be-b8bc-0ffe96383f12','bdfe0313-1260-46b3-8366-9eb7f09605d8','A frequência de uma onda sonora determina principalmente:','Frequência (em Hz) define a altura percebida: mais frequência = mais agudo, menos frequência = mais grave.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('ba9ad156-f0d1-41be-b8bc-0ffe96383f12','O volume do som',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('ba9ad156-f0d1-41be-b8bc-0ffe96383f12','Se o som é grave ou agudo',true,2);
