insert into public.quiz_options (question_id,texto,correta,ordem) values ('ba9ad156-f0d1-41be-b8bc-0ffe96383f12','A duração do som',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('f72da789-01f1-47eb-b340-025f61642e75','bdfe0313-1260-46b3-8366-9eb7f09605d8','Qual é a faixa de frequência audível média do ouvido humano?','A faixa audível típica vai de 20 Hz a 20 kHz, variando com a pessoa e a idade.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('f72da789-01f1-47eb-b340-025f61642e75','0 Hz a 100 Hz',false,1);
