insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('2d06dfc2-70ab-4670-be09-67e1f5ea986b','bdfe0313-1260-46b3-8366-9eb7f09605d8','Em que unidade se medem normalmente os níveis de intensidade e volume no áudio profissional?','A intensidade e os níveis de sinal são medidos em decibéis (dB), uma escala logarítmica.',4,1);
