insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('7100eac5-ad39-4ab2-bb0a-120562459a46','a8d57a07-f986-4337-967e-1f765e6764f9','Fase e cancelamento: o inimigo invisível do som','texto','<p><strong>Para começar:</strong> Fase é um conceito que não se vê e não se mede de ouvido fácil, mas que pode destruir o seu som sem você perceber a causa. Quando o grave ''some'' ou o som fica fino e sem corpo, muitas vezes o culpado é a fase. Entender isso separa o técnico amador do profissional.</p><p>A fase descreve a posição temporal de uma onda em relação a outra de mesma frequência. Quando duas ondas iguais se combinam fora de tempo, podem se reforçar ou se cancelar.</p><ul><li><strong>O que é fase:</strong> Fase é a posição relativa de uma onda no seu ciclo, em relação a um ponto de referência. É medida em graus (um ciclo completo = 360°) ou radianos (2π). Pense na fase como uma ''coordenada de tempo'' dentro de um ciclo da onda.</li><li><strong>Interferência construtiva:</strong> Quando duas ondas de mesma frequência estão em fase (cristas com cristas, vales com vales), elas se reforçam mutuamente e a amplitude aumenta. É o reforço do som.</li><li><strong>Interferência destrutiva:</strong> Quando duas ondas estão em oposição de fase (a 180°, crista de uma coincidindo com o vale da outra), elas se cancelam parcial ou totalmente, reduzindo a amplitude. No caso extremo, o som somido.</li><li><strong>Cancelamento na prática:</strong> É por isso que dois microfones captando a mesma fonte, ou um sinal somado fora de fase, podem deixar o som fino, sem grave ou ''oco''. O alinhamento de fase entre microfones e caixas é essencial para evitar isso.</li><li><strong>O botão de inversão de fase (Ø):</strong> Mesas e pré-amplificadores têm um botão de inversão de fase (símbolo Ø ou ''phase/polarity''). Ele inverte a polaridade do sinal em 180°, e é usado para corrigir cancelamentos, por exemplo entre o microfone de cima e o de baixo da caixa, ou entre microfone e captador (DI).</li><li><strong>Fase e efeitos:</strong> A fase também é usada de propósito em efeitos: panorâmica estéreo, sensação de espaço e modulação de fase (phaser, flanger) dependem de relações de fase entre canais.</li></ul><p><strong>Na prática:</strong> Você microfona um bumbo de bateria com um microfone por fora e um por dentro. Ao subir os dois juntos, o grave some e o som fica fraco: as duas captações estão fora de fase e se cancelando. Você aperta o botão de inversão de fase (Ø) em um dos canais e o grave volta com corpo. Esse é o uso mais comum de fase em uma passagem de som real.</p><h4>Resumo</h4><ul><li>Fase é a posição da onda no seu ciclo, medida em graus (360° = um ciclo completo).</li><li>Ondas em fase se reforçam (construtiva); em oposição de fase (180°) se cancelam (destrutiva).</li><li>O botão de inversão de fase (Ø) corrige cancelamentos entre microfones ou entre mic e DI.</li></ul>',20,3,true,false);
