insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('91d14a09-28c2-4460-aa3b-c554757d07bc','0c92a318-b41c-4849-8c84-b28006c7d316','Quando duas ondas de mesma frequência estão em oposição de fase (180°), o que acontece?','Em oposição de fase, a crista de uma coincide com o vale da outra, causando interferência destrutiva (cancelamento).',1,1);
