insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('ff932d7a-b4f3-415c-9684-b90a3012fe94','0c92a318-b41c-4849-8c84-b28006c7d316','O som de um bumbo fica fino e sem grave ao subir o mic de fora e o de dentro juntos. A causa mais provável é:','Duas captações da mesma fonte fora de fase se cancelam, tirando o corpo/grave. A correção é inverter a fase de um canal.',4,1);
