insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('1c1b44db-f925-4d40-8088-465a0479bd79','a8d57a07-f986-4337-967e-1f765e6764f9','Analógico x digital: dois caminhos para o mesmo som','texto','<p><strong>Para começar:</strong> Toda a indústria de som vive entre dois mundos: o analógico, contínuo e orgânico, e o digital, numérico e preciso. Você vai trabalhar com equipamentos dos dois tipos, e entender a diferença ajuda a saber o que cada um faz bem e onde cada um falha.</p><p>O sinal de áudio pode ser representado de forma contínua (analógico) ou numérica (digital). Cada abordagem tem vantagens e limitações que afetam o trabalho do técnico.</p><ul><li><strong>Som analógico:</strong> É a forma tradicional: representa a onda sonora de maneira contínua, como variações contínuas de tensão elétrica. O microfone converte a pressão do ar em corrente elétrica, e essa corrente é amplificada, processada e transmitida por cabos e circuitos.</li><li><strong>Vantagens e limites do analógico:</strong> É valorizado pela qualidade tonal e natureza orgânica. Mesas e amplificadores analógicos ainda são muito usados. Porém, é mais suscetível a ruídos e à degradação de qualidade ao longo de cabos e distâncias maiores.</li><li><strong>Som digital:</strong> É a representação numérica da onda: as variações de pressão viram sequências de números (valores discretos). Isso traz precisão, facilidade de manipulação, armazenamento e transmissão eficientes.</li><li><strong>Amostragem (sampling):</strong> Primeira etapa da conversão analógico→digital: a onda contínua é medida em intervalos regulares de tempo, e a amplitude é registrada em cada ponto. Quanto mais amostras por segundo (medido em Hz), maior a precisão. Ex.: CD usa 44.100 amostras por segundo (44,1 kHz).</li><li><strong>Quantização e profundidade de bits:</strong> Segunda etapa: cada amostra é arredondada para o valor mais próximo de uma escala finita. A profundidade de bits define quantos valores existem; 16 bits permitem 65.536 valores diferentes. Mais bits = mais detalhe e menos ruído de quantização.</li><li><strong>Vantagens do digital:</strong> Evita a degradação gradual típica do analógico e permite processamento (EQ, compressão, efeitos) sem perda significativa. Facilita compartilhar, transmitir pela internet e armazenar (CD, WAV, MP3).</li><li><strong>Limites do digital:</strong> Pode haver ruído de quantização, e o sinal precisa ser convertido de volta para analógico (D/A) para sair pelos alto-falantes ou fones, pois o ouvido só escuta vibração física, analógica.</li></ul><p><strong>Na prática:</strong> Numa mesa digital, ao plugar o microfone, o sinal analógico do mic é convertido para digital (A/D) logo na entrada, processado internamente como números, e só volta a ser analógico (D/A) na saída para os amplificadores e caixas. Numa mesa analógica clássica, o sinal permanece elétrico e contínuo do início ao fim. Saber em qual mundo você está ajuda a entender por que a mesa digital salva ''cenas'' e a analógica não.</p><h4>Resumo</h4><ul><li>Analógico = sinal elétrico contínuo, orgânico, porém mais sujeito a ruído e degradação por distância.</li><li>Digital = representação numérica via amostragem e quantização; preciso, processável e fácil de armazenar.</li><li>O som sempre termina em analógico: é preciso converter de volta (D/A) para o ouvido escutar.</li></ul>',25,4,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('ef96a990-71ee-4f44-acc2-541461be1123','1c1b44db-f925-4d40-8088-465a0479bd79','Quiz — Analógico x digital: dois caminhos para o mesmo som');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('90f77ffa-89c5-4a18-a5dc-3184b3be5a66','ef96a990-71ee-4f44-acc2-541461be1123','Qual é a principal diferença entre som analógico e digital?','O analógico é um sinal contínuo (tensão elétrica); o digital transforma a onda em sequências de números.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('90f77ffa-89c5-4a18-a5dc-3184b3be5a66','Analógico é mais alto e digital mais baixo',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('90f77ffa-89c5-4a18-a5dc-3184b3be5a66','Analógico representa a onda de forma contínua; digital representa em valores numéricos discretos',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('90f77ffa-89c5-4a18-a5dc-3184b3be5a66','Digital não usa microfones',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('90f77ffa-89c5-4a18-a5dc-3184b3be5a66','Analógico só funciona em estúdio',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('b3bab798-ab60-445e-bc4d-f8168abe2d46','ef96a990-71ee-4f44-acc2-541461be1123','Quais são as duas etapas principais da conversão analógico→digital?','A conversão A/D envolve amostragem (medir a amplitude em intervalos) e quantização (arredondar para valores discretos).',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('b3bab798-ab60-445e-bc4d-f8168abe2d46','Equalização e compressão',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('b3bab798-ab60-445e-bc4d-f8168abe2d46','Amostragem e quantização',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('b3bab798-ab60-445e-bc4d-f8168abe2d46','Gravação e reprodução',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('b3bab798-ab60-445e-bc4d-f8168abe2d46','Captura e amplificação',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('d2faccf0-f6cd-45ff-b746-c1b9dbb57d5e','ef96a990-71ee-4f44-acc2-541461be1123','Uma profundidade de 16 bits permite quantos valores diferentes por amostra?','16 bits permitem 2 elevado a 16 = 65.536 valores possíveis.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d2faccf0-f6cd-45ff-b746-c1b9dbb57d5e','256',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d2faccf0-f6cd-45ff-b746-c1b9dbb57d5e','1.024',false,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d2faccf0-f6cd-45ff-b746-c1b9dbb57d5e','65.536',true,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d2faccf0-f6cd-45ff-b746-c1b9dbb57d5e','Infinitos',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('2e5d4146-a7f0-48c4-839a-a9ce41a0353e','ef96a990-71ee-4f44-acc2-541461be1123','Por que um sinal digital precisa ser convertido de volta para analógico antes de ser ouvido?','O ouvido escuta vibração física do ar; é preciso a conversão D/A para o alto-falante gerar essa vibração.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('2e5d4146-a7f0-48c4-839a-a9ce41a0353e','Porque o digital é silencioso',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('2e5d4146-a7f0-48c4-839a-a9ce41a0353e','Porque o ouvido só percebe vibração física (analógica) vinda dos alto-falantes',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('2e5d4146-a7f0-48c4-839a-a9ce41a0353e','Porque o cabo não aceita sinal digital',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('2e5d4146-a7f0-48c4-839a-a9ce41a0353e','Porque o digital tem menos qualidade',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('f795fd13-275d-4cf2-9ddf-5050da4ffbd2','a8d57a07-f986-4337-967e-1f765e6764f9','Captura de som: microfones e seus tipos','texto','<p><strong>Para começar:</strong> O microfone é o ponto de entrada de todo o sistema: é onde o som do mundo real vira sinal elétrico. Escolher o microfone certo e posicioná-lo bem é metade do trabalho de uma boa captação. Esta aula é o coração do dia a dia do técnico.</p><p>Microfones convertem variações de pressão do ar em sinais elétricos (transdução). Tipos de transdutor e padrões de captação definem qual microfone usar em cada situação.</p><ul><li><strong>Princípio de transdução:</strong> O microfone é um transdutor: converte um tipo de energia em outro. Ele transforma as variações de pressão do ar (som) em sinal elétrico, que depois é processado, gravado, amplificado e reproduzido.</li><li><strong>Microfone dinâmico:</strong> Usa uma bobina móvel dentro de um campo magnético para gerar o sinal. É robusto, aguenta alto volume e é a escolha clássica para voz ao vivo, caixa de bateria, amplificadores de guitarra. Não precisa de alimentação externa (phantom power).</li><li><strong>Microfone condensador:</strong> Usa um diafragma sensível às variações de pressão. Tem resposta de frequência mais ampla e maior sensibilidade, captando detalhes e agudos. Ideal para estúdio, vocais, pratos e instrumentos acústicos. Geralmente exige alimentação phantom power (+48V).</li><li><strong>Padrão cardioide:</strong> Capta o som principalmente pela frente e rejeita os lados e a traseira. É o padrão mais usado ao vivo porque reduz vazamento e ajuda a evitar microfonia (feedback).</li><li><strong>Padrão omnidirecional:</strong> Capta o som igualmente de todas as direções. Útil para captar ambiente ou quando se quer um som natural, mas vaza mais e é mais propenso a feedback ao vivo.</li><li><strong>Padrão bidirecional (figura-8):</strong> Capta pela frente e pela traseira, rejeitando os lados. Usado em técnicas específicas de captação e entrevistas frente a frente.</li><li><strong>Pré-amplificação:</strong> O microfone gera sinal de baixa amplitude, por isso é conectado a um pré-amplificador (na mesa ou externo) que eleva o sinal a um nível adequado para processamento e gravação. O ajuste de ganho do pré é o primeiro controle da cadeia.</li><li><strong>Posicionamento e isolamento:</strong> Distância, ângulo e direção em relação à fonte mudam totalmente o som captado. Posicionar bem o microfone e isolar de ruídos de fundo é essencial para boa qualidade.</li><li><strong>Microfones específicos:</strong> Existem modelos para cada finalidade: lapela (discreto, voz), shotgun (direcional, vídeo/teatro), sem fio (mobilidade no palco), entre outros.</li></ul><p><strong>Na prática:</strong> Numa passagem de som de banda: o vocalista recebe um dinâmico cardioide (robusto, rejeita o que vem dos monitores e evita feedback). O microfone do bumbo é um dinâmico que aguenta o impacto. Os pratos da bateria recebem condensadores (captam o brilho e os agudos), e você liga o phantom power +48V para eles. Ao apontar o cardioide do vocal para longe do monitor de palco, você reduz a chance de microfonia.</p><h4>Resumo</h4><ul><li>Microfone dinâmico: robusto, aguenta volume alto, não precisa de phantom; ideal ao vivo.</li><li>Microfone condensador: sensível e detalhado, geralmente precisa de phantom power +48V; ideal para agudos e estúdio.</li><li>O padrão cardioide é o mais usado ao vivo porque rejeita laterais/traseira e reduz feedback.</li></ul>',30,5,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('4b968158-a66b-468e-b67a-d6d5c52becf7','f795fd13-275d-4cf2-9ddf-5050da4ffbd2','Quiz — Captura de som: microfones e seus tipos');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e08ee52f-b369-44dc-ba32-adff5e29a3e6','4b968158-a66b-468e-b67a-d6d5c52becf7','Qual tipo de microfone é mais robusto e indicado para situações de alto volume ao vivo?','O microfone dinâmico usa bobina móvel, é robusto e aguenta alto volume, sendo o padrão para voz ao vivo e fontes intensas.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('e08ee52f-b369-44dc-ba32-adff5e29a3e6','Condensador',false,1);
