insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e31a0d2d-eca3-44b4-bb8e-ed6de80e33d6','4b968158-a66b-468e-b67a-d6d5c52becf7','O padrão de captação cardioide capta o som principalmente:','O cardioide capta pela frente e minimiza lados e traseira, ajudando a evitar feedback ao vivo.',2,1);
