insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('ba233883-4440-40d0-a6b5-19ec4a754367','4b968158-a66b-468e-b67a-d6d5c52becf7','Qual recurso a maioria dos microfones condensadores precisa para funcionar?','Condensadores geralmente exigem alimentação phantom power, tipicamente +48V, fornecida pela mesa ou pré.',3,1);
