insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('f1fe9775-3dee-471d-8e1a-b3fe59d2826a','4b968158-a66b-468e-b67a-d6d5c52becf7','Por que o sinal do microfone passa por um pré-amplificador?','Microfones geram sinal fraco; o pré-amplificador (ganho) eleva o nível para o processamento e a gravação.',4,1);
