insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('03a24a4c-930c-4253-8a22-15ec76cefd88','a8d57a07-f986-4337-967e-1f765e6764f9','Captura de instrumentos e reprodução do som','texto','<p><strong>Para começar:</strong> Cada instrumento soa de um jeito e pede uma abordagem própria de captação. Depois de capturar, o som precisa percorrer o caminho inverso até chegar aos ouvidos do público. Esta aula liga a entrada (instrumentos) à saída (reprodução) do sistema.</p><p>Capturar instrumentos exige escolher o microfone certo, posicioná-lo bem e, às vezes, usar saída direta (DI). A reprodução é o processo oposto: transformar o sinal de volta em som audível.</p><ul><li><strong>Microfone certo para cada instrumento:</strong> Não existe um microfone universal. Condensadores de diafragma grande captam bem fontes com detalhe; dinâmicos lidam com fontes de alto volume. A escolha muda o resultado tonal.</li><li><strong>Posicionamento e direcionalidade:</strong> A posição do microfone afeta a qualidade tonal e o equilíbrio. Para um instrumento isolado, costuma-se usar cardioide; para grupos, técnicas mais amplas. Experimentar a posição é parte do trabalho.</li><li><strong>Cordas e sopros:</strong> Em cordas (violão, violino, contrabaixo), aproximar o microfone capta o detalhe das cordas e a ressonância da caixa. Em sopros (sax, trompete, flauta), posicionar perto da abertura capta o som direto; lapelas captam o som das chaves.</li><li><strong>Percussão e bateria:</strong> Instrumentos de percussão exigem vários microfones para captar elementos separados: cada tambor, pratos e demais peças têm seu microfone, permitindo controlar cada um na mesa.</li><li><strong>Piano:</strong> Pela ampla gama tonal, costuma-se usar microfones condensadores dentro e fora do piano, captando tanto o som direto das cordas quanto a ressonância da caixa.</li><li><strong>Instrumentos elétricos e DI:</strong> Guitarras e baixos elétricos podem ser captados diretamente por uma DI (Direct Injection / caixa direta), que mantém o sinal limpo e sem interferência, sem precisar microfonar o amplificador.</li><li><strong>Isolamento ao vivo:</strong> Para evitar vazamento de um instrumento no microfone do outro, usa-se posicionamento cuidadoso, isolamento acústico e telas de isolamento.</li><li><strong>Reprodução: o caminho inverso:</strong> Reprodução é transformar o sinal de áudio de volta em ondas sonoras audíveis. A fonte (arquivo, CD, streaming, instrumento) passa por processamento, é amplificada e chega aos alto-falantes ou fones.</li><li><strong>Componentes da reprodução:</strong> Fonte de áudio → processamento (EQ, efeitos, volume) → amplificação (potência) → alto-falantes ou fones. O espaço acústico (reverberação, absorção) afeta como o público ouve.</li><li><strong>Estéreo e surround:</strong> Estéreo usa dois canais para dar sensação de profundidade e direção; surround usa vários alto-falantes para uma experiência imersiva.</li></ul><p><strong>Na prática:</strong> Numa banda: o baixo entra direto pela DI (sinal limpo, sem microfonar o amplificador), o violão recebe um condensador apontado próximo às cordas, e a bateria recebe vários microfones (um por peça). Tudo isso entra na mesa, é equalizado e somado, amplificado e devolvido ao público pelas caixas de PA. O caminho do som vai do instrumento até o ouvido, passando por toda a cadeia.</p><h4>Resumo</h4><ul><li>A captação de instrumentos depende do microfone certo, do posicionamento e às vezes da DI.</li><li>Bateria e percussão usam múltiplos microfones; elétricos podem ir direto via DI.</li><li>Reprodução é o processo inverso: o sinal é processado, amplificado e vira som nas caixas/fones, influenciado pelo espaço acústico.</li></ul>',28,6,true,false);
