insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('bb854a88-23e0-4759-91bc-a600ce9f0e50','3993388e-316d-4124-8777-14a3a22157c8','Por que a bateria normalmente usa vários microfones?','Cada peça da bateria tem características próprias; microfones separados permitem captar e controlar cada elemento individualmente.',2,1);
