insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('3813309b-7c74-4d00-9922-fc0eb4c5351e','3993388e-316d-4124-8777-14a3a22157c8','A reprodução de som é, em relação à captura:','Reprodução é o oposto da captura: converte o sinal de áudio de volta em vibração sonora audível.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('3813309b-7c74-4d00-9922-fc0eb4c5351e','O mesmo processo',false,1);
