insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5b913bbc-e456-48d4-9225-e964e5f3a9ea','3993388e-316d-4124-8777-14a3a22157c8','O que afeta como o público ouve o som reproduzido em um ambiente?','O espaço acústico (reverberação, absorção e outras propriedades) influencia diretamente como o som é percebido.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5b913bbc-e456-48d4-9225-e964e5f3a9ea','Apenas o volume',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5b913bbc-e456-48d4-9225-e964e5f3a9ea','As características acústicas do espaço, como reverberação e absorção',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5b913bbc-e456-48d4-9225-e964e5f3a9ea','Apenas a marca da caixa',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5b913bbc-e456-48d4-9225-e964e5f3a9ea','Apenas o microfone usado',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('642be1fd-03e3-4a28-aa96-9ebf92e57f00','a8d57a07-f986-4337-967e-1f765e6764f9','O sistema de áudio do evento: equipamentos e a cadeia do som','texto','<p><strong>Para começar:</strong> No evento, nenhum equipamento trabalha sozinho. Mesa, microfones, amplificadores e caixas formam uma corrente onde o sinal passa de um ponto ao outro. Conhecer cada elo dessa cadeia é o que permite montar, operar e resolver problemas no sistema.</p><p>Um sistema de áudio profissional é um conjunto de equipamentos que captam, processam, amplificam e reproduzem o som. Cada peça tem uma função específica na cadeia do sinal.</p><ul><li><strong>A cadeia do som:</strong> O sinal segue um caminho: captação (microfone/DI) → mesa de mixagem → processamento → amplificação → caixas acústicas. Entender essa ordem é entender como o áudio chega ao público.</li><li><strong>Mesa de mixagem (FOH e Monitor):</strong> É o centro de controle: ajusta volumes, equalização e efeitos de cada fonte. A mesa FOH (Front of House) cuida do som que o público escuta, posicionada na plateia. A mesa de Monitor cuida do som que os músicos escutam no palco.</li><li><strong>PA x Monitor:</strong> O PA (sistema de público, ligado ao FOH) aponta para a plateia e entrega o som que o público ouve. Os monitores de palco apontam para os músicos e entregam o que eles precisam ouvir de si e dos colegas. São duas misturas diferentes para dois públicos diferentes.</li><li><strong>Microfones:</strong> Captam o som e o transformam em sinal elétrico. Há modelos para voz, instrumentos, bateria e sem fio, cada um adequado a uma aplicação.</li><li><strong>Caixas acústicas e subwoofers:</strong> As caixas (alto-falantes) transformam o sinal elétrico de volta em som audível para o público. Os subwoofers são caixas especializadas em frequências graves, responsáveis pela sensação de impacto.</li><li><strong>Amplificadores:</strong> Aumentam a potência do sinal antes de enviá-lo às caixas, garantindo energia suficiente para o som alcançar todo o público em espaços grandes.</li><li><strong>Processadores de sinal:</strong> Equipamentos que ajustam e melhoram o som: equalização, compressão, reverb, delay e controle de frequência. Ajudam a deixar o som equilibrado e agradável.</li><li><strong>Sistemas sem fio:</strong> Permitem que microfones e instrumentos funcionem sem cabos, dando mobilidade aos artistas no palco.</li><li><strong>Cabos, conectores e racks:</strong> Os cabos transportam o sinal entre todos os equipamentos; cabos de qualidade evitam ruído e interferência. Os racks organizam e protegem amplificadores, processadores e sistemas sem fio, facilitando transporte e montagem.</li><li><strong>Energia e proteção:</strong> Todo o sistema depende de alimentação elétrica segura: distribuidores de energia, estabilizadores e proteção elétrica garantem o funcionamento correto e protegem os equipamentos.</li><li><strong>Escolha conforme o evento:</strong> A seleção dos equipamentos depende do tamanho do evento, tipo de apresentação, local e necessidades técnicas dos artistas.</li></ul><p><strong>Na prática:</strong> Imagine o caminho de uma voz no show: o vocalista canta no microfone (captação), o sinal vai pela mala de cabos até a mesa FOH (mixagem), passa pelos processadores (EQ, compressão), entra nos amplificadores (potência) e sai pelas caixas de PA para o público. Em paralelo, a mesa de Monitor manda uma mistura própria para o monitor de palco do vocalista. Mesmo sinal de origem, dois destinos: PA para o público, monitor para o artista.</p><h4>Resumo</h4><ul><li>O sistema de áudio é uma cadeia: captação → mesa de mixagem → processamento → amplificação → caixas.</li><li>FOH/PA entrega o som ao público; a mesa de Monitor entrega aos músicos no palco (duas misturas distintas).</li><li>Amplificadores dão potência, processadores moldam o som, e cabos/racks/energia sustentam todo o sistema.</li></ul>',30,7,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('15436562-0ff6-4ea3-aef6-4554c33b3874','642be1fd-03e3-4a28-aa96-9ebf92e57f00','Quiz — O sistema de áudio do evento: equipamentos e a cadeia do som');
