insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('651fc611-240a-4cc0-b781-ce9c922b9506','15436562-0ff6-4ea3-aef6-4554c33b3874','Qual a diferença entre o PA e os monitores de palco?','PA é a mistura para o público; monitores são a mistura para os músicos ouvirem a si mesmos e aos colegas.',2,1);
