insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('985833de-e196-4ec2-ad0d-ee62a866f18f','15436562-0ff6-4ea3-aef6-4554c33b3874','Qual equipamento é especializado em reproduzir as frequências graves e dar sensação de impacto?','O subwoofer é a caixa especializada em frequências graves, responsável pela sensação de impacto.',3,1);
