insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('cc834ce7-c95d-4b46-b4e0-810356c44937','15436562-0ff6-4ea3-aef6-4554c33b3874','Qual a função do amplificador na cadeia do som?','O amplificador eleva a potência do sinal para que tenha energia suficiente para alcançar todo o público nas caixas.',4,1);
