insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('fe0ad2d7-0d64-43d8-9c1b-c686203284cd','a8d57a07-f986-4337-967e-1f765e6764f9','O técnico de som em ação: atividades, postura e responsabilidade','texto','<p><strong>Para começar:</strong> Conhecer a teoria e os equipamentos é só o começo. O que define o profissional é a rotina: montar, testar, mixar, resolver problemas na hora e desmontar com cuidado. Esta aula fecha o módulo mostrando o que se espera de você em um evento real.</p><p>O técnico de som garante a qualidade do áudio do início ao fim do evento. Suas atividades vão da montagem à desmontagem, passando pela mixagem ao vivo e pela solução rápida de problemas.</p><ul><li><strong>Montagem e preparação:</strong> Configurar e testar todo o equipamento: microfones, mesas, caixas, monitores, amplificadores e processadores. Organizar os cabos de forma limpa e conectar os equipamentos às fontes e instrumentos.</li><li><strong>Balanceamento de som (passagem de som):</strong> Ajustar os níveis de volume de cada instrumento e microfone para um equilíbrio sonoro adequado, equalizar para destacar o tom desejado e minimizar feedback e ruído. É a famosa passagem de som.</li><li><strong>Monitoramento de palco:</strong> Configurar e mixar os monitores para que os músicos ouçam com clareza, atendendo às solicitações de cada um sobre o que precisam ouvir no monitor.</li><li><strong>Mixagem ao vivo:</strong> Fazer a mixagem em tempo real durante o show, ajustando equalização, volumes e efeitos conforme as músicas e os momentos mudam, mantendo a qualidade constante.</li><li><strong>Solução de problemas:</strong> Identificar e resolver falhas rapidamente: equipamento que parou, cabo solto, interferência. Agir rápido contra feedback (microfonia) e ruído indesejado é parte essencial do trabalho.</li><li><strong>Microfonia (feedback):</strong> É o apito/zumbido que surge quando o som da caixa volta para o microfone e realimenta o sistema. Combate-se reposicionando microfones e monitores, baixando ganho e usando equalização (cortando a frequência que está apitando).</li><li><strong>Coordenação com a equipe:</strong> Trabalhar junto com técnicos de luz, engenheiro de monitor e a produção, e comunicar-se com os músicos para entender suas necessidades sonoras.</li><li><strong>Sincronização áudio e vídeo:</strong> Garantir que o áudio esteja sincronizado com qualquer conteúdo visual, como telões e vídeos exibidos durante o show.</li><li><strong>Desmontagem, armazenamento e manutenção:</strong> Desmontar com cuidado, guardar os equipamentos protegidos e fazer manutenção preventiva para que estejam sempre prontos para o próximo show.</li><li><strong>Segurança e proteção auditiva:</strong> Manter cabos organizados e fixos no piso, usar proteção elétrica adequada e protetores auditivos para a equipe técnica, que fica exposta a níveis altos por muito tempo.</li><li><strong>Postura profissional:</strong> Independentemente da área, toda função tem seus bônus e ônus. O resultado do espetáculo é coletivo: se um da equipe erra, o trabalho geral fica comprometido. Seja cordial e objetivo.</li></ul><p><strong>Na prática:</strong> Durante o show, no meio de uma música, surge um apito agudo: é microfonia. Você identifica que veio do microfone do vocal apontando para o monitor. Rapidamente baixa um pouco o ganho, corta com a equalização a frequência que está apitando e, no intervalo, reposiciona o monitor. O público mal percebe, e o show segue. Esse é o tipo de problema que você precisa resolver em segundos, com calma e método.</p><h4>Resumo</h4><ul><li>A rotina do técnico vai da montagem e passagem de som à mixagem ao vivo e à desmontagem cuidadosa.</li><li>Resolver feedback (microfonia) e falhas rapidamente, com método, é parte essencial do trabalho.</li><li>Segurança (cabos, energia, proteção auditiva) e trabalho em equipe sustentam um bom resultado, que é sempre coletivo.</li></ul>',25,8,true,false);
