insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('ec3c2ca3-e47c-4057-8f4f-45eef9172be0','ca62f274-a24c-4c4e-bfb5-5f37da38e927','Qual destas NÃO é uma forma comum de combater a microfonia?','Aumentar o volume piora a realimentação. As soluções corretas envolvem reposicionar, baixar ganho e equalizar para cortar a frequência problemática.',2,1);
