insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('9519f794-8c70-467f-979f-02bfbcb4a806','ca62f274-a24c-4c4e-bfb5-5f37da38e927','A ''passagem de som'' corresponde principalmente a qual atividade?','Na passagem de som ajustam-se volumes, equalização e monitores para deixar o som equilibrado antes da apresentação.',3,1);
