insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('556ed1ee-f684-4e18-97ab-6399386a4fec','ca62f274-a24c-4c4e-bfb5-5f37da38e927','Sobre o resultado de um evento, qual postura o material reforça?','O material destaca que o trabalho é 100% coletivo e que se deve ser cordial e objetivo, com atenção à equipe e à segurança.',4,1);
