insert into public.modules (id,course_id,titulo,ordem) values ('277c995e-db24-4038-9cc1-9b5649be7536','1320b04f-ec96-47e3-905c-46a6f7bce71e','Efeito',8);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('2686d638-a7cb-4bc5-bb69-f80f9bf09020','277c995e-db24-4038-9cc1-9b5649be7536','Introdução ao Ramo de Efeitos em Eventos','texto','<p><strong>Para começar:</strong> Quando o show atinge seu ponto alto e uma coluna de fumaça branca dispara para o céu, é o setor de efeitos que está em ação. Nesta aula você vai entender o que são efeitos especiais em eventos, por que eles existem e como se encaixam na produção técnica.</p><p>Os efeitos não substituem som e luz: eles entram para marcar momentos, criar atmosfera e aumentar a imersão. Entender esse papel é o primeiro passo para operar com critério.</p><ul><li><strong>O que é o ramo de efeitos:</strong> É a área da produção técnica responsável por criar impacto visual, sensorial e emocional no público. Enquanto som e iluminação constroem a base do espetáculo, os efeitos marcam momentos específicos: transições, clímax musicais, entradas de artistas e finais de apresentação.</li><li><strong>Formatos de efeitos:</strong> Os efeitos podem aparecer como fumaça, névoa (haze), jatos de CO₂, explosões de papel (confete e serpentina), faíscas frias, fogo cenográfico, neve artificial, bolhas, lasers e pirotecnia. Cada um é escolhido de forma estratégica conforme a música, a narrativa do show e a identidade do evento.</li><li><strong>Os três objetivos do setor:</strong> Criar impacto visual; aumentar a imersão do público; e valorizar os momentos importantes do show. Todo efeito acionado deve servir a pelo menos um desses objetivos — efeito sem propósito vira ruído visual.</li><li><strong>Trabalho em sincronia:</strong> O técnico de efeitos nunca trabalha sozinho. Ele se coordena com iluminação (muitos efeitos só aparecem se houver luz sobre eles), som (efeitos disparados em pontos exatos da música), direção artística (define quando e como) e segurança (essencial em fogo, pressão e pirotecnia).</li><li><strong>Roteiro técnico (cue sheet):</strong> Em evento profissional, nada é disparado ao acaso. Existe um roteiro técnico que determina exatamente em qual momento cada efeito é acionado, garantindo ritmo, impacto e — principalmente — segurança. Esse roteiro é ensaiado antes do show ao vivo.</li><li><strong>Responsabilidade técnica:</strong> Vários equipamentos usam gás comprimido, substâncias químicas ou sistemas elétricos de alta potência. Por isso o setor exige treinamento adequado, planejamento prévio e respeito às normas de segurança. Criatividade e responsabilidade andam juntas.</li></ul><p><strong>Na prática:</strong> Num show de música eletrônica, a direção artística pede um ''momento de explosão'' no refrão final. O técnico de efeitos anota no roteiro: no compasso X, disparar dois canhões de CO₂ junto com o confete, enquanto a iluminação fecha em strobe branco. Tudo é ensaiado na passagem de som para acertar o tempo exato antes do público chegar.</p><h4>Resumo</h4><ul><li>Efeitos especiais criam impacto visual, imersão e valorizam momentos do show, sempre apoiando som e luz</li><li>O técnico de efeitos trabalha em sincronia com iluminação, som, direção artística e segurança</li><li>Nada é disparado ao acaso: existe um roteiro técnico ensaiado, e a segurança é central</li></ul>',20,1,true,false);
