insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('4b590500-24c2-4320-9457-0d1be340f15b','0e0a8c76-d571-4bd8-8de2-85dd9c7b52d5','Qual é o papel dos efeitos especiais dentro da produção técnica de um evento?','Os efeitos não substituem som e luz; eles entram para marcar momentos (transições, clímax, entradas) e aumentar a imersão do público.',1,1);
