insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0b37d759-e424-4e50-aaf5-aedf767bf6ea','0e0a8c76-d571-4bd8-8de2-85dd9c7b52d5','O que é o roteiro técnico (cue sheet) de efeitos?','O roteiro técnico determina o momento exato de cada disparo, garantindo ritmo, impacto e segurança. Ele é ensaiado antes do show ao vivo.',2,1);
