insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c636ee93-3565-40c2-8d9d-077f1eecbcfa','0e0a8c76-d571-4bd8-8de2-85dd9c7b52d5','Com qual área a sincronia é especialmente crítica em efeitos que envolvem fogo, pressão ou pirotecnia?','Efeitos com gás comprimido, calor ou material pirotécnico exigem coordenação direta com a segurança, além de treinamento e planejamento.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('c636ee93-3565-40c2-8d9d-077f1eecbcfa','Marketing',false,1);
