insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('5584c1fd-eada-48b5-973b-7562e1f79d2d','277c995e-db24-4038-9cc1-9b5649be7536','Equipamentos de Atmosfera: Fumaça, Haze, Bolhas e Neve','texto','<p><strong>Para começar:</strong> Antes de qualquer efeito explosivo, existe um trabalho silencioso de criar a atmosfera do palco. Nesta aula você vai conhecer os equipamentos que enchem o ar de fumaça, névoa, bolhas e neve — e como cada um é usado.</p><p>Esses equipamentos parecem simples, mas envolvem fluidos, aquecimento e ventilação. Saber a diferença entre fumaça e haze, por exemplo, muda completamente o resultado visual e a escolha para cada tipo de evento.</p><ul><li><strong>Máquina de fumaça:</strong> Um dos equipamentos mais comuns. Aquece um fluido de fumaça específico que, ao vaporizar, cria uma nuvem artificial que se espalha pelo ambiente. Tem duas funções principais: destacar os feixes de luz (lasers, moving lights) e criar atmosfera no palco. Sem fumaça, muitos efeitos de luz quase não aparecem no ar.</li><li><strong>Máquina de haze (névoa):</strong> Semelhante à de fumaça, mas produz uma névoa muito mais fina e uniforme, quase imperceptível para o público. Não forma grandes nuvens, fica suspensa por mais tempo no ambiente e valoriza os feixes de luz de forma discreta e sofisticada. Muito usada em shows profissionais, teatros e eventos corporativos.</li><li><strong>Fluido correto e ventilação:</strong> Use sempre o fluido especificado pelo fabricante da máquina (à base de água/glicol para a maioria). Fluido errado pode danificar o equipamento e gerar resíduo. Em ambiente fechado, garanta ventilação adequada e atenção a detectores de fumaça do local, que podem disparar o alarme de incêndio sem aviso.</li><li><strong>Máquina de bolhas:</strong> Produz grande quantidade de bolhas de sabão lançadas por um sistema de ventilação. Cria um efeito leve e lúdico, muito usado em shows infantis, casamentos, festas temáticas e eventos ao ar livre. Atenção ao piso: o líquido das bolhas deixa o chão escorregadio.</li><li><strong>Máquina de neve artificial:</strong> Produz uma espuma leve que simula flocos de neve caindo. Muito usada em eventos natalinos, shows temáticos, parques e festivais. Não é neve real: é espuma que desaparece com o tempo, mas, assim como as bolhas, pode molhar e deixar o piso e equipamentos escorregadios ou úmidos.</li><li><strong>Onde posicionar:</strong> Equipamentos de atmosfera costumam ficar nas laterais ou no fundo do palco, direcionados para onde a luz vai trabalhar. Evite apontar fumaça/haze diretamente para músicos ou para sensores de fumaça, e mantenha cabos e máquinas longe de áreas de passagem do público.</li></ul><p><strong>Na prática:</strong> Num evento corporativo de premiação, a produção quer feixes de luz visíveis no ar, mas sem ''fumaça aparecendo'' nas fotos. O técnico escolhe a máquina de haze em vez da de fumaça: a névoa fina deixa os feixes lindos sem formar nuvens, e o ambiente continua com aparência limpa para a transmissão.</p><h4>Resumo</h4><ul><li>Máquina de fumaça cria nuvens; máquina de haze cria névoa fina e discreta para valorizar a luz</li><li>Sempre use o fluido correto do fabricante e cuide da ventilação e dos detectores de fumaça</li><li>Bolhas e neve são lúdicas, mas deixam o piso escorregadio: sinalize o risco</li></ul>',25,2,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('6d141126-bc12-4ebf-901e-ff6abbb8bc6c','5584c1fd-eada-48b5-973b-7562e1f79d2d','Quiz — Equipamentos de Atmosfera: Fumaça, Haze, Bolhas e Neve');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('68ef38d1-0e6d-468f-8d36-3ce7e4c8aace','6d141126-bc12-4ebf-901e-ff6abbb8bc6c','Qual a principal diferença entre máquina de fumaça e máquina de haze?','O haze gera uma névoa fina e uniforme, quase imperceptível, ideal para valorizar feixes de luz sem formar grandes nuvens como a fumaça comum.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('68ef38d1-0e6d-468f-8d36-3ce7e4c8aace','A de haze usa fogo de verdade',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('68ef38d1-0e6d-468f-8d36-3ce7e4c8aace','A de haze produz névoa muito fina e discreta, enquanto a de fumaça forma nuvens densas',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('68ef38d1-0e6d-468f-8d36-3ce7e4c8aace','Não há diferença, são o mesmo equipamento',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('68ef38d1-0e6d-468f-8d36-3ce7e4c8aace','A de fumaça só funciona ao ar livre',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('341f0465-ad46-43f6-90cf-1273c621dbdf','6d141126-bc12-4ebf-901e-ff6abbb8bc6c','Por que é importante avisar a produção e o local ao usar máquina de fumaça em ambiente fechado?','Detectores de fumaça do ambiente podem interpretar a fumaça artificial como incêndio e disparar o alarme. Avisar e planejar evita transtornos.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('341f0465-ad46-43f6-90cf-1273c621dbdf','Para economizar fluido',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('341f0465-ad46-43f6-90cf-1273c621dbdf','Porque a fumaça pode disparar os detectores e o alarme de incêndio do local',true,2);
