insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('475db19b-f9e6-43fe-b44e-942736733188','6d141126-bc12-4ebf-901e-ff6abbb8bc6c','Qual cuidado de segurança é específico ao usar máquinas de bolhas e de neve artificial?','Tanto o líquido de bolhas quanto a espuma de neve deixam o piso escorregadio e úmido. É preciso sinalizar e, se necessário, secar a área de circulação.',3,1);
