insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('4a933f8f-aa6a-4329-9abf-235cc74c0aad','6d141126-bc12-4ebf-901e-ff6abbb8bc6c','Qual fluido deve ser usado na máquina de fumaça?','Usar o fluido indicado pelo fabricante evita danos ao equipamento e resíduos. Líquidos improvisados podem estragar a máquina e gerar risco.',4,1);
