insert into public.quiz_options (question_id,texto,correta,ordem) values ('4a933f8f-aa6a-4329-9abf-235cc74c0aad','Álcool combustível',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('1d264ebd-e814-488c-849b-3c92c9af3ae6','277c995e-db24-4038-9cc1-9b5649be7536','Efeitos de Impacto: CO₂, Confete e Faíscas Frias','texto','<p><strong>Para começar:</strong> Estes são os efeitos que arrancam reação imediata do público: a coluna branca do CO₂, a chuva de confete e a cascata de faíscas na entrada do artista. Nesta aula você vai entender como cada um funciona e os cuidados que eles exigem.</p><p>Esses equipamentos trabalham com gás sob alta pressão, sistemas elétricos ou produtos que lançam material no ar. São de grande impacto, mas pedem distância segura, instalação correta e operação treinada.</p><ul><li><strong>Canhão de CO₂:</strong> Dispara jatos de dióxido de carbono em alta pressão, formando colunas de fumaça branca que sobem rapidamente. Comum em shows eletrônicos, festivais, casas noturnas e grandes palcos. Quando direcionado à plateia, gera sensação de vento gelado. Funciona com cilindros de gás CO₂ e exige atenção e treinamento.</li><li><strong>Cuidados com o CO₂:</strong> O gás está sob alta pressão: cilindros devem estar bem fixados e em pé, com mangueiras e conexões certificadas e em bom estado. CO₂ desloca o oxigênio, então evite acúmulo em ambientes fechados e mal ventilados. O jato é muito frio (pode causar queimadura por frio): nunca aponte para curta distância da pele das pessoas e mantenha distância segura do público.</li><li><strong>Lança/canhão de confete:</strong> Dispara papéis coloridos ou metalizados no ar, criando uma explosão visual para momentos de clímax. Pode funcionar por pressão de ar, CO₂ ou sistema elétrico. O confete cai lentamente sobre o público, marcando finais de apresentação. Existe também a lança serpentina, que dispara longas fitas coloridas.</li><li><strong>Cuidados com confete e serpentina:</strong> Prefira confete antichama (retardante de fogo), especialmente perto de luzes quentes e efeitos com calor. Use confete biodegradável quando possível e planeje a limpeza pós-evento. Direcione o disparo para cima e longe de rostos; o metalizado pode conduzir eletricidade — mantenha-o longe de partes elétricas expostas.</li><li><strong>Máquina de faísca fria (spark machine):</strong> Produz faíscas verticais que sobem vários metros, com efeito parecido com fogos de artifício, porém com faíscas frias — não são chamas abertas como a pirotecnia tradicional. Isso torna o uso mais viável em ambientes internos. Muito usada em entradas de artistas, casamentos, shows e eventos corporativos.</li><li><strong>Faísca fria não é ''sem risco'':</strong> Mesmo sendo mais segura que pirotecnia, a faísca fria ainda gera calor pontual e deve seguir normas de segurança: respeitar a distância mínima até pessoas e materiais inflamáveis indicada pelo fabricante, manter cortinas, tecidos e cenário afastados, usar o consumível correto e ter extintor por perto. Trate-a com o mesmo respeito de qualquer efeito quente.</li></ul><p><strong>Na prática:</strong> Na entrada do artista principal, a produção quer duas cascatas de faíscas frias na frente do palco. O técnico mede a distância mínima indicada pelo fabricante, confirma que não há cortinas nem tecidos no raio de alcance, posiciona um extintor próximo e só então programa o disparo no controlador para o momento exato da entrada.</p><h4>Resumo</h4><ul><li>CO₂ trabalha sob alta pressão e é muito frio: fixe os cilindros, ventile e mantenha distância do público</li><li>Confete e serpentina pedem material antichama/biodegradável, disparo para cima e limpeza planejada</li><li>Faísca fria é mais segura que pirotecnia, mas ainda gera calor: distância, área limpa e extintor são obrigatórios</li></ul>',25,3,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('748beee2-37e6-4a93-904c-8adce7fd3d93','1d264ebd-e814-488c-849b-3c92c9af3ae6','Quiz — Efeitos de Impacto: CO₂, Confete e Faíscas Frias');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('16d492f8-892b-4c17-b13a-d768b9b1a534','748beee2-37e6-4a93-904c-8adce7fd3d93','Por que o jato de um canhão de CO₂ exige distância segura do público?','O CO₂ sai gelado e sob alta pressão. A curta distância pode causar queimadura por frio, além de o gás deslocar oxigênio em ambientes fechados.',1,1);
