insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e55771d8-2f57-49a7-8f2c-18b2c3e4f4be','748beee2-37e6-4a93-904c-8adce7fd3d93','Qual tipo de confete é mais indicado perto de luzes quentes e efeitos com calor?','Próximo a fontes de calor deve-se usar confete antichama. O metalizado, além disso, pode conduzir eletricidade e deve ficar longe de partes elétricas.',2,1);
