insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('ff389a6a-7d67-4c7d-b1c9-75feb37d362d','748beee2-37e6-4a93-904c-8adce7fd3d93','A faísca fria é totalmente isenta de risco?','A faísca fria é mais segura que a pirotecnia por não ter chama aberta, mas gera calor pontual. Distância mínima, área sem inflamáveis e extintor continuam obrigatórios.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('ff389a6a-7d67-4c7d-b1c9-75feb37d362d','Sim, pode ser usada sem nenhum cuidado',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('ff389a6a-7d67-4c7d-b1c9-75feb37d362d','Não: ainda gera calor pontual e exige distância, área limpa de inflamáveis e extintor',true,2);
