insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('10c652e1-7931-4d6b-ae79-dbdb38a6e6ca','748beee2-37e6-4a93-904c-8adce7fd3d93','Qual é a forma correta de armazenar e usar cilindros de CO₂ durante o evento?','Cilindros de gás sob pressão devem ficar fixados e em pé, com conexões certificadas. Evita-se ambiente fechado pelo deslocamento de oxigênio.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('10c652e1-7931-4d6b-ae79-dbdb38a6e6ca','Deitados e soltos perto do palco',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('10c652e1-7931-4d6b-ae79-dbdb38a6e6ca','Bem fixados, em pé, com mangueiras e conexões certificadas e em bom estado',true,2);
