insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('616c3575-d499-4539-a430-8a16557edc4e','277c995e-db24-4038-9cc1-9b5649be7536','Pirotecnia, Controladores e Operação Segura','texto','<p><strong>Para começar:</strong> Chegamos aos efeitos de maior risco e ao cérebro que comanda tudo. Nesta aula você vai entender o que é pirotecnia profissional, como funcionam os controladores de efeitos e quais são os princípios de operação segura que valem para todo o setor.</p><p>Pirotecnia não é tarefa de iniciante: exige profissional certificado e autorizações. Já os controladores são o que garante que cada efeito aconteça no instante exato. Saber onde está o seu limite de atuação é parte do profissionalismo.</p><ul><li><strong>Equipamentos pirotécnicos:</strong> Usam materiais explosivos controlados para criar explosões visuais, fogos de artifício, chamas cenográficas, cometas e explosões de palco. Por envolver risco real e materiais inflamáveis, exigem licenças especiais, profissionais certificados (blaster/pirotécnico) e autorização dos órgãos responsáveis. São mais comuns em grandes shows e festivais.</li><li><strong>Limite de atuação do técnico junior:</strong> Pirotecnia profissional deve ser planejada e disparada por profissional certificado e habilitado, não pelo técnico junior. Seu papel é apoiar com segurança: isolar a área, ajudar no que for autorizado e nunca manipular ou disparar carga pirotécnica por conta própria. Reconhecer esse limite é uma competência, não uma fraqueza.</li><li><strong>Controladores de efeitos:</strong> Para que tudo aconteça no momento certo, usam-se controladores eletrônicos que programam e disparam os equipamentos com precisão. Podem ser painéis manuais, sistemas DMX (integrados à iluminação), disparo remoto ou programação sincronizada com a música. Garantem que o efeito ocorra exatamente no ponto planejado do show.</li><li><strong>DMX e disparo remoto:</strong> O DMX é o mesmo protocolo usado pela iluminação, o que permite que efeitos e luz sejam controlados em conjunto pela mesma mesa. O disparo remoto (por rádio ou cabo) separa o operador do equipamento perigoso. Sempre confirme o endereçamento (canal/endereço) de cada máquina antes do show para não disparar o efeito errado.</li><li><strong>Princípios gerais de segurança:</strong> Valem para todo o setor: distância segura do público; instalação correta e firme dos equipamentos; profissionais treinados; equipamentos certificados e em bom estado; e autorização/licença quando necessário. Calor, pressão, eletricidade e produtos químicos estão presentes — nenhum efeito justifica pular esses cuidados.</li><li><strong>Teste, ensaio e plano de emergência:</strong> Teste os disparos na passagem de som, nunca pela primeira vez com o público presente. Tenha extintores acessíveis, saídas desobstruídas e um plano de parada de emergência (como abortar um disparo). Mantenha comunicação por rádio com a direção e a segurança durante todo o show.</li></ul><p><strong>Na prática:</strong> Num festival, o roteiro prevê chamas cenográficas no palco. O técnico junior não toca na pirotecnia: ela fica com o pirotécnico certificado, que tem a licença. O junior fica responsável por isolar a zona de exclusão, conferir que os extintores estão no lugar e operar, pelo controlador DMX, apenas os canhões de CO₂ e o confete que lhe foram designados — tudo testado antes na passagem.</p><h4>Resumo</h4><ul><li>Pirotecnia exige licença, profissional certificado e autorização; o técnico junior apoia a segurança, mas não dispara</li><li>Controladores (painel, DMX, rádio) garantem o disparo no momento exato; confirme sempre o endereçamento</li><li>Segurança é regra geral: distância, instalação correta, equipamentos certificados, teste na passagem e plano de emergência</li></ul>',25,4,true,false);
