insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('8ef845de-5f79-45ce-adb5-bb02d22abb9b','85a17740-8751-40c5-98dc-3741afa54db4','Quem deve planejar e disparar efeitos pirotécnicos profissionais?','Pirotecnia envolve materiais explosivos e exige licença, profissional certificado e autorização. O técnico junior apoia a segurança, mas não manipula nem dispara a carga.',1,1);
