insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('31fc4ea2-9582-49e0-b1c3-4d888f62a4e3','85a17740-8751-40c5-98dc-3741afa54db4','Para que serve um controlador de efeitos (painel, DMX ou disparo remoto)?','Os controladores permitem programar e disparar os efeitos com precisão no ponto planejado, inclusive sincronizados com luz (DMX) e música.',2,1);
