insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5a004f11-a1e9-46d4-8682-6dba2f555e2f','85a17740-8751-40c5-98dc-3741afa54db4','Quando os disparos de efeitos devem ser testados?','Os disparos são testados na passagem, antes do público chegar. Isso ajusta o tempo do roteiro e evita falhas e riscos durante o show ao vivo.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('5a004f11-a1e9-46d4-8682-6dba2f555e2f','Pela primeira vez com o público presente, para causar surpresa',false,1);
