insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('a2bf8461-ce12-467d-924c-4d5a328f9835','85a17740-8751-40c5-98dc-3741afa54db4','Qual conjunto de cuidados é princípio geral de segurança para todo o setor de efeitos?','Esses são os cuidados essenciais: distância do público, instalação correta, equipamentos certificados, profissionais treinados e licença/autorização quando exigida.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('a2bf8461-ce12-467d-924c-4d5a328f9835','Volume alto, luzes fortes e improviso',false,1);
