insert into public.modules (id,course_id,titulo,ordem) values ('7839b457-26e0-421a-a982-c82e62e153c8','8febe92b-ca5e-48ce-ab73-0e672fadd3c0','Fundamentos do DJ',1);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('cdd9351f-fd84-480b-92d3-f53af1782e14','7839b457-26e0-421a-a982-c82e62e153c8','Introdução: o que é ser DJ','texto','<p><strong>Para começar:</strong> Antes de tocar no primeiro botão, você precisa entender o que realmente significa ser DJ. Esta aula apresenta a missão do DJ e o caminho que você vai percorrer no curso.</p><p>Ser DJ vai muito além de apenas tocar músicas. O DJ é o condutor da pista de dança, o narrador de emoções através do som. Um bom DJ entende seu público, cria atmosferas únicas e domina as ferramentas que transformam simples faixas em momentos mágicos. Neste curso você começa do zero, respeitando seu ritmo e sua evolução.</p><ul><li><strong>O que é ser DJ:</strong> É ser o condutor da pista: você lê o público, cria atmosferas e transforma faixas em momentos inesquecíveis. Não é só apertar play, é contar uma história sonora.</li><li><strong>Para quem é este curso:</strong> Para quem sonha em tocar em festas, clubes e eventos; para quem quer carreira na música eletrônica; para amantes da música que querem se expressar; e para quem busca uma nova habilidade e diversão.</li><li><strong>O que você vai aprender:</strong> História e evolução do DJing; equipamentos essenciais; noções de música (BPM, estrutura, gêneros); técnicas de mixagem, transição e equalização; uso de softwares e controladoras; e como montar seu setup e fazer suas primeiras apresentações.</li><li><strong>O objetivo do curso:</strong> Dar a base para você ter segurança na operação dos equipamentos, compreender a dinâmica da pista e, acima de tudo, desenvolver seu próprio estilo como DJ.</li><li><strong>Comece do zero, sem pressa:</strong> Não importa se você nunca encostou em uma controladora ou se já brincou de mixar em casa. O aprendizado é progressivo: técnica e prática constante valem mais que talento de primeira hora.</li></ul><p><strong>Na prática:</strong> Imagine sua primeira noite tocando: a pista está morna no começo, enche no meio e explode no pico. Seu papel é guiar essa jornada de energia. Antes de aprender botões, observe DJs em vídeos e perceba como eles controlam o clima da festa, não apenas a música.</p><h4>Resumo</h4><ul><li>O DJ é o condutor da pista e narrador de emoções, não apenas quem aperta play</li><li>O curso vai do zero: história, equipamentos, música, técnicas, performance e profissionalização</li><li>O objetivo final é segurança técnica, leitura de pista e estilo próprio</li></ul>',10,1,true,true);
