insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('be0ebfd5-b382-4e88-bcec-fb1be7a930d5','7839b457-26e0-421a-a982-c82e62e153c8','História do DJ: dos anos 70 até hoje','texto','<p><strong>Para começar:</strong> A profissão de DJ tem pouco mais de 50 anos e nasceu nas ruas do Bronx. Conhecer essa evolução ajuda você a entender de onde vêm as técnicas e equipamentos que vai usar.</p><p>Na década de 1970, nos bairros do Bronx, em Nova York, jovens começaram a organizar festas nas ruas e nos prédios. Como contratar bandas era caro, a solução foi usar toca-discos e vinis para manter a festa animada. Dali nasceu toda uma cultura que mudou a música mundial.</p><ul><li><strong>Anos 1970 — o nascimento:</strong> No Bronx, festas de rua usavam toca-discos e vinis. DJ Kool Herc, o "pai do hip-hop", percebeu que o público dançava mais nas partes instrumentais (os "breaks") e usou dois toca-discos para estender esses trechos, criando a base perfeita para dança.</li><li><strong>A cultura Hip-Hop:</strong> O DJing logo se uniu ao rap, ao breakdance e ao graffiti. Tudo começou no Bronx e se espalhou pelo mundo.</li><li><strong>Anos 1980 — o turntablism:</strong> DJs como Grandmaster Flash criaram técnicas avançadas como o scratching (arranhar o disco para criar sons rítmicos). O DJ deixou de só "tocar música" e passou a criar expressão sonora ao vivo. Surgem mixers melhores, toca-discos mais precisos e os primeiros samplers.</li><li><strong>Anos 1990 — a revolução eletrônica:</strong> House, techno, drum and bass e outros estilos explodiram em clubes e raves. Surge o "DJ superstar" (Carl Cox, Paul Oakenfold, Sasha). CDJs começam a substituir toca-discos e aparecem os primeiros softwares de DJ, como o Traktor.</li><li><strong>Anos 2000 até hoje — a era digital:</strong> Laptops, controladoras MIDI e pendrives entram em cena. Serato e Rekordbox permitem sincronizar músicas. Muitos DJs viram produtores. David Guetta, Calvin Harris e Martin Garrix alcançam o estrelato com músicas e redes sociais.</li><li><strong>O futuro:</strong> Realidade virtual, inteligência artificial e live sets devem mudar como os DJs criam e apresentam. E o DJing fica cada vez mais acessível para todas as idades, gêneros e culturas.</li></ul><p><strong>Na prática:</strong> Pesquise e ouça um trecho de um set de DJ Kool Herc (anos 70, vinil e breaks) e um set moderno de Carl Cox. Note como a técnica saiu da manipulação manual de discos para mixagens longas e precisas com tecnologia digital. Essa comparação mostra na prática a evolução de meio século.</p><h4>Resumo</h4><ul><li>O DJing nasceu no Bronx nos anos 70 com Kool Herc e os "breaks"</li><li>Cada década trouxe avanços: scratching (80), música eletrônica (90), digital (2000)</li><li>Hoje o DJ é também produtor e o acesso à profissão está cada vez mais democrático</li></ul>',15,2,true,false);
