insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0e539eea-9d4c-41ff-9929-b20b0d036919','e33f7e4e-69f6-4c64-812a-3e6fde91d08c','Quem é conhecido como o "Pai da House Music"?','Frankie Knuckles, de Chicago, criou a House Music no clube The Warehouse.',1,1);
