insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('930082f0-9643-48f6-8028-d49da3009134','7839b457-26e0-421a-a982-c82e62e153c8','Tipos de DJs','texto','<p><strong>Para começar:</strong> Existem várias formas de ser DJ, e cada uma exige habilidades e estilos diferentes. Saber qual perfil combina com você ajuda a direcionar seus estudos e sua carreira.</p><p>O mundo do DJing é maior do que parece. Conhecer os tipos de DJ ajuda você a escolher seu caminho e a entender que habilidades priorizar.</p><ul><li><strong>Club DJ:</strong> Trabalha em clubes, casas noturnas e festas. Mantém a energia da pista constante, lê o público e faz transições suaves criando uma "viagem sonora". Habilidade principal: criar a vibe certa para cada momento. Exemplo: Carl Cox.</li><li><strong>Turntablist (DJ de performance):</strong> Trabalha em competições, shows de hip-hop e batalhas. Usa o toca-discos como instrumento: scratches, beat juggling e body tricks. Habilidade principal: manipulação avançada do vinil. Exemplo: DJ Qbert.</li><li><strong>Mobile DJ (DJ de eventos):</strong> Trabalha em casamentos, aniversários, formaturas e eventos corporativos. Monta som e iluminação, toca estilos variados e interage com o público. Habilidade principal: versatilidade musical e comunicação.</li><li><strong>DJ Produtor:</strong> Trabalha em estúdios, shows próprios e festivais. Cria suas próprias músicas e remixes e mistura performance ao vivo com suas composições. Habilidade principal: produção musical e performance. Exemplos: David Guetta, Calvin Harris, Alok.</li><li><strong>Radio DJ:</strong> Trabalha em rádios, podcasts e programas online. Toca músicas, apresenta, dá notícias, entrevista artistas e às vezes cria sets exclusivos. Habilidade principal: comunicação e curadoria. Exemplo: Annie Mac (BBC Radio 1).</li><li><strong>Bedroom DJ (DJ de hobby/casa):</strong> Trabalha em casa com setups pessoais. Treina mixagem e grava sets para SoundCloud e Mixcloud. Muitos DJs famosos começaram assim. Habilidade principal: dedicação e prática constante.</li></ul><p><strong>Na prática:</strong> Pense em uma festa real: um Mobile DJ num casamento precisa agradar do avô à criança alternando estilos, enquanto um Club DJ num after de techno mantém um único clima por horas. Escolha agora com qual desses perfis você mais se identifica e pesquise um profissional dessa área para se inspirar.</p><h4>Resumo</h4><ul><li>Há vários perfis: Club, Turntablist, Mobile, Produtor, Radio e Bedroom DJ</li><li>Cada tipo exige habilidades distintas, da técnica de vinil à comunicação</li><li>Quase todo DJ começa como Bedroom DJ, praticando em casa</li></ul>',12,4,true,false);
