insert into public.modules (id,course_id,titulo,ordem) values ('2008d4d2-aa4c-4004-a773-90cf81ac79a6','8febe92b-ca5e-48ce-ab73-0e672fadd3c0','Equipamentos Essenciais',2);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('5d799cc9-d984-4339-85a6-fd51a9f2f48e','2008d4d2-aa4c-4004-a773-90cf81ac79a6','Controladoras, toca-discos, mixers e CDJs','texto','<p><strong>Para começar:</strong> Todo DJ precisa dominar seu equipamento. Entender as diferenças entre os tipos de setup ajuda você a escolher o que combina com seu estilo e orçamento.</p><p>Cada tipo de equipamento tem características únicas. Nesta aula você conhece os quatro pilares do hardware do DJ e descobre para quem cada um é indicado.</p><ul><li><strong>Controladoras (Controllers):</strong> Conectam ao computador e controlam softwares (Serato, Rekordbox, Traktor, Virtual DJ). Integram mixer e decks num só aparelho, com jog wheels, botões de cue, pads e faders. Dependem de um notebook. Vantagens: mais baratas, portáteis e práticas. Exemplos: Pioneer DDJ-FLX4, Numark Mixtrack Pro, Traktor S2. Ideal para começar com baixo investimento.</li><li><strong>Toca-Discos (Turntables):</strong> Tocam discos de vinil (LPs). Pratos giratórios por motor (direct drive ou belt drive), controle manual total de velocidade e posição, e permitem scratch e beat juggling. Vantagens: sensação clássica e controle absoluto. Desvantagens: mais caros, delicados e os vinis são trabalhosos de transportar. Exemplos: Technics SL-1200 MK2, Pioneer PLX-1000.</li><li><strong>Mixers:</strong> Recebem o áudio de dois ou mais tocadores e permitem misturar os sinais. Têm faders de volume por canal, equalizadores (graves, médios, agudos), crossfader para transição, entrada de microfone e saída para caixas. Modelos modernos têm efeitos (eco, delay, reverb), filtros e interface de áudio. Exemplos: Pioneer DJM-900NXS2, Allen &amp; Heath Xone:92. O mixer é a "ponte" entre as músicas.</li><li><strong>CDJs:</strong> Simulam toca-discos, mas tocam áudio digital de CDs, pendrives ou cartões. Têm jog wheel para manipular a música, pitch control, looping e cue points, e integram com Rekordbox. Vantagens: robustez, confiabilidade, autonomia (sem notebook) e alta qualidade. Exemplos: Pioneer CDJ-2000NXS2 (padrão de clubes), Pioneer XDJ-700. Quem quer tocar em clubes precisa aprender CDJ.</li></ul><p><strong>Na prática:</strong> Vá a uma loja ou peça para testar uma controladora de amigo: sinta o jog wheel girar, mova o crossfader de um lado ao outro e ajuste um equalizador enquanto a música toca. Esse contato físico mostra na prática a diferença entre uma controladora, que depende do notebook, e um CDJ, que toca sozinho com um pendrive.</p><h4>Resumo</h4><ul><li>Controladora integra mixer e decks e depende de um notebook; ótima para iniciar</li><li>Toca-discos é para vinil e turntablism; CDJ é o padrão digital dos clubes</li><li>O mixer é a ponte entre as músicas: faders, EQ, crossfader e efeitos</li></ul>',16,1,true,false);
