insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('7bafed9e-ad10-4345-80ca-f0f30e16c72a','2008d4d2-aa4c-4004-a773-90cf81ac79a6','Softwares populares para DJs','texto','<p><strong>Para começar:</strong> Hoje, dominar o software é tão importante quanto o equipamento físico. Ele organiza músicas, prepara sets e permite mixagens e performances ao vivo.</p><p>Os softwares oferecem ferramentas para organizar, preparar e tocar suas músicas. Conhecer os quatro principais ajuda você a escolher onde focar no início.</p><ul><li><strong>Serato DJ:</strong> Um dos mais famosos e confiáveis. Estável, com baixa latência, interface clara e suporte a controladoras, mixers e toca-discos DVS (vinil digital). Muito usado por DJs de hip-hop, open format e turntablists. Ótimo para scratch e performance. Usuários: DJ Jazzy Jeff, A-Trak.</li><li><strong>Rekordbox DJ:</strong> Criado pela Pioneer para preparar, organizar e tocar músicas, principalmente em CDJs e controladoras. Analisa BPM, tonalidade e waveform; prepara playlists, hot cues e loops; e permite tocar só com pendrive. É padrão em clubes e festivais. Usuários: Charlotte de Witte, Armin van Buuren.</li><li><strong>Traktor Pro:</strong> Da Native Instruments, muito usado por DJs criativos e de eletrônica. Tem Remix Decks para remixagem ao vivo, efeitos criativos e interface personalizável. Perfeito para inovar e construir sets ao vivo. Usuários: Richie Hawtin, Dubfire.</li><li><strong>Virtual DJ:</strong> Um dos mais conhecidos, sobretudo entre iniciantes. Interface intuitiva, compatível com quase todas as controladoras, com vídeo mixing e automix. Ótimo para começar e para eventos sociais com músicas variadas.</li><li><strong>Como escolher:</strong> Foco em performance e scratch: Serato. Sonho de tocar em clubes e festivais: Rekordbox (quase obrigatório). Sets criativos e remix ao vivo: Traktor. Começar rápido e sem complicação: Virtual DJ. A maioria tem versão gratuita para você testar.</li></ul><p><strong>Na prática:</strong> Baixe a versão gratuita de pelo menos um desses softwares e faça o básico: carregue duas músicas, dê play, use o crossfader e tente uma transição simples. Anote o que achou fácil e o que achou difícil. Esse primeiro contato já mostra qual interface combina mais com você.</p><h4>Resumo</h4><ul><li>Serato é forte em performance e scratch; Rekordbox é padrão de clubes e festivais</li><li>Traktor é o mais criativo (remix ao vivo); Virtual DJ é o mais fácil para iniciar</li><li>Quase todos têm versão gratuita: teste antes de escolher seu foco</li></ul>',14,2,true,false);
