insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('1f9edd05-0d6b-4368-9c66-d872829a37ba','2008d4d2-aa4c-4004-a773-90cf81ac79a6','Fones, caixas de som e interfaces de áudio','texto','<p><strong>Para começar:</strong> Além do equipamento principal, alguns acessórios são fundamentais para treinar e performar bem. Esta aula mostra como escolher fones, caixas e interfaces.</p><p>Fones, caixas de som e interfaces de áudio completam o seu setup. Cada um tem uma função específica que afeta diretamente a qualidade do seu treino e das suas apresentações.</p><ul><li><strong>Fones de ouvido (Headphones para DJ):</strong> Permitem escutar a próxima música enquanto outra toca para o público, garantindo a transição. Características: isolamento acústico (bloqueia o som da pista), alta fidelidade (graves, médios e agudos claros), conforto para longas horas e hastes que giram para escutar com um ouvido só. Exemplos: Pioneer HDJ-X10, Sennheiser HD 25, Audio-Technica ATH-M50X. Invista em um bom fone logo no começo.</li><li><strong>Caixas de som (Monitores de áudio):</strong> Permitem escutar o que toca para o público (PA) ou simular a pista em casa. Tipos: monitores de estúdio (som neutro e preciso, ideais para treinar/produzir) e caixas de PA (som potente, para festas e eventos). Características: resposta de frequência plana (monitores), alta potência e clareza (PA) e tamanhos variados (5, 6, 8 polegadas). Exemplos: KRK Rokit 5 e Yamaha HS5 (monitores); JBL EON 610 e QSC K12.2 (PA).</li><li><strong>Interfaces de áudio:</strong> Convertem o áudio do computador para caixas externas com alta qualidade. Importantes para quem usa software no notebook e quer melhor som, e para gravar sets em alta definição. Características: baixa latência, entradas e saídas balanceadas (menos ruído) e compatibilidade com Serato, Traktor e Rekordbox. Exemplos: Focusrite Scarlett 2i2, Native Instruments Traktor Audio 2, Reloop Tape 2 (gravação).</li><li><strong>Quando você precisa de cada um:</strong> Fone: indispensável desde o primeiro dia. Monitores de estúdio: para treinar em casa. Caixas de PA: para tocar em eventos. Interface separada: só se sua controladora não tiver uma embutida ou se você quiser gravar/tocar em configurações profissionais.</li></ul><p><strong>Na prática:</strong> Monte um pequeno setup em casa: notebook, controladora, um bom fone de ouvido e um par de caixas (no começo, até caixas Bluetooth servem). Coloque uma música tocando nas caixas e pré-escute a próxima no fone usando uma só haste no ouvido. Esse exercício simula exatamente o que você fará ao vivo.</p><h4>Resumo</h4><ul><li>O fone permite pré-escutar a próxima música; priorize isolamento e conforto</li><li>Monitores de estúdio são para treino; caixas de PA são para eventos</li><li>A interface de áudio melhora a qualidade e permite gravar sets</li></ul>',12,3,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('31c00ecc-c507-443b-9ffc-4fc5dfd75e11','1f9edd05-0d6b-4368-9c66-d872829a37ba','Quiz — Fones, caixas de som e interfaces de áudio');
