insert into public.modules (id,course_id,titulo,ordem) values ('ac8772a7-b927-4957-8188-5cb4df26146a','8febe92b-ca5e-48ce-ab73-0e672fadd3c0','Conhecendo a Música',3);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('17c7b7f4-f63f-4750-8ab4-b198a9a8f613','ac8772a7-b927-4957-8188-5cb4df26146a','BPM e gênero musical','texto','<p><strong>Para começar:</strong> Entender o BPM é essencial para fazer mixagens suaves e controlar a energia do set. É o conceito que conecta uma música à outra de forma harmoniosa.</p><p>BPM é o que permite sincronizar músicas, construir energia e manter a pista em movimento. Nesta aula você aprende o que é, como cada gênero se comporta e como usar o pitch para casar faixas.</p><ul><li><strong>O que é BPM:</strong> BPM significa Batidas Por Minuto: a medida da velocidade da música. Uma faixa de 120 BPM tem 120 batidas por minuto (2 por segundo). 70 BPM é lento (hip hop); 130 BPM é rápido (techno). DJs usam o BPM para sincronizar músicas e fazer transições suaves.</li><li><strong>BPM por gênero:</strong> Cada estilo tem uma faixa típica: Hip Hop 70–100 (ideal para scratch), Reggaeton 80–100, Funk Carioca 120–130, House 120–128, Techno 125–135, Drum and Bass 160–180, Trap 65–75 (double-time até 140), Pop 90–120 e Sertanejo Universitário 95–110. Quando os BPMs são próximos, a mixagem é mais fácil.</li><li><strong>Alterando o BPM (pitch adjustment):</strong> Nos equipamentos você ajusta o BPM com o pitch fader para sincronizar duas músicas. Regra básica: não altere demais; passar de 6% para cima ou para baixo muda o som natural da faixa (vozes e graves ficam estranhos).</li><li><strong>Escolhendo músicas para mixar:</strong> Antes de tocar, observe o BPM original, verifique a tonalidade (key) se possível e prepare faixas próximas em BPM ou que dê para "esticar" sem perder qualidade. Exemplo: para passar de um house de 124 BPM a um techno de 130, suba o house a ~126 e baixe o techno a ~128; a transição fica quase imperceptível.</li><li><strong>Construindo energia com BPM:</strong> Suba o BPM aos poucos para aumentar a energia ou diminua para criar uma quebra. Exemplo de set: começo House 122 (aquecimento), meio Tech House 126 (pista cheia), pico Techno 130 (explosão) e final Melodic Techno 124 (desaceleração).</li></ul><p><strong>Na prática:</strong> Escolha 10 músicas de estilos diferentes e anote o nome, o gênero e o BPM de cada uma. Organize-as em ordem crescente de BPM, do mais lento ao mais rápido. Depois, tente montar uma pequena sequência mixando faixas vizinhas: você vai perceber na prática como BPMs próximos tornam a transição muito mais fácil.</p><h4>Resumo</h4><ul><li>BPM é a velocidade da música em batidas por minuto e guia toda a mixagem</li><li>Cada gênero tem sua faixa de BPM; faixas próximas são mais fáceis de mixar</li><li>O pitch casa BPMs, mas não passe de ~6% para não distorcer o som</li></ul>',15,1,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('fbf9e931-9ca3-49ec-8bde-33f41e6e52bc','17c7b7f4-f63f-4750-8ab4-b198a9a8f613','Quiz — BPM e gênero musical');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c97b00da-5b4c-41d6-a8ff-d0786848011c','fbf9e931-9ca3-49ec-8bde-33f41e6e52bc','O que significa BPM?','BPM é Batidas Por Minuto, a medida da velocidade da música.',1,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('c97b00da-5b4c-41d6-a8ff-d0786848011c','Batidas Por Música',false,1);
