insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('d8563162-649d-46c2-a5be-844862a99fe0','fbf9e931-9ca3-49ec-8bde-33f41e6e52bc','Qual é a regra básica ao ajustar o pitch para casar BPMs?','Alterar mais de ~6% muda o som natural da música, distorcendo vozes e graves.',2,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d8563162-649d-46c2-a5be-844862a99fe0','Pode alterar o quanto quiser',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d8563162-649d-46c2-a5be-844862a99fe0','Não passar de cerca de 6% para cima ou para baixo',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d8563162-649d-46c2-a5be-844862a99fe0','Sempre dobrar o BPM',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d8563162-649d-46c2-a5be-844862a99fe0','Nunca usar o pitch',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('d8481e2e-2492-4769-88da-0dfc40483c65','fbf9e931-9ca3-49ec-8bde-33f41e6e52bc','Por que a mixagem fica mais fácil quando os BPMs são próximos?','BPMs próximos exigem pouco ajuste para alinhar as batidas, deixando a transição suave.',3,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d8481e2e-2492-4769-88da-0dfc40483c65','Porque as músicas tocam sozinhas',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d8481e2e-2492-4769-88da-0dfc40483c65','Porque as batidas se alinham com pouco ajuste de pitch',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d8481e2e-2492-4769-88da-0dfc40483c65','Porque o público não percebe',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('d8481e2e-2492-4769-88da-0dfc40483c65','Porque elimina a necessidade de fone',false,4);
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('b88bebae-5d6a-4dab-896c-3d8b185bdffa','fbf9e931-9ca3-49ec-8bde-33f41e6e52bc','Numa típica construção de set, o pico costuma ter:','No pico, o BPM mais alto (ex.: Techno 130) leva a pista à explosão de energia.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('b88bebae-5d6a-4dab-896c-3d8b185bdffa','O menor BPM da noite',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('b88bebae-5d6a-4dab-896c-3d8b185bdffa','Um BPM mais alto e enérgico (ex.: techno 130)',true,2);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('b88bebae-5d6a-4dab-896c-3d8b185bdffa','Apenas músicas lentas',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('b88bebae-5d6a-4dab-896c-3d8b185bdffa','Nenhuma batida',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('da6e1fb2-dad0-42e6-b44d-770ab6caae8c','ac8772a7-b927-4957-8188-5cb4df26146a','Estrutura de uma música para DJs','texto','<p><strong>Para começar:</strong> Saber onde começam e terminam as partes de uma música é o que permite mixar no momento certo. Esta aula ensina a "ler" a estrutura de uma faixa.</p><p>A maioria das músicas (eletrônicas, pop, hip hop e funk) segue uma estrutura que se repete em partes típicas. Reconhecer cada parte mostra exatamente onde entrar e sair com a próxima música.</p><ul><li><strong>Intro (introdução):</strong> Parte inicial, geralmente instrumental e simples. Ideal para a mixagem de entrada, encaixando a transição da música anterior. Sempre escute a intro para planejar onde colocar a próxima faixa.</li><li><strong>Verso:</strong> Onde entra o vocal ou o tema principal. Energia média, preparando o ouvinte para o build-up. Evite transições em cima de versos, pois podem confundir o público.</li><li><strong>Build-up (construção):</strong> Crescendo gradual de tensão: bateria acelerando, efeitos de subida (risers) e silêncio estratégico antes do drop. O build-up avisa que o drop vem aí; prepare a transição para antes ou logo depois dele.</li><li><strong>Drop:</strong> O ponto alto: refrão principal, batidas pesadas e linhas de baixo fortes. É onde a pista enlouquece. Evite misturar no meio do drop, pois o público quer sentir o impacto inteiro.</li><li><strong>Breakdown (quebra):</strong> Redução de energia, com melodias suaves, vocais isolados e menos bateria. Serve para dar uma "respirada" antes de um novo build-up. Excelente momento para preparar a próxima música, especialmente se quiser mudar de vibe.</li><li><strong>Outro:</strong> Parte final, instrumental ou com poucos elementos. Assim como a intro, facilita a saída de uma música e a entrada de outra sem cortes bruscos.</li><li><strong>Exemplo de estrutura (House):</strong> 00:00 Intro (16 compassos), 00:32 Verso, 01:04 Build-up, 01:20 Drop, 02:00 Verso 2, 02:32 Build-up, 02:48 Drop 2, 03:30 Breakdown, 04:00 Drop final, 04:30 Outro. Cada compasso tem 4 batidas, e cada parte costuma ter múltiplos de 8 ou 16 compassos.</li></ul><p><strong>Na prática:</strong> Pegue uma música eletrônica que você curte e mapeie no papel onde ficam intro, build-up, drop, breakdown e outro, anotando os tempos. Depois, planeje começar a próxima música durante a intro ou o outro, e nunca no meio do drop. Esse mapa é o que vai guiar suas transições no momento exato.</p><h4>Resumo</h4><ul><li>Músicas seguem partes típicas: intro, verso, build-up, drop, breakdown e outro</li><li>Intro e outro são os melhores pontos para entrar e sair com a próxima música</li><li>Nunca mixe no meio do drop; o público quer sentir o impacto inteiro</li></ul>',14,2,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('2973d6df-8277-458b-8229-73d442c65ef1','da6e1fb2-dad0-42e6-b44d-770ab6caae8c','Quiz — Estrutura de uma música para DJs');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('4e0cf52c-b3bd-4e1c-b38f-916a3e4cea5d','2973d6df-8277-458b-8229-73d442c65ef1','Qual parte da música é a mais indicada para iniciar a transição de entrada?','A intro é geralmente instrumental e simples, ideal para encaixar a música anterior.',1,1);
