insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('b808465e-553b-4f5f-b84d-a2d3008555e1','ac8772a7-b927-4957-8188-5cb4df26146a','Como analisar uma música para mixar melhor','texto','<p><strong>Para começar:</strong> Antes de tocar, o DJ "prepara" cada faixa. Esta aula reúne BPM, tonalidade e estrutura num método prático de análise que melhora todas as suas mixagens.</p><p>Analisar uma música é juntar tudo o que você aprendeu sobre BPM e estrutura para decidir como e quando ela entra no set. Os softwares ajudam, mas o ouvido e a preparação são seus maiores aliados.</p><ul><li><strong>BPM e tonalidade (key):</strong> Comece anotando o BPM e, quando possível, a tonalidade. Faixas em tons compatíveis soam harmônicas juntas; muitos softwares mostram a key e até sugerem combinações (mixagem harmônica). BPMs próximos facilitam o casamento das batidas.</li><li><strong>Mapeando a estrutura:</strong> Identifique intro, build-up, drop, breakdown e outro. Saber onde estão essas partes define os pontos de entrada e saída e evita transições em cima de versos ou drops.</li><li><strong>Pontos de mixagem:</strong> Marque mentalmente (ou com hot cues) onde a faixa entra e onde sai. O ideal é casar o outro/breakdown de uma música com a intro da próxima, mantendo as batidas alinhadas.</li><li><strong>Energia e momento do set:</strong> Avalie a energia da faixa: é de aquecimento, de pico ou de desaceleração? Isso define em que momento da noite ela cabe. Uma música de pico tocada cedo demais pode esvaziar a curva de energia.</li><li><strong>Preparação prévia (prep):</strong> Antes do show, ouça suas faixas inteiras, organize-as por BPM e energia, e deixe hot cues e loops prontos. DJs profissionais preparam a biblioteca com antecedência; improviso bom nasce de boa preparação.</li></ul><p><strong>Na prática:</strong> Pegue 5 músicas que pretende tocar e preencha uma pequena ficha para cada uma: BPM, tonalidade (se o software mostrar), onde estão a intro e o outro, e o nível de energia (baixa, média, alta). Com essas fichas em mãos, monte a ordem de tocar. Você vai notar que sabe exatamente quando começar e quando sair de cada faixa.</p><h4>Resumo</h4><ul><li>Analisar é cruzar BPM, tonalidade e estrutura para decidir entrada e saída</li><li>Tons compatíveis e BPMs próximos deixam a mixagem harmônica e suave</li><li>Preparar a biblioteca com antecedência é o segredo de um set fluido</li></ul>',12,3,true,false);
