insert into public.modules (id,course_id,titulo,ordem) values ('14b6dff0-0497-4d6f-afe9-76c63b99708c','8febe92b-ca5e-48ce-ab73-0e672fadd3c0','Técnicas Básicas e Beatmatching',4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('46cdc703-f813-480f-a9f8-b97c32e4805e','14b6dff0-0497-4d6f-afe9-76c63b99708c','Operação dos equipamentos e configuração do setup','texto','<p><strong>Para começar:</strong> Antes de mixar, você precisa montar e operar o equipamento com segurança. Esta aula cobre a configuração do setup e o uso básico de mixer, decks, pitch e jog wheels.</p><p>Dominar a operação é a base de tudo. Aqui você aprende a conectar e configurar seu setup e a entender o que cada controle do mixer e dos decks faz, incluindo pitch control e jog wheels.</p><ul><li><strong>Configurando seu setup:</strong> Conecte a controladora ao notebook por USB, abra o software e confira se ele reconhece o equipamento. Ligue a saída de áudio nas caixas e o fone na saída de monitoração. Ajuste o gain de entrada para o som não distorcer. Teste tudo antes de qualquer apresentação.</li><li><strong>Decks (tocadores):</strong> Cada deck toca uma música. Você dá play/pause, navega na faixa e ajusta a velocidade. Em geral o DJ trabalha com dois decks: enquanto um toca para o público, o outro é preparado no fone.</li><li><strong>Noções de mixer:</strong> O mixer tem um canal para cada deck. Use o fader (line fader) para o volume de cada canal, o crossfader para passar de um deck ao outro e o EQ de 3 bandas (graves, médios, agudos) para equilibrar as músicas. O botão de cue/PFL envia o canal para o fone sem mandar ao público.</li><li><strong>Pitch control:</strong> O pitch fader ajusta a velocidade (BPM) da música. É com ele que você alinha o BPM de duas faixas para o beatmatching. Lembre da regra de não passar muito de ~6% para não distorcer o som.</li><li><strong>Jog wheels:</strong> O jog wheel é o prato giratório. Use-o para dar nudge (pequenos empurrões para adiantar ou atrasar a batida e alinhar com a outra música) e, em alguns modos, para fazer scratch ou buscar pontos na faixa. É o controle fino do beatmatching manual.</li><li><strong>Gain, headroom e níveis:</strong> Mantenha os medidores de volume na faixa ideal (sem estourar no vermelho). Equilibre o gain dos canais para que as músicas tenham volume parecido na transição, evitando saltos de volume na pista.</li></ul><p><strong>Na prática:</strong> Monte seu setup do zero: conecte a controladora, abra o software, coloque uma música em cada deck e ajuste os ganhos até os medidores ficarem no verde/amarelo, sem estourar. Em seguida, brinque com cada controle isoladamente: mova o crossfader de um lado ao outro, abaixe os graves de um canal pelo EQ e dê um nudge no jog wheel. Conhecer cada botão na ponta dos dedos é o que dá segurança no ao vivo.</p><h4>Resumo</h4><ul><li>Configure e teste todo o setup antes de qualquer apresentação</li><li>O mixer controla volume (faders/crossfader), EQ e monitoração (cue)</li><li>Pitch fader ajusta o BPM e o jog wheel faz o ajuste fino da batida</li></ul>',14,1,true,false);
