insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('fde0eaf5-710a-4db0-967a-f6cf69cde4ee','40ad25ab-8b5d-444f-ba5e-b28f51d7682c','Para que serve dar um "nudge" no jog wheel?','Pequenos empurrões no jog wheel adiantam ou atrasam a batida no ajuste fino do beatmatching.',3,1);
