insert into public.quiz_options (question_id,texto,correta,ordem) values ('ad9f7049-5d3e-418f-8207-32b3b39a84e8','O crossfader trava',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('79bb3e24-0745-4789-a64b-941307bbc314','14b6dff0-0497-4d6f-afe9-76c63b99708c','Beatmatching: alinhando as batidas','texto','<p><strong>Para começar:</strong> Beatmatching é a habilidade que define o DJ: fazer duas músicas tocarem no mesmo ritmo. Dominar isso é o passaporte para transições profissionais.</p><p>Beatmatching é o ato de sincronizar o BPM e alinhar as batidas de duas músicas para que toquem juntas sem ficar "desencontradas". Pode ser feito manualmente, treinando o ouvido, ou com a ajuda do sync automático. Nesta aula você aprende os dois caminhos.</p><ul><li><strong>O que é beatmatching:</strong> É deixar duas músicas no mesmo BPM e com as batidas alinhadas (kick com kick), de forma que se sobreponham sem conflito rítmico. É a base de toda transição suave entre faixas.</li><li><strong>Passo a passo manual:</strong> 1) Ouça a faixa que vai entrar no fone (cue). 2) Ajuste o pitch fader até o BPM bater com o da música no ar. 3) Use o jog wheel para alinhar o primeiro tempo (downbeat) das duas. 4) Corrija com pequenos nudges se uma adiantar ou atrasar. 5) Quando estiverem travadas, suba o canal no mix.</li><li><strong>Sync automático:</strong> A maioria dos softwares e controladoras tem o botão SYNC, que casa o BPM (e às vezes a fase) automaticamente. É prático e usado por muitos profissionais, mas pode falhar se a grade de batida (beatgrid) estiver mal analisada.</li><li><strong>Manual x automático:</strong> O sync agiliza, mas aprender o beatmatching manual treina seu ouvido, te salva quando o sync erra e dá controle total. A recomendação para iniciantes: pratique o manual para entender o ritmo, e use o sync como ferramenta, não como muleta.</li><li><strong>Treinando o ouvido:</strong> Comece com duas faixas de batida marcada e BPM parecido. Foque em ouvir quando os kicks estão "juntos" (um som só) ou "separados" (eco/duplicado). Reconhecer esse descompasso é a habilidade central do beatmatching.</li><li><strong>Erros comuns:</strong> Ajustar o pitch tarde demais, esquecer de alinhar o downbeat, confiar cegamente no sync com beatgrid errado e exagerar no pitch (acima de ~6%), distorcendo o som.</li></ul><p><strong>Na prática:</strong> Escolha duas músicas com batida bem marcada e BPM próximo. Coloque uma tocando nas caixas e a outra no fone. Ajuste o pitch da segunda até o BPM bater, e use o jog wheel para que os kicks soem como um só. Quando estiverem travadas, deixe as duas tocando juntas por 30 segundos só de batida. Repita até conseguir manter o alinhamento sem que escorregue: esse é o exercício que mais evolui um DJ iniciante.</p><h4>Resumo</h4><ul><li>Beatmatching é alinhar BPM e batidas de duas músicas (kick com kick)</li><li>O passo a passo manual usa pitch para o BPM e jog wheel para a fase</li><li>Sync agiliza, mas dominar o manual treina o ouvido e te salva quando ele falha</li></ul>',16,2,true,false);
