insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('27f147c7-a7b8-4f23-a887-8f56ebfbff06','924803b0-a58f-41bf-9f25-75072320734d','No beatmatching manual, qual controle alinha o BPM das faixas?','O pitch fader ajusta a velocidade até os BPMs baterem; o jog wheel faz o alinhamento fino.',2,1);
