insert into public.modules (id,course_id,titulo,ordem) values ('cf71062d-3e8a-4524-a1a0-05f91cfa7ad5','8febe92b-ca5e-48ce-ab73-0e672fadd3c0','Mixagem, Performance e Set',5);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('127588cc-7f55-4ba2-9904-7d85eedb7d8a','cf71062d-3e8a-4524-a1a0-05f91cfa7ad5','Mixagem básica: transições suaves','texto','<p><strong>Para começar:</strong> Saber alinhar batidas é metade do caminho; a outra é fazer a troca de músicas soar natural. Esta aula ensina os principais tipos de transição.</p><p>Uma transição é a passagem de uma música para outra. Feita bem, é imperceptível e mantém a pista dançando; feita mal, quebra a energia. Aqui você aprende as técnicas essenciais, do corte seco à equalização cruzada.</p><ul><li><strong>Corte seco (cut):</strong> Troca direta de uma música para outra, geralmente no tempo certo (no início de um compasso). Funciona bem em hip hop, funk e quando você quer um impacto, mas exige timing preciso para não soar abrupto.</li><li><strong>Fade in / fade out:</strong> Subir gradualmente o volume da música que entra enquanto baixa o da que sai, usando os faders. Simples e eficaz, especialmente usando as intros e outros das faixas.</li><li><strong>Equalização cruzada (EQ blending):</strong> A transição mais profissional: com as duas faixas em beatmatch, você "troca" as frequências. Vai baixando os graves da música que sai e subindo os da que entra (dois kicks juntos embolam, então só um deve dominar o grave por vez), fazendo o mesmo com médios e agudos. A troca fica fluida e sem conflito de batidas.</li><li><strong>O papel do crossfader e dos faders:</strong> O crossfader desloca o áudio entre os dois decks; os line faders controlam o volume de cada canal. Em muitas transições por EQ, o crossfader fica no centro e o trabalho é feito pelos EQs e faders.</li><li><strong>Onde fazer a transição:</strong> Use a estrutura: entre durante a intro da nova música e saia pelo outro ou breakdown da atual. Evite trocar em cima de drops ou versos com vocal forte para não confundir o público.</li><li><strong>Comprimento da transição:</strong> Transições curtas (corte) dão impacto; longas (blend de 16 a 32 compassos) criam fluidez. Escolha conforme o gênero e o momento do set.</li></ul><p><strong>Na prática:</strong> Pegue duas faixas já com BPM casado. Comece a próxima ainda na intro com os graves abaixados no EQ. Quando as batidas estiverem travadas, vá tirando os graves da música que sai e subindo os da que entra, terminando com um fade do volume. Ouça como a troca acontece sem que a pista perceba o "corte". Repita variando entre corte seco e blend longo para sentir a diferença.</p><h4>Resumo</h4><ul><li>Tipos de transição: corte seco, fade in/out e equalização cruzada</li><li>No blend por EQ, só um kick deve dominar o grave de cada vez</li><li>Entre pela intro da nova faixa e saia pelo outro/breakdown da atual</li></ul>',15,1,true,false);
