insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('f71eab17-5206-4b94-b51e-0aff70fa62e2','d794d5f3-d4c3-48ce-98a2-e2068b5ffe08','Qual é o melhor ponto para iniciar a próxima música na transição?','A intro costuma ser instrumental e limpa, ideal para encaixar a nova faixa.',3,1);
