insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('c29e42f1-f1f4-43ac-bbe2-924069713089','cf71062d-3e8a-4524-a1a0-05f91cfa7ad5','Construção de um set','texto','<p><strong>Para começar:</strong> Um set não é uma playlist no aleatório: é uma jornada com começo, meio e fim. Esta aula ensina a escolher músicas e contar uma história sonora.</p><p>Construir um set é organizar suas músicas de forma que a energia da pista suba, se mantenha e desça nos momentos certos. É o que separa quem só toca faixas de quem cria uma experiência.</p><ul><li><strong>Escolha de músicas: energia, tom e harmonia:</strong> Selecione faixas pensando em três fatores: o nível de energia (aquecimento, pico, descanso), a tonalidade (keys compatíveis soam harmônicas) e o BPM (próximos facilitam a mixagem). Combinar esses três cria um fluxo coeso.</li><li><strong>Storytelling musical:</strong> Um bom set conta uma história: tem aquecimento, construção, pico e desfecho. Pense nele como uma "viagem sonora" onde cada música prepara a próxima e leva o público por diferentes emoções, sem altos e baixos aleatórios.</li><li><strong>A curva de energia:</strong> Estruture a energia ao longo do tempo. Exemplo prático já visto: começar com House 122 BPM (aquecimento), ir para Tech House 126 (pista cheia), chegar ao pico com Techno 130 (explosão) e desacelerar com Melodic Techno 124. Suba aos poucos e use quebras para respirar.</li><li><strong>Preparando para diferentes eventos:</strong> Adapte o set ao contexto: um aquecimento (warm-up) pede energia contida; um horário de pico pede as faixas mais fortes; um casamento exige variedade de estilos para todas as idades; um club de techno pede coesão de gênero. Leia o briefing e o público antes de montar.</li><li><strong>Leitura de pista:</strong> Mesmo com o set planejado, observe a pista e ajuste em tempo real: se a pista responde, mantenha a vibe; se esfria, mude a energia. Planejamento dá segurança, mas flexibilidade mantém a pista cheia.</li><li><strong>Abertura e fechamento:</strong> Comece sem queimar suas melhores faixas cedo demais e guarde momentos fortes para o pico. No fim, desacelere para encerrar com elegância, em vez de cortar a energia de repente.</li></ul><p><strong>Na prática:</strong> Monte um set de 5 a 6 músicas com começo, meio e fim. Ordene-as por energia crescente até um pico e depois uma desaceleração, garantindo que BPMs vizinhos sejam próximos e, se possível, tonalidades compatíveis. Toque essa sequência inteira de ponta a ponta, fazendo as transições. Você vai perceber como a ordem certa transforma faixas soltas em uma jornada.</p><h4>Resumo</h4><ul><li>Escolha faixas por energia, tonalidade e BPM para um fluxo coeso</li><li>Um bom set conta uma história com aquecimento, pico e desfecho</li><li>Adapte ao evento e leia a pista para ajustar em tempo real</li></ul>',15,2,true,false);
