insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('3e90c0c1-a0f5-469e-b815-6ea9c5c5d850','74ffe8f8-e0a1-4a0c-8008-defde2e0d8a6','O que significa fazer "storytelling musical" num set?','O set é uma viagem sonora: cada faixa prepara a próxima e guia as emoções da pista.',2,1);
