insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c4ad9906-7ddf-42bd-bd9d-3719b66752e5','74ffe8f8-e0a1-4a0c-8008-defde2e0d8a6','Por que não queimar as melhores faixas no início do set?','Reservar as faixas mais fortes para o pico mantém a construção de energia da noite.',3,1);
