insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('fafa0c8a-a0b7-41f6-88d1-5778e0337fc0','74ffe8f8-e0a1-4a0c-8008-defde2e0d8a6','Mesmo com o set planejado, o que o DJ deve fazer durante a apresentação?','A leitura de pista permite manter ou mudar a vibe conforme a reação do público.',4,1);
