insert into public.quiz_options (question_id,texto,correta,ordem) values ('fafa0c8a-a0b7-41f6-88d1-5778e0337fc0','Tocar tudo no máximo volume',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('fafa0c8a-a0b7-41f6-88d1-5778e0337fc0','Parar a música a cada faixa',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('1e9b1552-eda2-4ac4-b39a-4a220b470d1e','cf71062d-3e8a-4524-a1a0-05f91cfa7ad5','Técnicas de performance: efeitos, loops, hot cues e scratch','texto','<p><strong>Para começar:</strong> Com a mixagem dominada, é hora de adicionar personalidade. Esta aula apresenta os recursos que tornam seu set único: efeitos, loops, hot cues e uma introdução ao scratch.</p><p>Efeitos, loops, hot cues e scratch são ferramentas de expressão. Usadas com bom senso, elevam o set e marcam seu estilo; usadas em excesso, atrapalham. Aqui você aprende o básico de cada uma.</p><ul><li><strong>Efeitos (reverbs, delays, flangers):</strong> Reverb cria sensação de espaço/eco; delay repete o som em ecos rítmicos; flanger dá um efeito "varredura" futurista. São ótimos para transições e para criar tensão (ex.: aplicar um reverb crescente antes de cortar para a próxima faixa). Use com moderação: efeito demais cansa o ouvido.</li><li><strong>Loops:</strong> Um loop repete um trecho da música em ciclo (geralmente 4, 8 ou 16 compassos). Serve para estender uma intro ou um outro e ganhar tempo na transição, ou para criar tensão segurando um build-up. Ajuste o tamanho do loop conforme a necessidade.</li><li><strong>Hot cues:</strong> Hot cues são pontos marcados na faixa que você dispara instantaneamente com um pad. Permitem pular direto para o drop, reiniciar de um ponto exato ou criar pequenos rearranjos ao vivo. Prepare-os na sua biblioteca antes do show.</li><li><strong>Introdução ao scratching:</strong> Scratch é mover a música para frente e para trás no jog wheel (ou vinil) enquanto se manobra o crossfader/fader, criando sons rítmicos. Comece pelo baby scratch: empurra e puxa o som no mesmo ritmo. É a porta de entrada do turntablism; pratique devagar e no tempo da música.</li><li><strong>Bom senso na performance:</strong> Esses recursos servem à música, não o contrário. Um efeito ou scratch bem colocado num momento certo vale mais que muitos truques aleatórios. A base (beatmatch e transição limpa) sempre vem primeiro.</li></ul><p><strong>Na prática:</strong> Numa faixa que você conhece bem, marque um hot cue no início do drop. Depois, ative um loop de 8 compassos na intro da próxima música para ganhar tempo na transição, e finalize aplicando um reverb crescente no instante da troca. Por fim, em outra faixa, treine o baby scratch lentamente, acompanhando a batida. Combinar esses recursos com naturalidade é o que dá assinatura ao seu set.</p><h4>Resumo</h4><ul><li>Efeitos (reverb, delay, flanger) criam espaço e tensão; use com moderação</li><li>Loops estendem trechos e hot cues disparam pontos marcados ao vivo</li><li>O scratch começa pelo baby scratch; truques servem à música, não o contrário</li></ul>',14,3,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('8c86799d-eeed-4ec7-93a6-df21f0eb4fa2','1e9b1552-eda2-4ac4-b39a-4a220b470d1e','Quiz — Técnicas de performance: efeitos, loops, hot cues e scratch');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('39402c9e-71a9-4bf4-97f9-ac8f419ae746','8c86799d-eeed-4ec7-93a6-df21f0eb4fa2','Para que serve um loop durante a mixagem?','O loop repete um trecho (ex.: 8 compassos), útil para esticar intros/outros e criar tensão.',1,1);
