insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c470d286-1426-4151-8715-80652ff7cde7','8c86799d-eeed-4ec7-93a6-df21f0eb4fa2','Qual é um bom primeiro scratch para iniciantes?','O baby scratch, mover o som para frente e para trás no ritmo, é a porta de entrada do scratch.',3,1);
