insert into public.modules (id,course_id,titulo,ordem) values ('4a164dd5-eac7-48a1-9d97-6dea071026ba','8febe92b-ca5e-48ce-ab73-0e672fadd3c0','Profissionalização',6);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('3f38d1ba-8882-4001-b157-2718903479f3','4a164dd5-eac7-48a1-9d97-6dea071026ba','Marketing pessoal e identidade de DJ','texto','<p><strong>Para começar:</strong> Talento sozinho não enche agenda. Esta aula mostra como construir sua identidade de DJ e divulgar seu trabalho para ser encontrado e contratado.</p><p>Sua identidade é como o público e os contratantes te reconhecem. Construir nome, imagem e presença digital é o que transforma um hobbista em um DJ profissional procurado.</p><ul><li><strong>Construindo sua identidade:</strong> Defina seu estilo musical e a vibe que você entrega. Sua identidade nasce da coerência entre o que você toca, sua imagem e a forma como se comunica. Um DJ reconhecível tem uma marca clara, não tenta agradar a todos de forma genérica.</li><li><strong>Nome artístico e logotipo:</strong> Escolha um nome artístico curto, fácil de lembrar, fácil de pesquisar e que não esteja em uso por outro artista. Crie um logotipo simples e legível que funcione em foto de perfil, capa de set e flyer. Consistência visual ajuda as pessoas a te reconhecerem.</li><li><strong>Redes sociais e plataformas:</strong> Use Instagram e TikTok para presença e vídeos curtos de sets; SoundCloud e Mixcloud para hospedar mixes completos. Poste com regularidade, mostre bastidores e divulgue suas apresentações. As plataformas de mix são seu "portfólio sonoro".</li><li><strong>Gravando e divulgando sets:</strong> Grave seus sets em boa qualidade (a interface de áudio ajuda) e publique-os. Um set bem gravado vale mais que mil palavras para um contratante e serve de cartão de visitas. Muitos DJs começaram justamente assim, como bedroom DJs publicando online.</li><li><strong>Consistência e profissionalismo:</strong> Mantenha uma frequência de posts, responda mensagens, cumpra horários e seja confiável. Reputação digital e pontualidade abrem (ou fecham) portas tanto quanto a técnica.</li></ul><p><strong>Na prática:</strong> Reserve uma tarde para definir sua marca: escolha um nome artístico (verifique se está livre nas redes e no SoundCloud), esboce um logotipo simples e crie ou atualize um perfil no Instagram e no SoundCloud/Mixcloud. Depois, grave um mix curto de 15 a 20 minutos e publique-o como seu primeiro "cartão de visitas". Com isso, você já existe profissionalmente no mundo digital.</p><h4>Resumo</h4><ul><li>Identidade é a coerência entre o que você toca, sua imagem e sua comunicação</li><li>Nome curto e logotipo simples e consistente tornam você reconhecível</li><li>SoundCloud/Mixcloud são seu portfólio; poste sets com regularidade</li></ul>',13,1,true,false);
