insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('28cef542-cf69-4eb9-b7af-7dedb118d238','bb6e053d-24e5-44b8-bdc1-1270e85938dc','Como deve ser um bom nome artístico?','Um nome curto, memorável, fácil de pesquisar e original facilita ser encontrado e contratado.',3,1);
