insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('d0e2c0f9-6a15-4568-ac1d-f729e1490c09','4a164dd5-eac7-48a1-9d97-6dea071026ba','Conseguindo gigs e relacionamento profissional','texto','<p><strong>Para começar:</strong> Saber tocar e ter presença digital abre a porta; conseguir shows depende de network e abordagem certa. Esta aula mostra como conquistar seus primeiros gigs.</p><p>Gig é cada apresentação remunerada. Conseguir os primeiros exige um bom material de divulgação, uma abordagem profissional a casas e produtores, e bons relacionamentos no meio.</p><ul><li><strong>Abordando clubes e produtores:</strong> Pesquise casas e festas que tocam o seu estilo e aborde de forma profissional: apresente-se com clareza, mostre seu trabalho e proponha valor (um set, uma residência, um warm-up). Comece por eventos menores e construa reputação. Evite mensagens genéricas em massa.</li><li><strong>O press kit:</strong> O press kit é seu material de apresentação: uma bio curta, foto profissional, links dos seus melhores sets (SoundCloud/Mixcloud), eventos onde já tocou e contato. Um press kit bem feito facilita a vida do contratante e passa profissionalismo. Mantenha-o atualizado.</li><li><strong>Relacionamento com o público:</strong> Conecte-se com quem ouve seu som: responda comentários, agradeça presenças, lembre nomes. Um público fiel divulga você e lota suas próximas festas. A pista satisfeita é o seu melhor marketing.</li><li><strong>Relacionamento com outros DJs:</strong> Network entre DJs abre portas: indicações, line-ups compartilhados, troca de músicas e dicas. Trate colegas com respeito, valorize quem te dá espaço e retribua. O meio é pequeno e a reputação corre rápido.</li><li><strong>Começando de baixo:</strong> Aceite warm-ups, festas pequenas e oportunidades de visibilidade no início. Cada gig bem executado gera o próximo. Pontualidade, equipamento em ordem e postura profissional fazem você ser chamado de novo.</li></ul><p><strong>Na prática:</strong> Monte seu press kit em uma página: bio curta, melhor foto, dois links de sets e seu contato. Em seguida, liste cinco casas ou festas da sua cidade que tocam seu estilo e escreva uma mensagem personalizada para uma delas, anexando o press kit e propondo um warm-up. Esse é o caminho concreto entre praticar em casa e tocar para um público real.</p><h4>Resumo</h4><ul><li>O press kit (bio, foto, links e contato) é seu cartão profissional</li><li>Aborde casas e produtores de forma personalizada e comece por gigs menores</li><li>Network com público e DJs gera indicações e novas oportunidades</li></ul>',13,2,true,false);
