insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('d14f7cdb-8f63-4684-8d23-b8fc671c296f','cefb569c-e208-428f-85ca-64058d73cfca','Por que o relacionamento com outros DJs é importante?','O network entre DJs abre portas via indicações e parcerias, e a reputação circula rápido no meio.',3,1);
