insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('786c471e-c544-4b1d-8dce-ecb26a6396ff','4a164dd5-eac7-48a1-9d97-6dea071026ba','Ética, cuidados e evolução contínua','texto','<p><strong>Para começar:</strong> Ser profissional vai além da técnica: envolve respeito à profissão, à lei e ao equipamento. Esta aula encerra o curso com ética, cuidados e o caminho para continuar evoluindo.</p><p>Reputação se constrói com comportamento. Nesta aula final você vê os princípios éticos do DJing, os cuidados com música e equipamento, e como seguir evoluindo depois do curso.</p><ul><li><strong>Respeito à profissão:</strong> Valorize o trabalho dos colegas, seja pontual, cumpra acordos e mantenha postura profissional em qualquer evento. Crédito aos artistas e respeito ao público e à casa sustentam sua reputação a longo prazo.</li><li><strong>Direitos autorais e uso de músicas:</strong> Toda música tem autor e direitos. Use faixas de forma legal: prefira compras em lojas oficiais (como Beatport, Bandcamp, iTunes) e serviços de pool para DJs, e respeite as regras de cada plataforma e evento. Distribuir ou lucrar com música sem autorização pode gerar problemas legais.</li><li><strong>Cuidados com o equipamento (seu e dos outros):</strong> Trate o equipamento com zelo: não force jog wheels e faders, use cabos de qualidade, transporte com proteção e mantenha tudo limpo. Em casas e eventos, respeite o equipamento alheio como se fosse seu; danificar gear da casa fecha portas.</li><li><strong>Extras úteis:</strong> Aprofunde-se com o glossário de termos técnicos, playlists de prática recomendadas, tabelas de BPM por gênero e checklists para montar seu primeiro evento. Esses recursos aceleram seu aprendizado e organizam sua prática.</li><li><strong>Como continuar evoluindo:</strong> Pratique com constância, grave e analise seus próprios sets, busque feedback, estude DJs que admira e participe de comunidades. Considere cursos avançados (produção musical, técnicas de performance). A evolução é contínua: o futuro da música está nas suas mãos.</li></ul><p><strong>Na prática:</strong> Antes do seu próximo treino, faça uma revisão de boas práticas: confira se suas músicas vêm de fontes legais, monte um checklist de transporte e montagem para proteger seu equipamento, e grave seu set para analisar depois com olhar crítico. Em seguida, escolha uma comunidade de DJs ou um curso avançado para entrar. Encerrar o curso com esses hábitos é o que separa um amador de um profissional em formação.</p><h4>Resumo</h4><ul><li>Ética profissional é pontualidade, respeito aos colegas, à casa e ao público</li><li>Use músicas de forma legal e cuide do equipamento, seu e dos outros</li><li>Evolua sempre: grave, analise, busque feedback e participe de comunidades</li></ul>',12,3,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('bc6972c2-7178-4945-a75e-c1f53c512d8f','786c471e-c544-4b1d-8dce-ecb26a6396ff','Quiz — Ética, cuidados e evolução contínua');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0b20f0f6-0b77-4037-9229-8d072e9901d1','bc6972c2-7178-4945-a75e-c1f53c512d8f','Qual é a forma correta de obter músicas para tocar?','Respeitar direitos autorais e usar fontes legais (lojas oficiais, pools de DJ) evita problemas e valoriza os artistas.',1,1);
