insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('7173cbdf-eb43-413c-b4e9-439707406a11','bc6972c2-7178-4945-a75e-c1f53c512d8f','Qual atitude faz parte de continuar evoluindo como DJ?','Praticar com constância, analisar sets, buscar feedback e participar de comunidades mantém a evolução.',3,1);
