  ('8f29f6dd-3dc6-47fe-b4d3-1cd15514a21d','Pleno — Som','pleno-som','Curso Pleno — Som — SMU PRO','pleno','som','{}','free',800,27,false,false,4);
insert into public.modules (id,course_id,titulo,ordem) values ('397d4661-ba18-4bff-b2d8-3792b6f0a9e4','8f29f6dd-3dc6-47fe-b4d3-1cd15514a21d','Módulo 1 — Fundamentos do Som e da Cadeia de Sinal',1);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('d2609ce6-fbb1-4d53-b2fc-a1c6adbff681','397d4661-ba18-4bff-b2d8-3792b6f0a9e4','O Som como Onda: Física Aplicada à Engenharia de Áudio ao Vivo','texto','<p><strong>Para começar:</strong> Antes de tocar em qualquer cabo ou console, o operador profissional precisa entender o que está manipulando: ondas de pressão no ar. Esta aula constrói a base física que sustenta todas as decisões técnicas do curso. Sem ela, EQ, ganho e microfonação viram tentativa e erro.</p><p>Som é variação de pressão que se propaga em um meio elástico (geralmente o ar) e que nosso ouvido interpreta como altura, intensidade e timbre. Dominar frequência, amplitude, comprimento de onda, fase e a relação dB é o que separa o operador que ''mexe até ficar bom'' daquele que sabe o que está fazendo.</p><ul><li><strong>Frequência e altura (pitch):</strong> Frequência é o número de ciclos por segundo, medido em hertz (Hz). O espectro audível humano vai de aproximadamente 20 Hz a 20 kHz, e na prática a inteligibilidade da voz se concentra entre 300 Hz e 3,4 kHz. Graves (20–250 Hz), médios (250 Hz–4 kHz) e agudos (4–20 kHz) são as ''cores'' do som que o equalizador manipula. Conhecer onde mora cada instrumento no espectro (bumbo ~60 Hz, corpo da voz ~200 Hz, presença vocal ~3–5 kHz, brilho de prato ~10 kHz) é pré-requisito para qualquer EQ consciente.</li><li><strong>Amplitude e o decibel (dB):</strong> Amplitude é a ''força'' da onda e percebemos como volume. Como o ouvido responde de forma logarítmica, usamos o decibel. Atenção: o dB é uma razão, não um valor absoluto — só faz sentido com referência. dB SPL (Sound Pressure Level) mede pressão sonora no ar (0 dB SPL = limiar da audição; ~120 dB SPL = limiar da dor; um show de rock pode passar de 100 dB SPL na plateia). dBu e dBV medem tensão elétrica de sinal. dBFS (Full Scale) mede o nível digital, onde 0 dBFS é o teto absoluto — acima dele há clipping irreversível. Confundir essas escalas é erro clássico de iniciante.</li><li><strong>Comprimento de onda e o porquê do grave ser ''difícil'':</strong> Comprimento de onda (λ) = velocidade do som (~343 m/s no ar a 20 °C) dividido pela frequência. Um grave de 40 Hz tem λ ≈ 8,5 m; um agudo de 10 kHz tem λ ≈ 3,4 cm. Isso explica fenômenos práticos: graves contornam obstáculos e ''enchem'' a sala (são difíceis de direcionar e domar), enquanto agudos são direcionais e facilmente absorvidos/bloqueados. É a razão pela qual subgraves não precisam de mira precisa e drivers de agudo precisam apontar para o público.</li><li><strong>Fase e cancelamento:</strong> Fase é a posição da onda no seu ciclo, medida em graus (0–360°). Quando duas cópias do mesmo sinal chegam defasadas em 180°, elas se cancelam (somem graves, som fino e ''oco''). Esse é o inimigo silencioso da microfonação com vários microfones e do uso simultâneo de DI + microfone no mesmo instrumento. A regra prática ''3:1'' (o segundo microfone deve estar pelo menos 3× mais distante da fonte do que o primeiro) nasce do controle de fase.</li><li><strong>Timbre e harmônicos:</strong> Dois instrumentos tocando a mesma nota soam diferentes por causa do timbre, que é o conjunto de harmônicos (múltiplos inteiros da frequência fundamental) e sua envoltória dinâmica (ataque, sustentação, decaimento). Entender harmônicos explica por que cortar a fundamental nem sempre ''mata'' a nota e por que excitadores harmônicos e a saturação analógica ''colorem'' o som.</li></ul><h4>Passo a passo</h4><ol><li><strong>Calcular um comprimento de onda:</strong> Pegue a frequência-alvo, divida 343 por ela. Ex.: para tratar um modo de sala em 80 Hz → 343/80 ≈ 4,3 m. Isso indica que painéis finos não absorvem esse grave; é preciso bass trap espesso.</li><li><strong>Identificar faixas no ouvido:</strong> Use um gerador de tom ou um EQ paramétrico ''varrendo'' (sweep) uma banda estreita com boost de +10 dB sobre uma música conhecida. Mova a frequência e memorize a sensação de cada região: o ''bumbo'' em 60–80 Hz, a ''lama'' em 200–400 Hz, a ''dureza'' em 2–4 kHz, o ''sibilante'' em 6–8 kHz.</li></ol><p><strong>Na prática:</strong> Num casamento em salão de teto alto e paredes de vidro, o operador percebe a voz do celebrante ''sumindo'' e abafada. Em vez de só aumentar o volume (que gera microfonia), ele reconhece que o salão tem reverberação longa por superfícies reflexivas e que a inteligibilidade depende da faixa de 1–4 kHz. Em vez de brigar com a física, posiciona as caixas mais próximas e baixas em direção ao público e realça suavemente a presença vocal — decisão que só faz sentido para quem entende onda, frequência e reflexão.</p><h4>Resumo</h4><ul><li>Som é onda de pressão descrita por frequência (altura), amplitude (volume), fase e timbre.</li><li>O decibel é sempre uma razão — dB SPL, dBu e dBFS medem coisas diferentes e nunca se confundem.</li><li>Comprimento de onda explica por que graves são difíceis de direcionar/absorver e agudos são direcionais.</li></ul>',30,1,true,true);
