insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('397f2a8b-15fd-4c60-baf2-a708117bb453','1fcc0a51-92db-4482-9b1f-ba83ff4c5b30','O dBFS, usado em consoles e gravação digital, tem uma característica que o diferencia do dB SPL. Qual?','dBFS é a escala digital cujo máximo é 0; ultrapassá-lo causa distorção digital irreversível (clipping).',1,1);
