insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('12534cfb-c85a-440a-a88e-52b04d22c305','1fcc0a51-92db-4482-9b1f-ba83ff4c5b30','Dois microfones captam a mesma fonte e o resultado fica ''fino e oco'', com perda de graves. A causa provável é:','Sinais defasados próximos de 180° se cancelam, removendo principalmente graves — daí o som fino. A regra 3:1 ajuda a evitar.',3,1);
