insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('93018f6f-660a-44fc-b8a6-61a428ef30bc','cb352580-eda8-4bda-8877-74eb6f7b123e','Diante de ''não sai som no canal'', a primeira atitude do operador profissional é:','O diagnóstico sistemático pela cadeia (fonte, cabo, phantom, ganho, mute, fader, roteamento, amp) encontra a causa rapidamente.',4,1);
