insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('9bfe4304-8d10-40bb-8e88-eda2012b366a','3fd5e135-df54-4ff1-8a92-875897f0375f','A vantagem mais decisiva do console digital sobre o analógico no ao vivo é:','Cenas permitem viradas rápidas e configurações reproduzíveis — algo impossível na mesa analógica.',1,1);
