insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('68eebd57-ce06-43ed-9640-5968e43d1b4b','1eedc76e-6f84-4ca6-97e1-df54df84223b','A classe de amplificador que domina o PA moderno por eficiência e baixo peso é:','A Classe D usa chaveamento PWM de alta eficiência, gerando pouco calor e permitindo amplificadores leves e potentes.',3,1);
