insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('b6924986-acae-45b9-bea5-d65e33028f7d','1eedc76e-6f84-4ca6-97e1-df54df84223b','A ordem segura para energizar um sistema de som é:','Ligar a potência por último (e desligá-la primeiro) evita o transiente/pop que danifica os drivers.',5,1);
