insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('2f53d6ed-51e0-433e-8a5a-cb4daa2e7dbe','0af53581-6704-43f4-a429-de66a9dddd65','Headroom é:','Headroom é a margem até o teto digital; mantê-lo evita distorção em transientes inesperados.',3,1);
