insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('af97c4b6-451a-42ed-bca1-98bb6a160795','0af53581-6704-43f4-a429-de66a9dddd65','O filtro passa-altas (HPF) num canal de voz serve para:','O HPF corta abaixo de ~80–120 Hz onde a voz não tem conteúdo útil, limpando a mistura e liberando headroom.',4,1);
