insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('de6944ce-9271-41ac-a4ad-9bc5f45dc0ff','507d37d1-5131-4d0a-9179-ecd1817437f4','Em um compressor, ratio 4:1 significa:','A razão 4:1 reduz o que excede o threshold na proporção de 4 dB de entrada para 1 dB de saída.',1,1);
