insert into public.modules (id,course_id,titulo,ordem) values ('dd356152-d06c-450d-8b4f-fe6307a3c71d','8f29f6dd-3dc6-47fe-b4d3-1cd15514a21d','Módulo 4 — Simulador de Serviço: Montagem, Soundcheck e Microfonação',4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('4bf47728-0da7-4320-92c0-e51c4cc2d183','dd356152-d06c-450d-8b4f-fe6307a3c71d','Montagem do Sistema e Line Check','texto','<p><strong>Para começar:</strong> Antes do primeiro som, há a montagem: posicionar PA, passar cabos, definir o mapa de entradas e conferir canal a canal. Esta aula é o passo a passo do operador chegando vazio e deixando o sistema pronto para soar.</p><p>Montagem profissional segue ordem e método: estudar o rider/input list, distribuir energia, posicionar caixas, organizar cabos, patchear entradas e fazer o line check. Um line check bem feito elimina 80% dos sustos na passagem de som.</p><ul><li><strong>Rider técnico e input list:</strong> Rider é o documento que descreve as necessidades técnicas (PA, microfones, palco, energia); input list (mapa de entradas) lista o que entra em cada canal (1-Bumbo, 2-Caixa, 3-Voz...). Ler e montar a partir deles evita improviso. O operador completo sabe interpretar e, quando preciso, criar esses documentos.</li><li><strong>Energia e aterramento:</strong> Distribua a carga em circuitos adequados (vimos consumo no Módulo 2). Mantenha áudio e energia separados; use o mesmo ponto de terra para todo o sistema de áudio quando possível, evitando loops de terra (causa de zumbido). Nunca remova o pino terra (''benjamim'' sem terra é gambiarra perigosa).</li><li><strong>Posicionamento e cabeamento:</strong> Posicione PA cobrindo o público e fora do eixo dos microfones (anti-microfonia). Passe o multicabo/stage box até a mesa, distribua os cabos de palco identificados, evite tropeço (fitar/calhas). Cabeamento limpo é segurança e agilidade no troubleshooting.</li><li><strong>Patch e mapa de canais:</strong> Conecte cada microfone/DI à entrada correta conforme o input list e confira no console que o canal corresponde. Nomeie e (no digital) cor-codifique os canais. Um patch organizado é o que permite achar ''o canal 7 é a caixa'' instantaneamente durante o show.</li><li><strong>Line check:</strong> Antes do som musical, confira cada canal: peça/gere sinal na fonte e verifique se o canal certo recebe, sem ruído, com phantom onde precisa. Cheque polaridade/fase de pares (overheads, DI+mic). Line check valida toda a infraestrutura antes da banda chegar.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Stage box / multicabo e sistema de identificação:</strong> Stage box digital ou multicabo analógico para levar os canais à mesa. Etiquetas, fitas coloridas e numeração nos cabos. Lanterna/headlamp para trabalhar em palco escuro. Organização física é parte do equipamento profissional.</li><li><strong>Fones de monitoração e PFL/solo do console:</strong> Fone fechado para escutar canais isoladamente (solo/PFL) durante o line check e a passagem, sem depender do PA. Permite checar ruído, microfone e qualidade de cada canal individualmente.</li></ul><h4>Passo a passo</h4><ol><li><strong>Sequência de montagem:</strong> 1) Estude rider/input list. 2) Defina e distribua energia com aterramento correto. 3) Posicione e eleve o PA cobrindo o público. 4) Monte mesa, stage box e backline. 5) Passe e identifique cabos com segurança (sem tropeço). 6) Patcheie conforme o input list. 7) Nomeie/colora os canais no console.</li><li><strong>Executar o line check:</strong> Canal por canal: ative phantom onde for condensador (canal mutado), peça sinal/gere ruído na fonte, confira no PFL que o canal certo recebe sem chiado, ajuste um gain inicial. Marque os canais OK. Anote pendências (cabo ruim, microfone com defeito) e resolva antes da passagem.</li><li><strong>Conferir fase e polaridade:</strong> Em pares (overheads, snare top/bottom, DI+microfone), cheque se somados o som engrossa (em fase) ou afina/some grave (fora de fase). Inverta a polaridade do canal problemático no console. Fase resolvida agora evita uma mix ''oca'' depois.</li></ol><p><strong>Na prática:</strong> O operador chega cedo, monta a partir do input list de uma banda de 5 integrantes, distribui a energia em dois circuitos com nobreak para a mesa, eleva o PA mirando o público e patcheia 16 canais nomeados e coloridos. No line check descobre que o cabo do tom 2 chia: troca antes que a banda chegue. Quando os músicos sobem ao palco, tudo já funciona — e a passagem de som vira ajuste fino, não caça a problemas.</p><h4>Resumo</h4><ul><li>Montagem profissional parte do rider/input list e segue ordem: energia, PA, cabos, patch, nomes.</li><li>Energia bem distribuída e aterrada evita zumbidos e quedas; cabeamento limpo dá segurança e agilidade.</li><li>O line check valida cada canal e a fase antes da banda chegar, eliminando a maioria dos sustos.</li></ul>',32,1,true,false);
