insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('49493378-e735-444c-aae4-8d1c69f8c347','3e4c09dd-0a2e-415f-9d28-af13e192ce10','Remover o pino terra dos equipamentos para ''tirar o zumbido'' é:','Tirar o terra cria risco elétrico; loops de terra se resolvem com aterramento comum e isolamento adequado, não removendo o terra.',2,1);
