insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('a402c33b-98e0-4979-95b0-ef6a61d2b3f8','3e4c09dd-0a2e-415f-9d28-af13e192ce10','Ao somar overheads ou DI+microfone e o som ''afinar e perder grave'', a causa provável é:','Sinais fora de fase se cancelam (principalmente graves); inverter a polaridade de um canal resolve.',4,1);
