insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('6887d697-4763-4416-a41a-bd18714f2ceb','c0d5722f-93f2-4b76-8a6f-4055f209ab66','Diante de microfonia ao aumentar o monitor de voz, a melhor atitude é:','Subir mais realimenta; controla-se cortando a frequência específica e ajustando posição/mira.',3,1);
