insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('4fd81d04-8ed6-42c8-b487-ef252c4ec9ba','c0d5722f-93f2-4b76-8a6f-4055f209ab66','A sala cheia, comparada à vazia, tende a:','O público absorve som; antecipar e ajustar agudos/graves ao encher mantém a mix equilibrada.',4,1);
