insert into public.quiz_options (question_id,texto,correta,ordem) values ('4fd81d04-8ed6-42c8-b487-ef252c4ec9ba','Dispensar a cena salva',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('28284b0f-a2fd-4621-b6c4-cb3556bc9135','dd356152-d06c-450d-8b4f-fe6307a3c71d','Combate à Microfonia (Feedback) e Operação Durante o Show','texto','<p><strong>Para começar:</strong> A microfonia é o pesadelo do som ao vivo. Esta aula ensina a entender, prevenir e eliminar o feedback com método — e a operar com firmeza durante o show, mantendo o controle do começo ao fim.</p><p>Feedback acontece quando o som do PA volta ao microfone, é reamplificado e cria um loop que cresce até o apito. Combater microfonia é entender ganho antes da realimentação (gain before feedback) e agir nas causas: posicionamento, padrão polar, EQ e níveis. Esta aula também cobre a operação ativa durante o show.</p><ul><li><strong>O que é e por que acontece:</strong> Feedback é um loop: microfone capta o som da caixa/monitor, a mesa reamplifica, sai mais alto, volta ao microfone... até oscilar numa frequência (apito/ronco). Acontece quando o ganho total do loop supera a unidade. Quanto mais ganho você precisa, mais perto do feedback opera — daí a importância de captação eficiente.</li><li><strong>Prevenção: as causas:</strong> Posicionamento: microfone longe e fora do eixo das caixas/monitores; usar a rejeição traseira do cardioide. Padrão polar adequado (super/hipercardioide rejeita mais). Distância fonte-microfone curta (mais sinal útil, menos ganho necessário). Menos microfones abertos (gate/mute do que não está em uso). Monitores só com o essencial. PA mirado no público, não no palco.</li><li><strong>EQ contra feedback:</strong> Toda sala/monitor tem frequências que realimentam primeiro. Com EQ gráfico (ou paramétrico cirúrgico), identifique e atenue essas frequências antes de chegarem ao apito. Ring out: suba o ganho até começar a tocar a microfonia, identifique a frequência e corte-a; repita para ganhar mais ''gain before feedback''. Não exagere para não descaracterizar o som.</li><li><strong>Ferramentas e supressores:</strong> Existem supressores de feedback automáticos (no DriveRack e em alguns consoles) que detectam e cortam a frequência. Úteis como auxílio, mas não substituem boa captação e posicionamento. O operador competente resolve a causa; o automático cobre o resíduo.</li><li><strong>Operação durante o show:</strong> O show é dinâmico: acompanhe cada música ajustando o fader da voz nos versos/refrões, segurando dinâmica com o compressor, subindo um solo, controlando DCAs. Fique atento a surpresas (microfone caindo, cabo falhando) e tenha plano B (canal reserva, microfone extra). Monitore o PA andando pela área quando possível.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>EQ gráfico de monitor / supressor de feedback (dbx DriveRack):</strong> GEQ 31 bandas por monitor para cortes cirúrgicos das frequências de realimentação; supressores automáticos como apoio. O ''ring out'' dos monitores antes do show ganha margem de volume sem apito.</li><li><strong>Microfones direcionais (super/hipercardioide) e gates:</strong> Microfones mais direcionais (Beta 58A, e935) e gates/mutes nos canais não usados reduzem o ganho desnecessário no sistema, atacando a causa raiz do feedback.</li></ul><h4>Passo a passo</h4><ol><li><strong>Ring out de um monitor:</strong> 1) Suba devagar o nível do monitor com um microfone aberto na posição de uso. 2) No limiar do apito, identifique a frequência (pelo ouvido ou RTA). 3) Corte essa banda no GEQ do monitor. 4) Repita: surgirá outra frequência; corte também. 5) Pare quando tiver volume suficiente com margem segura. Não corte demais.</li><li><strong>Eliminar feedback no meio do show:</strong> 1) Identifique rápido a frequência (grave=ronco, agudo=apito). 2) Baixe levemente o canal/monitor culpado. 3) Corte a frequência no EQ. 4) Cheque se um microfone saiu de posição ou alguém apontou ao monitor. Aja com calma e precisão — pânico piora.</li><li><strong>Operar ativamente a mix do show:</strong> Acompanhe a estrutura das músicas: realce a voz nas partes cantadas, abra o solo no momento certo, controle a dinâmica com compressão, use DCAs para transições. Mantenha um olho nos medidores (sem clip) e ouvido na sala.</li></ol><p><strong>Na prática:</strong> No meio de um culto, um apito agudo surge quando o pregador se aproxima da caixa. O operador reconhece na hora a frequência (~3 kHz), aplica um corte cirúrgico nessa banda, recua levemente o monitor próximo e percebe que o microfone estava apontado para a caixa lateral — reorienta. O apito some sem cortar o discurso. Antes, ele havia feito o ring out dos monitores, o que deu margem; durante, agiu pela causa e pela frequência. Controle total nasce de método.</p><h4>Resumo</h4><ul><li>Feedback é um loop de reamplificação; combatê-lo é reduzir o ganho do loop nas causas certas.</li><li>Prevenção vem de posicionamento, padrão polar, distância curta e menos microfones abertos; EQ/ring out dão margem.</li><li>No show, o operador atua ativamente: dinâmica, faders, DCAs e resposta calma a imprevistos.</li></ul>',30,4,true,false);
