insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5408536a-3da9-4afb-9b25-20c93e000099','19400f3d-3456-44b5-bb02-5932b41f6455','Ao surgir feedback durante o show, a atitude correta é:','Agir pela frequência e pela causa, com calma e precisão, elimina o apito sem interromper o evento.',4,1);
