insert into public.modules (id,course_id,titulo,ordem) values ('e63d370d-a5c6-4b91-96dc-5d2b53fa2ca2','8f29f6dd-3dc6-47fe-b4d3-1cd15514a21d','Módulo 5 — Gravação, DAW e Pós-Produção',5);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('72f32e82-6d3f-429e-ad68-e54c05e7150e','e63d370d-a5c6-4b91-96dc-5d2b53fa2ca2','Áudio Digital: Taxa de Amostragem, Resolução e Formatos','texto','<p><strong>Para começar:</strong> Para gravar bem, é preciso entender como o som vira números. Esta aula domina amostragem, resolução em bits e formatos — e a diferença real entre gravação analógica e digital.</p><p>A gravação digital amostra o sinal analógico em intervalos regulares e o representa em bits. Taxa de amostragem, resolução e formato definem a fidelidade e o tamanho do arquivo. Entender o teorema de Nyquist e escolher os parâmetros certos é base da produção.</p><ul><li><strong>Analógico x digital:</strong> Analógico grava o som como sinal contínuo (fita magnética), com ''cor'', saturação e compressão naturais apreciadas, mas sujeito a desgaste e ruído. Digital converte o sinal em dados (WAV, etc.): alta precisão, reprodutibilidade sem degradação, edição flexível e baixo ruído. Muitas produções combinam: gravam digital e processam com equipamentos/emulações analógicas.</li><li><strong>Taxa de amostragem:</strong> Quantas amostras por segundo são capturadas, em Hz. Padrões: 44,1 kHz (CD), 48 kHz (vídeo/broadcast, padrão em áudio ao vivo/produção), 96 kHz (alta resolução). Teorema de Nyquist-Shannon: para reproduzir até uma frequência, a taxa deve ser pelo menos o dobro dela — por isso 44,1 kHz cobre os ~20 kHz audíveis.</li><li><strong>Resolução (bit depth):</strong> Quantos bits representam cada amostra: 16 bits (CD, ~96 dB de faixa dinâmica) e 24 bits (padrão de gravação, ~144 dB teóricos, muito mais headroom). Mais bits = maior faixa dinâmica e menos ruído de quantização. Grave em 24 bits para ter margem; o destino final pode ser 16 bits.</li><li><strong>Independência dos dois:</strong> Taxa de amostragem e resolução são independentes: uma define quantas amostras por segundo (resolução temporal/frequência), a outra a precisão de amplitude de cada amostra. Ambas contribuem para a fidelidade. O padrão profissional de captura é 48 kHz / 24 bits.</li><li><strong>Formatos de áudio:</strong> Sem perdas (lossless): WAV, AIFF (não comprimidos), FLAC (comprimido sem perda) — preservam toda a informação, ideais para gravação/edição. Com perdas (lossy): MP3, AAC — comprimem descartando dados para reduzir tamanho, bons para distribuição/streaming, ruins para edição. Grave em WAV; exporte MP3/AAC só na entrega.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Console digital como gravador multitrack / interface:</strong> Mesas como X32/M32 gravam todos os canais via USB (multitrack) para virtual soundcheck e registro do show. Configure 48 kHz/24 bits. Permite remixar o show depois e ensaiar a mix com a casa vazia rodando a gravação.</li><li><strong>Interface de áudio + HD/SSD rápido:</strong> Interface (Scarlett, Apollo, RME) define a qualidade da conversão; SSD garante leitura/gravação sem estouros em projetos multicanal. Grave em disco dedicado, não no disco do sistema.</li></ul><h4>Passo a passo</h4><ol><li><strong>Escolher os parâmetros de gravação:</strong> Para a maioria dos trabalhos: 48 kHz / 24 bits, formato WAV. Use 44,1 kHz só se o destino final for CD e você quiser evitar conversão. 96 kHz para projetos que justifiquem (orquestra, alta resolução) e tenham recurso de armazenamento/CPU.</li><li><strong>Evitar clipping na captura digital:</strong> No digital, 0 dBFS é teto absoluto: ajuste o nível para picos confortavelmente abaixo (ex.: −6 a −12 dBFS de pico), pois clipping digital é distorção irreversível. Com 24 bits há headroom de sobra, então gravar com folga é seguro.</li><li><strong>Exportar no formato certo:</strong> Edição/arquivo: WAV/FLAC. Entrega para streaming/cliente: MP3 320 kbps ou AAC. Mantenha sempre o WAV original como master; o MP3 é cópia de distribuição.</li></ol><p><strong>Na prática:</strong> Após um show, o operador exporta o multitrack gravado pelo X32 em 48 kHz/24 bits WAV. No dia seguinte, refaz a mix com calma no estúdio e gera tanto um WAV master quanto um MP3 para a banda divulgar. Como gravou em 24 bits com headroom, não houve clipping mesmo nos picos do show, e a edição teve margem para comprimir e equalizar sem ruído. Os parâmetros corretos preservaram a qualidade do início ao fim.</p><h4>Resumo</h4><ul><li>Gravação digital amostra o sinal (Hz) e o representa em bits; Nyquist exige taxa ≥ 2× a maior frequência.</li><li>Padrão profissional: 48 kHz / 24 bits em WAV, com headroom para evitar clipping irreversível.</li><li>WAV/FLAC preservam tudo (edição); MP3/AAC comprimem para distribuição.</li></ul>',28,1,true,false);
