insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('897ea4f8-bd05-4bf0-95d8-bc03b4c50133','c0d9d9b9-bb85-44aa-96c3-629cf2bfa712','O teorema de Nyquist-Shannon afirma que a taxa de amostragem deve ser:','Para reproduzir até X Hz, amostra-se a pelo menos 2X Hz — por isso 44,1 kHz cobre os ~20 kHz audíveis.',1,1);
