insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('fdbca15e-e1fa-4048-a5b9-3fb156e667a1','c0d9d9b9-bb85-44aa-96c3-629cf2bfa712','No áudio digital, ultrapassar 0 dBFS causa:','0 dBFS é o teto absoluto; acima dele o sinal é cortado e distorce de forma irreversível.',3,1);
