insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('1f1a9b7d-dcaf-4e29-816b-f5675eb3ef66','c0d9d9b9-bb85-44aa-96c3-629cf2bfa712','Para arquivar e editar com máxima qualidade, o formato adequado é:','WAV/FLAC preservam toda a informação; MP3/AAC descartam dados e são para distribuição.',4,1);
