insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('81dc315e-b6d3-41dc-805e-529a85dce6bc','de10b0ad-5fad-4924-8664-1ed04cf898fd','Ao configurar uma sessão para gravar com baixa latência, o ajuste relevante é:','Buffer menor reduz a latência de monitoramento na gravação (à custa de mais carga de CPU).',4,1);
