insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('959998ac-204e-413c-b5d6-ba129bfac490','e63d370d-a5c6-4b91-96dc-5d2b53fa2ca2','Workflow de Produção: Captura, Edição, Mixagem e Masterização','texto','<p><strong>Para começar:</strong> Uma produção tem etapas claras, da captura à entrega. Esta aula percorre o workflow completo e a aplicação de efeitos/processadores na mixagem, fechando o ciclo do operador completo.</p><p>Planejamento, captura, edição, mixagem e (opcional) masterização: cada etapa tem objetivos e cuidados. Aplicar efeitos e processadores com critério, na ordem certa e com sutileza, é o que transforma trilhas cruas em um produto coeso e profissional.</p><ul><li><strong>As etapas do workflow:</strong> 1) Planejamento: objetivos, local, equipamentos. 2) Captura: posicionar microfones, ajustar pré sem distorção, gravar multitrack, monitorar. 3) Edição: organizar trilhas, cortar/compilar tomadas, alinhar fase, ajustar tempo e afinação. 4) Mixagem: balanço, pan, EQ, dinâmica, efeitos, automação. 5) Masterização (opcional): processamento final, limitação/normalização. 6) Entrega: exportar e distribuir.</li><li><strong>Mixagem: ordem de decisões:</strong> Comece pelo balanço de níveis e pan (a base). Depois EQ (criar espaço), dinâmica (firmeza), efeitos (profundidade) e automação (movimento). Decida sempre no contexto da mix, não em solo isolado. Referencie em sistemas diferentes (fone, caixa, celular) — se soa bem em todos, está robusta.</li><li><strong>Aplicação de efeitos e a ordem importa:</strong> A ordem na cadeia muda o resultado: EQ antes ou depois do compressor soam diferente; reverb antes de compressão dá sensação mais natural. Use efeitos com sutileza — ''menos é mais''. Automatize parâmetros ao longo do tempo para dinâmica (abrir reverb num refrão, mover o pan). Experimente, mas com propósito.</li><li><strong>Processadores na produção:</strong> Compressão para consistência e cola; EQ para timbre e espaço; reverb/delay para profundidade; de-esser para sibilância; excitador harmônico para presença; expansão dinâmica para clareza. Cada um resolve um problema específico — escolher o certo para a função é o que diferencia o profissional.</li><li><strong>Masterização e entrega:</strong> Masterização equilibra a mix final, ajusta loudness e prepara para distribuição (limitação para o pico, normalização). Mesmo sem ser masterizador, o operador entende o objetivo: coesão e nível competitivo sem destruir a dinâmica. Exporte WAV master + MP3, faça backup e entregue organizado.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Plugins de mixagem (EQ, compressor, reverb, limiter):</strong> DAWs trazem plugins nativos competentes; há suites de terceiros (Waves, FabFilter, UAD) que emulam clássicos. Conhecer um EQ paramétrico, um compressor versátil, um reverb de qualidade e um limiter resolve a maioria das mixagens.</li><li><strong>Monitores de referência e fone:</strong> Monitores de estúdio de resposta plana (ex.: Yamaha HS, KRK) em sala tratada e fone de referência para checar detalhe. Decisões de mix dependem de ouvir a verdade — monitoração honesta é tão importante quanto plugins.</li></ul><h4>Passo a passo</h4><ol><li><strong>Conduzir uma mixagem do zero:</strong> 1) Organize e nomeie as trilhas. 2) Balanço de níveis e pan (base). 3) HPF e EQ para limpar e criar espaço. 4) Compressão para firmeza onde precisa. 5) Reverb/delay por send para profundidade. 6) Automação de volume/efeitos para dinâmica. 7) Referencie em vários sistemas e revise.</li><li><strong>Aplicar efeitos na ordem certa:</strong> Pense na cadeia de cada trilha: normalmente HPF → EQ corretivo → compressor → EQ tonal → efeitos por send. Experimente trocar a ordem quando o resultado pedir (ex.: comprimir antes de equalizar para domar antes de moldar). Mantenha a sutileza.</li><li><strong>Preparar a entrega:</strong> Exporte o mix em WAV (master). Se for masterizar, deixe headroom (pico ~−3 a −6 dBFS) antes da etapa final. Gere MP3 320 kbps para distribuição, nomeie corretamente e faça backup do projeto e dos arquivos.</li></ol><p><strong>Na prática:</strong> O operador recebe o multitrack de uma banda gravada ao vivo e conduz a produção: edita as tomadas (corta contagens, alinha fase dos overheads), mixa começando pelo balanço, cria espaço com EQ, firma a voz e a bateria com compressão, adiciona um reverb sutil por send e automatiza a voz para subir nos refrões. Referencia no fone e no celular, ajusta os agudos e entrega WAV master + MP3. O ciclo completo — da captura à entrega — fecha a formação do operador de som.</p><h4>Resumo</h4><ul><li>A produção segue etapas: planejamento, captura, edição, mixagem e (opcional) masterização até a entrega.</li><li>A mixagem decide na ordem balanço/pan → EQ → dinâmica → efeitos → automação, sempre no contexto.</li><li>A ordem dos efeitos importa, ''menos é mais'', e referenciar em vários sistemas valida a mix antes da entrega.</li></ul>',32,3,true,false);
