insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('6ef16aba-db2e-45ae-b705-0f196b27ea73','f00598de-2de0-49e2-8dda-d6cd645cb5d9','Referenciar a mix em vários sistemas (fone, caixa, celular) serve para:','Se a mix se traduz bem em sistemas diversos, ela está robusta e equilibrada.',3,1);
