insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('67acf27b-9580-4ad3-a57f-eec3b1240684','f00598de-2de0-49e2-8dda-d6cd645cb5d9','Antes de uma etapa de masterização, é recomendável que a mix final tenha:','Deixar headroom dá margem para a masterização ajustar loudness e limitação sem distorção.',4,1);
