insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e0e6b229-885d-4039-a6cf-9819f5cf92ea','36cb5a17-0ff6-4a20-98e2-9e4f6d1036dc','A diferença entre isolamento e tratamento acústico é:','Isolar é barreira ao som; tratar é moldar reflexões e reverberação dentro do espaço.',4,1);
