insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('682db6ec-cead-4cf3-b088-191724dcbb44','372b9564-a517-4496-b164-149ec3a3c185','Tratamento Acústico, Monitores e Posicionamento de Escuta','texto','<p><strong>Para começar:</strong> Para mixar e monitorar bem, o ambiente de escuta importa tanto quanto os equipamentos. Esta aula cobre tratamento acústico aplicado e o posicionamento correto de monitores de referência.</p><p>Salas de mixagem e gravação exigem controle de reverberação, primeiras reflexões e graves. Materiais absorventes, difusores e bass traps, somados ao posicionamento correto dos monitores e do ouvinte, criam uma escuta confiável — pré-requisito para decisões de mix corretas.</p><ul><li><strong>Absorventes, difusores e bass traps:</strong> Absorventes (fibra de vidro, lã mineral, espuma) controlam médios/agudos e reverberação. Difusores (QRD, skyline) espalham o som, evitando reflexões diretas sem ''matar'' a sala. Bass traps nos cantos controlam o acúmulo de graves e os modos. O equilíbrio entre absorção e difusão é a chave — sala 100% absorvida fica ''morta'' e cansativa.</li><li><strong>Onde tratar:</strong> Primeiras reflexões (paredes laterais e teto entre monitor e ouvinte): absorventes para clareza. Cantos: bass traps. Parede traseira: difusão e/ou absorção. Janelas/superfícies duras: absorver. O ponto das primeiras reflexões se acha com a ''técnica do espelho'' (onde você vê o monitor refletido na parede, ali trate).</li><li><strong>Posicionamento de monitores de referência:</strong> Monitores e ouvinte formam um triângulo equilátero; tweeters na altura dos ouvidos; monitores afastados de paredes/cantos (que reforçam grave); simetria lateral (mesma distância às paredes) para imagem estéreo correta. Posição errada engana o ouvido e arruína decisões de mix.</li><li><strong>Minimizar reflexões e cancelamentos:</strong> Reflexões precoces e o reforço de grave por proximidade de paredes causam picos e cancelamentos que distorcem o que você ouve. Afastar os monitores das paredes, tratar as primeiras reflexões e posicionar o ouvinte fora de nulos modais reduzem o problema. O objetivo é ouvir a verdade da mix.</li><li><strong>Ambiente conforme a função:</strong> Gravação: neutro e controlado, com isolamento. Mixagem: resposta linear, primeiras reflexões tratadas, monitores em níveis realistas. Audição crítica: equilíbrio entre absorção e difusão. Cada função pede um ajuste — e o operador entende para que serve cada decisão acústica.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Painéis absorventes, bass traps e difusores:</strong> Painéis de fibra/lã para reflexões e reverberação; bass traps de canto para graves; difusores na traseira/laterais para espalhar sem matar a sala. Combinados, criam a escuta confiável.</li><li><strong>Monitores de estúdio (Yamaha HS, KRK, Genelec) e suportes:</strong> Monitores de resposta plana sobre suportes desacoplados (isoladores) na altura dos ouvidos, posicionados simetricamente. A qualidade da decisão de mix depende da honestidade da escuta.</li></ul><h4>Passo a passo</h4><ol><li><strong>Posicionar monitores corretamente:</strong> 1) Forme um triângulo equilátero entre os dois monitores e sua cabeça. 2) Alinhe os tweeters à altura dos ouvidos. 3) Afaste os monitores de paredes/cantos para não inchar o grave. 4) Garanta simetria lateral. 5) Use isoladores para desacoplar da mesa/superfície.</li><li><strong>Tratar as primeiras reflexões (técnica do espelho):</strong> Sente na posição de mixagem e peça a alguém para deslizar um espelho pela parede lateral/teto; onde você vir o monitor refletido, instale um painel absorvente. Repita dos dois lados (simétrico). Isso melhora foco e imagem.</li><li><strong>Controlar graves com bass traps:</strong> Posicione bass traps nos cantos (encontro de paredes e parede-teto/chão), onde o grave se acumula. Reavalie ouvindo: o grave deve ficar mais firme e parelho ao andar pela sala.</li></ol><p><strong>Na prática:</strong> Um operador monta um pequeno estúdio para mixar os shows que grava. Sem tratamento, o grave ''enganava'' e suas mixes ficavam fracas em outros sistemas. Ele posiciona os monitores em triângulo simétrico, afastados das paredes, trata as primeiras reflexões pela técnica do espelho e instala bass traps nos cantos. Agora ouve a verdade: as mixes passam a se traduzir bem no carro, no fone e nas caixas. Escuta confiável é o que torna possível mixar com consistência.</p><h4>Resumo</h4><ul><li>Tratamento equilibra absorção, difusão e controle de grave (bass traps) sem ''matar'' a sala.</li><li>Monitores em triângulo simétrico, tweeters na altura dos ouvidos e afastados das paredes dão escuta honesta.</li><li>Tratar primeiras reflexões e controlar grave faz a mix se traduzir bem em outros sistemas.</li></ul>',28,2,true,false);
