insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('3fdc133b-34a9-4134-a46c-f06ca13c3c82','c0de9f88-f510-4381-9957-67ddc8ed5429','A ''técnica do espelho'' serve para:','Onde você vê o monitor refletido na parede/teto está a primeira reflexão; ali se instala o painel.',3,1);
