insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('625c1f95-9573-48f4-af21-ebf9e18942d2','c0de9f88-f510-4381-9957-67ddc8ed5429','Uma sala 100% absorvida (sem difusão) tende a ficar:','Excesso de absorção elimina a vida da sala; o equilíbrio com difusão é o ideal.',4,1);
