insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0bdd3298-0e64-4ed6-b056-2a1a783200d1','c31deda9-13c7-4c92-919d-38e409e2a0a9','Um ativo central para a carreira do operador de som freelancer é:','Confiabilidade, organização, portfólio e relacionamento sustentam a carreira mais do que qualquer equipamento isolado.',4,1);
