insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('939854e2-af00-4f83-98f7-3560aa3460a0','1c8273af-bb80-434f-9682-90579d5cec65','Qual é uma escolha clássica para locução/podcast de estúdio?','O SM7B é um dinâmico de broadcast muito usado em locução e podcast.',5,1);
