insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('2992ce7e-694f-4432-bab1-a87f16a0c133','a1d9714d-d87b-423d-8226-7f52aa2abc0b','Por que coordenar frequências quando há muitos canais?','Múltiplas RFs podem interferir entre si; a coordenação calcula frequências compatíveis.',2,1);
