insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('12117d7e-baad-4ebd-9f3f-4b4378481892','a1d9714d-d87b-423d-8226-7f52aa2abc0b','No monitor in-ear, qual recurso protege a audição do músico?','O limiter impede que picos de volume cheguem ao ouvido em níveis perigosos.',3,1);
