insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c1e801e3-613f-40a3-a23f-992071aa1a2a','b1432535-f27b-4785-a7c9-6951c1042fa7','Qual conector é o padrão para ligar amplificador às caixas (alto-falante)?','O Speakon (Neutrik) é o conector padrão e seguro para sinais de potência de alto-falante.',5,1);
