insert into public.courses (id,titulo,slug,descricao_curta,nivel,categoria,categorias,tipo,carga_horaria,total_aulas,ativo,destaque,ordem) values
  ('2a795665-27a5-45b2-b392-4da014b9450c','Pleno — Luz','pleno-luz','Curso Pleno — Luz — SMU PRO','pleno','luz','{}','free',853,24,false,false,5);
insert into public.modules (id,course_id,titulo,ordem) values ('9ea43da2-68fb-4521-8577-427478edff50','2a795665-27a5-45b2-b392-4da014b9450c','Módulo 1 — Fundamentos da Luz e a Profissão do Iluminador',1);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('85ca6d52-81f0-42e6-944e-25f99b042170','9ea43da2-68fb-4521-8577-427478edff50','O que faz um Light Designer / Operador de Luz','texto','<p><strong>Para começar:</strong> Antes de tocar em qualquer mesa, entenda quem você quer ser: o profissional que transforma watts em emoção.</p><p>A iluminação cênica não é apenas ''acender luzes''. É uma linguagem visual que conta histórias, marca o ritmo da música e dirige o olhar do público. Nesta aula você vai mapear as funções, responsabilidades e a cadeia de comando de uma produção, distinguindo papéis que muita gente confunde: o Light Designer (LD), que concebe o desenho; o operador, que executa na mesa; e o técnico/roadie de luz, que monta, conecta e mantém o rig. Vamos também situar onde a luz se encaixa entre som, vídeo, palco e direção.</p><ul><li><strong>Iluminação como linguagem:</strong> Iluminar é comunicar. Temperatura de cor, intensidade, distribuição e padrão de luz são as ''palavras'' do iluminador. O mesmo palco com luz quente e baixa transmite intimidade; com luz fria, intensa e em movimento, transmite energia de festa. Dominar essa gramática é o que separa o operador do designer.</li><li><strong>Light Designer (LD):</strong> É o autor do conceito visual. Define paleta de cores, ângulos, momentos-chave e como a luz acompanha a narrativa ou o setlist. Produz o rider técnico, o plot (planta de luz) e a lista de cues. Em turnês grandes, o LD frequentemente opera a mesa; em produções menores, ele entrega a programação para um operador local.</li><li><strong>Operador de luz:</strong> Executa o show na mesa. Pode rodar uma cuelist pré-programada (apertando GO a cada música) ou tocar ''no improviso'' (busking), reagindo à banda em tempo real. Precisa conhecer a fundo a navegação do console, ter reflexo musical e calma sob pressão — um GO errado na hora errada estraga o clímax.</li><li><strong>Técnico / roadie de luz:</strong> Responsável pela parte física: montar truss, pendurar e endereçar fixtures, passar cabos DMX e AC, focar refletores e fazer manutenção. É quem garante que, quando o operador apertar um botão, algo realmente aconteça. Em produções pequenas, uma só pessoa acumula LD, operador e técnico.</li><li><strong>A cadeia de comando:</strong> Numa produção típica: Direção/Artista define a intenção → Produtor viabiliza → LD desenha → equipe de luz monta → operador executa. A luz dialoga constantemente com o operador de som (PA), o diretor de palco (stage manager) e o vídeo/LED. Comunicação clara por intercom é parte do trabalho.</li><li><strong>Onde se trabalha:</strong> Shows e festivais, teatro, TV e cinema, eventos corporativos, casamentos, igrejas, baladas, desfiles e instalações artísticas. Cada nicho tem ritmo e exigências próprias: teatro valoriza precisão e repetição de cues; show de festival valoriza impacto e busking; corporativo valoriza branding e luz limpa no palestrante.</li></ul><p><strong>Na prática:</strong> Num show de médio porte de banda de rock, o LD chega com o rider já enviado à casa. A casa entrega o rig montado. O LD/operador faz o ''patch'' batendo os endereços com o que está pendurado, programa cores e posições durante a passagem de som e, à noite, opera a mesa lendo a banda: puxa strobes no refrão, fecha tudo (blackout) no fim de uma balada e abre wash âmbar quente na próxima. Três funções, às vezes uma pessoa só.</p><h4>Resumo</h4><ul><li>Iluminar é contar histórias com luz, não apenas acender refletores.</li><li>LD concebe, operador executa, técnico monta e mantém — em pequenas produções tudo isso pode ser uma pessoa.</li><li>O iluminador trabalha em equipe e em diálogo constante com som, palco e direção.</li></ul>',25,1,true,true);
