insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('42e93f4e-5f55-4bf5-9f7f-9de6e17ec342','4c5f8642-4d1f-4e05-aba4-544e8df91790','Para calcular a corrente consumida por um circuito, você usa:','Corrente = Potência ÷ Tensão. Some os watts e divida pela tensão para achar os ampères.',3,1);
