insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('fd3a3a35-085b-4480-b518-976e22652e31','4c5f8642-4d1f-4e05-aba4-544e8df91790','A ART (Anotação de Responsabilidade Técnica) em um evento é assinada por:','A ART de instalações elétricas é responsabilidade de um engenheiro eletricista, atestando conformidade com as normas.',4,1);
