insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('1ace2073-f6b5-4b66-a21d-309800752c94','7d927c09-22f4-49c7-a42c-af76775aefa8','Para 3 moving heads de 16 canais, os endereços corretos sem sobreposição são:','Cada um ocupa 16 canais: 1–16, 17–32, 33–48, logo os endereços iniciais são 1, 17 e 33.',4,1);
