insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('721b92ed-1446-4eb3-af62-e57600111387','7d927c09-22f4-49c7-a42c-af76775aefa8','Equipamentos antigos costumam ter o endereço definido por:','Fixtures legadas usam chaves DIP em binário, cujas posições somadas formam o endereço.',5,1);
