insert into public.modules (id,course_id,titulo,ordem) values ('a544d155-e870-4800-94bd-49307608f5b3','2a795665-27a5-45b2-b392-4da014b9450c','Módulo 3 — Equipamentos: Fixtures, Efeitos e Dimmers',3);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('34e6aa66-1ef3-4813-92fd-3480b74a5b6b','a544d155-e870-4800-94bd-49307608f5b3','Moving heads: Spot, Beam e Wash','texto','<p><strong>Para começar:</strong> Os ''robôs'' do palco. Entender quando usar Spot, Beam ou Wash é o que dá identidade ao seu desenho.</p><p>Os moving heads (cabeças móveis) são as fixtures inteligentes mais marcantes de um show. Eles giram em pan (horizontal) e tilt (vertical) e mudam cor, foco e padrão por DMX. Existem três grandes famílias — Spot, Beam e Wash — e híbridos que combinam tudo. Esta aula detalha o que cada um faz, seus parâmetros DMX típicos e quando escolher cada um.</p><ul><li><strong>Pan, tilt e a cabeça móvel:</strong> Todo moving head tem uma cabeça que gira: pan (horizontal, tipicamente 540°) e tilt (vertical, ~270°). Esses movimentos são controlados por canais DMX e permitem ''desenhar'' no ar e varrer o palco. A precisão e a velocidade do motor definem a fluidez dos efeitos coreografados.</li><li><strong>Moving Wash:</strong> Emite luz ampla e suave para ''banhar'' grandes áreas com cor. Geralmente LED RGBW/RGBA, com zoom para abrir/fechar o facho. Ideal para colorir o palco, criar atmosferas e transições suaves de cor. Não cria padrões nítidos — sua força é a cobertura e a mistura de cor.</li><li><strong>Moving Beam:</strong> Produz um facho estreito, intenso e paralelo (raio ''laser-like'') que corta o ar, especialmente com fumaça/haze. Usa lâmpada de descarga ou LED de alta densidade, prisma e por vezes gobos de aro. É o efeito ''aéreo'' clássico de festival e EDM. Ângulo de facho bem fechado (poucos graus).</li><li><strong>Moving Spot:</strong> Versátil: projeta gobos (padrões/texturas/logos), tem íris, foco ajustável, roda de cores e frequentemente prisma. Cria padrões nítidos no chão, no cenário e no ar. É o ''canivete suíço'' — usado para projeção de formas, recortes e efeitos definidos.</li><li><strong>Híbridos e parâmetros DMX comuns:</strong> Muitos modelos atuais são híbridos (Spot+Beam+Wash). Parâmetros DMX típicos: pan/tilt (e suas versões ''fine'' para precisão), dimmer, shutter/strobe, cor (roda ou RGBW), gobo (roda fixa e rotativa), foco, zoom, prisma, frost, controle/reset. Quanto mais funções, mais canais.</li><li><strong>Quando usar cada um:</strong> Wash para cor e cobertura; Beam para efeito aéreo e impacto; Spot para padrões e projeção. Um rig equilibrado costuma combinar os três: washes preenchem, beams criam o ''show de ar'', spots desenham. A escolha depende do gênero, do tamanho do palco e do orçamento.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Moving Head Wash (LED RGBW, com zoom):</strong> Banha grandes áreas de cor com facho amplo e mistura suave. Use para colorir palco e fundo, criar climas e transições de cor. Verifique o range de zoom e a quantidade de LEDs/potência.</li><li><strong>Moving Head Beam (descarga ou LED, facho estreito):</strong> Cria raios intensos e paralelos que cortam o ar com fumaça. Use para efeito aéreo, looks de EDM/festival e impacto rítmico. Atenção ao calor e ao consumo das versões de descarga.</li><li><strong>Moving Head Spot (gobos, prisma, foco, íris):</strong> Projeta padrões, texturas e logos com bordas nítidas. Use para desenhar no chão/cenário e para recortes. Avalie nº de gobos rotativos e fixos e a qualidade do foco.</li><li><strong>Moving Head Híbrido (Spot+Beam+Wash):</strong> Combina as três funções numa só fixture, economizando pontos e peso no truss. Excelente custo-benefício em rigs compactos; confira se cada modo entrega qualidade suficiente para sua necessidade.</li></ul><h4>Passo a passo</h4><ol><li><strong>Identificar o tipo de moving head:</strong> Olhe o facho: largo e difuso = Wash; estreito e duro que ''risca o ar'' = Beam; com lente frontal e gobos projetando padrões = Spot. Confirme no datasheet o ângulo de facho (graus) e os recursos (gobo, prisma, zoom).</li><li><strong>Mapear os parâmetros no patch:</strong> Após o patch, abra a visão de canais da fixture na mesa e localize pan, tilt, dimmer, cor, gobo, foco, zoom e prisma. Mova cada um isoladamente para entender o que controla — base para criar paletas depois.</li><li><strong>Escolher a fixture para o objetivo:</strong> Precisa colorir o palco inteiro? Wash. Quer raios no ar no drop da música? Beam. Vai projetar a logo do artista no telão de fundo? Spot. Orçamento apertado e pouco ponto no truss? Híbrido.</li></ol><p><strong>Na prática:</strong> Num show de eletrônico, o LD montou 8 beams na régua de trás para os raios aéreos sincronizados com a batida, 6 washes para inundar o palco de cor a cada virada e 4 spots para projetar gobos giratórios no piso durante os breaks. No drop, todos os beams subiram juntos formando um leque — efeito impossível com washes, que não fecham o facho.</p><h4>Resumo</h4><ul><li>Wash banha cor, Beam corta o ar, Spot projeta padrões; híbridos fazem os três.</li><li>Pan/tilt movem a cabeça; cor, gobo, foco, zoom e prisma moldam o facho.</li><li>Um rig equilibrado combina os três tipos conforme gênero e palco.</li></ul>',30,1,true,false);
