insert into public.quiz_options (question_id,texto,correta,ordem) values ('40ae068d-88c1-46b7-9a69-2f4a7eea60f3','Máquina de fumaça',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('ba321ead-24e7-49df-bdee-0fbcf6130136','a544d155-e870-4800-94bd-49307608f5b3','Efeitos: strobe, atomic, laser, fumaça/hazer e gobos','texto','<p><strong>Para começar:</strong> São os temperos do show. Usados na dose certa, eletrizam; em excesso, cansam e até adoecem o público.</p><p>Efeitos especiais dão a ''pancada'' visual: o strobe que congela o movimento, o laser que rasga o ar, a fumaça que torna a luz visível, os gobos que projetam padrões. Esta aula apresenta cada efeito, seu funcionamento, e — crucial — os cuidados de segurança e saúde, especialmente com strobe (epilepsia fotossensível) e laser (visão).</p><ul><li><strong>Strobe e o efeito estroboscópico:</strong> O strobe emite flashes intensos e rápidos (xenônio ou LED de alta potência) em frequência ajustável, criando a ilusão de movimento congelado ou acelerado. Energiza refrões e drops. ATENÇÃO: pode causar desconforto, enxaqueca e até convulsões em pessoas fotossensíveis — use com moderação e avise o público em eventos sensíveis.</li><li><strong>Atomic / strobe de alta potência:</strong> O ''Atomic'' (popularizado pela linha da Martin e usado como termo genérico para strobes potentes) é um strobe de altíssima saída, às vezes com canal de cor e dimmer próprio, capaz de pulsos cegantes. Cuidado: o material-base nota que ''atomic'' também é usado como adjetivo para qualquer efeito muito intenso — verifique sempre o modelo real.</li><li><strong>Laser:</strong> Emite luz monocromática, coerente e altamente concentrada, criando feixes, leques e padrões geométricos nítidos no ar. Controlado por DMX. É classificado por risco (classes I a IV); equipamentos de show costumam ser classe IIIb/IV e EXIGEM precauções rígidas: nunca apontar para os olhos do público, respeitar altura mínima de varredura e regulamentação local.</li><li><strong>Máquina de fumaça vs. hazer:</strong> Máquina de fumaça aquece um fluido (à base de glicol/glicerina) gerando névoa densa e visível — ótima para ''nuvens'' e revelar feixes pontualmente. O hazer gera uma neblina fina e homogênea que fica suspensa, deixando TODO o ar levemente difuso e tornando beams e lasers visíveis o show inteiro. Para raios aéreos contínuos, hazer é o ideal.</li><li><strong>Gobos:</strong> Gobo é um disco/placa com padrão recortado (metal ou vidro) colocado no caminho da luz para projetar formas, texturas, logos e padrões. Em movings spot há roda de gobos fixos e rotativos. Combinados com prisma e foco, criam desde folhagens e janelas até logos de marca.</li><li><strong>Segurança e saúde com efeitos:</strong> Strobe e laser são os efeitos com maior risco à saúde. Sinalize uso de estroboscópico (gatilho de epilepsia). Garanta ventilação ao usar fumaça (pode causar desconforto respiratório). Lasers exigem operador habilitado e conformidade legal. A regra: efeito serve à narrativa, não ao ego do operador.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Strobe / Atomic LED ou xenônio:</strong> Flashes intensos e rápidos para refrões e drops. Ajuste frequência e intensidade. Risco de fotossensibilidade — use com parcimônia e avise público sensível.</li><li><strong>Laser de show (classe IIIb/IV):</strong> Feixes e padrões geométricos coerentes via DMX. Exige operador habilitado, varredura segura acima do público e conformidade legal. Nunca apontar aos olhos.</li><li><strong>Máquina de fumaça:</strong> Névoa densa pontual para revelar feixes e criar ''nuvens''. Fluido à base de glicol. Garanta ventilação; dispersa-se rápido.</li><li><strong>Hazer:</strong> Neblina fina e homogênea que fica suspensa, deixando o ar difuso o show todo. Ideal para beams e lasers contínuos. Consumo de fluido menor e efeito mais ''limpo'' que a fumaça.</li><li><strong>Gobos (fixos e rotativos):</strong> Discos com padrões para projetar texturas, formas e logos via movings spot. Vidro (coloridos/detalhados) ou metal (recortes). Combine com prisma e foco.</li></ul><h4>Passo a passo</h4><ol><li><strong>Revelar beams com hazer:</strong> Antes do show, ligue o hazer e deixe o ar ''carregar'' alguns minutos. Ajuste a densidade para que os fachos fiquem visíveis sem ''lavar'' o palco. Reponha ao longo da noite conforme o ar limpa.</li><li><strong>Programar um strobe seguro:</strong> Crie um efeito de strobe num botão/cuelist separado, com frequência controlada. Dispare só em picos curtos. Em eventos com público sensível, evite ou avise; jamais deixe strobe contínuo por longos períodos.</li><li><strong>Projetar e ajustar um gobo:</strong> No spot, selecione a roda de gobos, escolha o padrão, ajuste o foco até a borda ficar nítida (ou propositalmente suave), adicione rotação e prisma se quiser multiplicar o padrão. Direcione com pan/tilt ao alvo.</li></ol><p><strong>Na prática:</strong> Num festival de EDM, o operador deixou o hazer mantendo o ar uniformemente difuso a noite toda, o que fez os beams aparecerem como raios sólidos. Reservou o strobe e os lasers só para os drops: lasers varrendo acima das cabeças (nunca nos olhos) e strobe em rajadas curtas. Para um break melódico, projetou gobos giratórios lentos no piso — alternando energia e respiro sem cansar o público.</p><h4>Resumo</h4><ul><li>Strobe e laser são os efeitos de maior risco à saúde — exigem moderação e conformidade legal.</li><li>Hazer (neblina fina contínua) é o segredo para beams e lasers visíveis o show inteiro.</li><li>Gobos projetam padrões, texturas e logos; foco, prisma e rotação ampliam as possibilidades.</li></ul>',28,3,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('6e2313cf-3733-4f1a-85a3-87622b9f9b7b','ba321ead-24e7-49df-bdee-0fbcf6130136','Quiz — Efeitos: strobe, atomic, laser, fumaça/hazer e gobos');
