insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c81b6ee0-b666-4589-b053-c5c4ba532a65','57d9e9bd-6105-4f5e-aef5-3a8b8c67dde5','A função de um dimmer é:','O dimmer regula a potência entregue às lâmpadas convencionais, controlando a intensidade.',2,1);
