insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('288cb542-526f-4aaa-9f13-b9b2ed4900a4','57d9e9bd-6105-4f5e-aef5-3a8b8c67dde5','Um splitter DMX serve para:','O splitter ramifica o DMX em linhas isoladas e reforçadas, evitando flicker e isolando falhas.',3,1);
