insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c296ab04-c8ae-45aa-af76-0f2653340288','57d9e9bd-6105-4f5e-aef5-3a8b8c67dde5','Boa prática ao desligar o rig:','Faça blackout antes de cortar energia e desligue por etapas para evitar picos e acidentes.',5,1);
