insert into public.modules (id,course_id,titulo,ordem) values ('7c6983f9-976d-4ebb-a1c1-ba438bcfd9be','2a795665-27a5-45b2-b392-4da014b9450c','Módulo 4 — Operando a Mesa de Luz: Consoles e Fluxo de Trabalho',4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('817c7a4a-564e-4ab8-9547-9c7e73817359','7c6983f9-976d-4ebb-a1c1-ba438bcfd9be','Tipos de console e as principais marcas/modelos','texto','<p><strong>Para começar:</strong> A mesa é o seu instrumento. Conhecer as famílias de consoles ajuda a falar a língua de qualquer casa.</p><p>Existem muitos consoles, mas eles compartilham uma lógica comum. Esta aula classifica os tipos (físicos, baseados em PC, touch, híbridos, portáteis) e apresenta as marcas e modelos reais mais usados no mercado, situando para que tipo de trabalho cada plataforma costuma ser escolhida. O objetivo é você reconhecer qualquer mesa e saber onde procurar o que precisa — sempre consultando o manual do fabricante.</p><ul><li><strong>Tipos de console:</strong> Tradicionais (mesas físicas com faders e botões, comuns em teatro e instalações fixas); baseados em PC (software num computador, controlado por mouse/teclado/superfície); com tela sensível ao toque; híbridos (faders físicos + touch); e portáteis/compactos (para shows itinerantes e pequenos eventos). A tendência atual é híbrida: hardware tátil + software poderoso.</li><li><strong>MA Lighting (grandMA):</strong> A família grandMA2 e grandMA3 (Full-Size, Light, Compact) é referência mundial em grandes turnês, festivais e TV. Lógica baseada em executors, sequences e um motor de programação muito profundo. O grandMA3 onPC permite rodar o software em PC com superfícies de comando. Padrão de mercado para shows grandes.</li><li><strong>ChamSys MagicQ:</strong> Linha MagicQ (ex.: MQ80, MQ500 Stadium) e o software MagicQ gratuito para PC. Muito popular pelo custo-benefício e por permitir começar só no software e migrar para o hardware depois. Forte em busking e em rigs de médio/grande porte.</li><li><strong>Avolites:</strong> Titan é o sistema operacional da marca (Tiger Touch, Quartz, e a superfície Titan Mobile/Go que roda em PC). Conhecida por uma abordagem ágil de programação e busking, com forte presença em shows de banda e turnês.</li><li><strong>Obsidian Onyx e ETC:</strong> Obsidian Control Systems usa o software Onyx (consoles NX) — sucessor do Martin M-PC, com versão gratuita para começar. ETC (Eos Ti, Ion Xe, Element, ColorSource) domina o mundo do teatro, com fluxo de trabalho ''tracking'' baseado em cues e canais, ideal para espetáculos com muitas deixas precisas.</li><li><strong>Outras marcas e o critério de escolha:</strong> High End (Hog 4), Jands (Vista), Zero 88 (FLX), Martin, LSC e outras coexistem no mercado. A escolha depende do porte do evento, do gênero (teatro favorece ETC; show/festival favorece grandMA/Avo/ChamSys), do orçamento e — muito — daquilo que o operador já domina. Regra: sempre estude o manual do modelo específico antes do show.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>MA Lighting grandMA2 / grandMA3:</strong> Console de referência para grandes shows, festivais e TV. Programação profunda por executors e sequences; grandMA3 onPC roda em computador. Quando o evento é grande e complexo, é o padrão de muitos LDs.</li><li><strong>ChamSys MagicQ (MQ80, MQ500):</strong> Plataforma com software gratuito para PC e consoles dedicados. Excelente custo-benefício e forte em busking; ótima porta de entrada por permitir aprender no software antes de comprar hardware.</li><li><strong>Avolites Titan (Tiger Touch, Titan Mobile):</strong> Sistema ágil para programação e busking ao vivo, popular em turnês de banda. Titan Mobile/Go roda em PC com superfície USB.</li><li><strong>Obsidian Onyx (NX) e ETC Eos/Ion:</strong> Onyx: software (com versão grátis) e consoles NX, bom para clubes e médio porte. ETC Eos/Ion/Element: padrão do teatro, fluxo de cues ''tracking'' com altíssima precisão de deixas.</li></ul><h4>Passo a passo</h4><ol><li><strong>Identificar a mesa da casa:</strong> Ao chegar, identifique a marca e o modelo exatos. Localize o manual (online ou na própria mesa). Reconheça os blocos universais: área de seleção de fixtures, faders/executors, área de programação (Record/Store), playback e telas de patch.</li><li><strong>Escolher a plataforma para um projeto:</strong> Show de festival com muitos movings e efeitos? grandMA/Avolites/ChamSys. Peça de teatro com 200 deixas precisas? ETC Eos/Ion. Evento pequeno/orçamento curto? MagicQ ou Onyx no PC com uma superfície barata. Sempre pondere o que você domina.</li><li><strong>Treinar de graça antes de comprar hardware:</strong> Baixe MagicQ ou Onyx (gratuitos) ou o grandMA3 onPC e pratique em modo offline/visualizador. Você aprende a lógica de patch, grupos, paletas e cuelists sem precisar do console físico.</li></ol><p><strong>Na prática:</strong> Um operador foi contratado para um festival cuja casa só tinha grandMA3, mas ele vinha do ChamSys. Em vez de improvisar, baixou o grandMA3 onPC dias antes, estudou o manual oficial e treinou o patch e a criação de executors no visualizador. No dia, reconheceu a lógica (sequences/executors) e operou com segurança — provando que entender o fluxo padrão vale mais que decorar uma única mesa.</p><h4>Resumo</h4><ul><li>Consoles variam em forma, mas compartilham a mesma lógica: selecionar, programar, reproduzir.</li><li>grandMA, Avolites e ChamSys dominam shows; ETC domina o teatro de cues precisos.</li><li>Várias plataformas têm software gratuito para PC — treine a lógica antes de encarar o hardware.</li></ul>',28,1,true,false);
