insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('14a27ff4-3c26-42bf-b3cc-905ee1137ea4','5b4411b5-56a1-463d-ae8e-981ff1c637f6','A sintaxe ''1 THRU 8 ENTER'' normalmente serve para:','Na linha de comando, ''THRU'' seleciona um intervalo contínuo de fixtures (1 a 8).',5,1);
