insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('44eef2ca-5604-4bcb-bef1-e58f1b844c98','2318b31b-3461-43cf-9438-f801deef434c','Se você reajusta a paleta ''Centro'' e a cena que a usa se atualiza sozinha, isso é:','Como a cena aponta para a paleta, alterar a paleta propaga a mudança às cenas que a referenciam.',4,1);
