insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('8896a57e-2a38-4b61-862f-a104b4ba1325','da96b649-b246-4e44-936b-c2d67c763edc','Simulador 3 — Montar uma cuelist para uma música','texto','<p><strong>Para começar:</strong> O exercício que junta tudo: pegar uma música real e transformar sua estrutura em uma cuelist completa.</p><p>Simulador final: você vai analisar a estrutura de uma música (intro, verso, refrão, ponte, refrão final, fim), criar um look para cada parte e encadeá-los numa cuelist com tempos. É a integração de todo o curso — patch, grupos, paletas, cenas, cuelist e a sensibilidade musical do busking, agora estruturada. Ao final, você terá um ''mini-show'' rodável com GO.</p><ul><li><strong>Analisar a estrutura musical:</strong> Ouça a música e marque as seções: Intro (atmosfera), Verso (intimista), Pré-refrão (crescendo), Refrão (energia máxima), Ponte/break (respiro), Refrão final (clímax) e Final (resolução). Cada seção vira um cue. Anote os tempos aproximados ou as deixas.</li><li><strong>Definir um look por seção:</strong> Intro: spots em azul, baixo, hazer; Verso: PARs âmbar suave + 1 spot no vocalista; Pré-refrão: subir intensidade, cor mais saturada; Refrão: tudo aberto, movimento, beams/chase; Ponte: derrubar para um único foco quente; Refrão final: clímax com strobe/blinder nos acentos; Final: fade lento ao blackout.</li><li><strong>Gravar os cues com tempos:</strong> Grave cada look como um cue na mesma cuelist, em ordem, com fades coerentes: intro entra em 4 s, verso transita em 2 s, refrão pode ''estourar'' em 0,5 s, final sai em 6 s. O tempo é o que dá a sensação musical à transição.</li><li><strong>Encadear e ensaiar a cuelist:</strong> Rode a cuelist do cue 1 ao último com GO, idealmente com a música tocando, marcando onde apertar GO em cada virada. Ajuste fades que ficaram lentos ou rápidos demais. Repita até as transições caírem no tempo da música.</li><li><strong>Combinar cuelist com efeitos ao vivo:</strong> Deixe o ''esqueleto'' na cuelist (estrutura e cores) e mantenha strobe, blinder e bumps em botões para temperar ao vivo nos acentos. Assim você tem a segurança da cuelist e a expressividade do busking ao mesmo tempo.</li><li><strong>Documentar e repetir:</strong> Anote a ordem dos cues e as deixas (ex.: ''GO no início do refrão''). Salve o show. Uma cuelist documentada pode ser repetida noite após noite ou passada a outro operador — princípio que vem direto do roteiro/rider do show.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Console com cuelist em playback e botão GO:</strong> A cuelist da música vai num playback; o operador avança com GO nas viradas. Botões extras seguram strobe/blinder para os acentos. É o setup clássico de show com setlist.</li><li><strong>Player de áudio / metrônomo de referência:</strong> Tocar a música durante o ensaio (ou usar o BPM como referência) é essencial para casar os tempos de fade e marcar as deixas de GO com precisão.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Mapear as seções:</strong> Ouça a música e escreva a ordem: Intro, Verso, Pré-refrão, Refrão, Ponte, Refrão Final, Final. Marque os tempos/deixas de cada virada.</li><li><strong>2. Criar o look de cada seção:</strong> Para cada parte, monte o look com grupos + paletas (cor, posição, intensidade, efeito) conforme a energia da seção.</li><li><strong>3. Gravar a cuelist:</strong> Grave o cue 1 (Intro) com seu fade; repita para cada seção em ordem na mesma cuelist, ajustando fade/delay de acordo com a transição musical.</li><li><strong>4. Ensaiar com a música:</strong> Toque a música e rode a cuelist com GO, marcando o ponto exato de cada GO. Corrija tempos até cair certo.</li><li><strong>5. Adicionar tempero ao vivo:</strong> Mantenha strobe/blinder/bump em botões para os acentos do refrão e do clímax, disparados manualmente sobre a cuelist.</li><li><strong>6. Salvar e documentar:</strong> Anote as deixas (''GO no drop''), salve o show e faça um backup do arquivo da mesa.</li></ol><p><strong>Na prática:</strong> Para uma música pop de ~3 min, o operador mapeou 7 seções e criou 7 cues: intro azul com hazer; verso âmbar com foco no vocalista; pré-refrão subindo a cor; refrão com beams em leque e chase nos PARs; ponte num único spot quente; refrão final com strobe nos acentos; final em fade lento ao blackout em 6 s. Ensaiou com a faixa tocando, ajustou os fades, e marcou no roteiro onde apertar GO. No show, rodou a cuelist e ainda deu bumps de blinder manuais nos acentos — estrutura + expressão.</p><h4>Resumo</h4><ul><li>A estrutura da música vira a estrutura da cuelist: cada seção é um cue.</li><li>Os tempos de fade dão musicalidade às transições — estouro no refrão, fade lento no final.</li><li>Combine a segurança da cuelist com o tempero ao vivo do busking e documente tudo.</li></ul>',35,3,true,false);
