insert into public.modules (id,course_id,titulo,ordem) values ('1151c86a-5306-41f6-98a4-07279b6a5d5f','2a795665-27a5-45b2-b392-4da014b9450c','Módulo 6 — Projeto, Rider Técnico e Carreira',6);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('e12c1798-ed6e-4649-9eef-5a0aab742f51','1151c86a-5306-41f6-98a4-07279b6a5d5f','Briefing, projeto de luz e o rider técnico','texto','<p><strong>Para começar:</strong> Todo grande show começa num documento. Saber projetar e comunicar no papel é o que separa o amador do profissional.</p><p>Antes da montagem, vem o projeto. Esta aula percorre o ciclo de planejamento: o briefing (entender objetivo, espaço, estilo e orçamento), a elaboração do projeto/roteiro de luz, e a peça-chave de comunicação técnica — o rider técnico — que diz à casa exatamente quais fixtures, energia, console e estruturas o show precisa. É o conhecimento que transforma uma ideia em algo executável e contratável.</p><ul><li><strong>O briefing:</strong> Reunião/documento que define a base do projeto: objetivos e visão, espaço e layout, estilo e atmosfera desejados, cores e temperatura, funcionalidade (o que iluminar), controle/programação, orçamento, prazos, equipe e requisitos técnicos do local. Um bom briefing alinha cliente, artista e equipe e evita mal-entendidos caros.</li><li><strong>Elaboração do projeto:</strong> Com o briefing, o LD define o conceito (paleta, ângulos, momentos), seleciona equipamentos pela necessidade e pelas specs, faz cálculos luminotécnicos básicos (cobertura, intensidade, distância) e posiciona as fixtures. Considera energia disponível, controle (console/software) e segurança. O resultado é a planta de luz (plot) e a lista de cues/cenas.</li><li><strong>O roteiro de projeto:</strong> Documento que organiza tudo em etapas: introdução, objetivos, levantamento do local, equipe, design conceitual, planta de iluminação, seleção de equipamentos, plano de energia, programação, orçamento, cronograma, testes, segurança, aprovação e apresentação. Adaptável à complexidade de cada evento.</li><li><strong>O rider técnico de luz:</strong> Documento entregue à casa/produção com TODOS os requisitos: dados do evento e horários (montagem, soundcheck, show), lista de fixtures (modelo e quantidade: washes, spots, PARs, strobes, moving heads, efeitos), posicionamento, cores/filtros, console e software, cabos DMX, requisitos de energia (potência total e pontos), estruturas (grid, truss, suportes) e equipe necessária. É o contrato técnico do show.</li><li><strong>Energia, estrutura e pessoal no rider:</strong> O rider especifica a potência total estimada e os pontos de energia (para a casa dimensionar), as estruturas de suporte (grid de iluminação, suportes de solo) e a equipe local necessária para montagem/operação. Quanto mais preciso, menos surpresa no dia.</li><li><strong>Licenças e responsabilidade:</strong> Eventos exigem alvará, laudo de segurança, autorização do Corpo de Bombeiros e, em instalações elétricas, ART de engenheiro. O projeto de luz é parte da documentação que sustenta essas licenças. Trabalhar legalizado protege o profissional e o público.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Software de plot/planta de luz:</strong> Ferramentas como Vectorworks/Spotlight, WYSIWYG, Capture ou MagicQ/grandMA 3D ajudam a desenhar a planta, posicionar fixtures e pré-visualizar o desenho antes da montagem. Geram a documentação visual do rider.</li><li><strong>Modelo de rider técnico:</strong> Template com campos de evento, horários, lista de fixtures, console, DMX, energia, estruturas e equipe. Padronizar o rider acelera o orçamento e a comunicação com qualquer casa.</li></ul><h4>Passo a passo</h4><ol><li><strong>Conduzir um briefing:</strong> Pergunte: qual o objetivo e a atmosfera? Como é o espaço (dimensões, pé-direito, pontos de energia)? Qual o estilo/paleta? Há câmera? Qual o orçamento e o prazo? Quem é a equipe? Documente as respostas — elas guiam todo o projeto.</li><li><strong>Esboçar o projeto:</strong> Defina o conceito e a paleta; selecione fixtures por função (wash de cor, spots de padrão, beams de ar, blinders); posicione no plot considerando ângulos e distância; estime a energia (soma de watts) e escolha o console.</li><li><strong>Escrever o rider técnico:</strong> Preencha: dados/horários do evento; lista de fixtures com modelo e quantidade; posicionamento; cores/filtros; console e software; quantidade/comprimento de cabos DMX; potência total e pontos de energia; estruturas; equipe necessária. Anexe o plot. Assine e date.</li><li><strong>Validar com a casa:</strong> Envie o rider antecipadamente e confirme com a equipe técnica do local que a energia, as estruturas e os pontos existem. Ajuste o que a casa não puder atender antes do dia da montagem.</li></ol><p><strong>Na prática:</strong> Para um show de turnê, a LD fez o briefing com a produção (palco 12×8 m, pé-direito 7 m, paleta quente, com câmeras para telão), desenhou o plot num software, selecionou o rig (washes, spots, beams e blinders) e escreveu o rider: lista de fixtures e quantidades, console grandMA3, energia total estimada e pontos, truss frontal e de fundo, e 4 técnicos locais. Enviou à casa uma semana antes; a casa confirmou tudo, exceto um ponto de energia, que foi providenciado a tempo. No dia, a montagem fluiu sem surpresas.</p><h4>Resumo</h4><ul><li>O briefing define objetivo, espaço, estilo, orçamento e prazo — a base de tudo.</li><li>O projeto vira plot e lista de cues; o rider técnico é o contrato técnico enviado à casa.</li><li>Energia, estruturas, equipe e licenças precisam estar previstos e validados antes da montagem.</li></ul>',30,1,true,false);
