insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('ff5fcd0a-836c-4ff5-9c23-2932c5338a77','7674eec2-af04-46a0-a308-5ba5aca45d06','Qual console é considerado padrão de referência em teatro/Broadway?','A família ETC Eos, com sua filosofia de tracking, é o padrão do teatro profissional.',2,1);
