insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('cee27e77-dcd0-423d-90f3-94d692293847','7674eec2-af04-46a0-a308-5ba5aca45d06','Por que grandMA3 onPC e MagicQ onPC são úteis para estudo?','As versões onPC permitem aprender e programar no computador, com universos limitados sem node/chave.',4,1);
