insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('8d8f999a-58f6-4815-9e20-1d0292037775','30b53488-353b-4a53-9a22-05a2482ba8e3','Para um banho de cor amplo e barato no palco, o ideal é:','PAR LED entrega cor por DMX com bom custo e cobertura.',3,1);
