insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('dd579a13-594b-4405-ad82-8d87122f9628','30b53488-353b-4a53-9a22-05a2482ba8e3','Um refletor convencional (PAR 64) precisa de quê para acender e variar intensidade?','Convencionais não têm eletrônica de intensidade; usam dimmer externo.',4,1);
