insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('eadf5434-3650-418b-acef-5a9833e33478','30b53488-353b-4a53-9a22-05a2482ba8e3','O JDC1 da GLP é conhecido como:','O GLP JDC1/JDC2 combina blinder e strobe num só aparelho, popular em festivais.',5,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('eadf5434-3650-418b-acef-5a9833e33478','Elipsoidal de teatro',false,1);
