insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('4f185912-8b30-4f87-a40d-034d6b28d754','e80aa660-48aa-423f-8520-5f550cc736fc','Por que beams ''somem'' num palco sem atmosfera?','O feixe só fica visível quando há partículas (haze/fumaça) refletindo a luz no ar.',1,1);
