insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0b070ed5-4ca0-4fcc-a113-baf2374c1fed','e80aa660-48aa-423f-8520-5f550cc736fc','Qual família é a ideal para revelar feixes de forma sutil durante todo o show?','Haze cria névoa fina e durável, ideal para revelar beams sem virar nuvem.',2,1);
