insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('f957ae29-636a-4b86-bc60-a35e1b7451f3','e80aa660-48aa-423f-8520-5f550cc736fc','O efeito de ''tapete de fumaça no chão'' é produzido por:','Low fog é fumaça resfriada que fica rasteira por ser mais densa/pesada.',3,1);
