insert into public.modules (id,course_id,titulo,ordem) values ('e5f47a97-042a-4297-9121-5b2009bc7a61','c8ee74bd-37a4-4ca1-bac4-00d6535d7a5e','Módulo 1 - Fundamentos do Sinal de Vídeo e da Função do VJ/Técnico',1);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('86afa2ea-8e43-4458-96fc-7a12b6b6dec1','e5f47a97-042a-4297-9121-5b2009bc7a61','O que faz um técnico de vídeo/VJ em eventos ao vivo','texto','<p><strong>Para começar:</strong> Antes de tocar em qualquer cabo, você precisa entender o que está sendo entregue ao público e qual é a sua responsabilidade na cadeia.</p><p>O técnico de vídeo ao vivo é o profissional que garante que a imagem certa chegue à tela certa, no momento certo e na qualidade certa. Diferente do editor de pós-produção (que trabalha offline, com tempo), o técnico de vídeo ao vivo opera em tempo real: não há segunda chance. Nesta aula você entende o escopo da função, os papéis que existem dentro de uma operação (VJ, switcher/cortador, operador de mídia server, operador de LED, engenheiro de sinal) e como eles se articulam num evento real, de um culto a um show de arena.</p><ul><li><strong>VJ (Video Jockey):</strong> Profissional que cria e manipula conteúdo visual em tempo real, geralmente sincronizado com a música, usando software como Resolume Arena. É o equivalente visual do DJ: mistura clips, aplica efeitos e reage ao ambiente. Atua muito em festas, raves, shows eletrônicos e cenografia de palco.</li><li><strong>Operador de corte (switcher/TD):</strong> Também chamado de Technical Director em broadcast. Recebe várias fontes (câmeras, slides, vídeos) e decide qual vai para a tela principal e para o telão, fazendo cortes e transições. É a função central em conferências, cultos, transmissões e eventos corporativos.</li><li><strong>Operador de mídia server / playback:</strong> Responsável por reproduzir conteúdo pré-produzido (aberturas, vinhetas, lower-thirds, fundos de palco) de forma confiável e sincronizada. Usa servidores como Watchout, Resolume, Modulo Pi, disguise (d3) ou PlaybackPro.</li><li><strong>Operador de LED / engenheiro de sinal:</strong> Cuida do telão físico: configura o processador de LED, mapeia os módulos, garante resolução e calibração de cor. Em estruturas grandes, é uma especialidade própria.</li><li><strong>Diferença entre ao vivo e pós-produção:</strong> Na pós você renderiza, revisa e refaz. Ao vivo tudo é processado e exibido em frações de segundo (latência baixa é crítica). O erro vai ao ar instantaneamente — por isso redundância, ensaio e checklist são obrigatórios.</li><li><strong>Cadeia de sinal (signal flow):</strong> É o caminho que a imagem percorre: fonte (câmera/computador) → conversor/distribuidor → switcher/mídia server → processador → tela/projetor. Entender essa cadeia é a base de todo diagnóstico de problema.</li><li><strong>Atribuições típicas do cargo:</strong> Mixagem de vídeo ao vivo, mapeamento (mapping), efeitos e transições, integração com áudio (timecode/SMPTE), controle por MIDI e OSC, suporte a múltiplas telas, compatibilidade com diversas fontes e hardware, e flexibilidade para reconfigurar rápido em campo.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Notebook/PC de operação:</strong> Máquina robusta (i7/i9 ou Ryzen 7/9, 32 GB RAM, GPU dedicada) rodando o software de VJ ou playback. É a ''mesa'' do operador moderno.</li><li><strong>Switcher de vídeo (ex.: Blackmagic ATEM, Roland V-60HD):</strong> Mesa de corte que recebe múltiplas fontes e entrega o programa final. Usado pelo operador de corte.</li><li><strong>Monitor de preview/program:</strong> Telas de referência para o operador ver o que está no ar (Program) e o que vem a seguir (Preview), evitando cortar ''às cegas''.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Mapeie os papéis do evento:</strong> Pergunte ao produtor: vai ter câmera ao vivo? Telão de LED ou projeção? Conteúdo pré-produzido? Isso define quantas funções e que equipamento serão necessários.</li><li><strong>2. Desenhe a cadeia de sinal no papel:</strong> Liste todas as fontes (PCs, câmeras, players) e todos os destinos (telão, projetor, gravação, streaming). Una-os com setas. Esse diagrama vira seu mapa de montagem.</li><li><strong>3. Defina a resolução de trabalho:</strong> Escolha a resolução comum do evento (ex.: 1920x1080@60) e garanta que todas as fontes e destinos a suportem, para evitar reescalas e atrasos.</li></ol><p><strong>Na prática:</strong> Num culto médio, o operador de corte fica numa mesa Roland V-60HD recebendo 3 câmeras e o computador da letra/slides; ele corta entre câmeras durante o louvor e abre a letra no telão no momento certo. O telão é LED P3 alimentado por um processador Novastar. Entender que esse computador de slides é só mais uma ''fonte'' na cadeia muda completamente a forma como você diagnostica uma tela preta.</p><h4>Resumo</h4><ul><li>O técnico de vídeo ao vivo entrega a imagem certa, na tela certa, em tempo real, sem segunda chance.</li><li>Existem papéis distintos: VJ, operador de corte, operador de mídia server e operador de LED.</li><li>Tudo começa por entender a cadeia de sinal — fonte, processamento e destino.</li></ul>',25,1,true,true);
