insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('76f7fd6a-ab89-43fa-8d11-89c2d75bd095','802d4d74-e568-4b2d-9f24-fec11e406bd4','Qual a diferença central entre vídeo ao vivo e pós-produção?','No ao vivo o erro vai ao ar instantaneamente; não há renderização nem segunda chance, por isso a redundância é vital.',1,1);
