insert into public.modules (id,course_id,titulo,ordem) values ('41103baa-5f61-434f-8b5b-941ab2c2e82b','c8ee74bd-37a4-4ca1-bac4-00d6535d7a5e','Módulo 2 - Hardware: Computador, Cabos, Conexões e Conversão',2);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('0d50ba2c-29f5-40a2-809c-7e3467852c18','41103baa-5f61-434f-8b5b-941ab2c2e82b','Montando a estação de trabalho de vídeo (PC para VJ/playback)','texto','<p><strong>Para começar:</strong> O computador do VJ não é um PC comum: ele precisa despejar pixels em tempo real sem engasgar. Saber especificá-lo é o que separa um show fluido de um show travado.</p><p>Software como Resolume, Watchout e TouchDesigner são vorazes por GPU, RAM e disco rápido. Esta aula detalha cada componente, por que ele importa para vídeo ao vivo e como dimensionar a máquina para o porte do evento — de uma festa pequena a uma projeção em 4 telas 4K.</p><ul><li><strong>Processador (CPU):</strong> Multicore de última geração (Intel Core i7/i9 ou AMD Ryzen 7/9). Decodifica vídeo, gerencia efeitos e controla o sistema. Para várias camadas simultâneas, mais núcleos ajudam.</li><li><strong>Placa de vídeo (GPU):</strong> O componente mais crítico para VJ. NVIDIA GeForce RTX (ex.: RTX 4070/4080) ou linha profissional (RTX A-series/antiga Quadro) aceleram playback, efeitos e múltiplas saídas. A GPU define quantas camadas e que resolução você roda sem cair de FPS.</li><li><strong>Memória RAM:</strong> Mínimo 32 GB para trabalho profissional. Vídeo em alta resolução e muitos clips carregados consomem muita RAM; pouca memória causa travadas e gargalo.</li><li><strong>Armazenamento SSD/NVMe:</strong> SSD NVMe rápido para sistema e mídia ativa — vídeo 4K exige taxas de leitura altas (centenas de MB/s a GB/s). HDD só para arquivamento, nunca para playback ao vivo.</li><li><strong>Saídas de vídeo e quantidade de displays:</strong> Verifique quantas saídas (HDMI/DisplayPort) a GPU tem. Para várias telas/projetores, pode-se usar GPU com múltiplas saídas ou um expansor como Datapath FX4/Matrox para dividir uma saída em várias regiões.</li><li><strong>Resfriamento e fonte:</strong> Sob carga total a máquina esquenta; refrigeração eficiente evita throttling (queda de desempenho). Fonte de alta qualidade garante energia estável — instabilidade derruba show.</li><li><strong>Conectividade e rede:</strong> Thunderbolt/USB para placas de captura e controladores; rede rápida (Gigabit) para Art-Net/sACN (controle de LED via rede), NDI (vídeo sobre rede) e transferência de mídia.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Notebook de VJ (ex.: laptop com RTX 4080, 32-64 GB, NVMe):</strong> Solução portátil para festas e shows; cuidado com superaquecimento e número limitado de saídas.</li><li><strong>Workstation desktop (ex.: torre com RTX A5000/4090):</strong> Para projeção multicanal e mídia server caseiro; mais saídas, melhor refrigeração, mais estável.</li><li><strong>Datapath FX4 / Matrox TripleHead:</strong> Expansor que pega uma saída da GPU e a divide em até 4 monitores/projetores como uma área de trabalho única — clássico para mapping multitela.</li><li><strong>Placa de captura (ex.: Blackmagic DeckLink/UltraStudio, Magewell):</strong> Entra sinal externo (câmera, outro PC) no software como uma fonte ao vivo.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Dimensione pela carga:</strong> Conte camadas simultâneas, resolução e número de saídas. Quanto maior, mais GPU/RAM/SSD você precisa.</li><li><strong>2. Priorize GPU e disco:</strong> Para VJ, GPU forte e NVMe rápido importam mais que CPU topo de linha.</li><li><strong>3. Confira saídas físicas:</strong> Garanta que há saídas suficientes (ou um expansor) para todas as telas do evento.</li><li><strong>4. Teste sob carga real:</strong> Antes do evento, rode a composição completa por 30+ minutos vendo FPS e temperatura — simule o pior caso.</li><li><strong>5. Desative atualizações e energia:</strong> No SO, desligue updates automáticos, modo de suspensão e economia de energia que possam interromper o show.</li></ol><p><strong>Na prática:</strong> Para um show eletrônico com Resolume rodando 6 camadas de clips 1080p + efeitos, saindo para um telão P3, o operador usa um laptop RTX 4080 com 64 GB e NVMe. Ele desliga o Wi-Fi, fixa o plano de energia em ''alto desempenho'', e monitora o FPS no canto da tela do Resolume — se cair de 60, ele reduz resolução de saída ou simplifica efeitos antes que trave no palco.</p><h4>Resumo</h4><ul><li>Para VJ/playback, GPU e disco NVMe são os componentes mais críticos.</li><li>Mínimo prático: i7/Ryzen 7, 32 GB RAM, NVMe e GPU dedicada.</li><li>Sempre teste sob carga real e desative o que pode interromper o show.</li></ul>',28,1,true,false);
