insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('86ef4086-62d9-4d75-9de3-c1419655f5de','b35615d3-0f23-43e3-874a-3e3830499c04','Por que não usar HDD para playback ao vivo?','Vídeo 4K exige leitura muito rápida; HDD causa travadas. Use NVMe/SSD.',2,1);
