insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('51a9612e-e3cc-4461-b24e-96bf4cb340c0','b35615d3-0f23-43e3-874a-3e3830499c04','O que fazer no SO antes do show?','Qualquer interrupção do SO pode derrubar o show; desative tudo que pode pausar a máquina.',4,1);
