insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('fa06ff72-ad21-4e9c-8629-3d832ee32ebc','acb322e2-3dab-4f39-a2f8-d15f8e2d97e9','O que pode causar tela preta com material de streaming/Blu-ray?','Proteção HDCP não passa em muitos equipamentos profissionais, causando tela preta.',4,1);
