insert into public.modules (id,course_id,titulo,ordem) values ('174bb92d-4026-47e8-9690-b226a38377c6','c8ee74bd-37a4-4ca1-bac4-00d6535d7a5e','Módulo 3 - Telas, Telões de LED e Projeção',3);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('afbd3452-6272-4f3c-82b3-acc06ca9e63e','174bb92d-4026-47e8-9690-b226a38377c6','Tecnologias de tela: LCD, LED, OLED e a escolha por aplicação','texto','<p><strong>Para começar:</strong> Cada tela funciona de um jeito físico diferente, e isso muda brilho, contraste, ângulo e onde ela pode ser usada. Entender a tecnologia evita escolhas erradas.</p><p>O técnico de vídeo precisa saber não só operar, mas recomendar a tela certa. Esta aula percorre as principais tecnologias de display, suas vantagens e limites, com foco no que importa para evento ao vivo: brilho, contraste, ângulo de visão e uso interno x externo.</p><ul><li><strong>LCD:</strong> Cristais líquidos modulam a luz de um backlight (geralmente LED). Boa cor e contraste, custo acessível. Em eventos aparece como monitores, TVs de apoio e painéis de sinalização. Limite: brilho insuficiente para sol forte e molduras (bezels) ao montar videowall.</li><li><strong>LED (painel emissivo):</strong> Cada ponto é formado por LEDs que emitem a própria luz — é o telão de palco moderno. Altíssimo brilho (1.000 a 5.000+ nits), modular (monta-se qualquer tamanho/forma), sem moldura entre módulos. Domina shows, igrejas e arenas.</li><li><strong>OLED:</strong> Cada pixel emite sua própria luz, com pretos absolutos e cores vibrantes; telas finas e até flexíveis. Comum em TVs premium e celulares; em evento aparece menos por custo e tamanho, mas excelente para cenografia refinada.</li><li><strong>Plasma e outras legadas:</strong> Plasma teve boa cor e ângulo, mas alto consumo e desgaste; praticamente extinto. E-ink, transparente e curva são nichos (vitrine, cenografia, sinalização).</li><li><strong>Brilho (nits) e ambiente:</strong> Telas internas pedem menos brilho; sol direto exige LED de alto brilho (outdoor 5.000+ nits). Brilho insuficiente ''lava'' a imagem no claro.</li><li><strong>Ângulo de visão e uniformidade:</strong> Em eventos o público vê de muitos ângulos; LED e OLED mantêm cor; LCD pode perder contraste nas laterais. Uniformidade de cor entre módulos exige calibração.</li><li><strong>Videowall de LCD vs LED:</strong> Videowall de LCD tem molduras finas mas visíveis (linhas pretas); LED não tem emendas visíveis, por isso é preferido para imagem contínua grande.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Painel de LED indoor (ex.: pixel pitch P2/P2.5/P3):</strong> Para palco interno e câmeras próximas; pitch menor = mais resolução por metro.</li><li><strong>Painel de LED outdoor (ex.: P4/P6+, alto brilho/IP):</strong> Para externo, com vedação contra chuva e brilho alto para o sol.</li><li><strong>Monitor/TV LCD profissional:</strong> Apoio de palco, confidence monitor, sinalização; barato e simples.</li><li><strong>Display OLED:</strong> Cenografia premium e estandes onde preto profundo e finura importam.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Defina interno ou externo:</strong> Externo/sol → LED de alto brilho e à prova d''água (IP). Interno → pitch menor e brilho moderado.</li><li><strong>2. Calcule a distância de visão:</strong> Quanto mais perto o público, menor o pixel pitch necessário para não ''ver os pontos''.</li><li><strong>3. Decida imagem contínua x informativa:</strong> Imagem grande contínua → LED sem emendas. Painéis informativos isolados → LCD pode bastar.</li><li><strong>4. Considere câmera no recinto:</strong> Se o telão será filmado, exija LED com refresh alto para evitar faixas pretas na captação.</li></ol><p><strong>Na prática:</strong> Para um culto interno onde a câmera filma o pastor com o telão ao fundo, escolhe-se LED P3 com refresh acima de 1920 Hz: o pitch garante boa resolução para a distância da plateia, e o refresh alto evita que a câmera capture scan lines no telão atrás dele.</p><h4>Resumo</h4><ul><li>LED emissivo domina o palco por brilho, modularidade e ausência de emendas.</li><li>LCD é apoio barato; OLED é cenografia premium; plasma está extinto.</li><li>Pixel pitch, brilho e refresh dependem da distância, da luz e da presença de câmera.</li></ul>',24,1,true,false);
