insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('9d5f181a-170a-4593-919d-5a119a3b25d1','174bb92d-4026-47e8-9690-b226a38377c6','Projeção: tipos, projetores, lúmens e cálculo de imagem','texto','<p><strong>Para começar:</strong> Projetar bem é equilibrar luz, distância e superfície. Errar lúmens ou lente arruína a imagem mesmo com ótimo conteúdo.</p><p>Projeção continua essencial em mapping, cenários e ambientes onde o LED não cabe ou não convém. Esta aula cobre os tipos de projeção, as tecnologias de projetor (DLP, LCD, laser), o conceito de lúmens, throw ratio (distância x tamanho) e o passo a passo para dimensionar uma imagem projetada.</p><ul><li><strong>Projeção frontal x traseira:</strong> Frontal: projetor na frente da tela (mais comum, mas cria sombra se alguém passa). Traseira (rear): projetor atrás de tela translúcida, sem sombra e visual limpo — ótima para palco e cenografia.</li><li><strong>Distância de projeção (throw):</strong> Curta, ultracurta e longa distância. Ultracurta projeta colado à parede (sem sombra, bom para espaço apertado); longa distância joga de longe. O ''throw ratio'' relaciona distância x largura da imagem.</li><li><strong>Projeção mapeada (mapping), imersiva e panorâmica:</strong> Mapping projeta sobre superfícies 3D/irregulares com software de alinhamento. Panorâmica/imersiva usa vários projetores com blend (mistura suave nas bordas) para cobrir grandes superfícies.</li><li><strong>Tecnologias: DLP, LCD e laser:</strong> DLP usa micro-espelhos (bom contraste, robusto); 3LCD usa três painéis (cores vivas). Fonte de luz: lâmpada (barata, troca periódica) ou laser (mais brilho estável, vida longa, ligar/desligar rápido) — laser é o padrão profissional atual.</li><li><strong>Lúmens (brilho):</strong> Mede o fluxo luminoso. Quanto mais luz ambiente e maior a imagem, mais lúmens você precisa. Sala escura pequena: alguns milhares; palco com luz e tela grande: 10.000-30.000+ lúmens.</li><li><strong>Lentes e zoom:</strong> Projetores profissionais têm lentes intercambiáveis (curta, padrão, tele) e lens shift (desloca a imagem sem mover o projetor). A lente certa permite posicionar o projetor onde der e ainda cobrir a tela.</li><li><strong>Keystone e blending:</strong> Keystone corrige a distorção trapezoidal quando o projetor não está perpendicular (use com parcimônia — degrada). Blending suaviza a emenda entre projetores numa imagem grande única.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Projetor laser profissional (ex.: Epson, Panasonic, Barco, 10k-30k lúmens):</strong> Alto brilho e estabilidade para palco e mapping; lente intercambiável e lens shift.</li><li><strong>Lente intercambiável (curta/padrão/tele):</strong> Escolhida pelo throw ratio para cobrir a tela a partir da posição possível do projetor.</li><li><strong>Tela de projeção frontal/rear:</strong> Frontal reflexiva ou rear translúcida; o ganho da tela e o tipo afetam brilho e ângulo.</li><li><strong>Mídia server / software de mapping (Resolume, MadMapper, Watchout):</strong> Faz warp, mask e blend para alinhar a projeção à superfície e juntar projetores.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Meça a tela e o ambiente:</strong> Defina largura desejada da imagem e quanta luz ambiente há — isso dita os lúmens.</li><li><strong>2. Calcule lúmens necessários:</strong> Imagem maior + ambiente mais claro = mais lúmens. Some margem para não ficar ''lavado''.</li><li><strong>3. Defina a distância e a lente (throw ratio):</strong> Com a distância possível e a largura da imagem, escolha a lente certa (curta/padrão/tele) usando o throw ratio do fabricante.</li><li><strong>4. Posicione e foque:</strong> Monte o projetor, use lens shift/zoom para enquadrar sem keystone se possível; foque com um test pattern de grade.</li><li><strong>5. Faça mapping/blend se necessário:</strong> No software, ajuste warp e mask para a superfície; em multiprojetor, faça o blend das bordas.</li><li><strong>6. Calibre brilho/cor:</strong> Iguale brilho e cor entre projetores e ao ambiente; verifique com imagem real.</li></ol><p><strong>Na prática:</strong> Para projetar atrás de um palco numa tela rear de 8 m de largura, com alguma luz de palco, o técnico escolhe um projetor laser de ~20.000 lúmens, calcula pelo throw ratio que precisa de uma lente curta porque o espaço atrás é apenas 6 m, posiciona, foca com grade e usa lens shift para centralizar sem keystone. A projeção rear elimina sombras dos artistas que passam na frente.</p><h4>Resumo</h4><ul><li>Lúmens e ambiente andam juntos: mais luz e tela maior exigem mais brilho.</li><li>Throw ratio e lentes definem de onde dá para cobrir a tela; lens shift evita keystone.</li><li>Projeção rear elimina sombras; mapping e blend juntam superfícies e projetores.</li></ul>',28,3,true,false);
