insert into public.modules (id,course_id,titulo,ordem) values ('7c771dd8-b14e-4148-8a1c-f503ffb892eb','c8ee74bd-37a4-4ca1-bac4-00d6535d7a5e','Módulo 4 - Switchers e Mixagem de Vídeo ao Vivo',4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('015f5acc-0d96-43ca-920c-1184115b904e','7c771dd8-b14e-4148-8a1c-f503ffb892eb','Mesas de corte (switchers): ATEM e Roland na prática','texto','<p><strong>Para começar:</strong> O switcher é o coração da operação ao vivo: é nele que você decide, em tempo real, o que o mundo vê. Dominar o corte é dominar o evento.</p><p>Esta aula ensina o conceito e a operação prática de um switcher de vídeo: barramentos de Program e Preview, cut, dissolve, wipe, keyer (chroma/luma), PIP, e os fluxos das mesas mais comuns — Blackmagic ATEM e Roland V-60HD/V-800HD. Você termina sabendo configurar e cortar um evento.</p><ul><li><strong>O que é um switcher:</strong> Mesa que recebe várias fontes (câmeras, PCs, players) e seleciona/mixa qual vai para a saída de programa (o que vai ao ar). Substitui ligar/desligar cabos por uma troca instantânea e limpa.</li><li><strong>Program e Preview (barramentos):</strong> Program (PGM) é o que está no ar agora. Preview (PVW/PST) é o que você prepara para entrar a seguir. Você seleciona a próxima fonte no Preview e a ''leva'' ao ar com cut ou transição — nunca corta às cegas.</li><li><strong>Cut, Dissolve (Mix) e Wipe:</strong> Cut = troca instantânea (corte seco). Dissolve/Mix = transição suave com fade entre fontes. Wipe = uma fonte ''empurra/varre'' a outra com forma geométrica. A barra T (T-bar) controla transições manualmente.</li><li><strong>Keyer: chroma key e luma key:</strong> Keyer sobrepõe uma fonte sobre outra removendo uma cor (chroma, ex.: fundo verde) ou por luminância (luma, ex.: logo branco sobre preto). Usado para legendas, logos e personagens sobre fundo.</li><li><strong>PIP (Picture-in-Picture) e DSK:</strong> PIP coloca uma imagem menor sobre outra (ex.: câmera no canto). DSK (Downstream Keyer) sobrepõe gráficos/lower-thirds ''por cima de tudo'', sem afetar as transições principais.</li><li><strong>Multiview e tally:</strong> Multiview mostra todas as fontes + PGM/PVW num só monitor para o operador. Tally é a luzinha vermelha que acende na câmera que está no ar, avisando o cinegrafista.</li><li><strong>Macros e AUX:</strong> Macros gravam sequências de ações para repetir com um botão. Saídas AUX entregam um sinal específico (ex.: só o telão, sem os gráficos do streaming).</li><li><strong>ATEM vs Roland (filosofias):</strong> ATEM (Blackmagic) é muito usado em streaming/igrejas, controlado por painel físico ou pelo software ATEM Software Control. Roland (V-60HD/V-800HD) é robusto, com muitos controles físicos e scaling por entrada, popular em eventos corporativos e ao vivo.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Blackmagic ATEM Mini Pro / Extreme:</strong> Switcher HDMI compacto com streaming embutido, multiview e DSK; ótimo para igrejas e lives. Controlado por software ou painel.</li><li><strong>Blackmagic ATEM Television Studio / Constellation:</strong> Switchers SDI maiores para produções broadcast com mais entradas e keyers.</li><li><strong>Roland V-60HD:</strong> Switcher HD com scaling por entrada, 6 entradas (HDMI/SDI), PinP, key e controles físicos — clássico de eventos ao vivo.</li><li><strong>Roland V-800HD MK II:</strong> Switcher maior para grandes eventos, multicamadas e processamento robusto.</li><li><strong>Monitor de multiview:</strong> Tela que mostra todas as fontes + PGM/PVW para o operador cortar com segurança.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Conecte e identifique as fontes:</strong> Ligue câmeras/PCs nas entradas; nomeie cada entrada (CAM1, SLIDES, VT) no switcher para não se perder.</li><li><strong>2. Case resolução e frame rate:</strong> Configure o formato do switcher (ex.: 1080p60) e garanta que todas as fontes batem; no Roland, use o scaler por entrada para fontes diferentes.</li><li><strong>3. Configure o programa de saída:</strong> Defina a saída de PGM para o telão/gravação/stream; configure AUX se o telão precisar de um corte diferente do stream.</li><li><strong>4. Prepare keys e DSK:</strong> Monte chroma/luma key se houver; carregue lower-thirds/logo no DSK para sobrepor sem atrapalhar o corte.</li><li><strong>5. Ensaie o corte:</strong> Selecione no Preview a próxima fonte e leve ao ar com cut ou dissolve pela T-bar; observe o tally e o multiview.</li><li><strong>6. Grave macros das jogadas repetidas:</strong> Para sequências fixas (ex.: abrir letra + DSK do nome), grave uma macro e dispare com um botão.</li></ol><p><strong>Na prática:</strong> Num culto, o operador num Roland V-60HD tem CAM1 (geral), CAM2 (pastor), CAM3 (plateia) e o PC de letras. Ele deixa CAM2 no PGM durante a pregação, prepara CAM3 no Preview e dá um dissolve suave para a plateia num momento de aplauso, depois sobrepõe a referência bíblica via DSK. Tudo guiado pelo multiview, com o tally avisando os cinegrafistas qual câmera está no ar.</p><h4>Resumo</h4><ul><li>Program é o que está no ar; Preview é o que você prepara — nunca corte às cegas.</li><li>Cut, dissolve e wipe são as transições; keyer e DSK sobrepõem logos e gráficos.</li><li>ATEM brilha em streaming/igreja; Roland é robusto com scaling e controles físicos.</li></ul>',34,1,true,false);
