insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('9674d1bc-374b-4f86-8086-4ff82a70537d','66630888-7811-4623-b3e8-4ec648f977e8','Por que usar um servidor de backup?','A redundância garante que o show continue mesmo se o server principal cair.',4,1);
