insert into public.modules (id,course_id,titulo,ordem) values ('501170b7-a1b4-4ff2-a552-eadc32374042','c8ee74bd-37a4-4ca1-bac4-00d6535d7a5e','Módulo 5 - Video Mapping, Edição e Conteúdo',5);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('3fcd525f-7bb3-4a36-b52c-3806a5702d90','501170b7-a1b4-4ff2-a552-eadc32374042','Video mapping: warp, mask, blending e o passo a passo','texto','<p><strong>Para começar:</strong> Mapping é transformar qualquer objeto numa tela. A mágica vem do alinhamento preciso entre o conteúdo e a geometria real da superfície.</p><p>Video mapping (projeção mapeada) projeta imagem sobre superfícies 3D ou irregulares — prédios, cenários, objetos — fazendo o conteúdo ''vestir'' a forma. Esta aula explica os conceitos (warp, mask, mesh, blend) e dá um passo a passo de um mapping simples usando MadMapper/Resolume.</p><ul><li><strong>Conceito de mapping:</strong> Em vez de uma tela retangular plana, você projeta sobre uma forma real e deforma o conteúdo para que cada parte caia exatamente sobre a superfície correspondente.</li><li><strong>Warp (deformação):</strong> Ajusta os cantos e a malha da imagem para encaixar na perspectiva da superfície (correção de keystone e distorção). Você arrasta pontos até a imagem ''colar'' no objeto.</li><li><strong>Mask (máscara):</strong> Recorta a projeção para que a luz só apareça onde deve (na fachada, no objeto) e não vaze para o entorno. Define o contorno exato da área projetada.</li><li><strong>Slices e mesh:</strong> A composição é fatiada em slices, cada um mapeado para uma parte da superfície. Mesh warping usa uma grade flexível para superfícies curvas/irregulares.</li><li><strong>Blending (soft-edge):</strong> Quando vários projetores cobrem uma superfície grande, sobrepõem-se as bordas e o software suaviza a emenda (blend) para parecer uma imagem única, sem linha mais clara.</li><li><strong>Conteúdo feito para a forma:</strong> O conteúdo precisa ser produzido considerando a geometria: elementos animados que respeitam arestas, janelas, colunas. Um modelo/template da superfície guia o designer.</li><li><strong>Alinhamento e ajuste fino:</strong> Projeta-se uma grade sobre o objeto e ajusta-se warp/mask até cada linha cair na aresta certa; pequenos deslocamentos quebram a ilusão.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>MadMapper (software):</strong> Especializado em mapping: warp, mask, mesh, slices e saída multi-projetor com blend. Interface focada em superfícies.</li><li><strong>Resolume Arena (Advanced Output):</strong> Faz slicing, warp, mask e soft-edge no Output, unindo VJing e mapping num só software.</li><li><strong>Projetor laser com lens shift:</strong> Permite posicionar o projetor e alinhar a imagem ao objeto sem keystone excessivo.</li><li><strong>HeavyM / Millumin:</strong> Alternativas de mapping; HeavyM é simples para iniciantes, Millumin é forte em teatro/instalações.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Modele a superfície:</strong> Tire fotos/medidas do objeto e crie um template com suas formas para o designer produzir o conteúdo certo.</li><li><strong>2. Posicione o projetor:</strong> Coloque o projetor cobrindo toda a superfície, usando lens shift para minimizar keystone.</li><li><strong>3. Projete uma grade de alinhamento:</strong> Mande um test pattern de grade sobre o objeto para enxergar a deformação real.</li><li><strong>4. Crie slices e faça warp:</strong> No software, fatie a composição e arraste os cantos de cada slice até alinhar com as arestas do objeto.</li><li><strong>5. Aplique máscaras:</strong> Recorte a projeção para a luz só atingir a superfície desejada, sem vazamento.</li><li><strong>6. Faça blending se multiprojetor:</strong> Sobreponha as bordas dos projetores e ajuste o soft-edge até a emenda sumir.</li><li><strong>7. Rode o conteúdo e ajuste fino:</strong> Toque o conteúdo real e corrija pequenos desalinhamentos até a ilusão ficar perfeita.</li></ol><p><strong>Na prática:</strong> Para mapear uma fachada com três janelas, o técnico mede a fachada, cria um template e pede ao designer animações que ''acendem'' as janelas. No MadMapper, ele fatia a imagem em slices (uma por janela + a parede), faz warp de cada slice até casar com as arestas reais e mascara o entorno para a luz não vazar na calçada. Uma grade de alinhamento garante que cada animação caia exatamente na janela certa.</p><h4>Resumo</h4><ul><li>Mapping deforma o conteúdo (warp) e recorta (mask) para vestir uma superfície real.</li><li>Slices, mesh e blending permitem cobrir formas complexas e grandes com vários projetores.</li><li>O conteúdo precisa ser feito para a geometria, com alinhamento fino guiado por grade.</li></ul>',32,1,true,false);
