insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('dc87d3a0-473f-439f-877c-bf41fc9cb9ce','51078ff3-8755-421e-9f8e-98a9a0d1a6a6','Por que exportar na resolução exata do destino?','Casar a resolução evita scaling no palco, que adiciona latência e borra a imagem.',4,1);
