insert into public.modules (id,course_id,titulo,ordem) values ('eb4fb5d5-6ced-47c6-b160-34fe56469aff','c8ee74bd-37a4-4ca1-bac4-00d6535d7a5e','Módulo 6 - Projeto, Operação e Documentação Profissional',6);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('1659c14b-12d7-40e3-aede-ec54126a8bea','eb4fb5d5-6ced-47c6-b160-34fe56469aff','Conceitos avançados: resolução de trabalho, encode, formato e gestão de mídia','texto','<p><strong>Para começar:</strong> Organização e padronização técnica são o que separam o amador do profissional. Aqui você consolida resolução, encode e a gestão da mídia do evento.</p><p>Esta aula amarra os conceitos técnicos com a prática de organização: como padronizar resolução e encode do projeto inteiro, escolher formatos, e gerir mídia e armazenamento para que nada se perca ou trave no dia do evento.</p><ul><li><strong>Resolução de trabalho do projeto:</strong> Padronize uma resolução-mãe coerente com os destinos (telão/projeção). Produza e exporte tudo nela para evitar reescala em cadeia.</li><li><strong>Encode e bitrate:</strong> Encode é como o vídeo é comprimido. Bitrate alto = mais qualidade e peso; baixo = leve mas com artefatos. Para playback ao vivo, prefira codecs intra-frame (HAP/ProRes) a inter-frame muito comprimido (H.264 pesado), que exige mais da CPU.</li><li><strong>Formato e contêiner:</strong> Contêiner (MP4, MOV) embala vídeo+áudio; codec é a compressão interna. Saber a dupla certa (ex.: MOV+ProRes, MOV/AVI+HAP) garante compatibilidade com o software de playback.</li><li><strong>Pixels, profundidade de cor e gamut:</strong> Além da contagem, importa profundidade de bits (8/10 bits) e espaço de cor. 10 bits evita banding em degradês; o telão/processador deve suportar.</li><li><strong>Gestão de mídia e nomenclatura:</strong> Nomeie arquivos com clareza (evento_cena_versao_resolucao) e versione (v1, v2, final). Evite ''final_final2'' — use convenção e datas.</li><li><strong>Armazenamento e backup:</strong> SSD/NVMe para mídia ativa, HDD/rede para arquivo. Tenha pelo menos duas cópias (3-2-1: 3 cópias, 2 mídias, 1 fora do local). Leve a mídia do evento em mais de um pendrive/SSD.</li><li><strong>Organização de pastas:</strong> Estrutura padrão: /Conteúdo, /Masters, /Export_Telao, /Backup. Pastas claras aceleram a montagem e evitam rodar o arquivo errado ao vivo.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>SSD/NVMe externo (ex.: Samsung T7/T9, NVMe em case):</strong> Mídia ativa do evento com leitura rápida; leve duplicado como backup.</li><li><strong>NAS / HD de rede:</strong> Arquivo central e backup do projeto, acessível pela equipe.</li><li><strong>Software de transcode (Media Encoder, Shutter Encoder):</strong> Converte/padroniza arquivos para o codec/resolução do evento (ex.: gerar HAP de tudo).</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Defina o padrão técnico do projeto:</strong> Fixe resolução-mãe, frame rate, codec e contêiner para todo o conteúdo.</li><li><strong>2. Transcode tudo para o padrão:</strong> Converta os arquivos recebidos para o codec/resolução do evento, eliminando surpresas no palco.</li><li><strong>3. Padronize a nomenclatura:</strong> Aplique uma convenção de nomes e versões clara em todos os arquivos.</li><li><strong>4. Estruture as pastas:</strong> Organize em pastas de conteúdo, masters, export e backup.</li><li><strong>5. Faça backup 3-2-1:</strong> Mantenha 3 cópias em 2 mídias com 1 fora do local; leve a mídia do evento duplicada.</li><li><strong>6. Valide no playback:</strong> Abra os arquivos finais no software do evento e confirme que rodam liso.</li></ol><p><strong>Na prática:</strong> Antes de um show, o técnico recebe vídeos em formatos variados (MP4 H.264, MOV ProRes, alguns 30p, outros 24p). Ele transcoda tudo para HAP 1536x768 a 60p no Shutter Encoder, nomeia como ''show_musica03_v2_1536x768.mov'', organiza em /Export_Telao, e leva em dois SSDs idênticos. No palco, tudo roda liso no Resolume porque está padronizado — nada de reescala ou codec pesado travando.</p><h4>Resumo</h4><ul><li>Padronize resolução, frame rate, codec e contêiner em todo o projeto.</li><li>Para playback ao vivo, prefira codecs intra-frame leves (HAP/ProRes) a H.264 pesado.</li><li>Nomenclatura, pastas e backup 3-2-1 evitam rodar o arquivo errado ou perder mídia.</li></ul>',24,1,true,false);
