insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c5b3c3c2-301c-4c24-8206-2cd7135338d6','f9060998-b1b7-4af1-8d61-cbaaa4da1851','Por que evitar H.264 muito comprimido em muitas camadas ao vivo?','H.264 inter-frame exige mais processamento; HAP/ProRes intra-frame são mais leves ao vivo.',2,1);
