insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('bb032e5f-f577-4872-bbe3-9b04d008f54f','8f08a1f8-490c-4ea2-b4d1-a972ff56aee1','Por que verificar licenças do conteúdo?','Músicas, vídeos e fontes de terceiros podem exigir licença de uso.',4,1);
