insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('1f55737e-089c-4197-9d0b-bcd4dda97dc8','8f08a1f8-490c-4ea2-b4d1-a972ff56aee1','Qual a função do mapa de sinal na documentação?','O diagrama de cabeamento guia a montagem e permite achar falhas rapidamente.',5,1);
