insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('4026ad09-fd64-44f7-a5a3-74b3f1eaba7d','858b03b2-1a18-4607-a146-d90b66aee43b','Qual a diferença entre output mapping e projection mapping?','Output mapping organiza qual pedaço vai para qual saída; projection mapping warpa/alinha a imagem com a geometria física da superfície.',1,1);
