insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('31c3d625-615d-4e31-a3d4-987044b347c2','858b03b2-1a18-4607-a146-d90b66aee43b','Qual sistema é tipicamente baseado em timeline e usado em museus e instalações fixas?','O Watchout é referência em display multitela por timeline, comum em exposições e instalações permanentes.',2,1);
