insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('05dc88c9-1ed1-4574-87e5-1189abd4287b','763ab410-5817-47c7-908b-401774f03190','Por que o refresh rate alto importa quando há câmera filmando o painel?','Câmeras captam o flicker de painéis com refresh baixo como faixas; refresh alto (3840 Hz+) elimina esse artefato na imagem.',3,1);
