insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('9f606238-4fb7-48f6-b413-7a0a2548d7f3','763ab410-5817-47c7-908b-401774f03190','Para um telão outdoor com público a 15 m sob sol forte, o que faz mais sentido?','A 15 m, um pitch maior (P6/P10) é suficiente, e o alto brilho (4000-6000 nits) é necessário para vencer a luz do sol.',5,1);
