insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('de6d75a6-89d6-41d8-af76-c794a8003d41','8692c8a6-cec5-4b69-a987-bdd62799db14','Por que dimensionar lumens com folga em mapping de prédio?','Paredes coloridas/escuras e perdas de distância e lente reduzem o brilho útil, então se projeta com folga (e/ou stacking).',4,1);
