insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('69bc2765-9f01-446f-833f-8c5005f2a282','66ed803d-5d56-454a-b40a-0d2c71929d17','Quando a saída SDI é preferível à HDMI numa câmera?','SDI usa BNC, suporta cabos longos e conexão travada, sendo o padrão profissional para distâncias e confiabilidade.',5,1);
