insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5a798e4d-b3b5-45d8-a2fa-465dbe33c798','8ff670d6-912e-4661-8d4f-2e2d9a0da944','Qual a principal vantagem do NDI?','NDI leva vídeo/áudio/controle por rede IP, permitindo muitas fontes num cabeamento simples — desde que a rede seja bem dimensionada.',4,1);
