  ('831af45f-bd33-487c-8149-e11e72741d34','Pleno — Efeito','pleno-efeito','Curso Pleno — Efeito — SMU PRO','pleno','efeitos','{}','free',765,21,false,false,7);
insert into public.modules (id,course_id,titulo,ordem) values ('bb447714-3bca-4577-90fa-28f8caf7627e','831af45f-bd33-487c-8149-e11e72741d34','Módulo 1 — Fundamentos da Pirotecnia e Efeitos Especiais para Eventos',1);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('9ed75ad0-3e86-4a07-84d0-f1b022eafc3f','bb447714-3bca-4577-90fa-28f8caf7627e','Introdução ao ofício: arte, ciência e responsabilidade do operador de efeitos','texto','<p><strong>Para começar:</strong> Antes de qualquer faísca, existe um profissional treinado, calmo e disciplinado. É dele que este curso trata.</p><p>A pirotecnia e os efeitos especiais de palco unem química, física, engenharia, arte e — acima de tudo — gestão de risco. Esta aula define o que é o operador de efeitos (também chamado técnico de efeitos especiais ou pirotécnico), o escopo da profissão e por que a segurança é o eixo central de tudo o que faremos no curso PLENO EFEITO. Você não é apenas alguém que ''aperta o botão'': você é o responsável técnico por uma operação de alto risco que envolve público, artistas, estruturas e patrimônio.</p><ul><li><strong>O que é o operador de efeitos:</strong> É o profissional que projeta, monta, opera e desmonta efeitos visuais e sensoriais em eventos ao vivo — fogos de artifício, faíscas frias, jatos de CO2, fumaça, fogo controlado, confete e serpentina, painéis e iluminação. O ofício combina sensibilidade artística (criar emoção e impacto) com rigor técnico (química dos compostos, distâncias de segurança, sincronização). Acima de tudo, é uma função de responsabilidade legal: a assinatura do responsável técnico responde por incidentes.</li><li><strong>A fusão entre ciência e criatividade:</strong> Cada efeito é o resultado de princípios físico-químicos: oxidantes e combustíveis gerando luz e calor, gases sob pressão produzindo nuvens, retardos pirotécnicos definindo o tempo. O operador traduz uma ideia artística (''quero uma cascata dourada caindo do teto no refrão'') em parâmetros técnicos seguros (qual produto, qual distância, qual ângulo, qual cue).</li><li><strong>Segurança em primeiro lugar — sempre:</strong> A pirotecnia é classificada como atividade de ALTO RISCO porque manipula materiais combustíveis e explosivos, gases pressurizados e fontes de calor intenso. Nenhum efeito vale um acidente. A cultura de segurança não é um anexo do curso: é o curso. Toda decisão criativa passa pelo filtro ''isto é seguro para público, equipe, artistas e local?''.</li><li><strong>Domínio da sincronia temporal:</strong> O tempo é variável crítica. Um disparo fora do tempo arruína o impacto e pode ser perigoso. O operador é o ''maestro temporal'' que sincroniza efeitos com música, luz e vídeo — manualmente ou via time code. Compreender retardos (delays) inerentes a cada produto é parte essencial do planejamento.</li><li><strong>Trabalho em equipe e cadeia de comando:</strong> Efeitos nunca são operação solo. Há diálogo com produção, direção de palco, sonoplastia, iluminação, segurança do evento, brigada de incêndio e bombeiros. Comunicação clara, cues combinados e hierarquia de decisão (quem aborta o show?) são tão importantes quanto o equipamento.</li><li><strong>Ética e conformidade:</strong> O operador profissional jamais improvisa em segurança, jamais opera sem licença, jamais usa produto vencido ou fora de norma, e jamais cede à pressão de produção para ''fazer mais barato'' ou ''mais perto do público''. A responsabilidade ética protege vidas e a própria carreira.</li></ul><p><strong>Na prática:</strong> Em um briefing real, um produtor pede ''fogos bem perto da plateia, no estádio lotado''. O operador profissional não responde ''sim'' nem ''não'' de imediato: ele anota o desejo artístico, mede o local, calcula a distância de segurança exigida pelo tamanho do produto, verifica a legislação e só então propõe uma solução segura equivalente (por exemplo, faíscas frias indoor em vez de shells aéreos). Saber dizer ''isso eu faço de outra forma, com segurança'' é a marca do profissional.</p><h4>Resumo</h4><ul><li>O operador de efeitos une arte, ciência e responsabilidade legal.</li><li>Segurança é o eixo central de todo o ofício, não um detalhe.</li><li>Sincronia, trabalho em equipe e ética definem o profissional completo.</li></ul>',25,1,true,true);
