insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('94f56a4f-82af-4243-91eb-32582918ca3f','0b78febb-dd29-4d78-a1f0-3269ef56eb99','Por que a pirotecnia é classificada como atividade de alto risco?','O risco vem da natureza dos materiais e das energias envolvidas — por isso a segurança é central.',1,1);
