insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0163a06c-f8a2-433a-9ac0-dcb1477f8134','8bef7fde-c29f-4596-a067-a31c80eb4b8a','Qual efeito é adequado para um palco fechado com público próximo?','Faíscas frias são projetadas para baixa temperatura e uso indoor controlado; shells e cascatas são outdoor.',1,1);
