insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('eafa5e08-d945-41e4-9e10-226f8a8ea49d','8bef7fde-c29f-4596-a067-a31c80eb4b8a','Por que NÃO se deve usar um gerb pirotécnico comum em ambiente fechado?','Em ambiente fechado usa-se efeito certificado indoor (fonte de palco ou faísca fria).',4,1);
