insert into public.modules (id,course_id,titulo,ordem) values ('3483b982-8d99-4858-83ee-3896f6f3dc4b','831af45f-bd33-487c-8149-e11e72741d34','Módulo 2 — Química, Comportamento e Tempo dos Efeitos',2);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('9ca798bd-6672-4d30-a61d-36d680b0d994','3483b982-8d99-4858-83ee-3896f6f3dc4b','Como funciona um artefato pirotécnico: composição, cargas e ignição','texto','<p><strong>Para começar:</strong> Entender o que acontece dentro do tubo é o que separa o operador seguro do amador.</p><p>Para operar com segurança você precisa compreender a anatomia de um efeito: a composição pirotécnica, as diferentes cargas (projeção, abertura, efeito), o iniciador e o retardo. Esta aula explica esses elementos com base na norma técnica brasileira, sem entrar em fabricação — o operador de eventos compra produto homologado, não produz pólvora.</p><ul><li><strong>Composição pirotécnica:</strong> Mistura de um oxidante (que fornece oxigênio) e um combustível, capaz de produzir efeitos de projeção, propulsão, som, luz, fumaça ou combinações. Exemplos da norma: pólvora negra, pólvora branca, mistos fumígenos, mistos de retardo, mistos de iniciação, cargas de efeito. O operador não manipula essas misturas a granel; ele lida com o produto acabado e lacrado.</li><li><strong>As cargas de um shell:</strong> Carga de projeção/propulsão: impulsiona a shell para fora do morteiro (tipicamente pólvora negra). Carga de abertura: rompe a shell no ápice e espalha as baladas/estrelas. Carga de efeito: responsável pelo efeito final (cor, brilho, estalo). Entender essa sequência explica por que existe um retardo entre o disparo e o efeito no céu.</li><li><strong>Iniciador e ignição:</strong> O iniciador (igniter/estopim) é o dispositivo que, por chama, fricção, percussão ou corrente elétrica, dá o calor inicial. No mundo profissional usa-se o iniciador elétrico (e-match): a mesa de disparo envia corrente que aquece um filamento e acende o produto. A norma identifica o iniciador comum por coloração marrom-escura e o elétrico por cor laranja ou marrom-escuro, protegido contra disparo acidental por eletricidade estática.</li><li><strong>Retardo pirotécnico:</strong> Dispositivo de queima lenta que cria um tempo de espera entre a iniciação e a carga de abertura/efeito, compatível com segurança e com o efeito desejado. É o que faz a shell explodir na altura certa, e não no chão. O operador precisa conhecer esse tempo para sincronizar.</li><li><strong>Tubo de lançamento (morteiro):</strong> Tubo de carregamento antecarga, em papel, plástico de alta densidade ou fibra de vidro, dimensionado para suportar a pressão de serviço. Fibra de vidro é o padrão profissional moderno por resistência. Nunca se usa tubo improvisado, danificado ou de material proibido.</li><li><strong>O que o operador NÃO faz:</strong> Não altera composições, não abre produtos, não remenda estopins, não improvisa cargas. A norma brasileira proíbe substâncias perigosas em fogos (arsênio, cloratos fora de exceções, chumbo, mercúrio, ácido pícrico etc.). Confiar no produto homologado e íntegro é parte da segurança.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Iniciador elétrico / e-match:</strong> Cabeça pirotécnica com dois fios; a mesa envia corrente e ele acende o produto. Parâmetros da norma: corrente máxima de NÃO-iniciação 0,300 A por no mínimo 5 min; corrente mínima de iniciação 0,600 A por 10 ms; cabos com no mínimo 5 m. Manuseado com o sistema em modo seguro (sem energia) até o momento do disparo.</li><li><strong>Morteiro de fibra de vidro (tubo de lançamento):</strong> Tubo profissional para shells, reforçado com epóxi (resistência mínima conforme norma). Mais seguro que papel/plástico contra ruptura. Usado em racks fixados ao solo, inclinados para longe do público.</li><li><strong>Produto pirotécnico homologado (shell, cake, gerb, fonte):</strong> Cake/bolo: bloco com vários tubos que disparam efeitos em sequência rápida a partir de um único cue — muito usado por concentrar efeito com um disparo. Sempre adquirido com nota, dentro da validade, rótulo legível e categoria compatível.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Leia o rótulo:</strong> Confirme nomenclatura, categoria/classe, responsável técnico (CRQ), instruções de uso, ambiente permitido, distância segura e número de tiros (no caso de cakes).</li><li><strong>2. Inspecione a integridade:</strong> Produto deve estar íntegro, limpo, sem rasgos, rachaduras, partes soltas ou umidade. Produto danificado é descartado conforme orientação do fornecedor/autoridade — nunca usado.</li><li><strong>3. Identifique o iniciador:</strong> Verifique cor e proteção do iniciador. Mantenha o sistema sem energia até o disparo. Operadores não portam celular durante a iniciação (norma).</li><li><strong>4. Posicione no tubo/holder correto:</strong> Cada produto no seu morteiro ou base do fabricante, com a folga e o retardo expostos conforme a norma (ex.: retardo do iniciador exposto no mínimo 150 mm para fora do tubo após inserir a bomba).</li></ol><p><strong>Na prática:</strong> Ao receber uma caixa de shells, o operador confere nota fiscal, lacre, rótulo e validade; separa uma unidade visivelmente amassada e a devolve ao fornecedor em vez de usá-la. Carrega cada shell no morteiro de fibra correspondente ao calibre, conecta o e-match com o sistema desenergizado e só arma a mesa no momento combinado, sem celular no bolso.</p><h4>Resumo</h4><ul><li>O efeito resulta de cargas de projeção, abertura e efeito mais um retardo.</li><li>O operador usa produto homologado e íntegro — nunca fabrica ou altera.</li><li>Iniciador elétrico e morteiro correto, com sistema seguro até o disparo.</li></ul>',30,1,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('9335a3c4-85e1-4acd-86a1-57b35ab861ae','9ca798bd-6672-4d30-a61d-36d680b0d994','Quiz — Como funciona um artefato pirotécnico: composição, cargas e ');
