insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('a41e494a-0a40-4346-aa78-540d9bac92c5','dd764507-1ba3-48ba-9086-c511a5af0148','Para sincronizar uma shell com a música, o operador deve:','O efeito só coincide se o disparo for antecipado pelo delay somado.',3,1);
