insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('b297b118-3946-49ac-9aa6-dc425896be27','dd764507-1ba3-48ba-9086-c511a5af0148','O simul-firing serve para:','É o ensaio que valida tempos e cues com segurança antes do evento.',4,1);
