insert into public.modules (id,course_id,titulo,ordem) values ('38646969-e2ca-47f9-b9ff-eb53de809ca4','831af45f-bd33-487c-8149-e11e72741d34','Módulo 3 — Equipamentos de Efeitos: CO2, Fumaça, Confete e Faíscas',3);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('c78dd78e-0088-4a4f-a133-62ae2cd49833','38646969-e2ca-47f9-b9ff-eb53de809ca4','Jatos de CO2 e máquinas de fumaça/haze: efeito atmosférico com segurança','texto','<p><strong>Para começar:</strong> Nuvem, jato e névoa transformam o ar em cenário — mas gás sob pressão e ambientes fechados pedem respeito.</p><p>Efeitos atmosféricos são onipresentes em shows: jatos de CO2 que explodem nuvens brancas, máquinas de fumaça e haze que criam atmosfera e revelam feixes de luz, e low fog (gelo seco) que cobre o chão. Esta aula cobre os equipamentos reais, como montar e operar, e os riscos específicos — pressão, asfixia em ambiente confinado e baixa temperatura.</p><ul><li><strong>Jatos de CO2 (cryo jets):</strong> Usam CO2 líquido pressurizado em cilindro; ao liberar, o gás expande e forma um jato branco frio e visualmente impactante. Acionados manualmente ou via DMX/sistema de controle, sincronizados com som e luz. O CO2 é frio o suficiente para causar queimadura por frio (frostbite) e, em grande volume em ambiente fechado, deslocar oxigênio.</li><li><strong>Componentes do sistema de CO2:</strong> Cilindro pressurizado (com sifão/tubo pescador para retirar CO2 líquido), mangueiras de alta pressão com conectores e anéis de vedação, válvula/eletroválvula, e o bico de ejeção (jet) fixado em truss ou base. Fixação firme com clamps e abraçadeiras metálicas é obrigatória — uma mangueira solta sob pressão é um chicote perigoso.</li><li><strong>Máquinas de fumaça x haze:</strong> Máquina de fumaça (fogger): produz nuvem densa e visível, ótima para impacto, dissipa relativamente rápido. Máquina de haze (hazer): produz neblina fina e homogênea que fica suspensa, ideal para revelar feixes de luz e laser sem ''poluir'' o palco. Ambas usam fluido à base de glicol/glicerina aquecido.</li><li><strong>Low fog / gelo seco:</strong> Fumaça baixa que fica rente ao chão (efeito ''nuvem no piso''). Obtida com gelo seco (CO2 sólido a -78,5 °C) em água quente, ou por máquinas de low fog com resfriamento. Riscos: queimadura por frio ao manusear gelo seco (sempre com luvas térmicas) e acúmulo de CO2 baixo, que pode asfixiar em fossos, poços ou áreas sem ventilação.</li><li><strong>Ventilação e detecção:</strong> Em ambientes fechados, CO2 e fumaça densa exigem ventilação. CO2 é mais pesado que o ar e se acumula em baixo; em grandes volumes recomenda-se monitorar e garantir renovação de ar. Sistemas antincêndio por detecção de fumaça podem disparar falsamente com fog/haze — alinhar com a brigada/bombeiros antes.</li><li><strong>Conforto e saúde:</strong> Fumaça de glicol em excesso irrita vias respiratórias de artistas e público sensível; usar a menor quantidade que entrega o efeito. Avisar artistas sobre jatos de CO2 próximos (frio e ruído de pressão).</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>MagicFX (jatos de CO2 e sistemas):</strong> Fabricante referência em efeitos de CO2 (Stadium Shot, CO2 Jet, Swirl Fan). Sistemas com eletroválvula controlada por DMX, conexão a cilindro de CO2 líquido com tubo sifão. Specs variam por modelo (pressão de trabalho típica de CO2 ~50–60 bar). Usados para jatos verticais/laterais e cortinas de CO2 em palcos e arenas.</li><li><strong>Antari (máquinas de fumaça, haze e low fog):</strong> Linha ampla: fog machines (ex.: série Z), hazers a base de água/óleo e low fog (ex.: ICE/IP series que resfriam a fumaça para mantê-la baixa). Boa relação custo-benefício, muito usada em eventos. Selecionar fluido recomendado pelo fabricante.</li><li><strong>MDG (haze e fog de alta gama):</strong> Fabricante premium (ATMe, theONE) conhecido por haze ultrafino e consistente, com baixo consumo de fluido — padrão em TV, teatro e turnês grandes onde se quer revelar luz sem nuvem visível pesada.</li><li><strong>Look Solutions (Unique, Viper, Tiny):</strong> Fabricante alemão de hazers (Unique) e fog machines (Viper) muito usado em produções profissionais; o Unique gera haze por fricção/aquecimento com fluido próprio, excelente para feixes de luz.</li><li><strong>Cilindro de CO2 com tubo sifão (pescador):</strong> Para jatos é necessário CO2 LÍQUIDO; o cilindro precisa ter tubo sifão interno (ou ser usado invertido conforme tipo) para que saia líquido e não apenas gás. Cilindro sempre acorrentado/fixado de pé, com proteção de válvula.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Posicionar e fixar os jatos:</strong> Monte os bicos de CO2 em pontos estratégicos (laterais/frente de palco), longe de materiais inflamáveis. Fixe em truss com clamps de aço e prenda com abraçadeiras metálicas — nunca apenas apoiado.</li><li><strong>2. Conectar mangueiras de alta pressão:</strong> Use conectores específicos com anéis de vedação íntegros. Verifique que cada conexão está firme. Prenda as mangueiras ao longo da estrutura com zip ties para evitar tropeços e chicoteamento.</li><li><strong>3. Fixar e abrir o cilindro com cuidado:</strong> Cilindro de pé, acorrentado. Abra a válvula lentamente. Confirme ausência de vazamento (som de escape, gelo na conexão indica fuga).</li><li><strong>4. Testar jato e ajustar:</strong> Com a área liberada, faça um disparo de teste curto, ajuste direção e altura. Confirme que ninguém está na linha do jato a curta distância (risco de frio/pressão).</li><li><strong>5. Posicionar fumaça/haze e checar detecção:</strong> Posicione foggers/hazers para cobertura desejada; confirme com a brigada que o sistema de detecção de incêndio do local não disparará falso alarme; garanta ventilação.</li><li><strong>6. Fechar e despressurizar na desmontagem:</strong> Feche o cilindro, alivie a pressão residual das mangueiras antes de desconectar, e só então desmonte. Manuseie gelo seco apenas com luvas térmicas.</li></ol><p><strong>Na prática:</strong> Num show indoor o operador instala dois CO2 jets MagicFX na frente do palco e um hazer MDG ao fundo. Ele acorrenta o cilindro com tubo sifão, testa cada conexão com água e sabão para detectar vazamento, faz um burst de teste com a área limpa, alinha com a brigada para travar o alarme de fumaça durante os cues e mantém uma porta de ventilação aberta. Nada de gelo seco em fosso sem ventilação.</p><h4>Resumo</h4><ul><li>Jatos de CO2 usam gás líquido pressurizado — risco de frio, pressão e asfixia.</li><li>Fumaça (densa) e haze (fina) criam atmosfera; low fog cobre o chão.</li><li>Fixação firme, ventilação e alinhamento com a brigada são obrigatórios.</li></ul>',35,1,true,false);
