insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('23b65157-32cb-4f4d-928d-2759baaeef7e','3886fe53-6270-44ae-a4da-7418a4ba7979','Os canhões de confete a CO2 devem ser mirados:','A direção segura é para cima e longe das pessoas a curta distância.',5,1);
