insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('3acba141-7345-436b-9fe9-9a0cbbadb214','d169898c-6b15-4c5b-81eb-10a68fa1b011','Se o time code falhar durante o show, o sistema bem configurado deve:','A salvaguarda impede execução errada; o abort também fica disponível.',4,1);
