insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('1a80aaee-b376-4385-bf5f-956314dc0fc0','635b2c59-9c08-4f29-9a4c-37abb4b2e7c9','Painéis e efeitos visuais não pirotécnicos: LED, pixel e fogo cênico','texto','<p><strong>Para começar:</strong> Nem todo impacto vem do fogo: painéis e luz são parte do arsenal do operador de efeitos completo.</p><p>Painéis de LED, pixel mapping, strobes e outros recursos visuais complementam (e às vezes substituem com segurança) a pirotecnia. Esta aula apresenta os tipos de painel, como se operam e o problema do delay de vídeo/sincronia áudio-imagem, fundamental para integrar visual e som.</p><ul><li><strong>LED video walls e painéis de LED:</strong> Paredes de vídeo de alta resolução (módulos de LED) exibem imagens, vídeos e efeitos; painéis de LED criam padrões e fundos dinâmicos. Configuram-se conectando módulos, definindo resolução e controlando por software/console de mídia. Podem simular ''explosões'' e luz sem risco pirotécnico.</li><li><strong>Pixel mapping:</strong> Mapeia-se digitalmente a disposição física dos painéis/pontos de LED para controlar cada pixel individualmente, criando padrões e movimentos precisos sincronizados ao show — muito usado para efeitos coordenados com a música.</li><li><strong>Strobes, tubos de LED e piso de LED:</strong> Strobes geram flashes intensos sincronizados (cuidado com fotossensibilidade do público — avisos e limites). Tubos de LED criam contornos e formas 3D. Pisos de LED interagem com artistas e público. Todos controlados por console de luz/DMX ou pixel.</li><li><strong>Painéis de fogo e água com projeção:</strong> Painéis de fogo usam dispositivos de chama controlada (alto risco — ver aula de fogo controlado). Telas/cortinas de água servem de superfície de projeção. Combinam-se com vídeo mapeado para grande impacto.</li><li><strong>Delay de vídeo e sincronia A/V:</strong> Painéis e sistemas de vídeo introduzem latência: processamento interno, cabos (HDMI/DisplayPort longos), redes IP congestionadas, pós-processamento. Se a imagem atrasa em relação ao áudio, a sincronia quebra. Mede-se e compensa-se esse delay, e usa-se cabeamento/rede de qualidade. Em sistemas controlados por IP, evita-se congestionamento de rede.</li><li><strong>Quando usar visual em vez de pirotecnia:</strong> Em locais onde fogo é proibido ou arriscado (teto baixo, público muito próximo, restrição dos bombeiros), painéis de LED e luz entregam impacto com risco muito menor. O operador completo sabe propor essa troca.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Painel de LED (video wall) modular:</strong> Módulos com pitch variável (ex.: P2 a P5 para palco) montados em estrutura; controlados por processador de vídeo e console de mídia. Para efeitos de ''explosão'' e luz brilhante sem pirotecnia.</li><li><strong>Controladora de pixel / processador de vídeo:</strong> Faz o mapeamento e a sincronização dos pixels com a timeline do show, frequentemente integrada por DMX/Art-Net e até por time code.</li><li><strong>Strobes profissionais (DMX):</strong> Geram flashes de alta intensidade sincronizados à música; usar com cautela por fotossensibilidade, com avisos ao público quando intensos.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Montar e configurar o painel:</strong> Conecte os módulos, defina resolução e mapeamento; alimente e teste a imagem.</li><li><strong>2. Integrar ao controle do show:</strong> Ligue ao processador de vídeo/pixel e sincronize com a timeline (DMX/Art-Net/time code conforme o caso).</li><li><strong>3. Medir e compensar o delay de vídeo:</strong> Compare imagem e áudio; ajuste atrasos para alinhar A/V; use cabos/rede de qualidade e evite congestionamento IP.</li><li><strong>4. Avaliar substituição segura da pirotecnia:</strong> Onde fogo for arriscado, projete efeitos de luz/LED equivalentes para entregar impacto com risco menor.</li></ol><p><strong>Na prática:</strong> Num teatro com teto baixo e proibição de fogo, o operador substitui a ''explosão'' pirotécnica do clímax por um efeito de pixel mapping em LED com strobe sincronizado, medindo e compensando o delay de vídeo para a imagem bater exatamente com a batida do som. Resultado de grande impacto, zero risco de incêndio.</p><h4>Resumo</h4><ul><li>Painéis de LED, pixel mapping e strobes complementam ou substituem a pirotecnia.</li><li>Delay de vídeo e sincronia A/V precisam ser medidos e compensados.</li><li>Onde o fogo é arriscado, o visual entrega impacto com risco muito menor.</li></ul>',25,3,true,false);
