insert into public.modules (id,course_id,titulo,ordem) values ('e81b6fbc-d6f9-4ee4-b597-504ea0597343','831af45f-bd33-487c-8149-e11e72741d34','Módulo 5 — Segurança Operacional: o Coração do Pleno Efeito',5);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('ef1cd2c1-f67d-4c28-b32e-fce731798bbc','e81b6fbc-d6f9-4ee4-b597-504ea0597343','Distâncias de segurança e posicionamento de efeitos','texto','<p><strong>Para começar:</strong> A distância correta é a primeira barreira contra acidentes. Errar aqui é colocar vidas em risco.</p><p>Distância de segurança é a separação mínima entre a área de disparo e o público/equipe/estruturas, e depende do tipo e tamanho do efeito. Esta aula ensina a regra prática internacional para shells, o posicionamento e a inclinação dos morteiros, e a definição das zonas do evento. Atenção: distâncias variam por legislação e fabricante — sempre adote o MAIOR valor exigido e seja conservador.</p><ul><li><strong>Por que a distância importa:</strong> Mantém público e equipe fora do alcance de detritos, calor, projeção e de uma eventual explosão prematura ou queda de shell ativo. É a salvaguarda que funciona mesmo quando algo dá errado.</li><li><strong>Regra prática para shells aéreos:</strong> Regra internacional comum: distância mínima de aproximadamente 70 a 100 pés por polegada de diâmetro da shell. Exemplos típicos: 3 pol → ~70–90 m; 4 pol → ~100–120 m; 6 pol → ~150–180 m; 8 pol → ~200–240 m. São valores de referência: a legislação local e o fabricante podem exigir mais — adote sempre o maior.</li><li><strong>Distâncias para efeitos de palco e indoor:</strong> Faíscas frias, gerbs e fontes de palco têm distâncias bem menores, definidas pelo fabricante (até pessoas, cortinas, gride e sensores). Para CO2 e fogo controlado, seguir o manual e a brigada. Nunca presumir — ler a ficha do produto.</li><li><strong>As três zonas:</strong> Área de disparo (onde estão os efeitos), área técnica (equipe e mesa) e área de público. A distância de segurança deve ser respeitada entre todas elas. A zona de disparo (blast zone) é isolada e de acesso restrito.</li><li><strong>Inclinação e direção dos morteiros:</strong> Tubos sempre inclinados para LONGE do público e de estruturas, na direção segura de queda dos detritos (fallout). Considera-se o vento: inclina-se de forma que vento e detritos não levem material sobre o público. Racks bem fixados ao solo.</li><li><strong>Direção do vento e fallout:</strong> A zona de fallout (onde caem resíduos e detritos) deve estar livre de público e de materiais inflamáveis, e a favor do vento em relação ao público (vento empurrando detritos para longe das pessoas). Reavaliar se o vento mudar.</li><li><strong>Margem e conservadorismo:</strong> Na dúvida, aumente a distância. É melhor um efeito um pouco menor ou mais distante do que um acidente. A distância nunca é ''negociável'' por pressão de produção.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Racks de morteiro em fibra de vidro e bases:</strong> Estruturas que seguram os tubos firmemente, permitindo inclinação controlada para longe do público. Fixados ao solo (estacas, peso) para não tombarem no disparo.</li><li><strong>Trena/medidor a laser e mapa do local:</strong> Para medir e marcar as distâncias reais entre disparo, técnica e público no terreno, em vez de estimar a olho.</li><li><strong>Anemômetro (medidor de vento):</strong> Mede a velocidade do vento no local; essencial para decidir inclinação, posição de fallout e eventual cancelamento (vento ~30 km/h costuma ser limite para cancelar).</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Identificar o maior efeito e seu calibre:</strong> Determine o maior shell/efeito do show; ele define a maior distância exigida.</li><li><strong>2. Calcular a distância mínima:</strong> Aplique a regra (≈70–100 pés por polegada) e compare com a exigência legal/fabricante; adote o MAIOR valor.</li><li><strong>3. Marcar as três zonas no local:</strong> Meça e demarque com barreiras a área de disparo, a técnica e a de público, respeitando a distância em todas as direções.</li><li><strong>4. Posicionar e inclinar os morteiros:</strong> Fixe os racks, incline para longe do público e na direção segura de fallout, considerando o vento medido.</li><li><strong>5. Reavaliar com o vento real:</strong> Meça o vento antes e durante; se mudar de direção/intensidade, reposicione ou cancele conforme o caso.</li></ol><p><strong>Na prática:</strong> Com shells de 4 polegadas, o operador calcula ~100–120 m de raio de segurança, mede com trena a laser, demarca a blast zone com barreiras e posiciona os racks inclinados para o lado oposto ao público, onde há campo aberto para o fallout. Mede o vento (18 km/h, soprando para longe da plateia) e segue; combina com a equipe que, se o vento virar para o público, o show é reavaliado.</p><h4>Resumo</h4><ul><li>Distância de segurança depende do tamanho do efeito; adote sempre o maior valor exigido.</li><li>Regra prática para shells: ~70–100 pés por polegada de diâmetro.</li><li>Inclinação para longe do público e gestão de vento/fallout são essenciais.</li></ul>',35,1,true,false);
