insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('6eba1cb5-446e-4d60-b312-d9e6a1e386e4','ea3d61bb-b7ed-45ec-9054-d42d8efcd5b2','A regra prática internacional para distância de shells aéreos é:','Quanto maior o calibre, maior a distância — cerca de 70–100 pés por polegada.',1,1);
