insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0977e0bd-5004-4870-9c25-77e01d372c5d','ea3d61bb-b7ed-45ec-9054-d42d8efcd5b2','Quando a legislação local exige mais distância que a regra prática, o operador deve:','Sempre se adota o maior valor para máxima margem de segurança.',2,1);
