insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c0d3828b-2a9d-499d-b453-949057898229','ea3d61bb-b7ed-45ec-9054-d42d8efcd5b2','A zona de fallout deve estar:','Os detritos caem ali; precisa estar livre e com o vento empurrando-os para longe do público.',4,1);
