insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('9f012961-6666-4da8-8fe4-3eee913b95d1','ea3d61bb-b7ed-45ec-9054-d42d8efcd5b2','Na dúvida sobre a distância, o operador deve:','Conservadorismo salva vidas; mais distância é sempre mais seguro.',5,1);
