insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('39e3adaa-3f15-488d-a87e-3ad63982d558','e81b6fbc-d6f9-4ee4-b597-504ea0597343','EPI, segurança coletiva e procedimentos em caso de falha (misfire)','texto','<p><strong>Para começar:</strong> Quando algo dá errado, é a disciplina nos procedimentos que evita a tragédia.</p><p>Esta aula cobre a proteção do profissional (EPI), a proteção coletiva (extintores, barreiras, comunicação) e — crucialmente — o protocolo de misfire (falha de disparo), o momento mais perigoso de uma operação pirotécnica. Aqui a regra é: paciência e procedimento, nunca pressa.</p><ul><li><strong>EPI obrigatório:</strong> Capacete de segurança, óculos de proteção/viseira, protetor auricular, luvas adequadas (resistentes a chama/calor e, quando elétrico, antiestáticas), roupas de algodão ou antiestáticas resistentes a chama (nada sintético que derrete), botas de segurança. A norma também exige EPI completo em ensaios e inspeções.</li><li><strong>Proibições durante a operação:</strong> Não portar fósforos, isqueiros, cigarros ou qualquer material que produza faísca; não usar telefone móvel durante a iniciação; nunca operar sob efeito de álcool, narcóticos ou medicamentos que afetem reflexos e julgamento (exigência da norma).</li><li><strong>Segurança coletiva:</strong> Extintores adequados (classe ABC para uso geral; nunca água sobre risco elétrico), iluminação de emergência, rádios de comunicação, barreiras físicas e sinalização de áreas restritas. Tudo posicionado e testado antes do show.</li><li><strong>Principais riscos a antecipar:</strong> Misfire (falha de disparo), explosão prematura (no tubo ou perto do solo), queda de shell ativo, incêndio no local e projeção de detritos. Causas frequentes: erro de montagem, tubo danificado, ignição incorreta, vento forte e falha elétrica.</li><li><strong>Protocolo de misfire — o mais importante:</strong> Se um efeito não dispara: NÃO se aproximar imediatamente. Aguardar pelo menos 15 a 30 minutos (a norma fixa mínimo de 15 min para examinar/remover a falha). Desligar/desarmar o sistema de ignição. Só então aproximar-se com extrema cautela. Isolar a área. De preferência, investigar apenas após o término do show e a saída do público.</li><li><strong>O que NUNCA fazer num misfire:</strong> Nunca tentar reacender manualmente, nunca remover imediatamente o artefato, nunca inclinar/olhar dentro do tubo, nunca apressar o tempo de espera. Um shell ''que não disparou'' pode disparar com atraso e matar quem estiver por perto.</li><li><strong>Comunicação na emergência:</strong> Quem identifica a falha avisa imediatamente o operador-chefe pelo rádio; a decisão de aguardar, isolar ou abortar é centralizada. Mantém-se a calma e segue-se o procedimento, sem heróis.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Kit de EPI pirotécnico:</strong> Capacete, óculos/viseira, protetor auricular, luvas resistentes a calor/antiestáticas, roupa de algodão/antichama, botas de segurança. Conferido e em bom estado antes de cada operação.</li><li><strong>Extintores classe ABC e ferramenta antifaísca:</strong> Extintores ABC posicionados próximos à zona de disparo; ferramentas que não geram faísca para manuseio. Nunca água sobre circuitos energizados.</li><li><strong>Rádios de comunicação dedicados:</strong> Comunicação clara e imediata entre equipe e operador-chefe, especialmente para reportar falhas e coordenar o abort.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Vestir e conferir o EPI:</strong> Antes de montar/operar, todos vestem o EPI completo e conferem o estado. Sem EPI, não se entra na zona de disparo.</li><li><strong>2. Posicionar a segurança coletiva:</strong> Extintores ABC, barreiras, sinalização, iluminação de emergência e rádios testados e em posição.</li><li><strong>3. Em caso de misfire — parar:</strong> Identificou a falha? NÃO se aproxime. Avise o operador-chefe pelo rádio.</li><li><strong>4. Aguardar e desarmar:</strong> Aguarde no mínimo 15 a 30 minutos. Desligue/desarme o sistema de ignição. Mantenha a área isolada.</li><li><strong>5. Aproximar com cautela e neutralizar:</strong> Só depois do tempo de espera e do sistema desarmado, aproxime-se com cautela para neutralizar conforme procedimento — idealmente após o público sair.</li><li><strong>6. Registrar o incidente:</strong> Documente a falha (qual circuito, produto, causa provável) para o relatório pós-evento e para o fornecedor.</li></ol><p><strong>Na prática:</strong> Durante o show, o cake do canal 12 não dispara. O assistente avisa pelo rádio: ''misfire canal 12''. O operador-chefe NÃO manda ninguém ao local; continua o show com os demais cues, e ao final isola o ponto, desarma a mesa, aguarda 30 minutos e só então, com o público já fora, aproxima-se com cautela para neutralizar o produto. Ninguém tenta reacender ou mexer no tubo antes da hora.</p><h4>Resumo</h4><ul><li>EPI completo e proibição de fontes de faísca, celular e substâncias na operação.</li><li>Segurança coletiva: extintores ABC, barreiras, sinalização e comunicação.</li><li>Misfire: aguardar 15–30 min, desarmar, isolar e nunca reacender ou mexer no tubo.</li></ul>',30,2,true,false);
