insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('41ffffde-6ab5-487c-bdef-78c38885c189','01b3833f-1207-48f3-8927-b1873846fa17','Quem identifica um misfire deve:','A decisão é centralizada no chefe; segue-se o procedimento, sem heróis.',5,1);
