insert into public.modules (id,course_id,titulo,ordem) values ('13c9b641-a6b6-4025-aa02-92dc37969143','831af45f-bd33-487c-8149-e11e72741d34','Módulo 7 — Projeto, Execução e Comunicação Profissional',7);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('a3fee94a-c12a-4ace-a1d3-5b375bef0641','13c9b641-a6b6-4025-aa02-92dc37969143','Simulador do show: do briefing à desmontagem, passo a passo','texto','<p><strong>Para começar:</strong> Agora juntamos tudo: vamos planejar e executar um efeito do começo ao fim, como num evento real.</p><p>Esta é a aula-síntese: um ''simulador'' que percorre todas as fases de um efeito — briefing, licença, projeto, montagem, teste, disparo e desmontagem — com checklist de segurança em cada etapa. Use-a como roteiro mental para qualquer operação real, do pequeno efeito indoor ao grande show outdoor.</p><ul><li><strong>Fase 1 — Briefing e concepção:</strong> Capte o desejo do cliente (momentos, música, intensidade, identidade), levante o local e as restrições (indoor/outdoor, pé-direito, público, vento típico). Defina objetivos do efeito e já filtre o que é viável e seguro. Saída: conceito e lista preliminar de efeitos.</li><li><strong>Fase 2 — Projeto e documentação:</strong> Transforme o conceito em roteiro de cues (com delays e distâncias calculados), escolha os produtos e categorias adequados ao ambiente, monte o rider técnico, reúna licenças e planos de segurança/emergência. Saída: projeto aprovado e documentação completa.</li><li><strong>Fase 3 — Logística e armazenamento:</strong> Garanta procedência dos produtos (fornecedor autorizado), transporte e armazenamento conforme norma (iniciadores separados), e organize equipe e EPI. Saída: material e equipe prontos e legais.</li><li><strong>Fase 4 — Montagem técnica:</strong> Inspecione o terreno; demarque as zonas e distâncias; fixe racks/holders e morteiros inclinados para longe do público; posicione CO2/fumaça/faíscas com folga; instale a mesa em local seguro; conecte e ETIQUETE os circuitos. Mantenha o sistema desarmado. Saída: sistema montado e seguro.</li><li><strong>Fase 5 — Teste e ensaio:</strong> Rode o teste de continuidade canal a canal; corrija falhas; alinhe time code (se houver) e faça simul-firing para validar sincronia e delays. Alinhe com brigada/bombeiros. Saída: sistema testado e equipe alinhada.</li><li><strong>Fase 6 — Disparo:</strong> Verifique o clima (vento/chuva) e os gatilhos de cancelamento; isole a zona de disparo; confirme ''palco limpo'' pela equipe; arme a mesa apenas então; opere os cues (manual ou time code) com o abort sempre acessível; monitore continuamente. Saída: show executado com segurança.</li><li><strong>Fase 7 — Desmontagem e pós-evento:</strong> Avalie a área (procure misfires e produtos não disparados — respeite o tempo de espera!); desarme e descarregue o sistema; separe iniciadores; recolha resíduos/fallout; embale e transporte o que sobrou conforme norma; produza o relatório pós-evento. Saída: local limpo, material guardado, registro feito.</li><li><strong>A mentalidade do operador completo:</strong> Em todas as fases, pergunte: está seguro para público, equipe, artistas e local? Tenho documentação? Tenho plano B (contingência)? Posso abortar a qualquer momento? Se a resposta a qualquer uma for ''não'', pare e corrija antes de prosseguir.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Checklist impresso e folha de cues:</strong> Documento operacional usado na montagem e no disparo, com cada cue, circuito, produto, delay e responsável. Reduz erro humano e organiza a operação.</li><li><strong>Kit completo: mesa, módulos, EPI, extintores ABC, anemômetro, trena a laser:</strong> O conjunto mínimo de uma operação segura: controle, proteção individual e coletiva, e instrumentos de medição de distância e vento.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Briefing:</strong> Reúna desejo do cliente + dados do local; defina conceito e filtre o que é seguro/viável.</li><li><strong>2. Projeto e documentação:</strong> Roteiro de cues com delays/distâncias, escolha de produtos por ambiente, rider, licenças e planos.</li><li><strong>3. Logística:</strong> Procedência, transporte e armazenamento conforme norma; equipe e EPI prontos.</li><li><strong>4. Montagem:</strong> Inspeção do terreno, demarcação de zonas, fixação e inclinação, posicionamento de efeitos, mesa e etiquetagem de circuitos — sistema desarmado.</li><li><strong>5. Teste e ensaio:</strong> Teste de continuidade, alinhamento de time code, simul-firing e alinhamento com a brigada.</li><li><strong>6. Disparo:</strong> Checar clima, isolar a zona, confirmar palco limpo, armar, operar com abort acessível e monitorar.</li><li><strong>7. Desmontagem e relatório:</strong> Procurar misfires (com tempo de espera), desarmar/descarregar, separar iniciadores, recolher resíduos, guardar material e registrar o relatório.</li></ol><p><strong>Na prática:</strong> Réveillon em praça pública: o operador faz o briefing com a prefeitura, projeta um roteiro de 4 minutos com shells de 3 e 4 polegadas (distância ~120 m, demarcada com trena e barreiras), obtém licença dos bombeiros, monta os racks inclinados para o mar (fallout seguro), etiqueta os circuitos, roda o teste de continuidade e o simul-firing por time code com a trilha sonora. Mede o vento (ok), isola a zona, confirma ''área limpa'', arma a mesa e dispara com o dedo no abort. Ao fim, procura misfires respeitando o tempo de espera, recolhe o fallout e faz o relatório.</p><h4>Resumo</h4><ul><li>O efeito profissional segue 7 fases: briefing, projeto, logística, montagem, teste, disparo e desmontagem.</li><li>Segurança e documentação são checadas em cada fase, com o abort sempre disponível.</li><li>A regra final: se não está seguro, documentado e com plano B, não dispara.</li></ul>',40,1,true,false);
