insert into public.modules (id,course_id,titulo,ordem) values ('cef76734-430c-404a-94e0-4feb3415736e','831af45f-bd33-487c-8149-e11e72741d34','Equipamentos de Efeito: Modelos e Detalhes',8);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('02333363-b75e-43d8-bafe-36f030c26758','cef76734-430c-404a-94e0-4feb3415736e','Atmosfera: Fumaça, Hazer e Low Fog','texto','<p><strong>Para começar:</strong> Antes de qualquer raio de luz aparecer no ar, alguém precisou colocar atmosfera nele. Fumaça e haze são a base de quase todo show iluminado.</p><p>Atmosfera é o efeito mais usado e mais subestimado. Sem partículas no ar, os feixes de luz não aparecem. Nesta aula você vai diferenciar fog (fumaça densa), haze (névoa fina e homogênea) e low fog (fumaça que fica rente ao chão), conhecer as máquinas de referência do mercado, o fluido correto para cada uma e como controlar tudo por DMX com segurança.</p><ul><li><strong>Fog x Haze x Low fog:</strong> Fog é fumaça densa de aparição rápida, ótima para blast e revelações; dissipa em segundos. Haze é uma névoa finíssima e contínua que fica suspensa por minutos, ideal para realçar feixes sem ''nuvem'' visível. Low fog é fumaça pesada e fria que se mantém rente ao piso (efeito ''mar de nuvens''), obtida resfriando o vapor com gelo, CO2 ou trocador térmico.</li><li><strong>Tecnologias de geração:</strong> Máquinas a base de óleo (haze cracker/óleo mineral) produzem haze de longuíssima duração. Máquinas a base de água/glicol aquecem fluido e geram fog/haze de aparência mais ''leitosa''. Low fog dedicado usa fluido próprio resfriado. Cada tecnologia exige o fluido certo do fabricante: misturar fluido errado entope, danifica a bomba e perde garantia.</li><li><strong>Por que DMX e ventilação importam:</strong> Toda atmosfera deve ser dosada: excesso dispara alarmes de incêndio, reduz visibilidade de saídas e satura o ambiente. Controle por DMX permite regular saída (output) e ventilador com precisão e repetibilidade. Conhecer o HVAC do local e a posição dos detectores de fumaça é parte do trabalho do operador.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Antari Z-series (ex.: Z-1520, Z-3000):</strong> Máquinas de fog a base de água/glicol, alta potência (1500 a 3000 W). O que é: fog denso de aparição rápida para revelações e blast. Specs típicas: saída ajustável, controle DMX e timer, aquecimento por bloco térmico. Quando usar: efeitos pontuais, entradas, cortinas de fumaça. Segurança: fluido Antari FLG/FLR específico; bocal e corpo ficam quentes; nunca acionar perto de detector sem coordenação.</li><li><strong>Antari F-series / Hazer (ex.: F-1, M-series haze):</strong> Hazers para névoa fina e contínua. O que é: realça feixes de luz por longos períodos. Specs: ventilador integrado, baixo consumo de fluido, DMX. Quando usar: shows, TV e teatro onde se quer luz ''desenhada'' no ar sem nuvem aparente. Segurança: usar fluido de haze próprio; haze de base água precisa reposição mais frequente que óleo.</li><li><strong>Look Solutions Unique 2.1:</strong> Hazer profissional a base de óleo (haze cracker). O que é: referência de haze homogêneo e fino, partícula muito pequena e duradoura. Specs: fluido Unique-fog específico, DMX, ventilador interno, consumo baixíssimo. Quando usar: broadcast, turnês e teatro de alto nível onde se exige haze invisível e estável por horas. Segurança: óleo mineral; não usar fluido de água; ventilação adequada do ambiente.</li><li><strong>Look Solutions Viper (NT/2.6/io):</strong> Máquina de fog/haze versátil de base água/glicol com controle eletrônico fino. O que é: faz desde haze leve até fog denso. Specs: bomba de precisão, DMX, telas/menu, fluidos Look (Quick, Regular, Slow conforme dissipação desejada). Quando usar: produções que precisam de uma só máquina flexível. Segurança: escolher o fluido conforme tempo de dissipação; corpo aquece.</li><li><strong>MDG ATMOSPHERE / theONE:</strong> Hazers premium movidos a CO2/nitrogênio comprimido. O que é: padrão de broadcast e grandes turnês; haze extremamente fino, uniforme e silencioso. Specs: alimentação por gás inerte de alta pureza, controle DMX/rede, baixíssima partícula. Quando usar: TV ao vivo, arenas, onde uniformidade é crítica. Segurança: cilindro de gás pressurizado fixo e ventilado; conexões certificadas; fluido MDG próprio.</li><li><strong>MDG / low fog dedicado (ex.: ICE FOG, máquinas de low fog com trocador):</strong> Geradores de fumaça pesada rente ao chão. O que é: cria o ''mar de nuvens'' para primeiras danças, óperas e cenas dramáticas. Specs: resfriamento por CO2/nitrogênio ou trocador térmico, mangueiras de distribuição. Quando usar: efeito de chão sem subir para o ambiente. Segurança: CO2 deslocando ar em piso/poços é risco de asfixia; ventilação e monitoramento de O2 em ambientes baixos.</li></ul><h4>Passo a passo</h4><ol><li><strong>Planejar e posicionar:</strong> Defina tipo de efeito (fog/haze/low fog), posicione a máquina longe de pessoas e fora do alcance direto de detectores; comunique-se com bombeiros/brigada e produção sobre o uso de atmosfera.</li><li><strong>Conferir fluido:</strong> Use somente o fluido recomendado pelo fabricante da máquina; verifique nível, validade e que não há mistura de tipos diferentes no tanque.</li><li><strong>Energizar e aquecer:</strong> Ligue a máquina, aguarde o aquecimento completo (LED/indicador de ''ready''); acionar antes do ready cospe fluido líquido e suja o palco.</li><li><strong>Endereçar DMX e testar baixo:</strong> Defina o endereço DMX, faça um teste de saída em valor baixo, observe densidade e dissipação reais no ambiente antes do show.</li><li><strong>Dosar durante o show:</strong> Trabalhe com rajadas curtas e antecipação; mantenha haze de fundo em nível constante e use fog denso só em momentos pontuais, sempre observando visibilidade de saídas.</li><li><strong>Desligar com purga:</strong> Ao final, siga o procedimento de desligamento/purga do fabricante para evitar entupimento; deixe esfriar antes de transportar.</li></ol><p><strong>Na prática:</strong> Em um show de médio porte, o operador sobe primeiro um nível baixo e constante de haze (Unique 2.1 ou MDG) cerca de 15 a 20 minutos antes do público entrar, deixando o ar ''carregado'' de forma sutil para os feixes aparecerem. Durante a apresentação, reserva uma Antari Z para blasts de fog em viradas e refrões, sempre em rajadas curtas. Se o local tem detectores sensíveis, combina previamente com a brigada a inibição/monitoramento dos sensores na área — nunca improvisa cobrindo um detector.</p><h4>Resumo</h4><ul><li>Fog é denso e rápido, haze é fino e duradouro, low fog fica rente ao chão — cada um pede máquina e fluido próprios.</li><li>Sempre use o fluido recomendado pelo fabricante e controle a saída por DMX em rajadas dosadas.</li><li>Atmosfera reduz visibilidade: comunique brigada/detectores e mantenha rotas de fuga sempre identificáveis.</li></ul>',55,1,true,false);
