insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c62ac9ea-edde-406d-b294-25ab708779fa','3178aaba-1a3a-4fac-972c-177990cf4490','Por que a faísca fria é chamada de ''fria''?','As partículas saem quentes mas esfriam rápido na trajetória; perto do jato ainda queimam.',1,1);
