insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('6ecea822-bd43-4e85-a354-4149b2354e57','3178aaba-1a3a-4fac-972c-177990cf4490','Por que não se deve usar pó genérico no lugar do consumível oficial?','Granulometria e composição são calibradas; pó genérico ou úmido entope e cria risco operacional.',4,1);
