insert into public.quiz_options (question_id,texto,correta,ordem) values ('6ecea822-bd43-4e85-a354-4149b2354e57','Não muda nada',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('009e5b65-3593-4f6f-8703-fb95fbd8d350','cef76734-430c-404a-94e0-4feb3415736e','CO2 e Confete: Jatos, Stadium Blaster e Lança-Confete','texto','<p><strong>Para começar:</strong> O ''CHHHH'' branco que sobe do palco e a chuva de confete que cobre a arena são efeitos de impacto imediato — e ambos dependem de gás e ar comprimidos manejados com técnica.</p><p>Efeitos de CO2 criam jatos densos de névoa branca e fria; lança-confetes usam ar comprimido ou CO2 para projetar papel a grandes distâncias. Nesta aula você vai entender a diferença entre CO2 jet e confete, os modelos MagicFX de referência, como funcionam cilindro e mangueira, e os riscos específicos de gás pressurizado e frio extremo.</p><ul><li><strong>CO2 jet x confete:</strong> O CO2 jet libera dióxido de carbono líquido de um cilindro; ao expandir, vira névoa branca densa e muito fria que sobe rápido e some — ótimo para impacto e ''respiração'' do palco. O lança-confete projeta tiras/quadrados de papel ou metalizado usando ar comprimido (compressor) ou CO2 como propelente, cobrindo grandes áreas em segundos.</li><li><strong>Cilindro, mangueira e conexões:</strong> O CO2 vem de cilindros (com ou sem tubo pescador/sifão, conforme o efeito) conectados por mangueiras de alta pressão certificadas até a máquina/jato. Conexões frouxas ou mangueiras fora de especificação são perigosas: o gás está sob alta pressão e a baixíssima temperatura pode causar queimadura por frio (frostbite) e fragilizar materiais.</li><li><strong>CO2 é asfixiante:</strong> CO2 é mais pesado que o ar e desloca o oxigênio; em ambientes fechados, fossos, palcos baixos ou porões, o acúmulo pode causar tontura, desmaio e asfixia. Ventilação, quantidade dosada e atenção a áreas baixas são parte central da operação. Confete também precisa de plano de limpeza e cuidado com piso escorregadio e detectores.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>MagicFX CO2 Jet (ex.: CO2 Jet / Swirl):</strong> Jato de CO2 controlado. O que é: dispara coluna de névoa branca fria para cima; versão Swirl gira o jato. Specs: conexão a cilindro de CO2 por mangueira de alta pressão, acionamento DMX/rádio, bocal direcionável. Quando usar: viradas, refrões, impacto em shows e DJs. Segurança: cilindro fixo e em pé, mangueira certificada, ninguém na frente do bocal; risco de queimadura por frio e de asfixia em local fechado.</li><li><strong>MagicFX Stadium Blaster:</strong> Lança-confete/streamer de longo alcance movido a CO2. O que é: projeta grande volume de confete ou serpentina a dezenas de metros, cobrindo arenas. Specs: alimentado por cilindro de CO2, cartucho/tremonta de confete, DMX. Quando usar: clímax de shows, estádios, grandes públicos. Segurança: alcance e força elevados — manter trajetória livre de pessoas próximas; cilindro e conexões seguros.</li><li><strong>MagicFX Stadium Shot / Power Shot (lança-confete):</strong> Canhões de confete/serpentina de impacto. O que é: disparo único potente de confete metalizado ou papel. Specs: propelido por CO2 ou ar, recarga por cartucho, acionamento DMX. Quando usar: momento único de grande efeito visual. Segurança: nunca apontar para pessoas a curta distância; o disparo tem força; planejar limpeza.</li><li><strong>Lança-confete a ar comprimido (Confetti Blower / máquinas contínuas):</strong> Sopradores que lançam confete de forma contínua usando ar/compressor em vez de CO2. O que é: criam ''chuva'' prolongada de papel. Specs: ventilador/compressor, tremonha de confete, DMX. Quando usar: efeito contínuo e prolongado, não só um disparo. Segurança: confete acumulado deixa piso escorregadio e pode obstruir saídas; combinar com detectores e limpeza.</li><li><strong>Cilindro de CO2 + mangueira de alta pressão (acessório crítico):</strong> Conjunto de alimentação. O que é: cilindro de CO2 (sifão/pescador para fase líquida) e mangueira certificada que leva o gás ao jato. Specs: pressão de trabalho elevada, engates específicos, válvula. Quando usar: em todo efeito de CO2. Segurança: cilindro sempre preso na vertical, longe de calor; mangueira sem dobras nem desgaste; checar vazamentos antes; usar luvas (frio extremo).</li></ul><h4>Passo a passo</h4><ol><li><strong>Planejar trajetória e público:</strong> Defina a direção do jato/confete garantindo que ninguém esteja na linha de disparo a curta distância; avalie ventilação e áreas baixas onde o CO2 pode acumular.</li><li><strong>Fixar o cilindro:</strong> Mantenha o cilindro de CO2 sempre na vertical e preso (cinta/corrente), longe de fontes de calor; confirme se é com ou sem tubo sifão conforme o efeito.</li><li><strong>Conectar mangueira e checar vazamentos:</strong> Use mangueira de alta pressão certificada e os engates corretos; aperte firme e teste vazamentos (audição/solução) antes de pressurizar para o show; use luvas.</li><li><strong>Carregar confete e endereçar DMX:</strong> Abasteça o canhão/lançador com o confete correto, defina o endereço DMX e o modo de disparo; confirme o acionamento.</li><li><strong>Teste controlado:</strong> Faça um teste curto com a trajetória livre, observando alcance, força e dispersão reais; reposicione se necessário.</li><li><strong>Operar e despressurizar:</strong> Dispare nos momentos combinados; ao final, feche a válvula do cilindro, alivie a pressão da linha conforme o manual e só então desconecte; planeje a limpeza do confete.</li></ol><p><strong>Na prática:</strong> No clímax de um show em arena, dois Stadium Blasters laterais e quatro CO2 Jets na boca do palco são acionados na última virada. O operador prende cada cilindro de CO2 na vertical com cinta, usa mangueiras certificadas e testa vazamentos antes da casa abrir. Confirma que ninguém da equipe fica na linha de disparo do confete e que o fosso e as laterais baixas têm ventilação, já que o CO2 desce. Após o efeito, fecha as válvulas, alivia a linha e aciona a equipe de limpeza para retirar o confete das saídas e do piso, evitando escorregões.</p><h4>Resumo</h4><ul><li>CO2 jet usa gás líquido de cilindro que vira névoa fria; lança-confete usa CO2 ou ar para projetar papel a distância.</li><li>Cilindro sempre preso e na vertical, mangueira certificada e teste de vazamento são inegociáveis.</li><li>CO2 desloca o oxigênio: cuide da ventilação e de áreas baixas, use luvas e nunca aponte para pessoas próximas.</li></ul>',50,3,true,false);
