insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('67d16237-3dc1-4da9-a025-c12342c459c3','f1bf5222-00d2-459c-8d4a-9d389316ebcf','Por que se usam luvas ao manusear o sistema de CO2?','O CO2 líquido/expandido é extremamente frio e pode causar queimadura por frio (frostbite) na pele.',4,1);
