insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('ff52e5f4-a02b-4acf-823c-6070d359fc73','228e1759-2e82-42f2-b1de-5ede7902a937','Por que a mesa de disparo separa a chave de ''armar'' do botão de ''disparar''?','A separação arm/fire é uma camada de segurança contra disparos acidentais.',2,1);
