insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('13f72e78-070e-4f4d-97f2-e32f6d1e1edc','228e1759-2e82-42f2-b1de-5ede7902a937','Mesmo usando time code, o operador de pirotecnia deve sempre poder:','Automação nunca substitui o controle humano: é preciso poder assumir manual e abortar imediatamente.',3,1);
