insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('d3de7ea2-8250-40bc-9e0a-bc92d8eceed0','228e1759-2e82-42f2-b1de-5ede7902a937','Quando se testa a continuidade dos cues, o sistema deve estar:','A continuidade é verificada com o sistema DESARMADO para evitar disparo acidental durante o teste.',4,1);
