insert into public.modules (id,course_id,titulo,ordem) values ('70490a9d-5f7f-4d28-be19-59e91f405bb9','f82b5aeb-95fd-4212-a067-4bec55c0fb6d','Módulo 1 - O Produtor Executivo: papel, perfil e estrutura da equipe',1);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('09fbf284-95c2-45dd-ab2f-1aeab21a2c24','70490a9d-5f7f-4d28-be19-59e91f405bb9','Quem é o Produtor e os tipos de produção','texto','<p><strong>Para começar:</strong> Antes de planilhas e riders, é preciso entender QUEM dá a última palavra dentro de uma produção e por quê.</p><p>O produtor é o eixo de uma produção de eventos. Nesta aula você vai entender as diferentes funções de produção, onde cada uma começa e termina, e por que o produtor executivo é a voz mais alta da operação. Compreender a hierarquia evita o erro clássico do iniciante: tentar fazer tudo sozinho ou pisar na função do colega.</p><ul><li><strong>Produtor Executivo / Geral:</strong> É o responsável por TODAS as camadas da equipe: transporte, hospedagem, pagamentos, aprovações, e a coordenação dos demais produtores (técnico e artístico). É o chefe da operação e a última voz em qualquer decisão. Quando há conflito de informação entre departamentos, é ele quem decide. Toda a cadeia de responsabilidade financeira e contratual passa por ele.</li><li><strong>Produtor Artístico:</strong> Coordena e gerencia os aspectos da criação artística: seleção de músicos, escolha de repertório, organização de ensaios e gravações, supervisão da produção musical e definição da direção criativa. Garante que a visão artística do projeto seja realizada da melhor forma possível. Em shows, alinha o set, as transições e os momentos-chave da apresentação.</li><li><strong>Produtor Técnico:</strong> Cuida da equipe técnica. Confere os detalhes do rider com o contratante, valida o que o local oferece, organiza transporte e hospedagem da equipe técnica (contratados pelo produtor geral) e aluga ou gerencia os equipamentos necessários. É a ponte entre a exigência técnica do artista e a realidade do local.</li><li><strong>Produtor Pessoal (do artista):</strong> Foca no lado administrativo e na coordenação logística do dia a dia do artista. Diferente do artístico ou do executivo, cuida das necessidades pessoais do artista, assegurando que ele tenha todo o suporte para se concentrar na carreira. Cuida de agenda pessoal, deslocamentos, alimentação e bem-estar.</li><li><strong>Por que a hierarquia importa:</strong> Numa operação de evento, decisões precisam de um dono. Se ''todos decidem'', ninguém decide, e o atraso ou o erro acontece. A definição clara de quem responde por cada camada (e quem dá a palavra final) é o que diferencia uma produção profissional de um amadorismo caro.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Organograma da produção:</strong> Diagrama que mostra a hierarquia e quem responde a quem. Serve para a equipe inteira saber a quem reportar cada tipo de problema. Monte um simples no Google Slides ou Canva e cole no grupo do evento.</li><li><strong>Lista de contatos da equipe (planilha):</strong> Planilha com nome, função, telefone/WhatsApp e responsabilidade de cada integrante. É o primeiro documento que o produtor monta. Mantenha sempre atualizada.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Defina as camadas do projeto:</strong> Liste quais frentes seu evento tem: artística, técnica, logística, financeira, segurança. Nem todo evento tem todas.</li><li><strong>2. Atribua um responsável por camada:</strong> Para cada frente, defina quem responde. Em eventos pequenos, uma pessoa pode acumular funções; registre isso explicitamente.</li><li><strong>3. Estabeleça a voz final:</strong> Deixe claro, por escrito no grupo, que o produtor executivo decide em caso de impasse. Isso evita travamento na hora da pressão.</li><li><strong>4. Desenhe e compartilhe o organograma:</strong> Distribua o diagrama para toda a equipe antes do evento.</li></ol><p><strong>Na prática:</strong> Imagine um show de médio porte. O contratante liga reclamando do horário de carga/descarga. Quem resolve? O produtor técnico fala com a equipe e o local; mas a decisão de pagar uma hora extra de pátio é financeira, então passa pelo produtor executivo. Saber esse fluxo em segundos é o que mantém o evento andando.</p><h4>Resumo</h4><ul><li>O produtor executivo coordena todas as camadas e dá a última palavra.</li><li>Artístico cuida da criação; técnico cuida da equipe e do rider; pessoal cuida do artista.</li><li>Definir responsáveis e a voz final evita travamento sob pressão.</li></ul>',25,1,true,true);
