insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('101dcafb-40db-4f1e-b6b1-fdb2358ecb97','70490a9d-5f7f-4d28-be19-59e91f405bb9','Competências do produtor: perfil profissional','texto','<p><strong>Para começar:</strong> Ferramentas se aprendem; postura se constrói. O que separa um produtor confiável de um improvisador é o conjunto de competências comportamentais.</p><p>Nenhuma planilha salva uma produção tocada por alguém desorganizado ou que não comunica. Esta aula consolida as competências centrais do produtor e mostra como cada uma se traduz em ação prática no dia a dia.</p><ul><li><strong>Proatividade:</strong> Tomar a iniciativa e agir antecipadamente, identificando problemas e oportunidades antes que se tornem evidentes. O produtor proativo não espera o problema explodir: antecipa necessidades, planeja com antecedência e age para influenciar o resultado. É a competência que evita a maioria dos incêndios.</li><li><strong>Discernimento:</strong> Capacidade de analisar e avaliar situações de forma clara e sensata para tomar decisões prudentes. Envolve distinguir opções, entender consequências e escolher a melhor abordagem com critérios racionais e éticos. Essencial em situações ambíguas, onde não há resposta óbvia.</li><li><strong>Organização:</strong> Estruturar, planejar e administrar tarefas, recursos e informações com eficiência. Priorizar tarefas, definir metas claras, acompanhar prazos e manter tudo acessível. Inclui manter a agenda sempre atualizada e confirmar com a equipe novas datas e horários.</li><li><strong>Comunicação:</strong> Expressar ideias com clareza e ouvir bem, adaptando a mensagem ao público e ao contexto. Comunicação eficaz constrói relacionamentos, viabiliza colaboração e resolve conflitos. No evento, comunicação ruim vira atraso e retrabalho.</li><li><strong>Confiabilidade:</strong> Ser alguém em quem a equipe pode depender: consistente em ações e palavras, cumpridor de promessas, ético e discreto. A confiança permite que pessoas compartilhem informações e trabalhem juntas. É construída ao longo do tempo e é a base do networking no setor.</li><li><strong>Foco:</strong> Manter a atenção no objetivo do evento mesmo sob ruído, imprevisto e pressão. O produtor que perde o foco perde o controle do cronograma.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Agenda digital (Google Agenda):</strong> Mantém datas, horários e confirmações da equipe sempre atualizados. Use lembretes e convites com confirmação de presença para registrar quem confirmou.</li><li><strong>App de tarefas / checklist:</strong> Trello, Notion ou Google Keep para registrar pendências e não confiar só na memória. Transforma a proatividade em sistema.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Faça autoavaliação:</strong> Para cada competência, dê uma nota de 1 a 5 em você mesmo. Seja honesto.</li><li><strong>2. Ataque a competência mais fraca:</strong> Escolha a de menor nota e defina uma ação concreta (ex.: organização → começar a usar uma planilha de tarefas hoje).</li><li><strong>3. Crie rotinas de confirmação:</strong> Toda nova data/horário deve ser confirmada com a equipe por escrito. Vire isso um hábito.</li></ol><p><strong>Na prática:</strong> Um fornecedor avisa que o caminhão atrasará 2h. O produtor proativo já tinha o telefone de um fornecedor reserva (organização), avalia se vale esperar ou trocar (discernimento), comunica a equipe imediatamente (comunicação) e mantém a calma para não contaminar o time (foco). As cinco competências agem juntas em segundos.</p><h4>Resumo</h4><ul><li>Proatividade, discernimento, organização, comunicação e confiabilidade são o núcleo do produtor.</li><li>Competências se traduzem em rotinas: agenda atualizada, confirmações por escrito, plano B pronto.</li><li>Sob pressão, as competências agem juntas e em segundos.</li></ul>',20,2,true,false);
