insert into public.modules (id,course_id,titulo,ordem) values ('22e48967-735f-485e-b1d9-971d1c3e99bf','f82b5aeb-95fd-4212-a067-4bec55c0fb6d','Módulo 2 - Pré-evento I: briefing, licenças e projeto',2);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('29163c42-4b0f-44d9-89bb-6d434e22c9ab','22e48967-735f-485e-b1d9-971d1c3e99bf','Briefing: o documento que dá origem ao evento','texto','<p><strong>Para começar:</strong> Todo evento bom nasce de um briefing claro. Sem ele, a produção vira adivinhação cara.</p><p>O briefing é o documento que fornece as informações essenciais e orientações para guiar a criação e a execução de um projeto. Ele alinha todas as partes envolvidas em uma compreensão comum das metas e expectativas. Nesta aula você vai aprender a estrutura completa de um briefing e como conduzi-lo com o cliente.</p><ul><li><strong>Informações gerais:</strong> Título do projeto, data de início e conclusão prevista, e o local onde o evento será realizado. É o cabeçalho que identifica o projeto.</li><li><strong>Objetivo do projeto:</strong> Descrição do que é o evento, sua finalidade e o que se espera alcançar. Inclui o público-alvo: para quem o evento é feito. Tudo o que vier depois precisa servir a esse objetivo.</li><li><strong>Inspiração e conceito:</strong> Tema ou conceito que orienta a produção e referências visuais (imagens, obras, exemplos) que inspiram a criação. Dá a ''cara'' do evento.</li><li><strong>Formato e mídia:</strong> Tipo de evento/arte (show, peça, exposição, performance) e as ferramentas ou materiais específicos a serem usados.</li><li><strong>Orçamento:</strong> Orçamento total disponível, incluindo materiais, equipamentos, honorários e demais custos. É o limite que define o que é possível.</li><li><strong>Cronograma e logística:</strong> Datas-chave (marcos, ensaios, instalação, abertura), características do espaço e requisitos técnicos (iluminação, som, projeção).</li><li><strong>Equipe, aprovações e métricas:</strong> Lista de participantes e funções, processo e número de aprovações/revisões, métricas de sucesso (como o resultado será medido), gestão de feedback e os contatos com a frequência de atualizações.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Modelo de briefing (Google Docs/Forms):</strong> Documento padronizado com todos os campos acima. Use um Google Forms para o cliente preencher e cair direto numa planilha, ou um Doc compartilhado para preencher na reunião.</li><li><strong>Pasta de referências visuais:</strong> Pasta no Drive ou board no Pinterest/Notion para reunir as referências de conceito que o cliente trouxer.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Agende a reunião de briefing:</strong> Marque com o cliente/contratante. Leve o modelo pronto para preencher campo a campo.</li><li><strong>2. Preencha informações gerais e objetivo:</strong> Comece pelo nome, data, local e, principalmente, o objetivo e o público-alvo.</li><li><strong>3. Capture conceito e referências:</strong> Peça exemplos visuais. ''Mostre-me um evento que você admira'' destrava o conceito.</li><li><strong>4. Trave orçamento e datas-chave:</strong> Sem o teto de orçamento e os marcos, nada do resto se planeja.</li><li><strong>5. Defina aprovações e métricas de sucesso:</strong> Quem aprova cada etapa e como o sucesso será medido (público, satisfação, impacto).</li><li><strong>6. Valide e distribua:</strong> Releia com o cliente, ajuste e compartilhe a versão final com a equipe. Clareza e precisão são essenciais.</li></ol><p><strong>Na prática:</strong> Cliente diz: ''quero um show inesquecível''. Inutilizável. Com o briefing você transforma isso em: evento dia 20/09, para 800 pessoas de 25-40 anos, conceito anos 80, orçamento de R$ 80 mil, sucesso medido por lotação e pesquisa de satisfação. Agora dá para produzir.</p><h4>Resumo</h4><ul><li>O briefing alinha todos numa compreensão comum do projeto.</li><li>Sem objetivo, público, orçamento e datas-chave, não há planejamento.</li><li>Clareza e precisão no briefing evitam retrabalho e surpresas.</li></ul>',30,1,true,false);
