insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('8d2276d2-21f3-4807-a6c2-76a9dc83c010','6ac49cc8-fd9c-4727-a64d-1d5b7ce92fba','Uma boa prática para capturar o conceito é:','Referências visuais destravam o conceito e alinham expectativas.',4,1);
