insert into public.quiz_options (question_id,texto,correta,ordem) values ('8d2276d2-21f3-4807-a6c2-76a9dc83c010','Começar pela desmontagem',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('09b1d99a-1337-4c67-85f7-c108e7c993e8','22e48967-735f-485e-b1d9-971d1c3e99bf','Licenças, autorizações e documentação legal do evento','texto','<p><strong>Para começar:</strong> Um evento sem documentação em ordem é uma multa (ou uma interdição) esperando para acontecer.</p><p>As licenças variam conforme o tipo de evento, o porte e o município/estado. O produtor não precisa ser advogado, mas precisa saber QUAIS frentes existem e acionar assessoria jurídica e os órgãos certos. IMPORTANTE: exigências, prazos e órgãos mudam conforme a legislação local; confirme sempre com a prefeitura e com assessoria especializada.</p><ul><li><strong>Licenças do evento:</strong> Alvará de autorização da prefeitura (uso do espaço), licença do Corpo de Bombeiros (segurança contra incêndio e pânico), licença ambiental (quando há impacto, como shows ao ar livre), licença de funcionamento de evento temporário, autorização para uso de som amplificado e autorização para venda de alimentos e bebidas (vigilância sanitária).</li><li><strong>Direitos autorais (ECAD):</strong> Para execução de músicas protegidas é necessária a autorização/recolhimento junto ao ECAD, garantindo a compensação a autores e compositores. Aplica-se a música ao vivo e mecânica.</li><li><strong>Casos específicos:</strong> Licença para venda de ingressos (evento pago), licença para fogos de artifício e licença de segurança/proteção contra incêndios em locais fechados. Cada um tem órgão e exigência próprios.</li><li><strong>Documentação do local:</strong> Habite-se (local apto para uso), laudo de segurança estrutural (palcos, arquibancadas), alvará sanitário (alimentos/banheiros) e contrato de locação do espaço.</li><li><strong>Documentação de contratação:</strong> Contratos de prestação de serviços, CNPJ/CPF dos prestadores, certificados de capacitação (operadores, seguranças, brigadistas) e seguro de responsabilidade civil para cobrir acidentes.</li><li><strong>Comunicação prévia às autoridades:</strong> Polícia Militar (segurança pública), Secretaria de Trânsito (impacto no tráfego) e Conselho Tutelar (eventos com menores). Avisar com antecedência evita problemas no dia.</li><li><strong>Seguro de responsabilidade civil:</strong> Não é uma licença, mas cobre danos ou lesões durante o evento. Altamente recomendado para qualquer evento com público.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Checklist de licenças por evento:</strong> Planilha onde cada licença vira uma linha com status (a solicitar / solicitada / emitida), órgão, prazo e responsável. É o mapa da regularização.</li><li><strong>Pasta 06_Documentação_Legal (Drive):</strong> Subpasta dedicada para guardar alvarás, laudos, contratos e comprovantes. Acesso restrito.</li><li><strong>Assessoria jurídica especializada:</strong> Profissional ou escritório que valida contratos e licenças. Para eventos de porte, é investimento, não custo.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Mapeie as exigências locais:</strong> Consulte a prefeitura do município do evento e/ou a assessoria jurídica. As regras são locais.</li><li><strong>2. Liste todas as licenças aplicáveis:</strong> Monte o checklist marcando o que se aplica ao seu caso (som, alimentos, fogos, ingressos, etc.).</li><li><strong>3. Identifique prazos e responsáveis:</strong> Cada órgão tem prazo. Licenças de bombeiros e ambiental costumam demorar; comece cedo.</li><li><strong>4. Reúna a documentação do local e dos prestadores:</strong> Habite-se, laudo estrutural, contratos, CNPJ/CPF, certificados de capacitação.</li><li><strong>5. Faça as comunicações prévias:</strong> PM, trânsito e Conselho Tutelar quando aplicável.</li><li><strong>6. Contrate o seguro de responsabilidade civil:</strong> Dimensione conforme o porte e o público.</li></ol><p><strong>Na prática:</strong> Show ao ar livre para 2 mil pessoas com venda de bebida. Frentes obrigatórias: alvará da prefeitura, bombeiros, licença ambiental (ruído/ar livre), autorização de som, autorização de bebidas (sanitária), ECAD, comunicação à PM e ao trânsito, e seguro. Esquecer uma única delas pode interditar o evento na véspera.</p><h4>Resumo</h4><ul><li>Licenças variam por tipo, porte e legislação local: sempre confirme com a prefeitura e assessoria.</li><li>ECAD, bombeiros, sanitária, ambiental e alvará são as frentes mais comuns.</li><li>Documentação do local e dos prestadores e seguro completam a regularização.</li></ul>',30,2,true,false);
