insert into public.modules (id,course_id,titulo,ordem) values ('731cdd00-a84e-4302-a3f4-b8032e7d5c9b','f82b5aeb-95fd-4212-a067-4bec55c0fb6d','Módulo 3 - Pré-evento II: roteiro logístico, cronogramas e rider técnico',3);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('fb0b730f-f363-440d-8370-0843d4ff9e39','731cdd00-a84e-4302-a3f4-b8032e7d5c9b','Roteiro logístico do evento','texto','<p><strong>Para começar:</strong> O roteiro logístico é o documento que garante que cada coisa esteja no lugar certo, na hora certa.</p><p>O roteiro logístico de um show garante que todos os elementos estejam no local e na hora corretos, contribuindo para uma produção suave e eficiente. Nesta aula você vai conhecer a estrutura completa do roteiro e aprender a montá-lo.</p><ul><li><strong>Informações gerais e equipe:</strong> Nome do evento, data, hora e local. Equipe envolvida dividida em produção, técnica (som, luz, palco) e segurança, com nomes e contatos.</li><li><strong>Cronograma do dia:</strong> Sequência horária: montagem e teste de som; montagem de iluminação e cenografia; check-in da banda/artista (com camarins); ensaio geral; portas abertas (conferência de ingressos e orientação do público); e o show ao vivo.</li><li><strong>Recursos necessários:</strong> Equipamento de som e iluminação, instrumentos, camarins, seguranças e equipe de atendimento ao público. É a lista do que precisa existir no local.</li><li><strong>Logística de carga e descarga:</strong> Horários designados para descarga e para carregamento pós-evento, local específico de carga/descarga e o responsável por essa logística.</li><li><strong>Segurança e emergência:</strong> Pontos de saída de emergência, localização do kit de primeiros socorros e procedimentos de evacuação. Item inegociável.</li><li><strong>Aprovações, contatos e anexos:</strong> Processo de aprovação, número de revisões, lista de contatos, frequência de atualizações, assinaturas e anexos (mapas do local, contratos relevantes).</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Modelo de roteiro logístico (Google Docs):</strong> Documento com as seções acima. Reaproveite como template entre eventos, ajustando datas e nomes.</li><li><strong>Planilha de cronograma horário:</strong> Coluna de horário, atividade e responsável. Visualiza o dia inteiro numa olhada (ver exemplo na próxima aula).</li><li><strong>Mapa do local / planta:</strong> Imagem ou planta do espaço marcando palco, carga/descarga, saídas de emergência, camarins e posto médico.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Preencha cabeçalho e equipe:</strong> Evento, data, local e a equipe por área com contatos.</li><li><strong>2. Monte o cronograma horário:</strong> Do início da montagem ao fim do show, hora a hora, com responsável por bloco.</li><li><strong>3. Liste recursos e carga/descarga:</strong> O que precisa existir e quando entra/sai do local, com responsável.</li><li><strong>4. Defina o plano de segurança e emergência:</strong> Saídas, primeiros socorros e evacuação. Comunique à equipe.</li><li><strong>5. Anexe mapa e contratos e colha aprovações:</strong> Mapa do local, contratos relevantes e assinaturas das partes.</li><li><strong>6. Distribua e mantenha versão única:</strong> Todos trabalham na MESMA versão. Datar o arquivo evita confusão.</li></ol><p><strong>Na prática:</strong> Sem roteiro, o caminhão de backline chega na hora das portas abrirem e trava tudo. Com o roteiro, a descarga foi às 07:30, o palco montou até as 12:00, o soundcheck rodou às 13:00 e o público entrou às 18:00 sem cruzar com equipamento. O roteiro é o que evita o caos do dia.</p><h4>Resumo</h4><ul><li>O roteiro logístico coloca cada coisa no lugar e na hora certa.</li><li>Cobre equipe, cronograma, recursos, carga/descarga, segurança e anexos.</li><li>Versão única e datada evita confusão no dia do evento.</li></ul>',30,1,true,false);
