insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('be7a5974-2353-4f9f-996b-f740dd932fca','1fb21913-f2fc-4a16-887e-d6f29dac097f','Por que manter versão única e datada do roteiro?','Versão única datada evita que a equipe trabalhe com informações divergentes.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('be7a5974-2353-4f9f-996b-f740dd932fca','Para gastar mais papel',false,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('be7a5974-2353-4f9f-996b-f740dd932fca','Para que todos trabalhem na mesma informação e evitar confusão',true,2);
