insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('26fbb910-2570-4488-a426-fea6346108e3','731cdd00-a84e-4302-a3f4-b8032e7d5c9b','Cronogramas de equipe técnica, artística e de viagem','texto','<p><strong>Para começar:</strong> O cronograma é o relógio do evento. Quem domina o cronograma domina a operação.</p><p>Existem cronogramas distintos que se encaixam: o da equipe técnica, o da equipe artística e o de viagem/turnê. Nesta aula você aprende a montar cada um e a sincronizá-los para que som, luz, artista e público convirjam no mesmo ponto.</p><ul><li><strong>Cronograma da equipe técnica:</strong> Do dia do evento: montagem e teste de som e luz; check-in e recepção do artista (camarins e requisitos específicos); ensaio e ajustes finais; performance ao vivo com monitoramento constante de som e luz; e a desmontagem e carga de equipamentos no pós-evento. A equipe técnica deve manter comunicação constante (rádio) e ter plano de contingência para falhas técnicas.</li><li><strong>Cronograma da equipe artística:</strong> Chegada e preparação nos camarins; ensaio geral e ajustes de som/luz/cenografia; tempo livre e descanso; jantar; check de figurino e maquiagem; preparação pré-show (revisão de repertório, alinhamento com a banda); performance; e interação com fãs/mídia (autógrafos, fotos, entrevistas).</li><li><strong>Cronograma de viagem/turnê:</strong> Para deslocamentos: check-in no aeroporto e verificação de documentos; voo; transferência e check-in no hotel; tempo de aclimatação; reunião de equipe (revisão de itinerário e briefing); ensaios e preparação. Em dias de show numa turnê, integra exploração local, refeições, preparação, show, interação com fãs e debriefing pós-show.</li><li><strong>Sincronização dos cronogramas:</strong> Os três precisam conversar: a montagem técnica tem que estar pronta antes do ensaio artístico; o check-in do artista depende da viagem; o soundcheck precisa de palco montado. O produtor é quem garante o encaixe.</li><li><strong>Reunião de briefing do cronograma:</strong> Ao compartilhar os cronogramas, faça reuniões de briefing para garantir que todos conheçam suas responsabilidades e o fluxo de trabalho. Cronograma sem briefing é papel ignorado.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Planilha de cronograma (Google Sheets):</strong> Colunas: Horário | Atividade | Responsável. Uma aba por frente (técnica, artística, viagem). Cores por status facilitam a leitura.</li><li><strong>Calendário compartilhado (Google Agenda):</strong> Registra ensaios, shows, deslocamentos e prazos. Convites com confirmação documentam quem está ciente.</li><li><strong>Rádio comunicador / grupo de WhatsApp:</strong> Comunicação constante no dia. Rádio para a operação técnica; grupo para alinhamentos e registros.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Defina o horário do show (âncora):</strong> Tudo se calcula a partir da hora do show, de trás para frente.</li><li><strong>2. Aloque a montagem técnica:</strong> Reserve tempo de sobra para montagem e teste de som/luz. Atraso aqui derruba o resto.</li><li><strong>3. Encaixe check-in do artista e ensaio:</strong> O artista chega depois da montagem; o ensaio acontece com o palco pronto.</li><li><strong>4. Posicione preparação, figurino e pré-show:</strong> Jantar, descanso, figurino/maquiagem e alinhamento de repertório antes de subir ao palco.</li><li><strong>5. Sincronize com a viagem:</strong> Se há deslocamento, o cronograma de viagem precisa entregar o artista antes do check-in.</li><li><strong>6. Faça a reunião de briefing:</strong> Apresente o cronograma e confirme que cada um entendeu sua responsabilidade.</li></ol><p><strong>Na prática:</strong> Show às 21:00. De trás para frente: pré-show 19:30, figurino 19:00, jantar 18:00, ensaio 14:00-16:00, montagem técnica 12:00-15:00, descarga 07:30. Se o voo do artista só pousa às 18:00, há conflito com o jantar; o produtor antecipa o jantar ou o transporte. É o encaixe dos três cronogramas que faz o show acontecer.</p><h4>Resumo</h4><ul><li>Há cronogramas técnico, artístico e de viagem, e eles devem se sincronizar.</li><li>Monte de trás para frente a partir do horário do show.</li><li>Cronograma sem reunião de briefing é papel ignorado.</li></ul>',30,2,true,false);
