insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('498b522f-a23f-4321-907e-c95c324092dd','422c4b5a-6b6f-477d-bb31-2d7821979186','A equipe técnica deve, durante o show:','Comunicação constante e plano de contingência são essenciais para a técnica.',3,1);
