insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('2a1cb3d4-8a10-40d8-978a-2f18b82d612f','731cdd00-a84e-4302-a3f4-b8032e7d5c9b','Rider técnico: o documento técnico do artista','texto','<p><strong>Para começar:</strong> O rider técnico é a ponte entre o que o artista exige e o que o local oferece. Lê-lo errado custa caro.</p><p>O rider técnico descreve as especificações técnicas necessárias para a produção: equipamentos, palco, energia, equipe e hospitalidade. É elaborado pelo artista/equipe e compartilhado com a equipe técnica do local. O produtor técnico confere o rider com o contratante e valida o que o local entrega. Nesta aula você aprende a ler, conferir e usar um rider.</p><ul><li><strong>Equipamentos:</strong> Especificações detalhadas de som, luz, palco e demais equipamentos, com marcas e modelos preferidos pelo artista (PA, monitores, microfones, backline). É a ''lista de compras'' técnica.</li><li><strong>Configuração de palco:</strong> Dimensões e layout do palco, número de microfones, caixas, monitores e os requisitos de cenografia e elementos visuais. Define o que precisa caber e onde.</li><li><strong>Requisitos elétricos:</strong> Necessidades de alimentação elétrica de todos os equipamentos e os pontos estratégicos de energia. Falha elétrica é uma das principais causas de problema em palco.</li><li><strong>Equipe técnica:</strong> Número e funções dos profissionais necessários: engenheiro de som (PA e monitor), iluminador, técnicos de palco e backline. Define quem precisa estar presente.</li><li><strong>Camarins e hospedagem:</strong> Necessidades de camarim (água, alimentos específicos) e os requisitos de hospedagem da equipe e do artista. É o rider de hospitalidade, parte do cuidado com o artista.</li><li><strong>Segurança e logística de carga:</strong> Requisitos de segurança no palco e no local, instruções de emergência, e horários/locais de carga e descarga, com necessidade de estacionamento.</li><li><strong>Rider técnico x rider de hospitalidade:</strong> O rider técnico trata de equipamentos e palco; o rider de hospitalidade trata de camarim, alimentação, transporte e conforto. Frequentemente vêm juntos, mas o produtor trata cada frente com o fornecedor certo.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Rider técnico (PDF do artista):</strong> Documento-fonte enviado pelo artista. Guarde sempre a última versão datada na pasta do artista.</li><li><strong>Stage plan / mapa de palco:</strong> Desenho que mostra onde fica cada músico, instrumento, monitor e microfone no palco. Acompanha o rider e orienta a montagem.</li><li><strong>Input list (lista de canais):</strong> Lista numerada de cada entrada na mesa de som (canal 1: bumbo, canal 2: caixa, etc.). É o que o engenheiro de som usa para ligar tudo.</li><li><strong>Planilha de conferência de rider:</strong> Coluna do que o rider pede x o que o local oferece x status (ok / faltando / substituto). É como o produtor técnico valida o rider.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Receba e leia o rider completo:</strong> Não pule. Cada linha de equipamento e energia importa.</li><li><strong>2. Confronte rider x infraestrutura do local:</strong> Monte a planilha de conferência: o que o rider pede e o que o local realmente tem.</li><li><strong>3. Resolva as lacunas:</strong> O que falta: aluga, substitui por equivalente (com aprovação do artista) ou negocia. Documente cada decisão.</li><li><strong>4. Valide o stage plan e a input list:</strong> Confira o mapa de palco e a lista de canais com o engenheiro de som.</li><li><strong>5. Trate a hospitalidade separadamente:</strong> Camarim, alimentação e hospedagem vão para os fornecedores certos.</li><li><strong>6. Confirme com o contratante e a equipe técnica do local:</strong> Alinhe expectativas antes do dia. O cumprimento do rider é o que garante a performance.</li></ol><p><strong>Na prática:</strong> O rider pede PA L-Acoustics, 6 vias de monitor in-ear, SM58 nas vozes e kit padrão de bateria. O local só tem 4 vias de monitor. O produtor técnico identifica a lacuna na planilha, aluga 2 vias extras e confirma com o engenheiro do artista antes do soundcheck. Sem essa conferência, o problema só apareceria na hora do show, sem solução.</p><h4>Resumo</h4><ul><li>O rider técnico especifica equipamentos, palco, energia, equipe e hospitalidade.</li><li>O produtor técnico confere rider x local e resolve as lacunas antes do dia.</li><li>Stage plan e input list orientam a montagem e a operação de som.</li></ul>',30,3,true,false);
