insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('bdb4d020-7916-473f-94d8-9dd50c0ff619','88269049-d0f3-46d6-8e58-8196457b7263','A diferença entre rider técnico e rider de hospitalidade é:','O técnico cuida de palco/equipamentos; a hospitalidade, de camarim e conforto.',4,1);
