insert into public.modules (id,course_id,titulo,ordem) values ('37296755-a6ac-43c8-b0a2-a2a46b427baf','f82b5aeb-95fd-4212-a067-4bec55c0fb6d','Módulo 4 - Equipe e financeiro: contratação, orçamento e documentos de pagamento',4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('f08dda32-5363-4765-9403-4609e9e0df99','37296755-a6ac-43c8-b0a2-a2a46b427baf','Montando a equipe: funções, contratação e escala','texto','<p><strong>Para começar:</strong> Formar uma equipe é essencial. O evento é tão bom quanto as pessoas que o operam.</p><p>Nesta aula você vai conhecer as funções de uma equipe de produção, os critérios de contratação e como montar a escala de trabalho que distribui as pessoas ao longo do pré, durante e pós-evento.</p><ul><li><strong>Funções técnicas e de apoio:</strong> Técnico de som, técnico de luz, VJ, técnico de efeito, técnico de segurança, técnico de transporte, roadie, produtor pessoal, produtor técnico e equipe artística (banda, DJ, músicos, dobra). Cada função tem responsabilidade e perfil próprios.</li><li><strong>Posições-chave da produção:</strong> Gerente de produção (supervisão geral e coordenação logística), diretor artístico (direção criativa), engenheiro de som (mixagem em estúdio e ao vivo), road manager (logística em turnê e solução de problemas em tempo real), técnico de palco, designer de iluminação, coordenador de marketing, assistente pessoal do artista, equipe de apoio em turnê e contratantes locais.</li><li><strong>Critérios de contratação:</strong> Selecione por habilidade técnica E por compatibilidade cultural e comprometimento com a visão do projeto. Para cada posição, avalie experiência comprovada, habilidades específicas (organização, comunicação) e, em funções sensíveis, discrição e confiabilidade. Comunicação aberta e colaboração são fundamentais.</li><li><strong>Contratantes locais:</strong> Em eventos fora da base, profissionais locais que conhecem regulamentações e têm rede estabelecida na cidade. Reduzem risco e custo de deslocamento de equipe.</li><li><strong>A escala de trabalho:</strong> Documento que distribui quem faz o quê em cada fase: pré-produção (semana anterior), dia do show (manhã, tarde, noite/durante, após) e pós-produção (dia seguinte e suporte contínuo). Garante que cada momento tenha responsável e evita buracos de cobertura.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Planilha de equipe e contatos:</strong> Nome | Função | Contato. Base para escala, logística e comunicação. Mantenha atualizada.</li><li><strong>Escala de trabalho (planilha):</strong> Distribui funções por fase (pré, dia, pós). Cada bloco com responsável nomeado.</li><li><strong>Documento de contratação de fornecedores/equipe:</strong> Registra fornecedor, serviço contratado, data/hora e valor acordado de cada contratação, com responsabilidades e condições gerais.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Liste as funções que o evento exige:</strong> Nem todo evento precisa de VJ ou designer de iluminação dedicado. Dimensione pelo porte.</li><li><strong>2. Defina critérios por posição:</strong> Para cada função, anote habilidade técnica + perfil (confiabilidade, comunicação) exigidos.</li><li><strong>3. Selecione e contrate:</strong> Avalie experiência e compatibilidade. Formalize com o documento de contratação (serviço, data, valor).</li><li><strong>4. Considere contratantes locais:</strong> Em eventos fora da base, contrate apoio local que conheça a cidade e as regras.</li><li><strong>5. Monte a escala por fase:</strong> Distribua a equipe na pré-produção, no dia (manhã/tarde/durante/após) e no pós.</li><li><strong>6. Faça o briefing de responsabilidades:</strong> Cada um precisa saber claramente o que faz e quando. Mantenha contingência para imprevistos.</li></ol><p><strong>Na prática:</strong> Para um show, a escala fica: na semana anterior o gerente de produção planeja e o técnico de palco confere equipamento; na manhã do dia, montagem; à tarde, soundcheck e luz; à noite, som e luz operando o show; após, desmontagem; no dia seguinte, avaliação e relatório. Cada bloco com nome. Sem escala, alguém sempre ''achava que era o outro''.</p><h4>Resumo</h4><ul><li>A equipe combina funções técnicas, artísticas, de apoio e posições-chave de gestão.</li><li>Contrate por habilidade técnica E por confiabilidade e alinhamento com o projeto.</li><li>A escala distribui responsáveis por fase e evita buracos de cobertura.</li></ul>',30,1,true,false);
