insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('9fed4ee2-09df-4046-b532-63eb662c232f','37296755-a6ac-43c8-b0a2-a2a46b427baf','Orçamento do evento: como montar a planilha','texto','<p><strong>Para começar:</strong> O orçamento é onde o evento prova que é viável. Sem ele, você produz no escuro.</p><p>Montar a planilha de orçamento pré-evento é etapa crucial para identificar e gerenciar todos os custos. Nesta aula você vai aprender o passo a passo completo da construção de um orçamento, com fórmulas, contingência e validação.</p><ul><li><strong>Categorias de custo:</strong> Liste todas as categorias possíveis: locação de espaço, equipe, equipamentos, marketing, catering, transporte, decoração, entre outros. Nada deve ficar de fora.</li><li><strong>Custos fixos x variáveis:</strong> Custos fixos são constantes (locação do salão); variáveis mudam com o porte/número de participantes (catering por pessoa). Distinguir os dois ajuda a simular cenários.</li><li><strong>Custos diretos x indiretos:</strong> Diretos são ligados ao evento (palco, artista); indiretos incluem despesas administrativas, seguro e taxas. Esquecer indiretos estoura o orçamento depois.</li><li><strong>Contingência:</strong> Reserve uma porcentagem do total para custos imprevistos e mudanças de última hora. É o que separa o produtor experiente do otimista.</li><li><strong>Taxas e impostos:</strong> Inclua taxas e impostos aplicáveis aos custos para evitar surpresas no valor final.</li><li><strong>Estrutura da planilha:</strong> Colunas: Categoria | Descrição do item | Quantidade | Custo unitário | Custo total. Use fórmulas (quantidade x custo unitário) e subtotais por categoria mais total geral.</li><li><strong>Validação e atualização:</strong> Revise para garantir que nada foi omitido, compartilhe com as partes interessadas (equipe, cliente, patrocinadores) e atualize sempre que surgirem novas informações.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Planilha de orçamento (Google Sheets / Excel):</strong> Onde o orçamento vive. Use SOMA, multiplicação e formatação de moeda. Uma aba de resumo com subtotais e total geral.</li><li><strong>Cotações de fornecedores:</strong> Documentos de apoio (e-mails, propostas) que sustentam cada valor estimado. Vincule-os à planilha.</li><li><strong>Modelo de estrutura de orçamento:</strong> Template com categorias-padrão (locação, catering, marketing, equipamentos, transporte, decoração, administrativo) para reaproveitar entre eventos.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Liste as categorias de custo:</strong> Levante todas as frentes do evento. Use o briefing como base.</li><li><strong>2. Detalhe os itens por categoria:</strong> Para cada categoria, crie linhas com descrição, quantidade e custo unitário.</li><li><strong>3. Estime com cotações reais:</strong> Baseie os valores em pesquisa de mercado, cotações de fornecedores e experiência. Nunca chute.</li><li><strong>4. Aplique fórmulas e subtotais:</strong> Custo total = quantidade x unitário. Some subtotais por categoria e o total geral.</li><li><strong>5. Some contingência, indiretos, taxas e impostos:</strong> Reserve a contingência e inclua custos indiretos, taxas e impostos.</li><li><strong>6. Revise, valide e compartilhe:</strong> Confira se nada foi omitido, valide com as partes interessadas e mantenha o documento de apoio (cotações) anexo.</li><li><strong>7. Atualize ao longo do projeto:</strong> Sempre que mudar algo, atualize a planilha para manter precisão.</li></ol><p><strong>Na prática:</strong> Exemplo simples: Locação (1 salão x R$ 5.000 = R$ 5.000) + Catering (150 coffee breaks x R$ 10 = R$ 1.500) + Marketing (5.000 flyers x R$ 0,20 = R$ 1.000)... total parcial R$ 15.000. Sobre isso, soma-se contingência (ex.: 10% = R$ 1.500), indiretos, taxas e impostos. O número final é o que torna o evento viável ou não.</p><h4>Resumo</h4><ul><li>O orçamento lista todas as categorias, distinguindo fixos/variáveis e diretos/indiretos.</li><li>Use fórmulas, subtotais e total geral; estime com cotações reais.</li><li>Sempre reserve contingência e inclua taxas/impostos para não estourar.</li></ul>',35,2,true,false);
