insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('641b86e1-b247-498a-beef-58c1414720a5','37296755-a6ac-43c8-b0a2-a2a46b427baf','Documentos financeiros: despesas, pagamentos e contratações','texto','<p><strong>Para começar:</strong> Dinheiro sem documento é problema. Cada real que entra ou sai precisa de registro.</p><p>Além do orçamento, o produtor mantém três documentos financeiros operacionais: o de despesas, o de pagamentos e o de contratações. Nesta aula você vê a estrutura de cada um e como usá-los para manter o controle e a transparência.</p><ul><li><strong>Documento de despesas pré-evento:</strong> Organiza as despesas em grupos (gerais, específicas e administrativas), cada item com descrição, quantidade, custo unitário e custo total, com subtotais por grupo e total geral. Mostra para onde o dinheiro vai antes do evento.</li><li><strong>Documento de pagamentos:</strong> Registra, por fornecedor, cada serviço com: data prevista, valor previsto, data de pagamento, valor pago e método de pagamento (transferência, cartão, cheque, dinheiro). Acompanha o total previsto x total pago e mantém recibos e comprovantes.</li><li><strong>Documento de contratações:</strong> Para cada fornecedor/equipe técnica: nome, serviço contratado, data e hora, e valor acordado. Inclui responsabilidades contratuais, termos e condições gerais e espaço para assinatura do organizador.</li><li><strong>Métodos de pagamento e comprovação:</strong> Cada transação pode ter método diferente; o essencial é registrar e guardar comprovante. A documentação de apoio (recibos, notas) sustenta o controle e a prestação de contas.</li><li><strong>Orientação jurídica:</strong> Ao elaborar contratos, busque sempre orientação jurídica para cobrir os aspectos legais. Os modelos são pontos de partida, não substituem assessoria.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Planilha de despesas (por grupo):</strong> Gerais, específicas e administrativas com subtotais e total geral. Reflete a saída de caixa pré-evento.</li><li><strong>Planilha de pagamentos (previsto x pago):</strong> Controla data prevista, valor previsto, data e valor pagos e método. Mostra o que ainda está pendente.</li><li><strong>Modelo de documento de contratações:</strong> Registra cada fornecedor, serviço, data/hora e valor acordado, com cláusulas e assinatura.</li><li><strong>Pasta de recibos e comprovantes:</strong> Arquivo organizado de notas fiscais, RPA e comprovantes. Base da prestação de contas e do fechamento.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Monte o documento de despesas:</strong> Agrupe em gerais, específicas e administrativas; calcule subtotais e total geral.</li><li><strong>2. Crie o controle de pagamentos:</strong> Para cada fornecedor, registre previsto x pago, datas e método. Atualize a cada pagamento.</li><li><strong>3. Formalize as contratações:</strong> Para cada contratação, registre serviço, data/hora e valor acordado, com termos e assinatura.</li><li><strong>4. Guarde todos os comprovantes:</strong> Recibo, nota ou comprovante de transferência para cada pagamento. Sem comprovante, não houve pagamento (para fins de controle).</li><li><strong>5. Mantenha comunicação clara com fornecedores:</strong> Qualquer alteração de serviço, data ou valor deve ser acordada por escrito entre as partes.</li><li><strong>6. Busque orientação jurídica nos contratos:</strong> Valide cláusulas com assessoria antes de assinar.</li></ol><p><strong>Na prática:</strong> Você fecha catering por R$ 1.500, pagamento previsto para o dia 10 via transferência. No documento de pagamentos, a linha fica: previsto R$ 1.500 / pago R$ 1.500 em 10/xx / transferência, com o comprovante anexado na pasta. No fechamento pós-evento, basta somar os ''valor pago'' para saber exatamente quanto saiu.</p><h4>Resumo</h4><ul><li>Despesas, pagamentos e contratações são os três documentos financeiros operacionais.</li><li>Pagamentos controlam previsto x pago, data e método, com comprovante guardado.</li><li>Modelos são ponto de partida: contratos pedem orientação jurídica.</li></ul>',30,3,true,false);
