insert into public.modules (id,course_id,titulo,ordem) values ('25d936ed-0c2b-4b15-a57c-1f5e5ef56467','f82b5aeb-95fd-4212-a067-4bec55c0fb6d','Módulo 5 - Durante o evento: logística, montagem e execução',5);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('4fbaf91c-4e38-45ae-868e-ca005b97d8ff','25d936ed-0c2b-4b15-a57c-1f5e5ef56467','Assegurar a logística e acompanhar a montagem','texto','<p><strong>Para começar:</strong> No dia do evento, o produtor deixa de planejar e passa a fazer acontecer. A logística e a montagem são o primeiro teste.</p><p>Assegurar a logística é fundamental para o sucesso da produção. Nesta aula você vê as responsabilidades do produtor no planejamento logístico prévio e, principalmente, no acompanhamento da montagem no dia, fase crítica que define se o evento começa bem.</p><ul><li><strong>Planejamento logístico prévio:</strong> Confirmar disponibilidade e adequação do local e a data/horário; colaborar com a equipe técnica para atender os requisitos do rider; e organizar transporte e hospedagem da equipe e dos equipamentos com reserva antecipada.</li><li><strong>Coordenação de chegada:</strong> Garantir que equipe técnica, artistas e envolvidos cheguem conforme o cronograma, mantendo comunicação aberta para lidar com atrasos ou problemas de transporte.</li><li><strong>Presença no local desde o início da montagem:</strong> O produtor deve estar presente ANTES do início da montagem para supervisionar desde o começo, cumprimentar e coordenar a equipe técnica garantindo que todos entendam suas funções.</li><li><strong>Coordenação com a equipe técnica:</strong> Revisar o plano técnico com a equipe, estar disponível para esclarecer dúvidas e monitorar de perto a montagem de palco, som, luz e demais equipamentos, garantindo o cumprimento do cronograma.</li><li><strong>Logística e testes de equipamentos:</strong> Verificar que todos os equipamentos estão presentes e funcionando, antecipar problemas com peças sobressalentes e realizar testes iniciais para evitar surpresas durante o evento.</li><li><strong>Ambiente de backstage:</strong> Supervisionar a organização do backstage para que seja funcional e confortável, com alimentos e bebidas disponíveis, coordenando iluminação adequada e catering com os departamentos certos.</li><li><strong>Verificação final:</strong> Após a montagem, fazer uma inspeção do local para garantir que tudo está conforme o planejado e em conformidade com as expectativas, antes do início do evento.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Roteiro logístico e cronograma de montagem:</strong> Documentos-guia do dia. O cronograma de montagem detalha o que sobe e quando (palco, som, luz).</li><li><strong>Rádio comunicador:</strong> Comunicação contínua entre produção e técnica durante a montagem. Agiliza a resolução de problemas.</li><li><strong>Checklist de equipamentos / peças sobressalentes:</strong> Garante que tudo chegou e funciona, e antecipa falhas com itens reserva.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Confirme local, transporte e hospedagem antes:</strong> Reservas antecipadas e adequação do espaço validada.</li><li><strong>2. Esteja no local antes da montagem começar:</strong> Chegue antes da equipe técnica para coordenar desde o início.</li><li><strong>3. Revise o plano técnico com a equipe:</strong> Garanta que todos entendam as especificações e suas funções.</li><li><strong>4. Monitore a montagem contra o cronograma:</strong> Acompanhe palco, som e luz e cobre os prazos. Aja se atrasar.</li><li><strong>5. Faça os testes iniciais:</strong> Teste equipamentos cedo para que problemas apareçam com tempo de resolver.</li><li><strong>6. Organize o backstage e faça a inspeção final:</strong> Camarim funcional, catering e luz; depois inspecione tudo antes de abrir.</li></ol><p><strong>Na prática:</strong> O produtor chega às 07:00, antes do caminhão. Cumprimenta a equipe, revisa o cronograma de montagem, acompanha palco e som subindo, percebe que um monitor não liga e — porque tinha peça reserva e tempo — resolve antes do soundcheck. Quando o artista chega, está tudo testado. Essa antecipação é o trabalho.</p><h4>Resumo</h4><ul><li>Logística prévia: confirmar local, transporte, hospedagem e requisitos técnicos.</li><li>O produtor chega antes da montagem e coordena a equipe desde o início.</li><li>Testes iniciais e peças reserva fazem problemas aparecerem com tempo de resolver.</li></ul>',30,1,true,false);
