insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('3fb82069-5851-4045-bdd9-b48967830086','25d936ed-0c2b-4b15-a57c-1f5e5ef56467','Gerenciar a execução do evento','texto','<p><strong>Para começar:</strong> Com o evento rolando, o produtor é o ponto central. Tudo passa por ele e ele mantém tudo no eixo.</p><p>Gerenciar a execução é a etapa em que o produtor centraliza comunicações, acompanha o cronograma em tempo real e resolve problemas sob pressão. Nesta aula você vê as responsabilidades durante o show e como manter a operação no controle.</p><ul><li><strong>Coordenação geral:</strong> Atuar como ponto central de todas as comunicações durante o evento, com linha clara e eficaz com toda a equipe, e supervisionar todas as atividades garantindo que ocorram conforme o planejado.</li><li><strong>Acompanhamento do cronograma em tempo real:</strong> Monitorar regularmente o cronograma, estar pronto para ajustá-lo conforme necessário e comunicar prontamente qualquer mudança a técnica, artistas e colaboradores.</li><li><strong>Resolução de problemas:</strong> Tomar decisões rápidas e eficazes para problemas emergentes, colaborando com a equipe e mantendo comunicação transparente com orientações claras.</li><li><strong>Relações com fornecedores e parceiros:</strong> Supervisionar o cumprimento de contratos e estar preparado para mediar conflitos entre partes, buscando soluções que mantenham um ambiente positivo e profissional.</li><li><strong>Gestão de pessoal:</strong> Oferecer apoio contínuo à equipe, atender necessidades e fornecer recursos adicionais; reconhecer conquistas e lidar proativamente com preocupações, mantendo a motivação.</li><li><strong>Avaliação contínua e gestão financeira:</strong> Dar feedback imediato à equipe, estar aberto a sugestões, e monitorar custos durante o evento para mantê-los no orçamento, decidindo rápido quando necessário.</li><li><strong>Postura sob pressão:</strong> Manter calma e compostura, transmitindo confiança à equipe. O produtor é o termômetro emocional da operação: se ele perde o controle, a equipe perde junto.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Rádio / grupo de comunicação:</strong> Mantém o produtor como ponto central. Decisões e mudanças circulam por aqui em tempo real.</li><li><strong>Cronograma do dia (impresso e digital):</strong> Referência constante para verificar se o evento segue o planejado e ajustar quando preciso.</li><li><strong>Plano de contingência:</strong> Lista de ''o que fazer se'' (falha técnica, atraso, emergência) preparada antes. Acelera a decisão sob pressão.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Centralize a comunicação:</strong> Seja o ponto por onde passam informações e decisões. Evite ordens paralelas e contraditórias.</li><li><strong>2. Monitore o cronograma em tempo real:</strong> Compare o que está acontecendo com o planejado e ajuste quando necessário.</li><li><strong>3. Comunique mudanças imediatamente:</strong> Toda alteração de horário ou fluxo vai para os envolvidos na hora.</li><li><strong>4. Decida rápido nos imprevistos:</strong> Colabore com a equipe, escolha a solução prática e oriente com clareza.</li><li><strong>5. Apoie e motive a equipe:</strong> Dê suporte, reconheça o esforço e mantenha o clima profissional sob pressão.</li><li><strong>6. Controle os custos do dia:</strong> Monitore gastos extras e decida com critério para não estourar o orçamento.</li></ol><p><strong>Na prática:</strong> O show atrasa 20 minutos porque a banda de abertura estendeu. O produtor recalcula o cronograma na hora, avisa luz, som e o road manager pelo rádio, comunica a mudança ao bar e à segurança para o fluxo de público, e mantém a calma para a equipe não entrar em pânico. Em 5 minutos, o evento voltou ao controle.</p><h4>Resumo</h4><ul><li>Na execução, o produtor centraliza comunicação e supervisiona tudo.</li><li>Monitorar o cronograma em tempo real e comunicar mudanças na hora é essencial.</li><li>Calma e plano de contingência transformam imprevistos em decisões rápidas.</li></ul>',30,2,true,false);
