insert into public.modules (id,course_id,titulo,ordem) values ('db404c27-9482-4439-bb2c-c0b040efd55a','f82b5aeb-95fd-4212-a067-4bec55c0fb6d','Módulo 6 - Pós-evento, documentação e organização digital',6);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('b2106b82-473d-4f80-a279-a1fc9994d6d3','db404c27-9482-4439-bb2c-c0b040efd55a','Desmontagem e fechamento financeiro pós-evento','texto','<p><strong>Para começar:</strong> O evento só termina quando o local está limpo, as contas fechadas e os equipamentos devolvidos. Não antes.</p><p>O pós-evento começa com a coordenação da desmontagem e o fechamento financeiro. Nesta aula você vê como encerrar a operação de forma organizada, segura e com as contas no lugar, condição para a saúde das próximas produções.</p><ul><li><strong>Coordenação da desmontagem:</strong> Atribuir tarefas específicas à equipe, supervisionar do início ao fim, e dar instruções claras de como desmontar e embalar cada equipamento, verificando possíveis danos durante o processo.</li><li><strong>Logística de transporte e devoluções:</strong> Comunicar-se com fornecedores de transporte para garantir veículos, listar e preparar tudo para embarque, e coordenar a devolução de equipamentos alugados ou emprestados nos prazos.</li><li><strong>Desmontagem de palco e backstage:</strong> Desmontar o palco com segurança e padrões corretos, recolher materiais (barricadas, grades), organizar o backstage e devolver pertences pessoais a artistas e equipe.</li><li><strong>Descarte de resíduos e sustentabilidade:</strong> Planejar o descarte adequado de resíduos, coordenar com serviços de remoção e promover práticas sustentáveis (reciclagem), deixando o local limpo e em ordem.</li><li><strong>Revisão de despesas e receitas:</strong> Revisar todas as despesas e receitas, conferir se estão conforme os contratos e garantir documentação completa (faturas, recibos, extratos).</li><li><strong>Contabilidade, pagamentos e cobranças:</strong> Atualizar registros contábeis, fazer conciliação bancária, finalizar pagamentos pendentes a fornecedores/artistas/equipe e acompanhar recebíveis (patrocínios, ingressos).</li><li><strong>Relatórios e arquivamento financeiro:</strong> Preparar demonstrações de resultado, comparar o realizado com o orçamento inicial, analisar variações e arquivar todos os documentos de forma organizada pelo período exigido.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Checklist de desmontagem:</strong> Lista de tarefas e responsáveis para encerrar com organização e sem perder equipamento.</li><li><strong>Controle de devoluções:</strong> Planilha do que foi alugado/emprestado, prazo e status de devolução. Evita cobrança por item não devolvido.</li><li><strong>Planilha de fechamento financeiro:</strong> Despesas e receitas finais, realizado x orçado, com conciliação bancária e variações.</li><li><strong>Pasta de documentos financeiros:</strong> Faturas, recibos, extratos e comprovantes arquivados pelo período legalmente exigido.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Distribua as tarefas de desmontagem:</strong> Cada pessoa com responsabilidade clara; supervisione do início ao fim.</li><li><strong>2. Verifique equipamentos e organize a devolução:</strong> Cheque danos, embale corretamente e coordene as devoluções dentro do prazo.</li><li><strong>3. Recolha pertences e deixe o local em ordem:</strong> Devolva pertences pessoais, descarte resíduos e entregue o local limpo.</li><li><strong>4. Revise despesas e receitas:</strong> Confira tudo contra os contratos e reúna a documentação completa.</li><li><strong>5. Finalize pagamentos e cobranças:</strong> Quite pendências e acompanhe recebíveis; faça a conciliação bancária.</li><li><strong>6. Compare realizado x orçado e arquive:</strong> Analise variações, prepare o relatório financeiro e arquive os documentos.</li></ol><p><strong>Na prática:</strong> Após o show, a desmontagem é distribuída: técnica desmonta som e luz, roadies embalam backline, apoio recolhe o backstage. O controle de devoluções garante que as 2 vias de monitor alugadas voltem no prazo. No financeiro, o produtor soma os ''valor pago'', compara com o orçamento (ex.: gastou R$ 26 mil de R$ 27,9 mil previstos) e fecha as contas com comprovantes arquivados.</p><h4>Resumo</h4><ul><li>A desmontagem é coordenada com tarefas, devoluções e local limpo.</li><li>O fechamento financeiro revisa despesas/receitas, concilia e compara com o orçamento.</li><li>Arquivar comprovantes de forma organizada sustenta as próximas produções.</li></ul>',30,1,true,false);
