insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('3311b215-1ced-43f8-8ba0-c0fb07643bf2','db404c27-9482-4439-bb2c-c0b040efd55a','Relatório pós-evento: avaliar e aprender','texto','<p><strong>Para começar:</strong> O relatório pós-evento transforma a experiência em aprendizado. É o que faz o próximo evento ser melhor que o atual.</p><p>Elaborar relatórios pós-evento é prática essencial para avaliar desempenho, identificar melhorias e gerar insights para futuras produções. Nesta aula você aprende a estrutura completa do relatório e como conduzi-lo.</p><ul><li><strong>Introdução e objetivos:</strong> Resumo executivo com os principais destaques, o propósito do relatório, e a revisão dos objetivos definidos antes do evento, avaliando o quanto foram alcançados.</li><li><strong>Planejamento, participação e público:</strong> Análise da eficácia do planejamento (logística, cronograma, equipe), número total de participantes comparado às expectativas, e o perfil demográfico do público (faixa etária, localização).</li><li><strong>Avaliação do público:</strong> Resultados de pesquisas de satisfação e feedback, com pontos positivos e negativos, e análise das interações em mídias sociais (posts, compartilhamentos, menções).</li><li><strong>Desempenho artístico e operações:</strong> Avaliação dos artistas (resposta do público, qualidade, desafios) e da eficiência das operações logísticas (montagem, desmontagem, equipamentos), apontando melhorias.</li><li><strong>Finanças e orçamento:</strong> Comparação dos custos reais com o orçamento, identificando desvios e razões, e apresentação das receitas (ingressos, patrocínios), avaliando a captação de recursos.</li><li><strong>Lições aprendidas e recomendações:</strong> Principais lições do evento, ações corretivas e preventivas, e recomendações específicas para futuras produções, considerando feedback de equipe, artistas e público.</li><li><strong>Agradecimentos, anexos e conclusão:</strong> Reconhecimento dos envolvidos, anexos de apoio (fotos, gráficos financeiros, relatórios de mídia) e um resumo final sobre o sucesso e os aprendizados do evento.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Modelo de relatório pós-evento:</strong> Documento estruturado nas seções acima. Reaproveite como template. Use gráficos e visualizações para facilitar a leitura.</li><li><strong>Pesquisa de satisfação (Google Forms):</strong> Coleta feedback do público de forma estruturada e gera dados para o relatório automaticamente.</li><li><strong>Pasta de registros do evento:</strong> Fotos, vídeos, prints de mídias sociais e gráficos financeiros que viram anexos e evidências.</li></ul><h4>Passo a passo</h4><ol><li><strong>1. Abra com resumo executivo e objetivos:</strong> Destaques principais e revisão dos objetivos definidos antes do evento.</li><li><strong>2. Avalie planejamento, público e satisfação:</strong> Eficácia do planejamento, número e perfil de público e resultados das pesquisas.</li><li><strong>3. Analise desempenho artístico e operações:</strong> Resposta do público aos artistas e eficiência logística, com melhorias.</li><li><strong>4. Compare finanças com o orçamento:</strong> Custos reais x previstos, receitas e patrocínios, com desvios analisados.</li><li><strong>5. Registre lições e recomendações:</strong> O que funcionou, o que melhorar e ações para os próximos eventos.</li><li><strong>6. Anexe evidências e compartilhe:</strong> Fotos, gráficos e relatórios de mídia; distribua para equipe e partes interessadas.</li></ol><p><strong>Na prática:</strong> Após o festival, o relatório mostra: meta de 800 pessoas, vieram 950 (acima do esperado); satisfação de 4,3/5; orçamento previsto R$ 80 mil, gasto R$ 78 mil; lição aprendida: a fila de entrada travou 30 min, recomendação de abrir mais um portão. No próximo evento, esse aprendizado evita o mesmo erro. É assim que a produção evolui.</p><h4>Resumo</h4><ul><li>O relatório pós-evento avalia objetivos, público, artístico, operações e finanças.</li><li>Lições aprendidas e recomendações alimentam as próximas produções.</li><li>Gráficos, fotos e dados de satisfação dão evidência ao relatório.</li></ul>',25,2,true,false);
