insert into public.modules (id,course_id,titulo,ordem) values ('e649b8c9-7385-4ab5-9f46-6a547c9ff1a3','f82b5aeb-95fd-4212-a067-4bec55c0fb6d','Produção Avançada: Gestão Profissional de Eventos',7);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('0785fc6b-4b6a-4d24-9784-e514e35c20a7','e649b8c9-7385-4ab5-9f46-6a547c9ff1a3','Orçamento Profissional: Estrutura de Custos, Margem e Contingência','texto','<p><strong>Para começar:</strong> Um evento não quebra por falta de talento — quebra por orçamento mal feito. Antes de pensar em luz, som ou line-up, você precisa saber exatamente para onde vai cada real.</p><p>Nesta aula você vai aprender a montar um orçamento de evento como uma empresa de verdade: separando custos fixos de variáveis, calculando ponto de equilíbrio, embutindo margem e contingência, e projetando fluxo de caixa para não ficar no vermelho antes do dia do show. Vamos sair do ''achismo'' e entrar na planilha.</p><ul><li><strong>Custos fixos:</strong> São os que não variam com o tamanho do público dentro de uma faixa: aluguel do espaço, cachê de artista, estrutura de palco, som e luz contratados por diária, equipe técnica fixa, seguro. Você paga o mesmo valor com 200 ou 800 pessoas. Some-os primeiro porque definem o piso de despesa.</li><li><strong>Custos variáveis:</strong> Crescem com o público ou com a operação: copos, gelo, insumos de bar, comissão de bilheteria por ingresso vendido, taxa de cartão/gateway, pulseiras, segurança extra por lotação, limpeza proporcional. Calcule sempre por unidade (custo por pessoa) para projetar cenários.</li><li><strong>Ponto de equilíbrio (break-even):</strong> É quantos ingressos (ou qual faturamento) você precisa para cobrir todos os custos. Fórmula prática: Custos Fixos ÷ (preço do ingresso − custo variável por pessoa). Abaixo disso você tem prejuízo; acima, lucro. Saber esse número antes de abrir venda é inegociável.</li><li><strong>Margem de lucro:</strong> É o que sobra depois de pagar tudo, expressa em % sobre a receita. Em produção de eventos, margens saudáveis costumam ficar entre 15% e 30% dependendo do risco. Margem não é ''sobra que aparece'' — você a define antes, somando-a ao custo para chegar ao preço.</li><li><strong>Contingência (reserva técnica):</strong> Uma reserva de 5% a 15% do orçamento total para o imprevisto: chuva, equipamento queimado, hora extra, fornecedor que falhou. Não é gordura, é gestão de risco. Eventos sem contingência transformam qualquer surpresa em prejuízo direto.</li><li><strong>Fluxo de caixa:</strong> É o calendário de entradas e saídas no tempo. Você paga sinal de fornecedores semanas antes, mas só recebe a bilheteria no repasse pós-evento. Mapear isso evita o cenário clássico: evento lucrativo no papel, mas sem dinheiro em caixa para pagar a conta de hoje.</li><li><strong>Formas de cobrança e recebimento:</strong> Bilheteria por plataforma (Sympla, Shotgun, Ingresse) com repasse D+ alguns dias; venda na porta (dinheiro/Pix/maquininha); patrocínio via contrato e NF; permuta. Cada uma tem prazo e taxa diferentes — o prazo de recebimento impacta diretamente o fluxo de caixa.</li><li><strong>Nota fiscal e formalização:</strong> Para receber de patrocinadores, locais e produtoras você precisa emitir NF — como MEI, ME ou produtora. NF de serviço (NFS-e) é municipal. Trabalhar formalizado dá acesso a contratos maiores, evita problemas fiscais e profissionaliza a imagem. Tributação varia por regime (ex.: Simples Nacional).</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Planilha de orçamento (Excel/Google Sheets):</strong> Documento mestre com abas de custos fixos, variáveis, receitas e cenários. Use fórmulas para o break-even recalcular sozinho ao mudar preço ou público.</li><li><strong>Modelo de fluxo de caixa:</strong> Tabela mês a mês (ou semana a semana) com data prevista de cada entrada e saída, mostrando o saldo acumulado para identificar quando o caixa fica negativo.</li><li><strong>Emissor de NF-e/NFS-e:</strong> Sistema da prefeitura ou plataforma contábil para emitir nota dos serviços prestados e dos recebimentos de patrocínio/cachê.</li></ul><h4>Passo a passo</h4><ol><li><strong>Liste todos os custos fixos:</strong> Levante cachê, espaço, estrutura, equipe e seguro. Peça orçamento a fornecedores e use o valor real, não estimado de cabeça.</li><li><strong>Calcule os custos variáveis por pessoa:</strong> Some insumos, taxas e comissões e divida pelo público estimado para ter o custo unitário.</li><li><strong>Defina o preço do ingresso e ache o break-even:</strong> Aplique Custos Fixos ÷ (preço − custo variável por pessoa) para saber quantos ingressos cobrem tudo.</li><li><strong>Adicione margem e contingência:</strong> Some a margem desejada (ex.: 20%) e a reserva (ex.: 10%) ao custo total antes de fechar o preço final.</li><li><strong>Monte o fluxo de caixa no tempo:</strong> Coloque cada pagamento e recebimento na data real e confira se o saldo nunca fica negativo; se ficar, negocie prazos ou antecipe receita.</li></ol><p><strong>Na prática:</strong> Você vai produzir uma festa para 400 pessoas. Custos fixos somam R$ 32.000 (espaço, DJ headliner, som/luz, equipe). Custo variável por pessoa é R$ 15 (copo, taxa de bilheteria, segurança proporcional). Ingresso a R$ 80. Break-even: 32.000 ÷ (80 − 15) = ~493 ingressos — ou seja, a 400 pessoas você teria PREJUÍZO. Aqui você decide: subir o preço, cortar custo fixo, aumentar a meta de público ou buscar patrocínio para cobrir o gap. É essa conta, feita ANTES, que salva o evento.</p><h4>Resumo</h4><ul><li>Custo fixo é o piso; custo variável escala com o público — separe-os para projetar cenários.</li><li>O ponto de equilíbrio diz o mínimo para não ter prejuízo; margem e contingência se somam ANTES do preço.</li><li>Evento lucrativo no papel pode quebrar por fluxo de caixa: mapeie quando o dinheiro entra e sai.</li></ul>',30,1,true,false);
