insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('2f83aa68-9efd-472a-99c4-b322d628467a','ca1d952c-d8d5-4177-b532-de70373752cb','Qual destes é um custo VARIÁVEL em um evento?','Comissão por ingresso cresce com o número de vendas, logo é variável; cachê, aluguel e diária são fixos dentro da faixa de público.',1,1);
