insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('db55742e-a02f-43f6-8602-8f9c76d07917','ca1d952c-d8d5-4177-b532-de70373752cb','O ponto de equilíbrio é calculado por:','O break-even mostra quantos ingressos cobrem os custos fixos depois de descontar o custo variável de cada pessoa.',2,1);
