insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('048740cf-81fb-4e84-91e4-2433a16a3535','ca1d952c-d8d5-4177-b532-de70373752cb','A contingência em um orçamento serve para:','Contingência é reserva de risco (geralmente 5% a 15%), não lucro nem substituição de obrigações.',3,1);
