insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('dd91dca5-c728-4cc6-845c-d65bf158caee','ca1d952c-d8d5-4177-b532-de70373752cb','Por que um evento lucrativo no papel pode quebrar?','O descasamento entre datas de pagamento e de recebimento pode deixar o caixa negativo mesmo com lucro final.',4,1);
