insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('8f16af9b-7415-4df0-9b4a-0a4642a9dd99','e649b8c9-7385-4ab5-9f46-6a547c9ff1a3','Contratos e Jurídico: Cláusulas, Direitos Autorais (ECAD) e Seguros','texto','<p><strong>Para começar:</strong> No improviso, tudo parece ir bem — até alguém não cumprir o combinado. Contrato não é desconfiança: é o que transforma uma promessa em obrigação exigível.</p><p>Esta aula te dá a base para negociar e ler contratos de evento sem ser advogado — entendendo cláusulas essenciais, responsabilidade civil, direitos autorais e ECAD, e seguros. O objetivo é te tornar capaz de orientar e cobrar sua assessoria jurídica, não substituí-la. Em valores e regras específicas, sempre confirme com um advogado.</p><ul><li><strong>Por que contrato sempre:</strong> Contrato define objeto, prazos, valores, obrigações e penalidades de forma exigível. Sem ele, qualquer descumprimento vira ''palavra contra palavra''. Para artista, fornecedor, espaço e patrocinador, o contrato protege os dois lados e dá previsibilidade.</li><li><strong>Tipos de contrato no evento:</strong> Contrato de apresentação artística (com o artista/empresário); contrato de locação de espaço; contrato de prestação de serviços (som, luz, segurança, catering); contrato de patrocínio/cota; contrato de cessão de imagem e som. Cada um tem objeto e riscos próprios.</li><li><strong>Cláusulas essenciais:</strong> Objeto (o que será feito), valor e forma de pagamento, datas e horários, obrigações de cada parte, rider técnico anexo, cláusula de cancelamento e no-show, multa por descumprimento, força maior, foro e cessão de direitos de imagem. Anexos (rider, mapa) fazem parte do contrato.</li><li><strong>Direitos autorais e ECAD:</strong> No Brasil, a execução pública de música exige pagamento de direitos autorais arrecadados pelo ECAD (escritório central que repassa às associações). Quem organiza o evento (não o artista) costuma ser o responsável por recolher. Calcule esse custo no orçamento — é obrigação legal, não opcional.</li><li><strong>Direito de imagem e som:</strong> Para gravar, transmitir ou usar imagens do artista e do público em divulgação, você precisa de autorização. Cláusula de cessão de imagem no contrato do artista e aviso/sinalização ao público (placas, termos) resolvem grande parte do risco.</li><li><strong>Responsabilidade civil:</strong> O organizador responde por danos a participantes, terceiros e patrimônio durante o evento. Estrutura que cede, acidente por superlotação, briga por falha de segurança — tudo pode recair sobre a produção. Por isso seguro e fornecedores idôneos não são luxo.</li><li><strong>Seguros:</strong> Seguro de responsabilidade civil (RC) de eventos cobre danos a terceiros; seguro patrimonial cobre equipamentos; e existem coberturas para cancelamento. Para muitos espaços e alvarás, apólice de RC é exigência. Cote com corretora especializada em eventos.</li><li><strong>Orientando a assessoria jurídica:</strong> Você não redige sozinho contratos complexos: leva à assessoria a minuta, os pontos de risco e o que negociou. Saber o que pedir — multa, força maior, cessão de imagem, prazo de pagamento — faz o advogado trabalhar a seu favor, não no escuro.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Minuta-modelo de contrato artístico:</strong> Base reutilizável com objeto, cachê, datas, rider anexo e cláusulas-padrão, ajustada a cada artista pela assessoria jurídica.</li><li><strong>Termo de cessão de direito de imagem:</strong> Documento que autoriza captação e uso de imagem/som do artista e sinalização para o público.</li><li><strong>Apólice de seguro de RC de eventos:</strong> Cobertura de responsabilidade civil contratada com corretora especializada, frequentemente exigida para alvará.</li></ul><h4>Passo a passo</h4><ol><li><strong>Identifique todas as partes e contratos necessários:</strong> Liste artista, espaço, fornecedores e patrocinadores e qual tipo de contrato cada relação exige.</li><li><strong>Reúna os pontos comerciais negociados:</strong> Valor, datas, forma de pagamento, obrigações e rider já acordados viram a base do contrato.</li><li><strong>Inclua as cláusulas de proteção:</strong> Cancelamento, multa, força maior, cessão de imagem e foro precisam estar escritos, não combinados de boca.</li><li><strong>Encaminhe à assessoria jurídica:</strong> Entregue a minuta com os pontos de risco destacados para revisão e adequação legal.</li><li><strong>Provisione ECAD e seguro no orçamento:</strong> Recolha os direitos autorais junto ao ECAD e contrate a apólice de RC antes do evento.</li></ol><p><strong>Na prática:</strong> Você fecha um artista por R$ 25.000. No contrato você inclui: 50% de sinal e 50% no dia, rider técnico anexo, cláusula de no-show com devolução em dobro do sinal, força maior (chuva extrema/decreto), e cessão de imagem para divulgação. Paralelamente, calcula o ECAD para execução das músicas, contrata seguro de RC exigido pelo espaço e guarda tudo em pasta única. Quando o artista atrasa o voo e ameaça não chegar, é a cláusula de no-show — e não o nervosismo — que define o que acontece.</p><h4>Resumo</h4><ul><li>Contrato transforma combinados em obrigações exigíveis — sempre por escrito, com anexos.</li><li>Execução pública de música exige ECAD; uso de imagem exige cessão — ambos entram no planejamento.</li><li>Organizador responde civilmente pelo evento; seguro de RC e fornecedores idôneos reduzem o risco.</li></ul>',32,2,true,false);
