insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('4f001d63-8e33-4530-98d1-8783e94257c8','b737a7fd-108f-4f29-947b-2d4616160c28','No Brasil, a execução pública de música em um evento exige:','O ECAD arrecada os direitos autorais de execução pública; a responsabilidade pelo recolhimento costuma ser do organizador.',1,1);
