insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('1750a5eb-ff6d-4331-9f46-18cff4b7b234','e649b8c9-7385-4ab5-9f46-6a547c9ff1a3','Equipe e Fornecedores: Contratação, Briefing, Escala e Hierarquia','texto','<p><strong>Para começar:</strong> Você não produz um evento sozinho. Produz através de pessoas. Saber montar, briefar e comandar a equipe certa é o que separa o produtor do faz-tudo sobrecarregado.</p><p>Nesta aula você vai entender como estruturar e contratar equipe, gerir fornecedores e terceirizados, escrever briefings que evitam retrabalho, montar escalas, e desenhar a hierarquia e a comunicação no dia (intercom, rádios, grupos). Gestão de gente é onde o evento vive ou morre na operação.</p><ul><li><strong>Estrutura e funções da equipe:</strong> Produtor executivo (responde pelo todo), coordenador/produtor de palco (manda no backstage e na ordem do show), produção de campo (resolve o operacional), técnicos (som, luz, vídeo), logística, credenciamento, segurança, limpeza, bar. Cada função tem responsável claro — sobreposição gera vácuo de decisão.</li><li><strong>Contratação e formalização:</strong> Defina se cada pessoa é CLT, freelancer (RPA/contrato), MEI ou via fornecedor terceirizado. Freelancers de evento normalmente faturam ou recebem por RPA. Formalizar protege você de passivo trabalhista e dá clareza de obrigações — combine valor, função e horário por escrito.</li><li><strong>Gestão de fornecedores:</strong> Som, luz, palco, gerador, banheiros químicos, catering, segurança, limpeza. Selecione por idoneidade, portfólio e referência — não só por preço. Tenha contrato, rider e prazo claros, e um plano B para os fornecedores críticos. Fornecedor que falha no caminho crítico para o evento.</li><li><strong>Terceirização:</strong> Você pode contratar empresas que entregam pacotes fechados (segurança, limpeza, A&amp;B). Vantagem: menos gente para gerir e responsabilidade da empresa. Cuidado: você ainda responde pelo resultado e deve checar documentação (alvará, seguro, treinamento) dos terceiros.</li><li><strong>Briefing:</strong> Documento ou reunião que alinha O QUE, COMO, QUANDO e POR QUÊ com cada equipe e fornecedor. Bom briefing traz objetivo, escopo, prazos, contatos, mapa e o que NÃO fazer. Briefing ruim gera retrabalho, atraso e estresse no dia. Escreva, não confie só na conversa.</li><li><strong>Escala de equipe:</strong> Quem trabalha, em qual horário, em qual posto, com qual folga. Numa operação longa, monte turnos para não esgotar a equipe. A escala deve cobrir montagem, evento e desmonte — muita gente esquece de escalar o desmonte e fica sem braço às 4h.</li><li><strong>Hierarquia e cadeia de decisão:</strong> Defina quem decide o quê e a quem cada um reporta. No dia, decisões precisam de dono: ''em caso de chuva, quem manda parar?''. Cadeia clara evita ordens contraditórias e paralisia. O coordenador de palco, por exemplo, é a autoridade do backstage.</li><li><strong>Comunicação no dia (intercom e grupos):</strong> Rádios HT/intercom para a equipe técnica e de produção (canais por área), grupo de mensagens para avisos e fechamento, e contatos-chave impressos. Combine códigos e protocolos antes. Comunicação travada no dia do evento custa minutos que viram crise.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Organograma da equipe:</strong> Mapa visual de funções, responsáveis e a quem cada um reporta, distribuído antes do evento.</li><li><strong>Documento de briefing por área:</strong> Alinhamento escrito de escopo, prazos, contatos e mapa para cada equipe e fornecedor.</li><li><strong>Planilha de escala:</strong> Tabela com nome, função, posto, horário e folga cobrindo montagem, evento e desmonte.</li><li><strong>Rádios HT / intercom e grupo de mensagens:</strong> Canais de comunicação por área para a operação ao vivo, com códigos e protocolos combinados.</li></ul><h4>Passo a passo</h4><ol><li><strong>Desenhe o organograma e as funções:</strong> Liste todas as funções necessárias e defina um responsável claro para cada uma.</li><li><strong>Contrate e formalize equipe e fornecedores:</strong> Defina o vínculo (CLT, freela, MEI, terceirizado), combine valor/horário e registre por escrito.</li><li><strong>Escreva o briefing de cada área:</strong> Documente objetivo, escopo, prazos, contatos, mapa e o que não fazer.</li><li><strong>Monte a escala completa:</strong> Distribua pessoas por posto e horário cobrindo montagem, evento E desmonte, com folgas.</li><li><strong>Defina hierarquia e plano de comunicação:</strong> Estabeleça quem decide o quê e configure rádios/intercom e grupo de avisos com protocolos.</li></ol><p><strong>Na prática:</strong> Para um show de 600 pessoas você monta: produtor executivo (você), coordenador de palco, 2 da produção de campo, técnicos de som/luz do fornecedor, 4 de credenciamento, 6 seguranças terceirizados, 3 de bar, 2 de limpeza. Cada fornecedor recebe briefing escrito com horário de chegada, mapa e contato. No rádio, canal 1 é produção/palco, canal 2 é segurança/portaria. Você define: ''chuva forte = coordenador de palco decide pausar, eu autorizo retomar''. Quando o credenciamento engasga às 20h, o canal 1 resolve em 90 segundos porque a cadeia estava clara.</p><h4>Resumo</h4><ul><li>Cada função precisa de um dono claro — sobreposição gera vácuo de decisão.</li><li>Briefing escrito e escala completa (inclusive desmonte) previnem retrabalho e falta de braço.</li><li>Cadeia de decisão e comunicação por canais salvam minutos que, no dia, viram crise.</li></ul>',31,4,true,false);
