insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('e87e7542-e63a-4491-b606-cdd2f1577d70','1013baa1-501c-43b6-91f4-146b3c6f2dd9','Um erro comum na escala de equipe é:','Muitas escalas cobrem montagem e evento, mas esquecem o desmonte e a operação fica sem braço no fim.',3,1);
