insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('64e0c14e-bdab-4fb9-b92b-9a1c5a998c9c','e649b8c9-7385-4ab5-9f46-6a547c9ff1a3','Documentação Completa: Rider Técnico, Stage Plan, Ordem de Serviço e Run of Show','texto','<p><strong>Para começar:</strong> Na produção profissional, o que não está documentado não existe. O dia do evento é executado por dezenas de pessoas — e elas seguem papéis, não a sua memória.</p><p>Esta aula reúne o pacote de documentos que faz uma produção rodar sem você precisar repetir tudo o tempo todo: briefing, rider técnico, stage plan (mapa de palco), ordem de serviço, checklist, contrato e run of show. Você vai entender o que cada um contém e como eles se conectam num kit de produção.</p><ul><li><strong>Briefing:</strong> O documento de partida: objetivo do evento, público, conceito, data, local, escopo de cada área e referências. É a fonte da qual todos os outros documentos derivam. Um briefing alinhado evita que cada fornecedor entenda o evento de um jeito diferente.</li><li><strong>Rider técnico:</strong> Lista de exigências técnicas do artista/banda: equipamentos de som, monitores, microfones, backline, input list (canais), energia, e às vezes hospitalidade (camarim). O rider vem do artista e vira contrato com o fornecedor de som/luz. Conferir o rider antes evita o pesadelo de descobrir no palco que falta equipamento.</li><li><strong>Stage plan (mapa de palco):</strong> Desenho de onde fica cada músico, instrumento, amplificador, monitor e ponto de energia no palco. Junto com o input list, orienta a montagem e a passagem de som. Sem stage plan, a montagem vira tentativa e erro e queima tempo precioso.</li><li><strong>Ordem de serviço (OS):</strong> Documento operacional que diz a cada equipe/fornecedor exatamente o que fazer, onde, quando e sob qual responsável. É a tradução do plano em tarefas executáveis no dia. A OS evita o ''achei que era você quem faria''.</li><li><strong>Mapa de palco e planta do evento:</strong> Além do palco, a planta geral mostra fluxos de público, posições de bar, banheiros, saídas de emergência, credenciamento, áreas técnicas e camarins. Serve para logística, segurança e aprovação junto a bombeiros/órgãos.</li><li><strong>Checklist:</strong> Listas de verificação por etapa (pré-evento, montagem, abertura, durante, desmonte). Transformam conhecimento em rotina à prova de esquecimento. Em operação sob pressão, o checklist garante que o óbvio não seja esquecido.</li><li><strong>Run of show (roteiro do evento):</strong> O roteiro minuto a minuto da experiência: abertura, falas, entrada de cada atração, viradas, cues técnicos (luz/som/vídeo), intervalos, encerramento. Diferente do schedule de produção, o run of show foca o que o PÚBLICO vê e ouve, e sincroniza palco, técnica e apresentação.</li><li><strong>Kit de produção integrado:</strong> Todos esses documentos vivem juntos numa pasta única (física e digital) acessível à equipe: briefing, contratos, riders, stage plan, OS, mapas, checklists, run of show, contatos. É o ''cérebro'' do evento — quem chega novo se vira lendo o kit.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Rider técnico + input list:</strong> Especificação de equipamentos e canais exigidos pelo artista, base do contrato com o fornecedor técnico.</li><li><strong>Stage plan (mapa de palco):</strong> Desenho posicional do palco que orienta montagem e passagem de som.</li><li><strong>Ordem de serviço:</strong> Documento que distribui tarefas, locais, horários e responsáveis a cada equipe no dia.</li><li><strong>Run of show:</strong> Roteiro minuto a minuto com cues de palco, técnica e apresentação para sincronizar a operação ao vivo.</li></ul><h4>Passo a passo</h4><ol><li><strong>Parta do briefing:</strong> Consolide objetivo, público, conceito e escopo como fonte para todos os demais documentos.</li><li><strong>Colete e confira o rider técnico:</strong> Receba o rider do artista, valide com o fornecedor de som/luz e resolva faltas antes do dia.</li><li><strong>Monte stage plan e planta do evento:</strong> Desenhe palco e layout geral com fluxos, áreas técnicas e saídas de emergência.</li><li><strong>Emita as ordens de serviço e checklists:</strong> Traduza o plano em tarefas por equipe e crie checklists por etapa da operação.</li><li><strong>Escreva o run of show e monte o kit:</strong> Detalhe o minuto a minuto com cues e reúna tudo em uma pasta única acessível à equipe.</li></ol><p><strong>Na prática:</strong> Antes do show você recebe o rider da banda: pede 24 canais, 4 monitores, backline específico e bateria com microfonação completa. Você confronta com o fornecedor de som — falta um monitor; resolve com 10 dias de antecedência, não às 17h da passagem. Desenha o stage plan posicionando bateria ao fundo, baixo à esquerda, e marca os pontos de energia. No dia, a OS diz ao técnico exatamente onde montar; o run of show diz 21h00 abertura DJ, 22h30 vinheta, 22h35 entrada da banda, 00h00 bis, 00h15 encerramento. Tudo vive na pasta de produção, e qualquer um da equipe consegue se localizar sem te perguntar.</p><h4>Resumo</h4><ul><li>Cada documento deriva do briefing e tem função específica — juntos formam o kit de produção.</li><li>Rider e stage plan conferidos com antecedência evitam descobrir falta de equipamento no palco.</li><li>Run of show foca o que o público vê e sincroniza palco, técnica e apresentação minuto a minuto.</li></ul>',33,5,true,false);
