insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('2de51a2d-252e-4f64-b70c-98defa875af4','dff24a80-7108-4124-8cdf-fed73901855e','Por que reunir tudo num kit de produção único?','O kit centraliza os documentos e torna a operação independente da memória de uma só pessoa.',5,1);
