insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('0bfc9bb3-2b3a-4a66-b74d-dd6ddf341a0c','e649b8c9-7385-4ab5-9f46-6a547c9ff1a3','Logística e Operação: Montagem, Credenciamento, Segurança e Contingência','texto','<p><strong>Para começar:</strong> Planejamento bonito não enche caminhão nem abre portão. Logística é onde o plano encosta na realidade — e onde os imprevistos chegam sem aviso.</p><p>Aqui você aprende a operar: transporte e carga/descarga, montagem e desmontagem com ordem certa, credenciamento e controle de acesso, segurança e controle de público, plano de contingência e gestão de crise. É a aula que prepara você para o que acontece quando algo dá errado — porque algo sempre dá.</p><ul><li><strong>Transporte e carga/descarga:</strong> Planeje rotas, horários de chegada de caminhões, área e janela de carga/descarga, e quem recebe cada fornecedor. Em locais com restrição de horário ou acesso difícil, isso é caminho crítico. Atraso na descarga atrasa toda a montagem em efeito dominó.</li><li><strong>Montagem e desmontagem (ordem correta):</strong> Há uma sequência lógica: estrutura/palco → energia/gerador → som e luz → cenografia → ambientação → testes. Desmontar é o inverso e costuma ser subestimado. Defina ordem, equipe e janela de horário; locais cobram multa por atraso na devolução.</li><li><strong>Credenciamento e controle de acesso:</strong> Sistema de check-in (QR code, lista, pulseira), filas separadas por categoria (público, VIP, imprensa, equipe, artistas), e pontos de credenciamento dimensionados para o pico de chegada. Credenciamento lento gera fila, frustração e risco na entrada — superdimensione o pico.</li><li><strong>Segurança e controle de público:</strong> Cálculo de lotação conforme a capacidade do espaço e normas de bombeiros, equipe de segurança proporcional, revistas, controle de fluxo, sinalização de saídas de emergência e brigada. Superlotação é risco de vida e responsabilidade direta do organizador — respeite o limite do AVCB/alvará.</li><li><strong>Energia e infraestrutura:</strong> Dimensione a carga elétrica total (palco, bar, iluminação, frio) e tenha gerador com folga e, idealmente, redundância para o palco. Falha de energia no headliner é o tipo de crise que vira manchete. Banheiros, água e acessibilidade também são infraestrutura obrigatória.</li><li><strong>Plano de contingência:</strong> Documento com ''se acontecer X, fazemos Y'' para os riscos prováveis: chuva, falta de energia, atraso/no-show de artista, emergência médica, briga, superlotação, evacuação. Cada cenário tem um responsável e uma ação definida ANTES — improvisar na hora custa caro.</li><li><strong>Gestão de crise no dia:</strong> Quando o imprevisto vira crise: mantenha a cadeia de decisão (quem manda parar/retomar), comunique com clareza (equipe, público, autoridades), priorize segurança de pessoas acima do show, e registre o que aconteceu. Calma e protocolo, não pânico e improviso.</li><li><strong>Acessibilidade e atendimento:</strong> Rampas, lugares para cadeirantes, comunicação acessível e ponto de primeiros socorros/ambulância conforme o porte. Além de obrigação legal em muitos casos, é parte da operação profissional e da reputação do evento.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Plano logístico de carga/descarga:</strong> Cronograma de chegada de fornecedores com janela, rota e responsável por recebimento.</li><li><strong>Sistema de credenciamento (QR/pulseira):</strong> Ferramenta de check-in e controle de acesso por categoria, dimensionada para o pico de entrada.</li><li><strong>Plano de contingência e evacuação:</strong> Documento com cenários de risco, ações e responsáveis, incluindo rota de evacuação e brigada.</li><li><strong>Gerador com redundância:</strong> Fonte de energia dimensionada com folga e backup para o palco, evitando queda no momento crítico.</li></ul><h4>Passo a passo</h4><ol><li><strong>Planeje transporte e janela de carga/descarga:</strong> Defina rotas, horários e responsável por receber cada fornecedor, respeitando restrições do local.</li><li><strong>Defina a ordem de montagem e desmontagem:</strong> Sequencie estrutura, energia, som/luz, cenografia e testes — e o inverso no desmonte, com janela de horário.</li><li><strong>Dimensione credenciamento e segurança:</strong> Calcule pontos de check-in para o pico e a equipe de segurança conforme a lotação permitida.</li><li><strong>Escreva o plano de contingência:</strong> Liste os riscos prováveis com ação e responsável definidos para cada cenário.</li><li><strong>Defina a cadeia de crise e a evacuação:</strong> Estabeleça quem decide parar/retomar, como comunicar e qual a rota de evacuação.</li></ol><p><strong>Na prática:</strong> Chega o dia. 12h o caminhão de estrutura descarrega na janela combinada (sem isso, nada sobe). 14h estrutura pronta, 14h30 gerador ligado, 15h som e luz, 17h passagem. Você dimensionou 6 pontos de credenciamento para o pico das 20h-21h, com fila VIP separada. No plano de contingência: ''chuva forte = lona no palco e o coordenador decide pausar; falta de energia = gerador backup assume o palco em 60s; emergência médica = ambulância no local aciona, segurança abre corredor''. Quando começa a chover às 22h, ninguém entra em pânico: o protocolo já estava escrito e cada um sabe seu papel.</p><h4>Resumo</h4><ul><li>Montagem e desmontagem têm ordem certa; atraso na carga/descarga derruba todo o cronograma.</li><li>Lotação, segurança e saídas de emergência são responsabilidade direta do organizador — nunca extrapole o limite legal.</li><li>Plano de contingência escrito antes transforma crise em protocolo executado com calma.</li></ul>',32,6,true,false);
