insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0245ed20-fce7-4348-afd5-ab1470df7b9c','1f2c3b52-2259-41db-8716-4a737435f405','A lotação máxima de um evento deve respeitar:','Superlotação é risco de vida e responsabilidade do organizador; o limite vem do AVCB/alvará e das normas de bombeiros.',2,1);
