insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('626af4df-5330-4455-aa21-44e7f6e1b3c8','1f2c3b52-2259-41db-8716-4a737435f405','O plano de contingência deve ser definido:','Antecipar ''se X, então Y'' com responsável evita improviso e perda de tempo na hora da crise.',3,1);
