insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('b7a52235-2e91-4450-b380-332155cfcec6','e649b8c9-7385-4ab5-9f46-6a547c9ff1a3','Financeiro e Pós-Evento: Settlement, Conciliação, Relatório e KPIs','texto','<p><strong>Para começar:</strong> O evento acaba quando o último centavo é conciliado e o relatório está fechado — não quando o headliner sai do palco. O pós-evento é onde você descobre se ganhou dinheiro e o que aprendeu.</p><p>Esta aula fecha o ciclo financeiro e analítico: o settlement (fechamento de contas com artista/parceiros), a conciliação de receitas e despesas, o relatório de resultado, os KPIs que medem o sucesso e o registro de aprendizados. Sem pós-evento estruturado, você repete erros e nunca sabe sua real lucratividade.</p><ul><li><strong>Settlement (fechamento de contas):</strong> É o acerto final de contas do evento, especialmente com o artista quando há participação na bilheteria (cachê + percentual ou modelo de divisão). Reúne receita bruta, deduções acordadas (taxas, ECAD, custos pactuados) e chega ao valor líquido a repassar. Faça com documentos, não de cabeça.</li><li><strong>Conciliação financeira:</strong> Bater cada entrada e saída real contra o previsto: bilheteria vendida x repasse da plataforma, vendas na porta x relatório da maquininha, despesas orçadas x notas pagas. Conciliar revela furos (taxa a mais, venda não repassada, despesa esquecida) e fecha o caixa de verdade.</li><li><strong>Relatório de resultado (DRE simplificado):</strong> Demonstrativo com receita bruta, deduções, custos, e resultado líquido. Mostra preto no branco se o evento deu lucro ou prejuízo e por quê. É a base para decidir repetir, ajustar preço ou cortar custos na próxima edição.</li><li><strong>KPIs do evento:</strong> Indicadores que medem desempenho: público total x meta, taxa de conversão de venda, receita por participante (ticket médio), custo por participante, margem realizada, ocupação (% da lotação), origem das vendas, e satisfação (NPS/pesquisa). KPIs transformam ''achei legal'' em dado.</li><li><strong>Comparar previsto x realizado:</strong> Coloque lado a lado o orçamento planejado e o resultado real. Onde estourou? Onde sobrou? Essa comparação é a aula mais valiosa de cada evento e calibra o orçamento do próximo — sem ela, você orça sempre no escuro.</li><li><strong>Avaliação qualitativa:</strong> Além dos números: como foi a experiência do público, da equipe e dos parceiros? Pesquisa pós-evento, feedback da equipe e dos fornecedores, observações do dia. Problemas operacionais que não viram número precisam ser registrados para não se repetirem.</li><li><strong>Registro de aprendizados (lessons learned):</strong> Documento honesto do que funcionou e do que falhou: fornecedor que atrasou, gargalo no credenciamento, item de orçamento subestimado. Vira insumo para o briefing e o checklist do próximo evento. Quem não registra, recomeça do zero toda vez.</li><li><strong>Prestação de contas a parceiros:</strong> Patrocinadores e investidores querem relatório: alcance, público, mídia, fotos, retorno. Entregar uma prestação de contas profissional, com KPIs e evidências, é o que renova patrocínio e abre o próximo evento. Pós-evento também é venda do próximo.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Planilha de settlement:</strong> Modelo que consolida receita, deduções e divisão para chegar ao líquido a repassar a artista/parceiros.</li><li><strong>Relatório de conciliação:</strong> Tabela que confronta previsto x realizado de cada receita e despesa para fechar o caixa.</li><li><strong>Dashboard de KPIs:</strong> Painel com público, ticket médio, ocupação, margem e satisfação para medir o desempenho.</li><li><strong>Relatório de prestação de contas:</strong> Documento com KPIs, evidências e fotos entregue a patrocinadores e investidores.</li></ul><h4>Passo a passo</h4><ol><li><strong>Consolide todas as receitas e despesas reais:</strong> Reúna repasses de bilheteria, vendas na porta, notas pagas e taxas efetivas.</li><li><strong>Faça o settlement com o artista/parceiros:</strong> Aplique a divisão acordada sobre os números reais e documente o repasse.</li><li><strong>Concilie previsto x realizado:</strong> Bata cada item contra o orçamento para identificar furos e fechar o caixa.</li><li><strong>Calcule os KPIs e monte o relatório:</strong> Apure público, ticket médio, ocupação, margem e satisfação e gere o DRE simplificado.</li><li><strong>Registre aprendizados e preste contas:</strong> Documente o que funcionou e falhou e entregue a prestação de contas aos parceiros.</li></ol><p><strong>Na prática:</strong> Acabou o show. Você consolida: bilheteria R$ 64.000 (já com taxa da plataforma descontada), bar R$ 18.000, patrocínio R$ 15.000 = receita real R$ 97.000. Despesas conciliadas: R$ 71.000 (orçamento previa R$ 68.000 — estourou R$ 3.000 em hora extra de segurança, anota no lessons learned). Settlement do artista: cachê fixo R$ 25.000, sem percentual, repasse confirmado por documento. Resultado líquido: R$ 26.000, margem ~27%. KPIs: 580 de 600 lotação (97% ocupação), ticket médio R$ 110, NPS 72. Você fecha um relatório, manda a prestação de contas ao patrocinador com fotos e números — e ele já fala da próxima edição.</p><h4>Resumo</h4><ul><li>Settlement e conciliação fecham o caixa com documentos e revelam a lucratividade real.</li><li>Comparar previsto x realizado e calcular KPIs calibra o próximo orçamento e prova o resultado.</li><li>Registrar aprendizados e prestar contas profissionalmente é o que renova patrocínio e melhora cada edição.</li></ul>',31,7,true,false);
