insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('2c593baf-d58a-4419-99cd-63a7b8869230','e649b8c9-7385-4ab5-9f46-6a547c9ff1a3','Gestão Profissional: Padronização, ''Artista = Empresa'' e Precificação do Serviço','texto','<p><strong>Para começar:</strong> Talento te coloca no jogo; gestão te mantém nele. A diferença entre quem faz eventos e quem vive de eventos está em tratar a própria operação como empresa.</p><p>A aula final eleva o olhar do evento para o negócio: padronizar processos para escalar, enxergar o artista e o produtor como empresa, construir networking e reputação, e precificar o próprio serviço com critério. É o que transforma esforço pontual em carreira sustentável e crescente.</p><ul><li><strong>Padronização de processos:</strong> Transformar o que deu certo em modelos reutilizáveis: planilha de orçamento padrão, checklist padrão, contratos-modelo, kit de produção, run of show template. Padronizar libera energia mental do operacional repetitivo e reduz erro — você para de reinventar a roda a cada evento.</li><li><strong>''Artista = empresa'' (e produtor também):</strong> Pense em si e no artista como uma microempresa: tem receita, custo, marca, contratos, impostos e reputação. Isso muda decisões — separar conta pessoal da profissional, emitir NF, reinvestir, precificar com margem, cuidar da imagem. Profissionalizar a gestão é o que dá longevidade.</li><li><strong>Escalabilidade:</strong> Crescer sem que tudo dependa de você. Documentação, processos padronizados, equipe de confiança e fornecedores recorrentes permitem produzir mais e maiores eventos sem proporcional aumento de caos. Escalar é multiplicar resultado sem multiplicar o esforço pessoal na mesma proporção.</li><li><strong>Networking e relacionamento:</strong> Em eventos, contrato bom muitas vezes vem de relação. Cultive fornecedores, artistas, espaços, patrocinadores e colegas com profissionalismo e palavra cumprida. Reputação de quem ''entrega e paga em dia'' é o ativo mais valioso e que mais abre portas no setor.</li><li><strong>Reputação e marca pessoal:</strong> Sua marca é o que falam de você quando você não está na sala. Entregar com qualidade, comunicar bem, resolver problemas e tratar a equipe com respeito constrói reputação. Em um mercado de relações, a marca pessoal precede o portfólio.</li><li><strong>Precificação do próprio serviço:</strong> Cobre pelo seu trabalho com método, não com chute: calcule seu custo (tempo, deslocamento, ferramentas, impostos), some a margem de lucro do seu serviço, e considere o valor entregue e o porte do evento. Cobrar barato demais sinaliza amadorismo e inviabiliza a operação no longo prazo.</li><li><strong>Modelos de remuneração do produtor:</strong> Fee fixo por projeto, percentual sobre o orçamento do evento, percentual sobre o resultado, ou misto. Cada modelo tem risco diferente — percentual sobre resultado alinha incentivos mas expõe você ao prejuízo; fee fixo protege. Deixe sempre claro em contrato o que está e o que não está incluído.</li><li><strong>Mentalidade de melhoria contínua:</strong> Cada evento alimenta o próximo: aprendizados viram processo, processo vira padrão, padrão libera você para pensar estratégia e crescimento. Profissional é quem melhora 1% a cada edição — em cinco anos, isso é um abismo de diferença para quem só ''vai fazendo''.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Biblioteca de templates:</strong> Conjunto de modelos padronizados (orçamento, contrato, checklist, kit, run of show) reutilizáveis a cada novo evento.</li><li><strong>Planilha de precificação do serviço:</strong> Ferramenta para calcular custo, margem e valor do seu trabalho e definir o fee com critério.</li><li><strong>CRM/agenda de relacionamento:</strong> Registro de contatos, fornecedores, artistas e parceiros para cultivar networking de forma organizada.</li></ul><h4>Passo a passo</h4><ol><li><strong>Padronize seus documentos-chave:</strong> Transforme orçamento, checklist, contratos e kit em templates reutilizáveis.</li><li><strong>Estruture sua operação como empresa:</strong> Separe contas, formalize (NF/regime tributário) e trate marca e reputação como ativos.</li><li><strong>Calcule o preço do seu serviço:</strong> Some custo, margem e valor entregue, e escolha o modelo de remuneração adequado ao risco.</li><li><strong>Cultive networking com método:</strong> Mantenha relações profissionais, cumpra a palavra e registre contatos para parcerias recorrentes.</li><li><strong>Implemente melhoria contínua:</strong> Converta os aprendizados de cada evento em ajustes nos templates e processos.</li></ol><p><strong>Na prática:</strong> Depois de cinco eventos, você para de começar do zero. Tem sua planilha de orçamento, seu contrato-modelo (revisado pela assessoria), seu kit de produção e seu run of show template. Você se formaliza como produtora (NF, conta separada) e precifica seu serviço: custo do seu tempo + ferramentas + impostos, mais margem de 25%, num fee fixo de R$ 12.000 por projeto deste porte — e deixa claro no contrato o que inclui. Seu fornecedor de som de confiança te dá prioridade porque você paga em dia; um patrocinador te indica para outro evento porque você prestou contas direito. Você não trabalha mais; trabalha melhor — e a operação escala.</p><h4>Resumo</h4><ul><li>Padronizar processos libera energia do operacional e permite escalar sem multiplicar o caos.</li><li>Tratar artista e produtor como empresa — marca, NF, margem, reputação — dá longevidade à carreira.</li><li>Precificar com método e cultivar networking transforma esforço pontual em negócio sustentável.</li></ul>',30,8,true,false);
