insert into public.modules (id,course_id,titulo,ordem) values ('68a1164f-7b80-4bc3-b406-08d97f904b15','07695dfc-c93c-4a8a-bb5a-58d3b926c76e','Módulo 1 — Fundamentos da Eletricidade',1);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('d2a632c4-6a46-43e6-b4a6-373d2793084b','68a1164f-7b80-4bc3-b406-08d97f904b15','Grandezas elétricas: tensão, corrente, resistência, potência e energia','texto','<p><strong>Para começar:</strong> Antes de medir, soldar ou ligar qualquer equipamento, você precisa dominar a linguagem da eletricidade. Este é o alfabeto de todo o curso.</p><p>Toda a eletrônica se apoia em poucas grandezas fundamentais. Entendê-las com precisão — incluindo unidades e símbolos corretos — evita erros caros e situações perigosas no palco e no rack.</p><ul><li><strong>Carga elétrica (Q):</strong> Propriedade fundamental da matéria, medida em coulombs (C). 1 C equivale à carga de aproximadamente 6,24×10¹⁸ elétrons. A corrente nada mais é do que carga em movimento.</li><li><strong>Tensão (V):</strong> Também chamada de diferença de potencial ou ddp. É o ''empurrão'' que move os elétrons, medida em volts (V). Um volt corresponde a um joule por coulomb (1 V = 1 J/C). É sempre medida ENTRE dois pontos. Símbolo de unidade: V; símbolo de grandeza: U ou V.</li><li><strong>Corrente elétrica (I):</strong> Fluxo ordenado de cargas, medido em ampères (A). 1 A = 1 coulomb por segundo (1 C/s). Por convenção, a corrente convencional flui do + para o − (sentido oposto ao movimento real dos elétrons). Mede-se em série com o circuito.</li><li><strong>Resistência (R):</strong> Oposição à passagem de corrente, medida em ohms (Ω). Depende do material, comprimento, seção e temperatura do condutor. Seu inverso é a condutância, medida em siemens (S).</li><li><strong>Potência (P):</strong> Taxa de transferência de energia, medida em watts (W). 1 W = 1 J/s. Em eletricidade, P = V×I. É o que define o consumo de um equipamento e o dimensionamento de fontes e cabos.</li><li><strong>Energia (E):</strong> Potência ao longo do tempo, medida em joules (J) ou, na conta de luz, em quilowatt-hora (kWh). 1 kWh = 3,6×10⁶ J. É energia, não potência, que você paga à concessionária.</li><li><strong>Prefixos e notação:</strong> Domine os múltiplos e submúltiplos: mili (m, 10⁻³), micro (µ, 10⁻⁶), nano (n, 10⁻⁹), pico (p, 10⁻¹²), quilo (k, 10³), mega (M, 10⁶), giga (G, 10⁹). Confundir mV com V ou µF com mF é fonte clássica de erro.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Multímetro:</strong> Mede tensão, corrente e resistência; instrumento básico para verificar todas estas grandezas.</li><li><strong>Wattímetro/medidor de energia:</strong> Mede potência e consumo (kWh) de equipamentos do evento.</li></ul><h4>Passo a passo</h4><ol><li><strong>Identifique a grandeza:</strong> Antes de medir, defina se procura tensão (entre dois pontos), corrente (no caminho) ou resistência (com circuito desenergizado).</li><li><strong>Confira a unidade e prefixo:</strong> Leia o display atentando para mV/V e mA/A; um fator de 1000 muda completamente a interpretação.</li><li><strong>Relacione com potência:</strong> Multiplique a tensão pela corrente medida para estimar a potência consumida pelo equipamento.</li></ol><p><strong>Na prática:</strong> No rack de um show, um operador vê ''0,5'' no multímetro e acha que mediu 0,5 V, mas o instrumento estava em mV — eram 0,5 mV, ruído desprezível. Ler corretamente a unidade e o prefixo é tão importante quanto o número.</p><h4>Resumo</h4><ul><li>Tensão (V), corrente (A) e resistência (Ω) são as três grandezas básicas; potência (W) é V×I.</li><li>Energia é potência no tempo, paga em kWh, não em watts.</li><li>Dominar prefixos (m, µ, k, M) evita erros de fator 1000 nas medições.</li></ul>',30,1,true,true);
