insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('fa02a582-0882-45b0-8daa-72eed63a22dd','68a1164f-7b80-4bc3-b406-08d97f904b15','Lei de Ohm e Leis de Kirchhoff','texto','<p><strong>Para começar:</strong> Três equações governam praticamente todo circuito que você vai analisar na carreira. Vamos dominá-las de vez.</p><p>A Lei de Ohm relaciona tensão, corrente e resistência; as Leis de Kirchhoff descrevem como tensões e correntes se distribuem em qualquer rede. Juntas, são a base do cálculo de circuitos.</p><ul><li><strong>Lei de Ohm:</strong> V = R×I. A tensão sobre um resistor é o produto da resistência pela corrente que o atravessa. Dela derivam I = V/R e R = V/I. Vale para componentes ôhmicos (resistores), em que R é constante.</li><li><strong>Potência dissipada:</strong> Combinando com P = V×I, obtêm-se P = I²×R e P = V²/R. São fórmulas essenciais para dimensionar a potência (wattagem) de um resistor e evitar que ele queime.</li><li><strong>1ª Lei de Kirchhoff (Correntes / LKC):</strong> A soma das correntes que entram em um nó é igual à soma das que saem. É a conservação da carga: nada se acumula no nó. ΣI_entra = ΣI_sai.</li><li><strong>2ª Lei de Kirchhoff (Tensões / LKT):</strong> A soma algébrica das tensões em qualquer malha fechada é zero. Subindo em fontes e caindo em cargas, ao dar a volta completa retorna-se ao mesmo potencial. ΣV = 0.</li><li><strong>Convenção de sinais:</strong> Defina um sentido de corrente, marque polaridades (+/−) nos componentes e seja consistente. Resultado negativo apenas indica que o sentido real é oposto ao arbitrado.</li><li><strong>Materiais ôhmicos x não-ôhmicos:</strong> Resistores seguem a Lei de Ohm (gráfico V×I é uma reta). Diodos, lâmpadas e semicondutores são não-ôhmicos: a relação V×I é curva.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Multímetro:</strong> Verifica tensão e corrente para validar cálculos de Ohm e Kirchhoff.</li><li><strong>Fonte de bancada:</strong> Aplica tensão controlada para estudar a relação V×I de um componente.</li></ul><h4>Passo a passo</h4><ol><li><strong>Desenhe o circuito:</strong> Identifique nós, malhas, fontes e resistores antes de calcular.</li><li><strong>Arbitre sentidos:</strong> Escolha sentidos de corrente em cada ramo e polaridades nos componentes.</li><li><strong>Aplique LKC e LKT:</strong> Escreva uma equação de corrente por nó e uma de tensão por malha independente.</li><li><strong>Resolva e confira:</strong> Resolva o sistema; sinais negativos indicam sentido invertido. Confira somando potências.</li></ol><p><strong>Na prática:</strong> Para acender um LED de 2 V e 20 mA a partir de 12 V, calcula-se o resistor série pela Lei de Ohm: R = (12−2)/0,02 = 500 Ω. A potência nele é P = I²R = 0,02²×500 = 0,2 W, então um resistor de 1/4 W já fica no limite — usa-se 1/2 W por segurança.</p><h4>Resumo</h4><ul><li>Lei de Ohm: V = R×I, com derivadas para corrente e resistência.</li><li>Kirchhoff: correntes se conservam no nó (LKC) e tensões somam zero na malha (LKT).</li><li>Potência por P=I²R e P=V²/R dimensiona a wattagem dos componentes.</li></ul>',35,2,true,false);
