insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('d2c25d96-c155-4f52-80bb-2d95b00abb23','68a1164f-7b80-4bc3-b406-08d97f904b15','CC x CA, circuitos série e paralelo','texto','<p><strong>Para começar:</strong> A bateria do walkie e a tomada do palco entregam energia de formas radicalmente diferentes. Entender CC, CA e como os componentes se associam é decisivo.</p><p>Corrente contínua e alternada têm comportamentos distintos; e a forma como resistores se associam (série ou paralelo) muda tensões e correntes em todo o circuito.</p><ul><li><strong>Corrente contínua (CC/DC):</strong> Polaridade e sentido constantes no tempo. Fornecida por baterias, pilhas e fontes de alimentação. Ideal para eletrônica de baixa tensão (5 V, 12 V, 48 V).</li><li><strong>Corrente alternada (CA/AC):</strong> Sentido e magnitude variam periodicamente, em geral senoidal. A rede elétrica brasileira opera a 60 Hz. Permite transmissão eficiente e uso de transformadores.</li><li><strong>Valores em CA:</strong> Distinga valor de pico (Vp), pico a pico (Vpp) e eficaz/RMS (Vrms). Para senoide, Vrms = Vp/√2. Os 127 V ou 220 V da tomada são valores RMS.</li><li><strong>Frequência e período:</strong> Frequência (f) em hertz (Hz) é o nº de ciclos por segundo; período T = 1/f. A 60 Hz, T ≈ 16,7 ms.</li><li><strong>Associação série:</strong> Componentes em sequência partilham a MESMA corrente. Resistências somam: Req = R1+R2+... A tensão se divide proporcionalmente a cada resistência.</li><li><strong>Associação paralelo:</strong> Componentes ligados entre os mesmos dois nós partilham a MESMA tensão. Condutâncias somam: 1/Req = 1/R1+1/R2+... A corrente se divide. A Req é sempre menor que o menor resistor.</li><li><strong>Caso de dois em paralelo:</strong> Para apenas dois resistores: Req = (R1×R2)/(R1+R2), o famoso ''produto sobre a soma''. Para N resistores iguais R, Req = R/N.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Multímetro:</strong> Mede tensão CC/CA (RMS) e resistência equivalente das associações.</li><li><strong>Osciloscópio:</strong> Mostra a forma de onda CA, pico, pico a pico e frequência.</li></ul><h4>Passo a passo</h4><ol><li><strong>Classifique a fonte:</strong> Verifique se é CC (bateria/fonte) ou CA (rede) antes de medir.</li><li><strong>Selecione a função correta:</strong> No multímetro, escolha V⎓ (CC) ou V∼ (CA) conforme a fonte.</li><li><strong>Identifique série ou paralelo:</strong> Mesma corrente = série; mesma tensão (mesmos dois nós) = paralelo.</li><li><strong>Calcule a equivalente:</strong> Some resistências em série; use produto-sobre-soma ou inverso das somas em paralelo.</li></ol><p><strong>Na prática:</strong> Duas caixas de som de 8 Ω ligadas em paralelo no mesmo canal resultam em 4 Ω, exigindo o dobro de corrente do amplificador. Ignorar isso pode sobrecarregar e proteger/desligar o ampli — por isso impedância de caixas é assunto crítico.</p><h4>Resumo</h4><ul><li>CC tem polaridade fixa; CA alterna periodicamente (rede a 60 Hz).</li><li>Tensão da tomada é valor RMS; para senoide Vrms = Vp/√2.</li><li>Série soma resistências e divide tensão; paralelo divide corrente e reduz a resistência.</li></ul>',35,3,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('d0fa1f53-3121-456e-95c2-5250120bb513','d2c25d96-c155-4f52-80bb-2d95b00abb23','Quiz — CC x CA, circuitos série e paralelo');
