insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('80a03a55-131c-489f-b917-eff8963b4793','68a1164f-7b80-4bc3-b406-08d97f904b15','Divisor de tensão e divisor de corrente','texto','<p><strong>Para começar:</strong> Dois circuitos simples aparecem em quase todo projeto: o divisor de tensão e o de corrente. Vamos calcular ambos com confiança.</p><p>Divisores permitem obter frações de uma tensão ou corrente — base de sensores, polarizações e ajustes de nível.</p><ul><li><strong>Divisor de tensão:</strong> Com dois resistores em série, a tensão sobre R2 é Vout = Vin × R2/(R1+R2). Usado para reduzir tensões, polarizar bases de transistor e criar referências.</li><li><strong>Efeito da carga:</strong> Se uma carga for ligada à saída, ela fica em paralelo com R2 e altera a relação. Para um divisor estável, a corrente pela carga deve ser bem menor que a corrente do divisor.</li><li><strong>Divisor de corrente:</strong> Com dois resistores em paralelo, a corrente em um ramo é fração da total. Para R1 e R2: I1 = Itotal × R2/(R1+R2). A corrente prefere o caminho de menor resistência.</li><li><strong>Potenciômetro como divisor:</strong> Um potenciômetro é um divisor de tensão ajustável: o cursor entrega uma fração contínua da tensão aplicada nas extremidades. É a base de faders e knobs de volume.</li><li><strong>Aplicação em sensores:</strong> Sensores resistivos (NTC, LDR) formam um divisor com um resistor fixo; a tensão de saída varia com temperatura ou luz, sendo lida por um ADC.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Resistores e potenciômetro:</strong> Montam divisores fixos e ajustáveis.</li><li><strong>Multímetro:</strong> Mede a tensão de saída do divisor para validar o cálculo.</li></ul><h4>Passo a passo</h4><ol><li><strong>Defina Vin e a fração desejada:</strong> Determine a tensão de entrada e o Vout alvo.</li><li><strong>Escolha R1 e R2:</strong> Calcule a razão R2/(R1+R2) para obter o Vout desejado.</li><li><strong>Verifique a corrente do divisor:</strong> Garanta corrente suficiente para que a carga não derrube a saída.</li><li><strong>Meça e ajuste:</strong> Confira Vout com o multímetro já com a carga conectada.</li></ol><p><strong>Na prática:</strong> Para ler um fader de volume num mixer digital, aplica-se 3,3 V nas pontas do potenciômetro; o cursor entrega de 0 a 3,3 V para o ADC, que converte a posição em valor de ganho. É um divisor de tensão variável puro.</p><h4>Resumo</h4><ul><li>Divisor de tensão: Vout = Vin×R2/(R1+R2), base de polarizações e referências.</li><li>A carga em paralelo com R2 altera a saída; mantenha a corrente do divisor alta.</li><li>Divisor de corrente reparte a corrente; ela prefere o menor resistor.</li></ul>',25,4,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('9f4177f2-2b9b-4c9a-8ae2-1b6d80ccbe7c','80a03a55-131c-489f-b917-eff8963b4793','Quiz — Divisor de tensão e divisor de corrente');
