insert into public.modules (id,course_id,titulo,ordem) values ('a4bf6f41-0098-4747-ad31-24b714145a91','07695dfc-c93c-4a8a-bb5a-58d3b926c76e','Módulo 2 — Componentes Eletrônicos',2);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('6aac751f-27db-4c41-ac9e-fd9f40c95828','a4bf6f41-0098-4747-ad31-24b714145a91','Resistores, capacitores e indutores','texto','<p><strong>Para começar:</strong> Os três componentes passivos fundamentais. Quem entende resistor, capacitor e indutor entende metade da eletrônica.</p><p>Resistores dissipam, capacitores armazenam energia em campo elétrico e indutores em campo magnético. Cada um reage de forma diferente a CC e CA.</p><ul><li><strong>Resistor:</strong> Limita corrente e dissipa energia em calor. Caracterizado por resistência (Ω), potência (W) e tolerância (%). Tipos: filme de carbono, filme metálico (mais preciso), fio (alta potência), SMD.</li><li><strong>Código de cores:</strong> Resistores axiais usam faixas coloridas: as duas/três primeiras são dígitos, a seguinte o multiplicador e a última a tolerância (dourado ±5%, prata ±10%). Domine a sequência preto-marrom-vermelho-laranja-amarelo-verde-azul-violeta-cinza-branco (0 a 9).</li><li><strong>Capacitor:</strong> Armazena carga em campo elétrico entre placas; capacitância em farads (F), na prática µF, nF, pF. Bloqueia CC em regime e deixa passar CA. Tipos: cerâmico, poliéster, eletrolítico (polarizado!), tântalo.</li><li><strong>Reatância capacitiva:</strong> A oposição do capacitor à CA: Xc = 1/(2πfC), em ohms. Quanto maior a frequência, menor a oposição — por isso capacitores acoplam sinais e filtram.</li><li><strong>Indutor:</strong> Armazena energia em campo magnético; indutância em henrys (H), na prática mH e µH. Opõe-se a variações de corrente. Deixa passar CC e dificulta CA.</li><li><strong>Reatância indutiva:</strong> Xl = 2πfL, em ohms. Cresce com a frequência: indutores bloqueiam altas frequências, sendo usados em filtros e fontes.</li><li><strong>Constante de tempo RC:</strong> Em um circuito RC, τ = R×C define a velocidade de carga/descarga. Após ~5τ o capacitor está praticamente carregado. Base de temporizações e filtros.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Multímetro/capacímetro:</strong> Mede resistência e capacitância para identificar e testar componentes.</li><li><strong>Ponte LCR:</strong> Mede com precisão indutância (L), capacitância (C) e resistência (R).</li></ul><h4>Passo a passo</h4><ol><li><strong>Leia o valor:</strong> Use o código de cores (resistor) ou a inscrição (capacitor/indutor) para identificar o valor.</li><li><strong>Respeite a polaridade:</strong> Em capacitores eletrolíticos/tântalo, ligue + e − corretamente; inversão pode explodir o componente.</li><li><strong>Teste com o instrumento:</strong> Meça R com ohmímetro e C com capacímetro, sempre com o circuito desenergizado.</li></ol><p><strong>Na prática:</strong> Num filtro de fonte, o capacitor eletrolítico de saída alisa a tensão. Se instalado com polaridade invertida, ele esquenta, incha e pode estourar — daí a regra de ouro de conferir a faixa de polaridade antes de energizar.</p><h4>Resumo</h4><ul><li>Resistor dissipa; capacitor armazena em campo elétrico; indutor em campo magnético.</li><li>Capacitor bloqueia CC e passa CA; indutor faz o oposto.</li><li>Reatâncias dependem da frequência: Xc cai e Xl sobe com f.</li></ul>',35,1,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('2e166ecc-52d4-42fe-824b-98eee921182b','6aac751f-27db-4c41-ac9e-fd9f40c95828','Quiz — Resistores, capacitores e indutores');
