insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('abb6e219-01e7-4cbf-96b3-7617ee5b8047','2e166ecc-52d4-42fe-824b-98eee921182b','Um capacitor eletrolítico ligado com polaridade invertida tende a:','A inversão de polaridade danifica eletrolíticos, podendo aquecer e explodir.',2,1);
