insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('5377bd92-d2ee-4b34-ad1d-b697fe4cc9ae','2e166ecc-52d4-42fe-824b-98eee921182b','A reatância capacitiva Xc, ao aumentar a frequência:','Xc=1/(2πfC): cresce f, cai Xc.',3,1);
