insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('4889dce7-3246-42cf-a72b-1c8eb4ac9406','2e166ecc-52d4-42fe-824b-98eee921182b','A constante de tempo de um circuito RC é:','τ=R×C define a velocidade de carga/descarga.',4,1);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('4889dce7-3246-42cf-a72b-1c8eb4ac9406','R/C',false,1);
