insert into public.quiz_options (question_id,texto,correta,ordem) values ('4889dce7-3246-42cf-a72b-1c8eb4ac9406','R×C',true,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('4889dce7-3246-42cf-a72b-1c8eb4ac9406','C/R',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('a6a7e353-6c2a-46aa-9199-d85ea4a6d093','a4bf6f41-0098-4747-ad31-24b714145a91','Diodos: retificador, LED e zener','texto','<p><strong>Para começar:</strong> O diodo é a válvula de mão única da eletrônica. Dele nascem fontes, indicadores e referências de tensão.</p><p>Diodos conduzem corrente em um só sentido. Essa propriedade simples viabiliza retificação, sinalização (LED) e regulação (zener).</p><ul><li><strong>Junção PN e polarização:</strong> O diodo é uma junção PN. Em polarização direta (anodo + em relação ao catodo) conduz; em reversa, bloqueia. Há uma queda direta típica: ~0,7 V em silício, ~0,3 V em germânio.</li><li><strong>Diodo retificador:</strong> Converte CA em CC ao permitir passagem só do semiciclo favorável. Especificado por corrente máxima (If) e tensão reversa máxima (VRRM). Ex.: série 1N400x.</li><li><strong>LED (diodo emissor de luz):</strong> Emite luz ao conduzir; a queda direta varia com a cor (~1,8 V vermelho a ~3,2 V azul/branco). SEMPRE usar resistor limitador de corrente; corrente típica 10–20 mA.</li><li><strong>Diodo zener:</strong> Projetado para operar em polarização reversa numa tensão de ruptura definida (ex.: 5,1 V), mantendo-a estável. Usado como referência e regulador simples, sempre com resistor série.</li><li><strong>Diodo de roda livre (flyback):</strong> Colocado em paralelo com bobinas/relés para escoar a corrente quando desligadas, protegendo transistores contra o pico de tensão indutivo.</li><li><strong>Especificações críticas:</strong> Atente para corrente direta, tensão reversa, velocidade (diodos rápidos/Schottky para chaveamento) e queda direta (Schottky ~0,3 V, menor perda).</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Multímetro (modo diodo):</strong> Verifica a queda direta e a polaridade do diodo, identificando anodo e catodo.</li><li><strong>Resistor limitador:</strong> Protege LEDs e zeners, limitando a corrente.</li></ul><h4>Passo a passo</h4><ol><li><strong>Identifique anodo e catodo:</strong> O catodo é marcado por uma faixa no corpo (retificador) ou pela perna mais curta/chanfro (LED).</li><li><strong>Teste no modo diodo:</strong> Ponta vermelha no anodo e preta no catodo deve mostrar ~0,5–0,7 V; invertido, OL (aberto).</li><li><strong>Dimensione o resistor do LED:</strong> R=(Vfonte−Vled)/Iled; ex.: (5−2)/0,015 ≈ 200 Ω.</li></ol><p><strong>Na prática:</strong> Para sinalizar ''energizado'' num painel com 12 V e um LED verde (≈2,1 V, 15 mA): R=(12−2,1)/0,015≈660 Ω, usa-se 680 Ω comercial. Sem o resistor, o LED recebe corrente excessiva e queima instantaneamente.</p><h4>Resumo</h4><ul><li>Diodo conduz só num sentido; queda direta ~0,7 V em silício.</li><li>LED precisa de resistor limitador; queda varia com a cor.</li><li>Zener regula em polarização reversa; flyback protege contra picos indutivos.</li></ul>',30,2,true,false);
