insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('30661da2-f105-497d-bea6-21830d20b92d','a4bf6f41-0098-4747-ad31-24b714145a91','Transistores: BJT e MOSFET','texto','<p><strong>Para começar:</strong> O transistor é o componente que mudou o mundo: ele amplifica e chaveia sinais. É o coração de todo equipamento ativo.</p><p>Transistores controlam uma corrente/tensão grande a partir de um sinal pequeno. Atuam como amplificadores ou como chaves eletrônicas.</p><ul><li><strong>BJT (Transistor Bipolar de Junção):</strong> Tem três terminais: base (B), coletor (C) e emissor (E). Uma pequena corrente de base controla uma corrente muito maior coletor-emissor. Tipos NPN e PNP.</li><li><strong>Ganho do BJT (β/hFE):</strong> A corrente de coletor é aproximadamente β vezes a de base: Ic ≈ β×Ib. Valores típicos de β: 100 a 300. Pequena corrente de base comanda grande corrente de carga.</li><li><strong>Regiões de operação:</strong> Corte (desligado), saturação (totalmente ligado, como chave fechada) e ativa (amplificação linear). Em chaveamento, usa-se corte e saturação; em áudio, a região ativa.</li><li><strong>MOSFET:</strong> Transistor de efeito de campo controlado por TENSÃO no terminal porta (gate); os outros são dreno (D) e fonte (S). Alta impedância de entrada, quase não consome corrente de gate. Tipos N e P.</li><li><strong>BJT x MOSFET:</strong> BJT é controlado por corrente; MOSFET por tensão. MOSFETs dominam o chaveamento de potência (fontes, dimmers, drivers de LED) por baixa perda em condução (RDS(on)) e alta velocidade.</li><li><strong>Transistor como chave:</strong> Levando à saturação (BJT) ou conduzindo plenamente (MOSFET), o transistor liga cargas (relés, LEDs de potência, motores) comandado por um microcontrolador.</li><li><strong>Cuidados:</strong> Respeite tensões e correntes máximas, use resistor de base (BJT) ou de gate (MOSFET) e dissipador quando houver potência. MOSFETs são sensíveis a descarga eletrostática (ESD).</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Multímetro (modo diodo/hFE):</strong> Identifica terminais e testa junções; alguns medem hFE de BJTs.</li><li><strong>Testador de componentes:</strong> Identifica tipo, pinagem e parâmetros de transistores automaticamente.</li></ul><h4>Passo a passo</h4><ol><li><strong>Identifique o tipo e pinagem:</strong> Consulte o datasheet para definir NPN/PNP ou canal N/P e os terminais.</li><li><strong>Defina a função:</strong> Decida se vai operar como chave (corte/saturação) ou amplificador (região ativa).</li><li><strong>Dimensione resistores:</strong> Calcule o resistor de base (BJT) para garantir saturação ou de gate (MOSFET) para chaveamento seguro.</li><li><strong>Teste em bancada:</strong> Verifique condução acionando a base/gate e medindo a tensão na carga.</li></ol><p><strong>Na prática:</strong> Para ligar uma fita de LED de 12 V com um Arduino (saída 5 V/poucos mA), usa-se um MOSFET de canal N como chave: o pino do Arduino comanda o gate e o MOSFET conduz a corrente da fita. O microcontrolador jamais conduziria essa corrente diretamente.</p><h4>Resumo</h4><ul><li>Transistores amplificam e chaveiam: pequeno sinal controla grande corrente.</li><li>BJT é comandado por corrente de base; MOSFET por tensão de gate.</li><li>Como chave, operam em corte/saturação para acionar cargas via microcontrolador.</li></ul>',35,3,true,false);
