insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('34c0a59b-a875-44a5-b069-656e091db3bb','23750b9a-6201-4400-a075-9a9f0b057bfc','Para usar o transistor como chave totalmente ligada, ele opera em:','Na saturação o BJT conduz plenamente, como chave fechada.',3,1);
