insert into public.quiz_options (question_id,texto,correta,ordem) values ('607fd25a-30aa-4d20-8498-0d2f2e3b3e49','Dispensam datasheet',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('30927e3f-4c2c-4115-8fc0-c1597131971d','a4bf6f41-0098-4747-ad31-24b714145a91','CIs, relés, transformadores, fusíveis e reguladores','texto','<p><strong>Para começar:</strong> Componentes que integram, isolam, transformam e protegem. São tijolos essenciais de qualquer equipamento profissional.</p><p>Aqui reunimos componentes de integração e infraestrutura: circuitos integrados, relés, transformadores, fusíveis e reguladores de tensão.</p><ul><li><strong>Circuito integrado (CI):</strong> Encapsula milhares a bilhões de transistores num único chip. Famílias: amplificadores operacionais, lógicos (74xx, CD4xxx), microcontroladores, reguladores. Encapsulamentos DIP (through-hole) e SMD.</li><li><strong>Amplificador operacional (op-amp):</strong> CI amplificador de altíssimo ganho com entradas inversora e não-inversora. Base de pré-amplificadores, filtros, somadores e comparadores de áudio.</li><li><strong>Relé:</strong> Chave eletromecânica: uma bobina, ao ser energizada, fecha/abre contatos isolados do circuito de comando. Permite que um sinal de baixa tensão controle cargas de alta tensão/potência. Sempre usar diodo de roda livre.</li><li><strong>Transformador:</strong> Transfere energia entre enrolamentos por indução magnética, elevando ou reduzindo tensão CA conforme a relação de espiras (Vs/Vp = Ns/Np). Oferece isolação galvânica entre primário e secundário.</li><li><strong>Fusível:</strong> Elemento de proteção que se rompe quando a corrente excede o valor nominal, interrompendo o circuito. Especificado por corrente (A), tensão e tipo (rápido/retardado). Nunca substituir por valor maior que o projetado.</li><li><strong>Regulador de tensão:</strong> Mantém a saída estável apesar de variações de entrada/carga. Lineares (série 78xx para positivos, 79xx negativos; LM317 ajustável) e chaveados (DC-DC, muito mais eficientes).</li><li><strong>Dissipação e proteção:</strong> Reguladores lineares dissipam a diferença (Vin−Vout)×I em calor, exigindo dissipador. Reguladores e CIs costumam ter proteção térmica e contra curto.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Multímetro:</strong> Testa continuidade de fusíveis, contatos de relé e tensões de saída de reguladores.</li><li><strong>Fonte de bancada:</strong> Alimenta e valida reguladores e CIs com tensão controlada.</li></ul><h4>Passo a passo</h4><ol><li><strong>Confira o datasheet:</strong> Identifique pinagem do CI/regulador e os limites do relé/transformador/fusível.</li><li><strong>Teste o fusível:</strong> Em continuidade, fusível bom apita; rompido fica aberto. Substitua pelo MESMO valor.</li><li><strong>Verifique o regulador:</strong> Meça a tensão de saída sem e com carga; confirme estabilidade e temperatura.</li><li><strong>Acione o relé com proteção:</strong> Comande a bobina e confirme o chaveamento; mantenha o diodo de roda livre.</li></ol><p><strong>Na prática:</strong> Um regulador 7805 entrega 5 V fixos a partir de 12 V para alimentar a lógica de um controlador DMX. Como dissipa (12−5)×I em calor, em correntes maiores aquece muito — por isso projetos modernos preferem um conversor DC-DC chaveado, bem mais eficiente.</p><h4>Resumo</h4><ul><li>CIs integram muitos transistores; op-amps são base de áudio analógico.</li><li>Relé e transformador isolam circuitos; o transformador também muda a tensão CA.</li><li>Fusível protege por ruptura; reguladores estabilizam tensão (linear x chaveado).</li></ul>',35,4,true,false);
