insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('8218492c-7800-4b1c-bb22-c31d893a4e28','d3faaac1-5ac7-4f7c-ab3b-c3e5b94dd3a4','A principal função do fusível é:','O fusível se rompe ao exceder a corrente nominal, protegendo o circuito.',1,1);
