insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('077e5519-0212-40ec-a5d9-cdc55857293d','d3faaac1-5ac7-4f7c-ab3b-c3e5b94dd3a4','O transformador transfere energia por:','O acoplamento é magnético; a relação de espiras define a tensão e há isolação galvânica.',2,1);
