insert into public.modules (id,course_id,titulo,ordem) values ('243b96ea-5c84-4a2d-9d5f-0e2d6e73216e','07695dfc-c93c-4a8a-bb5a-58d3b926c76e','Módulo 3 — Medição e Instrumentos',3);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('b49df8b9-022d-4ac8-b880-1d730d10d682','243b96ea-5c84-4a2d-9d5f-0e2d6e73216e','O multímetro: tensão, corrente, resistência e continuidade','texto','<p><strong>Para começar:</strong> Se você só pudesse levar um instrumento para o trabalho, seria o multímetro. Vamos dominar cada função com segurança.</p><p>O multímetro é a ferramenta universal de medição. Usá-lo corretamente — e com segurança — é habilidade obrigatória para qualquer técnico.</p><ul><li><strong>Tipos de multímetro:</strong> Analógico (ponteiro) e digital (display). O digital domina por precisão e facilidade. Versões TRUE RMS medem corretamente sinais não-senoidais (essencial em fontes chaveadas e dimmers).</li><li><strong>Medição de tensão (voltímetro):</strong> Selecione V⎓ (CC) ou V∼ (CA). Ligue as pontas EM PARALELO com o ponto a medir (entre dois pontos). O voltímetro tem alta impedância para não perturbar o circuito.</li><li><strong>Medição de corrente (amperímetro):</strong> Selecione A e, fundamental, ligue o instrumento EM SÉRIE, abrindo o circuito para a corrente passar por ele. Use o borne correto (mA ou 10A). Erro clássico: medir corrente em paralelo causa curto.</li><li><strong>Medição de resistência (ohmímetro):</strong> SEMPRE com o circuito DESENERGIZADO e o componente isolado. O instrumento injeta uma pequena corrente e lê a resistência. Mediu com tensão presente? Leitura errada e risco ao aparelho.</li><li><strong>Continuidade:</strong> Função com sinal sonoro (beep) que indica caminho fechado (baixa resistência). Ideal para testar cabos, fusíveis, conexões e curtos — sempre desenergizado.</li><li><strong>Outras funções:</strong> Muitos medem capacitância, frequência, temperatura, ganho (hFE) e têm teste de diodo. Conheça o que seu modelo oferece.</li><li><strong>Categoria de segurança (CAT):</strong> Multímetros têm classificação CAT I a IV indicando onde podem ser usados com segurança (CAT IV o mais severo, próximo à entrada da rede). Respeite a categoria e a tensão máxima.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Multímetro digital:</strong> Mede tensão, corrente, resistência e continuidade.</li><li><strong>Pontas de prova:</strong> Conectam o multímetro ao circuito; verifique isolação e estado das pontas.</li></ul><h4>Passo a passo</h4><ol><li><strong>Escolha a função e a faixa:</strong> Selecione V/A/Ω e CC/CA; em modelos manuais, comece pela faixa mais alta.</li><li><strong>Conecte os bornes corretos:</strong> COM (preto) sempre; vermelho em VΩ para tensão/resistência ou em A para corrente.</li><li><strong>Posicione as pontas:</strong> Paralelo para tensão; série para corrente; desenergizado para Ω e continuidade.</li><li><strong>Leia com atenção ao prefixo:</strong> Interprete mV/V e mA/A corretamente antes de concluir.</li></ol><p><strong>Na prática:</strong> Para descobrir por que um equipamento não liga, primeiro mede-se a tensão na tomada (paralelo), depois testa-se o fusível em continuidade (desenergizado). Se o fusível não apita, está rompido — achou o problema sem abrir nada mais.</p><h4>Resumo</h4><ul><li>Tensão se mede em paralelo; corrente em série; resistência desenergizada.</li><li>Continuidade (beep) testa cabos, fusíveis e curtos rapidamente.</li><li>True RMS e categoria CAT são critérios de precisão e segurança.</li></ul>',35,1,true,false);
