insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('aafccaaa-061e-401d-968d-a19a57613a49','243b96ea-5c84-4a2d-9d5f-0e2d6e73216e','Osciloscópio, pontas de prova e analisadores','texto','<p><strong>Para começar:</strong> O multímetro dá números; o osciloscópio mostra o sinal vivo no tempo. É a janela para enxergar a forma de onda.</p><p>O osciloscópio revela como a tensão varia no tempo, permitindo ver ruído, distorção, frequência e tempos. Pontas de prova e analisadores completam a bancada.</p><ul><li><strong>O que é o osciloscópio:</strong> Instrumento que plota tensão (eixo vertical) versus tempo (eixo horizontal). Permite medir amplitude, período, frequência, tempos de subida e observar a forma de onda real do sinal.</li><li><strong>Controles principais:</strong> Base de tempo (s/div, eixo horizontal), escala vertical (V/div), trigger (gatilho, que estabiliza a imagem) e acoplamento (DC mostra nível médio; AC remove o componente CC).</li><li><strong>Largura de banda e amostragem:</strong> A largura de banda (MHz) define a maior frequência fielmente exibida; a taxa de amostragem (digitais) deve ser bem maior que a do sinal. Escolha o aparelho conforme o sinal a observar.</li><li><strong>Pontas de prova:</strong> A ponta 1x passa o sinal direto; a 10x atenua por 10, aumentando a impedância e a banda úteis e reduzindo a carga sobre o circuito. Ajuste a compensação da ponta (quadrado de calibração) antes de medir.</li><li><strong>Aterramento da ponta:</strong> A garra de terra da ponta liga ao terra do circuito. Conectá-la em ponto errado pode causar curto pelo terra — cuidado em circuitos referenciados à rede.</li><li><strong>Analisadores:</strong> Analisador de espectro mostra o sinal no domínio da frequência (útil em RF e áudio). Analisador lógico captura múltiplos sinais digitais simultâneos para depurar barramentos.</li><li><strong>Medições típicas em eventos:</strong> Verificar ruído em linhas de áudio, integridade de sinais DMX/digitais, presença de oscilação, formas de onda de fontes chaveadas.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Osciloscópio:</strong> Visualiza e mede formas de onda no tempo.</li><li><strong>Ponta de prova 10x:</strong> Mede com menor carga sobre o circuito e maior banda; requer compensação.</li><li><strong>Analisador de espectro/lógico:</strong> Analisa sinais no domínio da frequência ou barramentos digitais.</li></ul><h4>Passo a passo</h4><ol><li><strong>Ajuste a ponta:</strong> Selecione 10x e compense na saída de calibração até a onda quadrada ficar com cantos retos.</li><li><strong>Conecte terra e ponta:</strong> Garra de terra ao terra do circuito; ponta ao ponto de medição.</li><li><strong>Configure escalas e trigger:</strong> Ajuste V/div e s/div para enquadrar a onda e use o trigger para estabilizar a imagem.</li><li><strong>Meça os parâmetros:</strong> Leia amplitude (Vpp), período e calcule a frequência (f=1/T).</li></ol><p><strong>Na prática:</strong> Ao investigar zumbido numa linha de áudio, o osciloscópio mostra uma senoide de 60 Hz somada ao sinal — sintoma clássico de loop de terra. O número do multímetro não revelaria a forma; o osciloscópio diagnostica de imediato.</p><h4>Resumo</h4><ul><li>Osciloscópio mostra tensão x tempo: amplitude, período e forma de onda.</li><li>Ponta 10x carrega menos o circuito; sempre compensar antes de medir.</li><li>Analisadores de espectro (frequência) e lógico (barramentos digitais) complementam.</li></ul>',35,2,true,false);
