insert into public.modules (id,course_id,titulo,ordem) values ('75795dd8-9b99-4871-b1dc-2f892c42aefc','07695dfc-c93c-4a8a-bb5a-58d3b926c76e','Módulo 4 — Sinais e Eletrônica Digital',4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('914feec5-39ba-4441-8420-3dcb654d220a','75795dd8-9b99-4871-b1dc-2f892c42aefc','Analógico x digital, níveis lógicos e binário','texto','<p><strong>Para começar:</strong> O mundo é analógico, mas os equipamentos modernos pensam em binário. Entender essa fronteira é entender a eletrônica atual.</p><p>Sinais analógicos variam continuamente; digitais assumem valores discretos (0 e 1). Esta aula estabelece a base do raciocínio digital.</p><ul><li><strong>Sinal analógico:</strong> Varia continuamente no tempo e pode assumir infinitos valores dentro de uma faixa. Ex.: tensão de um microfone, posição de um fader. Sensível a ruído, que se soma ao sinal.</li><li><strong>Sinal digital:</strong> Assume valores discretos, normalmente dois: 0 e 1 (binário). Mais robusto a ruído, pois o receptor só precisa distinguir ''alto'' de ''baixo''. Base de computadores e equipamentos modernos.</li><li><strong>Níveis lógicos:</strong> Cada família define faixas de tensão para 0 e 1. Em lógica de 5 V (TTL), ~0 V é nível baixo e ~5 V é alto, com faixa proibida no meio. Há lógica de 3,3 V e outras; misturar tensões exige atenção.</li><li><strong>Sistema binário:</strong> Base 2, com dígitos 0 e 1 (bits). Cada posição vale uma potência de 2. Ex.: 1011₂ = 8+0+2+1 = 11. Computadores operam nativamente em binário.</li><li><strong>Bits, bytes e múltiplos:</strong> 8 bits = 1 byte. Um byte representa 0 a 255 (256 valores). Múltiplos: kilobyte, megabyte, etc. A quantidade de bits define a resolução e a faixa de valores.</li><li><strong>Hexadecimal:</strong> Base 16 (0–9, A–F) usada para representar binário de forma compacta: cada dígito hex equivale a 4 bits. Comum em endereços e cores (ex.: #FF0000).</li><li><strong>Lógica positiva e negativa:</strong> Em lógica positiva, nível alto = 1; em negativa, alto = 0. Saber a convenção evita interpretar sinais ao contrário.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Multímetro/osciloscópio:</strong> Verifica níveis lógicos (alto/baixo) e a forma do sinal digital.</li><li><strong>Analisador lógico:</strong> Captura sequências de bits em barramentos digitais.</li></ul><h4>Passo a passo</h4><ol><li><strong>Identifique o tipo de sinal:</strong> Determine se a linha é analógica (variação contínua) ou digital (alto/baixo).</li><li><strong>Conheça a tensão da lógica:</strong> Verifique se é 5 V ou 3,3 V para não danificar entradas.</li><li><strong>Converta as bases:</strong> Treine conversões binário↔decimal↔hexadecimal.</li><li><strong>Meça os níveis:</strong> Confirme com o instrumento que ''1'' e ''0'' estão dentro das faixas válidas.</li></ol><p><strong>Na prática:</strong> Ao ligar um sensor de 5 V a um microcontrolador de 3,3 V, aplicar o nível alto de 5 V direto pode danificar a entrada. A solução é um divisor de tensão ou um conversor de nível lógico — questão prática frequente em integrações.</p><h4>Resumo</h4><ul><li>Analógico varia continuamente; digital usa valores discretos (0/1), mais imune a ruído.</li><li>Binário é base 2; hexadecimal compacta 4 bits por dígito.</li><li>Níveis lógicos definem faixas de 0 e 1; misturar 5 V e 3,3 V exige atenção.</li></ul>',30,1,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('644cecef-b64f-4b01-bbc6-3cf7835a76b3','914feec5-39ba-4441-8420-3dcb654d220a','Quiz — Analógico x digital, níveis lógicos e binário');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('a5d61f65-82c8-47dd-b9c7-a88d23071c0d','644cecef-b64f-4b01-bbc6-3cf7835a76b3','A principal vantagem do sinal digital é:','Por assumir valores discretos, o digital é mais robusto a ruído.',1,1);
