insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('333a776f-d4fb-4ab9-8584-b2ea5ec096b9','644cecef-b64f-4b01-bbc6-3cf7835a76b3','O número binário 1011 em decimal é:','1011₂ = 8+0+2+1 = 11.',2,1);
