insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('6ea276c0-7ef9-4157-bb39-e15192320d65','75795dd8-9b99-4871-b1dc-2f892c42aefc','Portas lógicas, amostragem e conversão (ADC/DAC)','texto','<p><strong>Para começar:</strong> Das portas lógicas nasce todo processamento digital; da amostragem nasce o áudio e o vídeo digitais. Vamos unir os dois mundos.</p><p>Portas lógicas implementam decisões em hardware; ADC e DAC fazem a ponte entre o mundo analógico e o digital, essencial em áudio e vídeo.</p><ul><li><strong>Portas lógicas básicas:</strong> Implementam funções booleanas. NOT (inverte), AND (1 só se todas as entradas forem 1), OR (1 se alguma for 1). São os blocos de todo circuito digital.</li><li><strong>Portas derivadas:</strong> NAND (AND negada), NOR (OR negada), XOR (1 quando as entradas diferem) e XNOR. NAND e NOR são ''universais'': qualquer função pode ser feita só com elas.</li><li><strong>Tabela-verdade:</strong> Lista todas as combinações de entrada e a saída correspondente. É a forma rigorosa de definir e verificar o comportamento de uma porta ou circuito lógico.</li><li><strong>Conversão Analógico-Digital (ADC):</strong> Transforma um sinal analógico em números digitais por dois processos: amostragem (medir em instantes) e quantização (arredondar a níveis discretos).</li><li><strong>Teorema da amostragem (Nyquist):</strong> Para reconstruir um sinal sem perda, a taxa de amostragem deve ser maior que o dobro da maior frequência do sinal. Por isso áudio (até ~20 kHz) usa 44,1 kHz ou 48 kHz.</li><li><strong>Quantização e resolução de bits:</strong> O número de bits define quantos níveis de amplitude existem: 16 bits = 65.536 níveis. Mais bits = menos erro de quantização e maior faixa dinâmica. Áudio profissional usa 24 bits.</li><li><strong>Conversão Digital-Analógico (DAC):</strong> Faz o caminho inverso: converte os números de volta em tensão analógica, reconstruindo o som ou o vídeo na saída do equipamento.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>CIs lógicos / microcontrolador:</strong> Implementam portas lógicas e contêm ADC/DAC internos.</li><li><strong>Osciloscópio:</strong> Compara o sinal analógico original com o reconstruído pelo DAC.</li></ul><h4>Passo a passo</h4><ol><li><strong>Monte a função lógica:</strong> Defina a tabela-verdade e escolha as portas (ou NAND/NOR universais).</li><li><strong>Defina a taxa de amostragem:</strong> Garanta taxa maior que o dobro da maior frequência do sinal (Nyquist).</li><li><strong>Escolha a resolução:</strong> Selecione o número de bits conforme a faixa dinâmica desejada.</li><li><strong>Verifique a reconstrução:</strong> Compare a saída do DAC com o sinal de entrada no osciloscópio.</li></ol><p><strong>Na prática:</strong> Uma mesa digital de som amostra cada entrada a 48 kHz com 24 bits. Respeitar Nyquist (&gt;2×20 kHz) e usar bits suficientes é o que garante áudio fiel, sem aliasing nem ruído de quantização audível.</p><h4>Resumo</h4><ul><li>Portas lógicas implementam decisões; NAND e NOR são universais.</li><li>ADC amostra (Nyquist: &gt;2× a maior frequência) e quantiza (bits = níveis).</li><li>DAC reconstrói o sinal analógico a partir dos números digitais.</li></ul>',35,2,true,false);
