insert into public.modules (id,course_id,titulo,ordem) values ('a30e9253-d15b-488e-8365-86f0176f816f','07695dfc-c93c-4a8a-bb5a-58d3b926c76e','Módulo 5 — Transmissão de Dados e Conectividade',5);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('bc4b2fac-0da8-4c3b-b3ba-505994468a1a','a30e9253-d15b-488e-8365-86f0176f816f','Cabos, conectores e impedância','texto','<p><strong>Para começar:</strong> No evento, o sinal só é tão bom quanto o cabo que o carrega. Conhecer cabos, conectores e impedância separa o amador do profissional.</p><p>Cada tipo de sinal pede um cabo e um conector adequados. Impedância e construção do cabo determinam qualidade e alcance.</p><ul><li><strong>Anatomia do cabo:</strong> Condutor (cobre), isolação, blindagem (malha/folha) e capa. A blindagem protege contra interferência externa e deve ser bem aterrada nas extremidades corretas.</li><li><strong>Impedância característica:</strong> Propriedade de cabos de transmissão (coaxial, de rede) que define como o sinal se propaga, em ohms. Ex.: coaxial de vídeo 75 Ω, antena 50 Ω. Casar a impedância evita reflexões.</li><li><strong>Reflexões e casamento:</strong> Quando a impedância da fonte, do cabo e da carga não casam, parte do sinal reflete, causando perda e distorção (importante em vídeo SDI, RF e DMX, que pede terminação de 120 Ω).</li><li><strong>Conectores de áudio:</strong> XLR (3 pinos, balanceado, microfones e linha profissional), P10/TRS (1/4'', balanceado ou estéreo), P10/TS (desbalanceado), RCA (desbalanceado, consumo), P2/3,5 mm.</li><li><strong>Conectores de vídeo/dados:</strong> BNC (vídeo/SDI, 75 Ω, travamento por baioneta), HDMI, RJ45 (rede Ethernet), USB, DisplayPort, fibra óptica para longas distâncias.</li><li><strong>Bitola e comprimento:</strong> Cabos longos têm mais resistência e capacitância, atenuando o sinal. Para potência (caixas), bitola maior (AWG menor) reduz perdas; para sinal, blindagem e qualidade importam mais.</li><li><strong>Cuidados de cabeamento:</strong> Evite emendas malfeitas, respeite o raio mínimo de curvatura, não passe cabo de sinal junto a cabo de energia e identifique/teste os cabos antes do show.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Testador de cabos:</strong> Verifica continuidade e mapeamento de pinos de cabos XLR, P10, RJ45, etc.</li><li><strong>Multímetro:</strong> Mede continuidade da malha e dos condutores.</li></ul><h4>Passo a passo</h4><ol><li><strong>Escolha o cabo pelo sinal:</strong> Selecione coaxial 75 Ω para vídeo, par trançado para rede, blindado para áudio.</li><li><strong>Confira a impedância:</strong> Garanta casamento entre fonte, cabo e carga; termine o que pede terminação (DMX 120 Ω).</li><li><strong>Conecte e trave:</strong> Use o conector correto e trave (XLR/BNC) para evitar quedas durante o evento.</li><li><strong>Teste antes do show:</strong> Passe todos os cabos no testador para flagrar mau contato ou inversão de pinos.</li></ol><p><strong>Na prática:</strong> Numa linha DMX longa sem o resistor de terminação de 120 Ω no último aparelho, o sinal reflete e causa cintilação aleatória nas luzes. Colocar a terminação correta resolve — exemplo direto de casamento de impedância na prática.</p><h4>Resumo</h4><ul><li>Cada sinal pede cabo e conector próprios; XLR e BNC travam e são profissionais.</li><li>Impedância característica deve casar para evitar reflexões e perdas.</li><li>Blindagem, bitola e teste prévio garantem confiabilidade no palco.</li></ul>',35,1,true,false);
