insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('29a22914-e26f-4a4d-aef7-65636925f242','a571c839-0656-48f2-8094-b6f877dd5058','Para grandes distâncias com imunidade a interferência, o melhor meio é:','A fibra óptica é imune a EMI e cobre longas distâncias.',4,1);
