insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('64999c14-61eb-4da4-a555-a9a004c3596c','a30e9253-d15b-488e-8365-86f0176f816f','Balanceado x desbalanceado e aterramento de sinal','texto','<p><strong>Para começar:</strong> Por que o cabo de microfone profissional tem três pinos e quase não pega ruído? A resposta está no sinal balanceado.</p><p>Linhas balanceadas rejeitam ruído por design; entender o conceito explica conexões profissionais de áudio e dados, e o papel do terra de sinal.</p><ul><li><strong>Sinal desbalanceado:</strong> Usa dois condutores: sinal e terra/blindagem. Simples e barato, mas a blindagem também é referência, captando ruído em cabos longos. Ex.: RCA, P10 TS, instrumentos.</li><li><strong>Sinal balanceado:</strong> Usa três condutores: dois para o sinal (em fase oposta) e um terra/blindagem. O sinal trafega como diferença entre os dois condutores.</li><li><strong>Rejeição de modo comum (CMRR):</strong> O ruído captado se soma igualmente aos dois condutores (modo comum). No receptor, ao subtrair um do outro, o sinal dobra e o ruído se cancela. Por isso linhas balanceadas correm longas distâncias com baixo ruído.</li><li><strong>Onde se usa:</strong> Balanceado: microfones, saídas de mesa, longas tiragens (XLR, TRS). Desbalanceado: curtas distâncias, equipamento doméstico, instrumentos (com cabo curto).</li><li><strong>Terra de sinal x terra de proteção:</strong> O terra de sinal é a referência 0 V do circuito; o terra de proteção (PE) é segurança elétrica. Confundi-los ou interligá-los em vários pontos cria loops de terra e zumbido.</li><li><strong>Lift de terra:</strong> Em equipamentos com problema de loop, alguns têm chave ''ground lift'' que desconecta o terra de sinal do chassi, quebrando o loop — sem jamais remover o terra de proteção da rede.</li><li><strong>Caixas de direct box (DI):</strong> Convertem sinal desbalanceado de alta impedância (instrumento) em balanceado de baixa impedância, permitindo longas tiragens com baixo ruído e isolando terras.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Direct box (DI):</strong> Balanceia e isola sinais de instrumentos para a mesa.</li><li><strong>Multímetro/osciloscópio:</strong> Identifica zumbido e diferenças de potencial de terra entre equipamentos.</li></ul><h4>Passo a passo</h4><ol><li><strong>Classifique a linha:</strong> Veja se a conexão é balanceada (XLR/TRS) ou desbalanceada (RCA/TS).</li><li><strong>Prefira balanceado em longas tiragens:</strong> Use cabos balanceados para microfones e tiragens longas, reduzindo ruído.</li><li><strong>Trate o terra com critério:</strong> Mantenha o terra de proteção; use DI ou ground lift para resolver loops de sinal.</li><li><strong>Verifique zumbido:</strong> Se houver zumbido de 60 Hz, suspeite de loop de terra e isole.</li></ol><p><strong>Na prática:</strong> Um teclado a 20 m da mesa, ligado por cabo desbalanceado, chega cheio de zumbido. Trocando por uma DI box (balanceando o sinal e isolando o terra), o ruído some — solução padrão do áudio ao vivo.</p><h4>Resumo</h4><ul><li>Balanceado usa dois condutores em oposição e cancela ruído por subtração (CMRR).</li><li>Desbalanceado é simples mas capta ruído em longas distâncias.</li><li>Terra de sinal e de proteção são distintos; loops de terra causam zumbido — trate com DI/lift, nunca removendo o PE.</li></ul>',30,2,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('0c17bc91-c746-4f81-b6ef-fda2c5487837','64999c14-61eb-4da4-a555-a9a004c3596c','Quiz — Balanceado x desbalanceado e aterramento de sinal');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('6f6940a9-17db-474e-b54e-f8a9af8d7929','0c17bc91-c746-4f81-b6ef-fda2c5487837','A linha balanceada rejeita ruído porque:','O ruído comum aos dois condutores se cancela na subtração; o sinal dobra.',1,1);
