insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('b6b6b751-a8b2-4c04-b949-994e7047bc37','a30e9253-d15b-488e-8365-86f0176f816f','Protocolos: DMX512, MIDI, USB, Ethernet/IP, Art-Net/sACN e sem fio','texto','<p><strong>Para começar:</strong> Eventos modernos são redes de dados. Dominar os protocolos de iluminação, áudio e controle é o que integra todo o show.</p><p>Cada protocolo carrega um tipo de informação com regras próprias de fios, velocidade e endereçamento. Conhecê-los permite integrar luz, som e vídeo.</p><ul><li><strong>DMX512:</strong> Protocolo padrão de iluminação cênica. Serial, baseado em RS-485, em par trançado com conector XLR de 5 pinos (às vezes 3). Um universo tem 512 canais; cada aparelho ocupa um endereço inicial e usa N canais. Exige terminação de 120 Ω.</li><li><strong>MIDI:</strong> Protocolo de instrumentos musicais (Musical Instrument Digital Interface). Serial a 31.250 bps, conector DIN de 5 pinos (ou via USB). Transmite mensagens como nota, velocity, controle e program change — não transmite áudio, e sim comandos.</li><li><strong>USB:</strong> Barramento serial universal para conectar periféricos (interfaces de áudio, controladores, pendrives). Fornece dados e alimentação (5 V). Várias gerações com velocidades crescentes; reconhece dispositivos automaticamente (plug and play).</li><li><strong>Ethernet/IP:</strong> Rede de dados padrão (cabo RJ45/par trançado ou fibra) sobre a qual trafegam protocolos de evento. Permite muitos universos de luz e canais de áudio por um único cabo, com switches gerenciáveis.</li><li><strong>Art-Net e sACN:</strong> Protocolos que transportam DMX sobre rede Ethernet/IP. Art-Net e sACN (E1.31) permitem centenas de universos por um cabo de rede, simplificando grandes montagens de iluminação e mídia.</li><li><strong>Áudio sobre IP:</strong> Padrões como Dante, AES67 e AVB transportam muitos canais de áudio digital por rede Ethernet com baixa latência, substituindo grandes multicabos analógicos.</li><li><strong>Sem fio (RF e IR):</strong> RF (rádio) para microfones sem fio, in-ear e controle remoto; opera em faixas licenciadas/livres e sofre com interferência e ocupação de espectro. IR (infravermelho) exige linha de visada, usado em controles e alguns sistemas.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Interface DMX/USB e nó Art-Net:</strong> Conecta computador à rede de iluminação.</li><li><strong>Switch de rede gerenciável:</strong> Trafega Art-Net/sACN e áudio sobre IP com confiabilidade.</li><li><strong>Analisador/monitor de rede:</strong> Verifica tráfego e endereçamento dos protocolos.</li></ul><h4>Passo a passo</h4><ol><li><strong>Defina o protocolo por função:</strong> Luz: DMX/Art-Net/sACN; áudio: Dante/AES67; instrumentos: MIDI.</li><li><strong>Enderece os aparelhos:</strong> Atribua endereço DMX inicial e universo; configure IPs na rede.</li><li><strong>Cabeie corretamente:</strong> Par trançado/RJ45 e terminação onde exigido (DMX 120 Ω).</li><li><strong>Verifique a comunicação:</strong> Confirme resposta dos aparelhos e ausência de conflitos de endereço/IP.</li></ol><p><strong>Na prática:</strong> Numa turnê grande, em vez de dezenas de cabos DMX, usa-se um único cabo de rede levando sACN com vários universos até nós que o convertem em DMX nos pontos de luz. Menos cabo, menos peso, montagem mais rápida.</p><h4>Resumo</h4><ul><li>DMX512 controla luz (512 canais/universo, RS-485, terminação 120 Ω).</li><li>MIDI envia comandos musicais; USB e Ethernet/IP conectam e transportam dados.</li><li>Art-Net/sACN levam DMX por rede; Dante/AES67 levam áudio; RF/IR cobrem o sem fio.</li></ul>',40,3,true,false);
