insert into public.modules (id,course_id,titulo,ordem) values ('3d94fa4f-f7fe-446c-990e-7a2ef8f6275f','07695dfc-c93c-4a8a-bb5a-58d3b926c76e','Módulo 6 — Eletrônica de Áudio',6);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('e8abc4e7-4ad3-4799-a9a8-bed9b3892b7d','3d94fa4f-f7fe-446c-990e-7a2ef8f6275f','Impedância, ganho e níveis de áudio','texto','<p><strong>Para começar:</strong> Som limpo começa no casamento de níveis e impedâncias. Aqui você aprende a falar a língua do áudio analógico.</p><p>Os conceitos de impedância, ganho e níveis de linha determinam se o sinal chega limpo, distorcido ou ruidoso à saída.</p><ul><li><strong>Impedância em áudio:</strong> Oposição à corrente em CA, em ohms. Regra prática: fonte de baixa impedância alimenta entrada de alta impedância (casamento por ponte de tensão). Microfones e saídas profissionais são de baixa impedância.</li><li><strong>Impedância de alto-falantes:</strong> Caixas têm impedância nominal (4, 8, 16 Ω). Ligar caixas em paralelo reduz a impedância e exige mais do amplificador; respeitar a carga mínima do ampli evita superaquecimento e proteção.</li><li><strong>Ganho:</strong> Quanto o sinal é amplificado, expresso em dB. Ganho positivo amplifica; negativo atenua. O estágio de ganho de entrada (gain/trim) ajusta o nível do sinal ao padrão interno da mesa.</li><li><strong>Decibel (dB):</strong> Unidade logarítmica de relação entre potências/tensões. +6 dB ≈ dobro de tensão; +10 dB ≈ percepção de ''dobro de volume''. dBu e dBV são referências de tensão; dBFS é referência digital (0 dBFS = máximo).</li><li><strong>Níveis de sinal:</strong> Mic level (baixíssimo, µV–mV, precisa de pré-amplificação), line level (nível de operação, ~+4 dBu profissional ou −10 dBV consumo), instrument level e speaker level (alto, pós-amplificação).</li><li><strong>Estrutura de ganho (gain staging):</strong> Ajustar cada estágio para operar com bom nível, longe do ruído (piso) e longe do clipping (teto). Gain staging correto maximiza a relação sinal-ruído e a faixa dinâmica.</li><li><strong>Clipping e headroom:</strong> Clipping é o ceifamento do sinal ao exceder o máximo, gerando distorção. Headroom é a margem entre o nível de trabalho e o máximo; manter headroom evita distorção em picos.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Mesa de som / pré-amplificador:</strong> Aplica ganho e ajusta níveis de mic para line.</li><li><strong>Medidor de nível (VU/PPM):</strong> Monitora nível e headroom para evitar clipping.</li></ul><h4>Passo a passo</h4><ol><li><strong>Identifique o nível da fonte:</strong> Veja se é mic, instrumento ou line para escolher a entrada certa.</li><li><strong>Ajuste o ganho de entrada:</strong> Suba o trim até bom nível, com picos abaixo do clipping (headroom).</li><li><strong>Casamento de impedância:</strong> Garanta fonte de baixa impedância para entrada de alta impedância.</li><li><strong>Verifique a carga do amplificador:</strong> Some as impedâncias das caixas e respeite a mínima do ampli.</li></ol><p><strong>Na prática:</strong> Se o trim do microfone está baixo demais, sobe-se o fader e o ganho seguintes, amplificando junto o ruído de fundo — sinal fraco e chiado. Ajustar o ganho de entrada corretamente (gain staging) resolve a relação sinal-ruído na origem.</p><h4>Resumo</h4><ul><li>Em áudio, fonte de baixa impedância alimenta entrada de alta impedância.</li><li>dB é logarítmico; níveis vão de mic (fraco) a speaker (forte), passando por line.</li><li>Bom gain staging maximiza sinal-ruído mantendo headroom contra clipping.</li></ul>',35,1,true,false);
