insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('6f6aee51-d35b-42c7-aef0-e266949b104c','3d94fa4f-f7fe-446c-990e-7a2ef8f6275f','Phantom +48V, ruído e relação sinal-ruído','texto','<p><strong>Para começar:</strong> O botão +48V e a luta contra o ruído definem a qualidade do som captado. Vamos entender ambos a fundo.</p><p>A alimentação phantom energiza microfones a condensador; e o controle de ruído determina a clareza do áudio. Dois pilares da captação profissional.</p><ul><li><strong>Phantom power +48V:</strong> Tensão CC de 48 V enviada pela mesa pelo mesmo cabo XLR balanceado para alimentar microfones a condensador e DIs ativas. É ''fantasma'' porque trafega igualmente nos dois condutores de sinal, sem afetar o áudio.</li><li><strong>Quem precisa e quem não:</strong> Microfones a condensador e DIs ativas PRECISAM de phantom. Microfones dinâmicos NÃO precisam — e, embora geralmente tolerem, conectar/desconectar com phantom ligado pode gerar estouros e, em equipamentos sensíveis (ribbon mal cabeado), causar dano.</li><li><strong>Boas práticas com phantom:</strong> Ligue o phantom só após conectar o microfone e com o fader/canal mudo; desligue antes de desconectar. Evite pops e protege os alto-falantes.</li><li><strong>Ruído eletrônico:</strong> Todo circuito gera ruído: térmico (agitação dos elétrons, inevitável), de fundo dos componentes e captado do ambiente (EMI, rede 60 Hz). O pré-amplificador é onde o ruído mais pesa, pois amplifica tudo a seguir.</li><li><strong>Relação sinal-ruído (SNR):</strong> Razão entre o nível do sinal e o do ruído de fundo, em dB. Quanto maior, mais limpo o áudio. Bom gain staging e cabos balanceados elevam a SNR.</li><li><strong>Tipos de interferência audível:</strong> Zumbido (hum) de 60 Hz por loop de terra; chiado (hiss) de ganho excessivo/ruído térmico; interferência de RF (celulares, transmissores). Cada um tem causa e tratamento próprios.</li><li><strong>Piso de ruído e faixa dinâmica:</strong> Piso de ruído é o nível mínimo audível do sistema; faixa dinâmica é a distância entre o piso e o nível máximo sem distorção. Sistemas profissionais buscam piso baixo e ampla faixa dinâmica.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Microfone a condensador:</strong> Requer phantom +48V para funcionar.</li><li><strong>Mesa com phantom e medidores:</strong> Fornece +48V e monitora nível e ruído.</li></ul><h4>Passo a passo</h4><ol><li><strong>Conecte com o canal mudo:</strong> Plugue o microfone com o fader abaixado e o canal em mute.</li><li><strong>Ative o phantom se necessário:</strong> Ligue +48V apenas para condensadores/DI ativa; deixe desligado para dinâmicos.</li><li><strong>Ajuste o ganho buscando SNR:</strong> Suba o trim até bom nível, mantendo o ruído de fundo bem abaixo do sinal.</li><li><strong>Desligue antes de desconectar:</strong> Desative o phantom e abaixe o canal antes de retirar o microfone.</li></ol><p><strong>Na prática:</strong> Um microfone a condensador ''mudo'' costuma ser falta de phantom +48V. Ligando o botão na mesa, ele ganha vida. Já um zumbido constante de 60 Hz aponta loop de terra, não falta de phantom — diagnósticos diferentes para sintomas diferentes.</p><h4>Resumo</h4><ul><li>Phantom +48V alimenta microfones a condensador pelo XLR balanceado.</li><li>Manuseie phantom com canal mudo; dinâmicos não precisam dele.</li><li>SNR mede a limpeza do áudio; hum, hiss e RF têm causas e soluções distintas.</li></ul>',30,2,true,false);
