insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('004b215f-b34e-495a-aa88-53ba715b075e','8b166523-782f-4fa2-9686-87e3d9a905ba','Uma alta relação sinal-ruído (SNR) significa:','Quanto maior a SNR, mais o sinal se sobressai ao ruído: áudio limpo.',3,1);
