insert into public.modules (id,course_id,titulo,ordem) values ('b90aa9b4-700d-4bf1-8d3f-dd592871375a','07695dfc-c93c-4a8a-bb5a-58d3b926c76e','Módulo 7 — Eletrônica de Vídeo',7);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('6803635c-62e7-47e5-af53-f07f039630ec','b90aa9b4-700d-4bf1-8d3f-dd592871375a','Sinais de vídeo: HDMI, SDI e conversão A/D','texto','<p><strong>Para começar:</strong> Telão, LED e projeção dependem de sinais de vídeo confiáveis. HDMI e SDI são os dois mundos que você precisa dominar.</p><p>Vídeo profissional trafega principalmente por HDMI e SDI, cada um com vantagens. Entender suas características evita telas pretas no momento crítico.</p><ul><li><strong>Vídeo analógico x digital:</strong> O vídeo migrou de analógico (composto, VGA, componente) para digital (HDMI, SDI, DisplayPort). O digital carrega imagem e, em alguns casos, áudio, com qualidade estável até o limite do alcance.</li><li><strong>HDMI:</strong> Padrão de consumo/profissional que leva vídeo e áudio digital por um único cabo. Prós: ubíquo, carrega áudio. Contras: alcance curto (poucos metros sem extensores), conector sem trava (cai fácil) e uso de HDCP (proteção de cópia).</li><li><strong>SDI (Serial Digital Interface):</strong> Padrão profissional de broadcast sobre cabo coaxial 75 Ω com conector BNC travado. Prós: longas distâncias (dezenas a centenas de metros), conector seguro. Padrões: SD-SDI, HD-SDI, 3G/6G/12G-SDI conforme a resolução/taxa.</li><li><strong>Resolução e taxa:</strong> Resolução (ex.: 1920×1080 ''Full HD'', 3840×2160 ''4K'') e taxa de quadros (fps). Maior resolução/fps exige mais banda no cabo — por isso surgem 3G/6G/12G-SDI e HDMI de versões superiores.</li><li><strong>Conversão A/D em vídeo:</strong> Câmeras e captura digitalizam a luz via sensor; o sinal pode ser convertido entre formatos por conversores (HDMI↔SDI), scalers (mudam resolução) e processadores, fundamentais para casar fontes e telões.</li><li><strong>Extensão de sinal:</strong> Para vencer distâncias, usam-se extensores HDMI sobre par trançado/fibra, ou simplesmente SDI (que já vai longe). Cabos ativos e fibra resolvem grandes tiragens de vídeo.</li><li><strong>Sincronismo e processamento:</strong> Em sistemas com várias fontes/telas, processadores e genlock mantêm o sincronismo, evitando rasgos (tearing) e quedas na troca de fontes.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Conversor HDMI↔SDI:</strong> Adapta o sinal entre o mundo de consumo (HDMI) e o broadcast (SDI).</li><li><strong>Scaler/processador de vídeo:</strong> Ajusta resolução e combina/troca fontes com sincronismo.</li></ul><h4>Passo a passo</h4><ol><li><strong>Escolha o padrão pela distância:</strong> Curto: HDMI; longo/seguro: SDI ou HDMI por fibra.</li><li><strong>Case resolução e taxa:</strong> Garanta que fonte, cabo e tela suportem a resolução/fps desejada.</li><li><strong>Converta quando preciso:</strong> Use conversor HDMI↔SDI para integrar equipamentos diferentes.</li><li><strong>Teste a cadeia antes:</strong> Verifique a imagem ponta a ponta antes do evento, incluindo troca de fontes.</li></ol><p><strong>Na prática:</strong> Para levar a imagem de um notebook (HDMI) a um telão a 60 m, converte-se HDMI para SDI, corre-se o coaxial até o palco e converte-se de volta para a entrada da tela. SDI percorre a distância que o HDMI puro não alcançaria.</p><h4>Resumo</h4><ul><li>HDMI é ubíquo e leva áudio, mas tem alcance curto e conector sem trava.</li><li>SDI percorre longas distâncias com BNC travado sobre coaxial 75 Ω.</li><li>Conversores e scalers integram fontes; teste sempre a cadeia ponta a ponta.</li></ul>',35,1,true,false);
