insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('696f472b-fe65-4e91-a228-52cb777d8c31','76ab2da1-e0ff-4296-9035-43b231444650','Um scaler de vídeo serve para:','O scaler converte a resolução para casar fonte e tela.',4,1);
