insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('e46ec519-3289-449a-933f-ab4004fac5cf','b90aa9b4-700d-4bf1-8d3f-dd592871375a','EDID e HDCP: visão geral','texto','<p><strong>Para começar:</strong> Tela preta inexplicável no evento? Muitas vezes a culpa é de EDID ou HDCP. Entender esses dois ''handshakes'' salva o show.</p><p>EDID e HDCP são negociações automáticas entre fonte e tela. Quando falham, a imagem some — por isso o técnico precisa conhecê-los.</p><ul><li><strong>O que é EDID:</strong> Extended Display Identification Data: dados que o monitor/tela envia à fonte informando suas capacidades (resoluções, taxas, áudio suportado). A fonte usa o EDID para escolher o formato a enviar.</li><li><strong>Problemas de EDID:</strong> Se o EDID não é lido (cabo ruim, distribuidor, switch), a fonte pode enviar formato incompatível ou nenhum — resultando em tela preta ou resolução errada. Distribuidores/matrizes às vezes precisam de gerenciamento/emulação de EDID.</li><li><strong>O que é HDCP:</strong> High-bandwidth Digital Content Protection: proteção contra cópia de conteúdo (filmes, streaming). Fonte e tela fazem um ''handshake'' criptográfico; só exibem se ambas forem compatíveis e autorizadas.</li><li><strong>Problemas de HDCP:</strong> Se algum equipamento na cadeia (switch, conversor, captura) não suporta HDCP, conteúdo protegido não passa — gera tela preta ou aviso de erro. Capturar/distribuir conteúdo protegido pode ser bloqueado por design.</li><li><strong>Visão geral e legalidade:</strong> HDCP é proteção de direitos autorais; contorná-la para pirataria é ilegal. O técnico deve usar equipamentos compatíveis e conteúdo próprio/licenciado, não ''quebrar'' a proteção.</li><li><strong>Diagnóstico prático:</strong> Tela preta intermitente ao trocar fonte sugere EDID; tela preta só com conteúdo protegido (streaming, Blu-ray) sugere HDCP. Identificar o sintoma direciona a solução.</li><li><strong>Boas práticas:</strong> Use cabos e distribuidores de qualidade com gerência de EDID e suporte a HDCP; teste a cadeia com o conteúdo real antes do evento; tenha conversores compatíveis de reserva.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Distribuidor/matriz com gerência de EDID:</strong> Mantém o handshake estável entre fontes e telas.</li><li><strong>Conversor compatível com HDCP:</strong> Garante exibição de conteúdo protegido na cadeia.</li></ul><h4>Passo a passo</h4><ol><li><strong>Verifique a leitura de EDID:</strong> Confirme que a fonte reconhece a tela (resolução correta detectada).</li><li><strong>Cheque o suporte a HDCP:</strong> Garanta que todos os equipamentos da cadeia suportam HDCP para conteúdo protegido.</li><li><strong>Diagnostique pelo sintoma:</strong> Falha ao trocar fonte → EDID; falha só com conteúdo protegido → HDCP.</li><li><strong>Teste com o conteúdo real:</strong> Reproduza o material do evento na cadeia completa antes do show.</li></ol><p><strong>Na prática:</strong> Um vídeo de streaming dá tela preta no telão enquanto um slide do notebook aparece normal. O slide não é protegido; o streaming é. O culpado é um conversor sem HDCP na cadeia — trocá-lo por um compatível resolve.</p><h4>Resumo</h4><ul><li>EDID informa à fonte o que a tela suporta; falhas geram tela preta ou formato errado.</li><li>HDCP é proteção de cópia por handshake; equipamento incompatível bloqueia conteúdo.</li><li>Diagnostique pelo sintoma e use equipamentos compatíveis — sem burlar a proteção.</li></ul>',25,2,true,false);
