insert into public.modules (id,course_id,titulo,ordem) values ('e2ee89f3-22b1-4a18-a703-8d01b5ce5d5e','07695dfc-c93c-4a8a-bb5a-58d3b926c76e','Módulo 8 — Fontes e Energia',8);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('b3c14119-7635-4416-84a6-7eb644dc45c3','e2ee89f3-22b1-4a18-a703-8d01b5ce5d5e','Retificação, filtragem e fontes lineares x chaveadas','texto','<p><strong>Para começar:</strong> Quase todo equipamento converte os 127/220 V da tomada em baixa tensão CC. Entender a fonte é entender o coração da alimentação.</p><p>A fonte de alimentação transforma a CA da rede em CC estável. Conhecer suas etapas e tipos permite diagnosticar e dimensionar a energia do sistema.</p><ul><li><strong>Etapas de uma fonte linear:</strong> Transformador (reduz a tensão CA e isola) → retificador (CA→CC pulsante) → filtro (alisa) → regulador (estabiliza). Cada etapa tem função e ponto de falha próprios.</li><li><strong>Retificação:</strong> Diodos convertem CA em CC pulsante. Meia-onda usa 1 diodo (aproveita metade do ciclo); onda completa usa ponte de 4 diodos, aproveitando os dois semiciclos — mais eficiente e com menos ripple.</li><li><strong>Filtragem:</strong> Capacitor de filtro após o retificador armazena carga e ''alisa'' a tensão pulsante, reduzindo o ripple (ondulação residual). Quanto maior a capacitância e menor a corrente, menor o ripple.</li><li><strong>Regulação:</strong> O regulador mantém a saída constante apesar de variações de entrada e carga (ex.: 78xx, LM317). Garante tensão estável para a eletrônica sensível.</li><li><strong>Fonte linear x chaveada:</strong> Linear: simples, baixo ruído, porém pesada e ineficiente (dissipa calor). Chaveada (SMPS): converte em alta frequência, é leve, eficiente e versátil, mas pode gerar ruído de chaveamento (EMI) se mal projetada.</li><li><strong>Por que chaveadas dominam:</strong> Equipamentos modernos, no-breaks e fontes de notebook/LED usam SMPS pela eficiência e tamanho reduzido. Em áudio sensível, ainda se valoriza fonte linear de baixo ruído em certos estágios.</li><li><strong>Diagnóstico de fonte:</strong> Sintomas: ripple alto (zumbido/instabilidade) sugere capacitor de filtro ressecado; saída zero pode ser fusível/retificador; tensão errada aponta regulador. O osciloscópio revela ripple que o multímetro esconde.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Fonte de alimentação / SMPS:</strong> Converte CA da rede em CC para os equipamentos.</li><li><strong>Osciloscópio:</strong> Mede o ripple e verifica a qualidade da CC.</li></ul><h4>Passo a passo</h4><ol><li><strong>Identifique as etapas:</strong> Localize transformador, ponte retificadora, capacitor de filtro e regulador.</li><li><strong>Meça a saída CC:</strong> Confirme a tensão correta com o multímetro em V⎓.</li><li><strong>Verifique o ripple:</strong> Use o osciloscópio em acoplamento AC para medir a ondulação residual.</li><li><strong>Isole a falha:</strong> Ripple alto → filtro; saída zero → fusível/retificador; tensão errada → regulador.</li></ol><p><strong>Na prática:</strong> Um equipamento começa a ''roncar'' e travar: ao medir a fonte, o osciloscópio mostra ripple elevado. O capacitor de filtro eletrolítico ressecou com o tempo. Trocá-lo restaura a CC limpa — defeito clássico em equipamentos antigos.</p><h4>Resumo</h4><ul><li>Fonte linear: transforma, retifica, filtra e regula a CA em CC estável.</li><li>Ponte de onda completa e capacitor de filtro reduzem o ripple.</li><li>SMPS é leve e eficiente (domina hoje); linear é de baixo ruído porém pesada.</li></ul>',35,1,true,false);
