insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('c1207bf4-c746-41da-80d2-a8c0b3d30d2f','e2ee89f3-22b1-4a18-a703-8d01b5ce5d5e','Aterramento, no-break/UPS e proteção contra surtos (DPS)','texto','<p><strong>Para começar:</strong> Energia confiável e segura é a fundação invisível do evento. Aterramento, UPS e proteção contra surtos evitam acidentes e quedas.</p><p>Esta aula trata da infraestrutura elétrica que mantém o show de pé: aterramento correto, alimentação ininterrupta e proteção contra surtos.</p><ul><li><strong>Função do aterramento:</strong> O condutor de proteção (PE, fio terra) leva a corrente de falta para a terra, fazendo a proteção atuar e mantendo as carcaças em potencial seguro. É item de SEGURANÇA, não opcional.</li><li><strong>Esquemas e equipotencialização:</strong> Em eventos, equipamentos devem compartilhar a mesma referência de terra (equipotencialização) para evitar diferenças de potencial entre racks, que causam choques e loops de terra.</li><li><strong>No-break / UPS:</strong> Uninterruptible Power Supply: fornece energia da bateria quando a rede falha, evitando desligamento abrupto de mesas digitais, computadores e processadores. Tipos: standby, line-interactive e online (dupla conversão, melhor para cargas críticas).</li><li><strong>Autonomia e dimensionamento:</strong> O UPS é dimensionado pela potência (VA/W) das cargas e pela autonomia desejada. Sobrecarregá-lo reduz autonomia ou desliga; subdimensionar deixa cargas críticas desprotegidas.</li><li><strong>DPS — proteção contra surtos:</strong> Dispositivo de Proteção contra Surtos: desvia para o terra picos de tensão (raios, manobras na rede), protegendo equipamentos. Instalado no quadro e/ou em réguas. Precisa de bom aterramento para funcionar.</li><li><strong>Proteção em cascata:</strong> Combina disjuntores (sobrecorrente), DR/IDR (corrente de fuga — segurança contra choque) e DPS (surto). Cada um protege contra um risco diferente; juntos formam a defesa elétrica.</li><li><strong>Boas práticas em eventos:</strong> Distribua cargas equilibrando as fases, não exceda a capacidade dos circuitos, use cabos e conexões adequados, garanta terra em todas as tomadas e proteja cargas críticas com UPS + DPS.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>No-break/UPS:</strong> Mantém cargas críticas alimentadas durante quedas da rede.</li><li><strong>DPS e DR:</strong> Protegem contra surtos e contra correntes de fuga (choque).</li><li><strong>Terrômetro / multímetro:</strong> Verifica a qualidade do aterramento e a presença de terra nas tomadas.</li></ul><h4>Passo a passo</h4><ol><li><strong>Verifique o terra:</strong> Confirme a presença e a continuidade do terra em todas as tomadas usadas.</li><li><strong>Equipotencialize os racks:</strong> Garanta referência de terra comum entre equipamentos para evitar loops.</li><li><strong>Dimensione o UPS:</strong> Some a potência das cargas críticas e escolha UPS com folga e autonomia adequada.</li><li><strong>Instale proteção em cascata:</strong> Combine disjuntor, DR e DPS, todos com aterramento eficaz.</li></ol><p><strong>Na prática:</strong> Numa mesa digital alimentada direto da rede, uma queda de energia derruba tudo no meio do show. Com um UPS online, a mesa segue ligada na bateria e o operador tem tempo de gerenciar a situação — proteção essencial para cargas críticas.</p><h4>Resumo</h4><ul><li>O aterramento é segurança: leva a falta à terra e mantém carcaças seguras.</li><li>UPS mantém cargas críticas na queda de energia; dimensione por potência e autonomia.</li><li>DPS desvia surtos (depende de bom terra); disjuntor, DR e DPS protegem riscos distintos.</li></ul>',35,2,true,false);
