insert into public.modules (id,course_id,titulo,ordem) values ('ae021f2c-edda-4b14-8c12-52b0ad930c5d','07695dfc-c93c-4a8a-bb5a-58d3b926c76e','Módulo 9 — Interferência (EMI/EMC) e Blindagem',9);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('468b1025-fbb1-4e39-aae9-ab3c3245569a','ae021f2c-edda-4b14-8c12-52b0ad930c5d','Interferência (EMI/EMC), blindagem e loops de terra','texto','<p><strong>Para começar:</strong> Zumbidos, chiados e travamentos misteriosos quase sempre têm a mesma raiz: interferência. Aprenda a preveni-la e a combatê-la.</p><p>EMI é a interferência eletromagnética; EMC é a capacidade de conviver sem causá-la nem sofrê-la. Blindagem, layout e tratamento de terra são as armas do técnico.</p><ul><li><strong>EMI e EMC:</strong> EMI (Interferência Eletromagnética) é energia indesejada que perturba circuitos. EMC (Compatibilidade Eletromagnética) é o projeto que permite ao equipamento funcionar sem causar nem sofrer interferência excessiva.</li><li><strong>Modos de acoplamento:</strong> A interferência se acopla por condução (pelos fios/terra), por campo elétrico (capacitivo), por campo magnético (indutivo) e por radiação (ondas). Identificar o modo direciona a solução.</li><li><strong>Fontes típicas em eventos:</strong> Fontes chaveadas, dimmers (cortam a senoide e geram ruído), motores, transmissores de RF, telefones celulares, lâmpadas e o próprio cabeamento mal disposto.</li><li><strong>Blindagem:</strong> Envolver o sinal com malha/folha aterrada barra campos elétricos e radiação. A blindagem só funciona bem se corretamente aterrada (em geral em uma extremidade para áudio, evitando loop).</li><li><strong>Loop de terra:</strong> Ocorre quando há mais de um caminho de terra entre equipamentos, formando uma ''antena'' onde circula corrente de 60 Hz, gerando zumbido. É a causa nº 1 de hum em sistemas de áudio/vídeo.</li><li><strong>Combate ao loop de terra:</strong> Equipotencializar; usar uma única referência de terra; isolar com DI box, transformador de isolação ou conversores ópticos; usar ground lift no sinal — NUNCA remover o terra de proteção da rede.</li><li><strong>Layout e separação:</strong> Separe fisicamente cabos de energia e de sinal; cruze-os em 90° quando inevitável; mantenha cabos de sinal curtos e afastados de fontes de EMI; use cabos balanceados e de qualidade.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Transformador de isolação / DI:</strong> Quebra loops de terra isolando galvanicamente o sinal.</li><li><strong>Osciloscópio / analisador:</strong> Identifica a frequência e a natureza da interferência.</li></ul><h4>Passo a passo</h4><ol><li><strong>Caracterize a interferência:</strong> Zumbido de 60 Hz → loop de terra; chiado de RF → transmissor próximo; ruído de dimmer → fonte chaveada/dimmer.</li><li><strong>Verifique o cabeamento:</strong> Afaste sinal de energia, cheque blindagens e conexões de terra.</li><li><strong>Isole o loop:</strong> Use DI/transformador de isolação ou ground lift no sinal, mantendo o PE.</li><li><strong>Confirme a melhora:</strong> Meça/escute novamente para validar a solução.</li></ol><p><strong>Na prática:</strong> Um sistema com som limpo passa a zumbir quando se liga o projetor pela tomada de outro circuito. Surgiu um loop de terra entre os equipamentos. Alimentando tudo do mesmo ponto (equipotencializando) ou isolando o sinal de vídeo, o zumbido desaparece.</p><h4>Resumo</h4><ul><li>EMI é a interferência; EMC é projetar para conviver com ela.</li><li>Blindagem aterrada e bom layout previnem acoplamento de ruído.</li><li>Loop de terra causa hum de 60 Hz; resolva isolando o sinal, jamais cortando o terra de proteção.</li></ul>',35,1,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('b6277fc2-26e0-4d40-905c-abae71fd433f','468b1025-fbb1-4e39-aae9-ab3c3245569a','Quiz — Interferência (EMI/EMC), blindagem e loops de terra');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('15db1ab8-a9b8-4de7-bcc6-bc0aed6b5ef1','b6277fc2-26e0-4d40-905c-abae71fd433f','A causa mais comum de zumbido (hum) em áudio é:','Loops de terra fazem circular corrente de 60 Hz, gerando hum.',1,1);
