insert into public.modules (id,course_id,titulo,ordem) values ('94287628-436a-4854-86bc-ef27e7ddf0d1','07695dfc-c93c-4a8a-bb5a-58d3b926c76e','Módulo 10 — Soldagem, Montagem e Segurança Elétrica',10);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('79052618-0256-4a24-9536-441e792ab5c8','94287628-436a-4854-86bc-ef27e7ddf0d1','Soldagem e montagem eletrônica','texto','<p><strong>Para começar:</strong> Uma boa solda é brilhante, sólida e confiável; uma ruim derruba o show. Vamos aprender a soldar como profissional.</p><p>Soldar é unir componentes eletricamente com liga metálica fundida. Técnica correta garante conexões duráveis; técnica ruim gera defeitos intermitentes.</p><ul><li><strong>O que é a solda:</strong> Uma liga metálica (tradicionalmente estanho-chumbo Sn-Pb; hoje também sem chumbo, lead-free) que, fundida pelo ferro, cria uma junção elétrica e mecânica entre o componente e a placa/terminal.</li><li><strong>Ferro de solda e temperatura:</strong> O ferro/estação aquece a ponta a uma temperatura controlada (tipicamente 300–370 °C). Mantenha a ponta limpa e estanhada; temperatura insuficiente gera solda fria, excessiva danifica componentes e placa.</li><li><strong>Fluxo:</strong> Substância que limpa e remove óxidos, permitindo que a solda ''molhe'' e flua bem. Solda eletrônica já vem com fluxo no núcleo (alma); fluxo extra ajuda em retrabalhos.</li><li><strong>Técnica correta:</strong> Aqueça SIMULTANEAMENTE o terminal e a ilha da placa com a ponta; aplique a solda no ponto aquecido (não na ponta do ferro); deixe fluir; retire a solda e depois o ferro. A junção boa é lisa, brilhante e côncava.</li><li><strong>Defeitos comuns:</strong> Solda fria (fosca, granulada, mau contato), excesso de solda (pontes/curtos), solda insuficiente, sobreaquecimento (ilha descolada), pontes entre trilhas. Geram falhas intermitentes difíceis de achar.</li><li><strong>Through-hole x SMD:</strong> Componentes com terminais (through-hole) são mais fáceis de soldar à mão; SMD (montagem em superfície) são minúsculos e exigem técnica/ferramentas específicas (ar quente, pasta de solda).</li><li><strong>Dessoldagem e retrabalho:</strong> Para remover componentes, usa-se sugador de solda, malha dessoldadora ou estação de ar quente. Aquecer, retirar a solda e extrair sem danificar a placa.</li><li><strong>Segurança e saúde:</strong> Solde em local ventilado (vapores de fluxo são irritantes), use exaustor, evite tocar a ponta quente, lave as mãos após manusear solda com chumbo e descarte resíduos corretamente.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Estação de solda:</strong> Aquece e controla a temperatura da ponta para soldar.</li><li><strong>Sugador / malha dessoldadora:</strong> Remove solda em retrabalhos e dessoldagens.</li><li><strong>Exaustor de fumaça:</strong> Capta vapores de fluxo, protegendo as vias respiratórias.</li></ul><h4>Passo a passo</h4><ol><li><strong>Prepare e estanhe a ponta:</strong> Aqueça, limpe na esponja/lã e aplique um pouco de solda na ponta.</li><li><strong>Aqueça a junção:</strong> Encoste a ponta no terminal e na ilha ao mesmo tempo por 1–2 s.</li><li><strong>Aplique a solda no ponto:</strong> Toque a solda na junção aquecida (não na ponta) e deixe fluir o suficiente.</li><li><strong>Retire e inspecione:</strong> Remova solda e ferro; a junção deve ficar lisa e brilhante. Verifique pontes e mau contato.</li></ol><p><strong>Na prática:</strong> Um equipamento que falha ''quando mexe no cabo'' costuma ter uma solda fria fosca em um conector. Reaquecer a junção com a técnica correta, formando uma solda brilhante e côncava, elimina a falha intermitente.</p><h4>Resumo</h4><ul><li>Solda boa une mecânica e eletricamente; é lisa, brilhante e côncava.</li><li>Aqueça a junção (não a solda na ponta) e use fluxo para boa molhagem.</li><li>Conheça defeitos (solda fria, pontes) e solde com ventilação e segurança.</li></ul>',35,1,true,false);
