insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('a95c2bbf-b50f-4750-8b73-cf765878f916','f1a99557-80df-4e75-af9d-3e8c6eff8719','O fluxo na soldagem serve para:','O fluxo remove óxidos e melhora a molhagem da solda.',4,1);
