insert into public.quiz_options (question_id,texto,correta,ordem) values ('a95c2bbf-b50f-4750-8b73-cf765878f916','Aumentar a resistência',false,3);
insert into public.quiz_options (question_id,texto,correta,ordem) values ('a95c2bbf-b50f-4750-8b73-cf765878f916','Isolar o terra',false,4);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('81c37fa5-396b-41d9-96a0-299ceb8d564d','94287628-436a-4854-86bc-ef27e7ddf0d1','Segurança elétrica e introdução à NR-10','texto','<p><strong>Para começar:</strong> Nenhum show vale um acidente. Esta aula fecha o curso com o tema mais importante: trabalhar com energia sem se ferir.</p><p>Segurança elétrica é prioridade absoluta. Aqui você conhece os riscos, as medidas de proteção e a base da norma brasileira NR-10.</p><ul><li><strong>Riscos da eletricidade:</strong> Choque elétrico (a corrente pelo corpo afeta músculos e coração — a partir de poucos dezenas de mA já há risco grave), queimaduras, arco elétrico e incêndio. A gravidade depende da corrente, do caminho e do tempo.</li><li><strong>O que determina o choque:</strong> Pela Lei de Ohm, a corrente no corpo depende da tensão e da resistência (pele seca x molhada). Por isso ambientes úmidos e mãos suadas aumentam muito o perigo.</li><li><strong>Medidas de proteção coletiva e individual:</strong> Coletivas: desenergização, aterramento, sinalização, isolação. Individuais (EPI): luvas isolantes, calçado adequado, óculos. A proteção coletiva tem prioridade sobre a individual.</li><li><strong>Desenergização segura:</strong> Sequência básica: seccionar a fonte, impedir reenergização (bloqueio/etiquetagem), constatar ausência de tensão, aterrar quando aplicável e sinalizar. Só então se trabalha com segurança.</li><li><strong>NR-10 — visão geral:</strong> Norma Regulamentadora nº 10 do Brasil: estabelece requisitos de segurança em instalações e serviços em eletricidade. Aplica-se a quem projeta, monta, opera e mantém instalações elétricas, protegendo a saúde dos trabalhadores.</li><li><strong>Exigências da NR-10:</strong> Inclui medidas de controle de risco, esquemas atualizados, procedimentos, EPI/EPC adequados e CAPACITAÇÃO obrigatória: curso básico da NR-10 (mínimo 40 h) para quem atua em zona de risco; trabalhos em alta tensão exigem complementar.</li><li><strong>Aplicação em eventos:</strong> Montagens de palco lidam com muita energia em pouco tempo e ambiente improvisado: terra em todas as tomadas, cabos dimensionados, proteção (disjuntor/DR/DPS), equipe capacitada e procedimentos são obrigatórios, não opcionais.</li><li><strong>Primeiros socorros:</strong> Em choque, NÃO toque a vítima ainda conectada à energia: desligue a fonte primeiro. Acione socorro; saber RCP pode salvar vidas. Prevenção, porém, é sempre a melhor estratégia.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>EPI (luvas isolantes, calçado, óculos):</strong> Protege o trabalhador durante intervenções elétricas.</li><li><strong>Detector de tensão / multímetro:</strong> Constata ausência de tensão antes de tocar no circuito.</li><li><strong>Sistema de bloqueio e etiquetagem:</strong> Impede reenergização acidental durante o serviço.</li></ul><h4>Passo a passo</h4><ol><li><strong>Planeje e desenergize:</strong> Antes de intervir, seccione a fonte de energia.</li><li><strong>Bloqueie e sinalize:</strong> Impeça a reenergização (bloqueio/etiqueta) e sinalize a área.</li><li><strong>Constate ausência de tensão:</strong> Confirme com detector/multímetro que o circuito está sem tensão.</li><li><strong>Trabalhe protegido:</strong> Use EPI, mantenha a área segura e siga os procedimentos; reenergize só ao final, com tudo conferido.</li></ol><p><strong>Na prática:</strong> Antes de mexer num quadro durante a montagem, o profissional desliga o disjuntor, bloqueia com cadeado e etiqueta, e confere com o detector que não há tensão. Esse ritual simples — desenergizar e constatar — é o que separa um serviço seguro de um acidente grave.</p><h4>Resumo</h4><ul><li>Eletricidade mata: choque, arco e incêndio exigem respeito e procedimento.</li><li>Desenergizar, bloquear, constatar ausência de tensão e sinalizar é a base segura.</li><li>A NR-10 rege a segurança elétrica no Brasil e exige capacitação dos trabalhadores.</li></ul>',35,2,true,false);
insert into public.quizzes (id,lesson_id,titulo) values ('5b69b65b-f9e0-428a-ad79-0580fd8b019e','81c37fa5-396b-41d9-96a0-299ceb8d564d','Quiz — Segurança elétrica e introdução à NR-10');
insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('140e9f9b-5c6c-49b1-b4b7-5b2f2879c112','5b69b65b-f9e0-428a-ad79-0580fd8b019e','Ao socorrer alguém sofrendo choque elétrico, a PRIMEIRA ação é:','Nunca toque a vítima energizada; desligue a fonte primeiro para não virar segunda vítima.',1,1);
