insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('f8967636-99e7-4bd3-96ca-8d6f8161b96c','5b69b65b-f9e0-428a-ad79-0580fd8b019e','Na proteção, deve-se priorizar medidas:','A proteção coletiva tem prioridade sobre a individual; o EPI complementa.',3,1);
