insert into public.modules (id,course_id,titulo,ordem) values ('5a20fb59-4b52-4da2-8ef8-644da0c58ffa','c6388794-36b6-4176-9839-d8208237613d','Estruturas (Treliça), Rigging, Energia e Padrões Técnicos',1);
insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('30c3838b-2108-4822-a114-96114899426c','5a20fb59-4b52-4da2-8ef8-644da0c58ffa','Treliça (Truss): anatomia, tipos e materiais','texto','<p><strong>Para começar:</strong> Antes de qualquer evento, a treliça é o esqueleto que sustenta luz, som, vídeo e cenografia. Entender sua anatomia é o primeiro passo para montar estruturas que não caem.</p><p>A treliça (truss) é uma estrutura modular treliçada, geralmente em liga de alumínio, formada por banzos (tubos principais) e diagonais/montantes soldados, projetada para vencer vãos com pouco peso próprio. Nesta aula você aprende a nomenclatura, os tipos por seção e aplicação, e por que o material e a geometria definem a capacidade de carga.</p><ul><li><strong>Por que treliça e não tubo maciço:</strong> Uma treliça distribui esforços pelos banzos (compressão/tração) e pelas diagonais (cisalhamento), atingindo alta rigidez com baixo peso. Isso permite vencer grandes vãos transportando carga (moving heads, line array, telões) sem o peso proibitivo de uma viga sólida. A geometria triangulada é o que confere rigidez.</li><li><strong>Material: liga de alumínio:</strong> A maioria das treliças profissionais usa ligas de alumínio das séries 6000 (ex.: 6082-T6 ou 6061-T6) nos tubos, soldadas com vareta da série 5000 (ex.: 5183). O alumínio é leve, resistente à corrosão e tem boa relação resistência/peso. ATENÇÃO: a solda reduz a resistência local (zona afetada pelo calor), e por isso o fabricante calcula as cargas admissíveis já considerando esse efeito — nunca extrapole.</li><li><strong>Tipos por seção:</strong> Quadrada/box (4 banzos, ex.: Q30S, Q40S de marcas como Prolyte/Global Truss) é a mais usada por suportar carga em qualquer eixo. Triangular (3 banzos) é mais leve, boa para vãos menores e treços decorativos. Ladder/escada (2 banzos, plana) serve para fixar a barras de luz e fundos. Circular/arco e quadros (frame) para portais e cenografia. Deck/palco é estrutura específica de piso, com norma própria.</li><li><strong>Nomenclatura de tamanho (Q30/Q40):</strong> Os códigos comerciais indicam família e seção: por exemplo, Prolyte H30V/H40V e Global Truss F33/F34 referem-se a treliças de ~290–400 mm de lado com tubos de banzo de ~48–50 mm. Sempre confirme a seção e a série no catálogo do fabricante — códigos parecidos NÃO são intercambiáveis e cada um tem load chart próprio.</li><li><strong>Geometria importa:</strong> A capacidade de uma treliça aumenta com a altura da seção (maior braço de alavanca entre banzos = maior momento resistente). Por isso uma Q40 (40 cm) suporta mais que uma Q30 (30 cm) no mesmo vão. Nunca compare apenas pela aparência: o load chart é a referência.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Treliça box Q30/Q40 (liga 6082-T6 / 6061-T6):</strong> Estrutura principal para grids, vãos e suporte de carga em qualquer eixo</li><li><strong>Treliça triangular:</strong> Vãos menores e estruturas decorativas mais leves</li><li><strong>Treliça ladder (escada):</strong> Fixação de barras de luz, fundos e cortinas</li><li><strong>Catálogo/Load chart do fabricante (Prolyte, Global Truss, Eurotruss, Milos, Tomcat):</strong> Documento oficial com cargas admissíveis, flecha e condições de apoio</li><li><strong>NBR 8800 / Eurocode 9 (EN 1999) — referência de cálculo de alumínio:</strong> Base normativa para verificação estrutural por profissional habilitado</li></ul><h4>Passo a passo</h4><ol><li><strong>Identifique a treliça:</strong> Leia a etiqueta/gravação: marca, série, seção. Sem identificação confiável, não use para carga estrutural.</li><li><strong>Confirme o material e estado:</strong> Verifique se é liga de alumínio estrutural, sem trincas na solda, sem amassados nos banzos nem corrosão branca pulverulenta.</li><li><strong>Localize o load chart correto:</strong> Baixe a tabela exata do modelo no site do fabricante. Não use tabela de marca/série diferente.</li><li><strong>Defina seção pela aplicação:</strong> Para vãos maiores e cargas pesadas, escolha seção maior (Q40 antes de Q30); confirme sempre no load chart.</li><li><strong>Registre o inventário:</strong> Anote modelo, comprimento e condição de cada barra para rastreabilidade e inspeção futura.</li></ol><p><strong>Na prática:</strong> Num show médio, o operador chega ao galpão, separa barras Q30 de 2 m e 3 m, confere as etiquetas Prolyte H30V e baixa o load chart correspondente no celular. Percebe que uma barra tem um banzo amassado por transporte — ela é separada e etiquetada como ''fora de serviço'' até inspeção. Esse simples hábito evita usar uma peça com capacidade comprometida.</p><h4>Resumo</h4><ul><li>Treliça é estrutura treliçada de alumínio que vence vãos com pouco peso graças à geometria triangulada.</li><li>Tipos: box/quadrada (mais versátil), triangular, ladder, circular e deck — cada um com aplicação própria.</li><li>Seção maior (Q40 &gt; Q30) suporta mais carga, mas a referência sempre é o load chart oficial do fabricante.</li></ul>',30,1,true,true);
