insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('728d95ec-176a-4eaa-914b-4cabf59609df','dcf9d737-a73c-409a-a3b8-1df58223cd66','Entre Q30 e Q40 no mesmo vão, qual tende a suportar mais carga e por quê?','Maior altura de seção aumenta o momento resistente, elevando a capacidade — mas sempre confirme no load chart.',3,1);
