insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('070c8c45-70ed-4c2e-a4b2-88ef8ba389e0','5a20fb59-4b52-4da2-8ef8-644da0c58ffa','Conexões da treliça: cubo, spigot/cone, conector e montagem','texto','<p><strong>Para começar:</strong> Uma treliça perfeita conectada de forma errada vira um perigo. As juntas são onde a carga passa de uma barra para outra — e onde mais se erra.</p><p>Esta aula cobre como as barras se unem: cubo (corner block), sistema spigot/cone com pinos e contrapinos (Prolyte CCS6) ou conexão por parafuso/flange (Global Truss), além das boas práticas de montagem no chão (assembly) antes de subir. Conexão errada anula o load chart.</p><ul><li><strong>Cubo e corner block:</strong> São os blocos de canto que permitem mudar de direção (formar quadros, portais, grids). O cubo deve ser do mesmo sistema/série da treliça e ter a mesma classe de carga. Misturar cubo de capacidade inferior cria o elo fraco da estrutura.</li><li><strong>Spigot/cone, pino e contrapino:</strong> Em sistemas tipo Prolyte CCS6/CCS7, a união é feita por um cone (spigot) inserido entre as barras, travado por dois pinos e seus contrapinos (clipes de segurança). TODOS os pinos e contrapinos devem ser instalados; faltar um contrapino é falha grave que pode soltar a junta sob vibração.</li><li><strong>Conexão por parafuso/flange:</strong> Sistemas como Global Truss F-series unem por parafusos (M-bolts) com porca e arruela, em furos de flange. Aperte conforme o fabricante, sem improvisar parafuso de bitola/classe diferente. Parafuso de ferragem comum não tem a classe de resistência exigida.</li><li><strong>Compatibilidade entre marcas:</strong> Não assuma que treliças de marcas diferentes encaixam ou têm a mesma capacidade só porque o cone ''entra''. Use adaptadores oficiais quando existirem e respeite o menor load chart envolvido. Conectar Q30 com Q40 muda completamente o comportamento.</li><li><strong>Montagem no solo (ground assembly):</strong> Monte o máximo possível no chão, sobre cavaletes, conferindo alinhamento e todas as conexões, antes de içar. É mais seguro e mais rápido do que conectar no alto. Marque a orientação (carga preferencial do load chart) para subir no sentido correto.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Cones/spigots, pinos e contrapinos (ex.: Prolyte CCS6):</strong> União estrutural travada entre barras do mesmo sistema</li><li><strong>Parafusos/porcas de classe especificada (ex.: Global Truss F34):</strong> Conexão por flange conforme torque do fabricante</li><li><strong>Cubo/corner block da mesma série e classe:</strong> Mudança de direção mantendo a capacidade da estrutura</li><li><strong>Cavaletes de montagem:</strong> Montar e conferir a treliça no solo com segurança</li><li><strong>Martelo de borracha e chaves corretas:</strong> Encaixar cones e apertar conexões sem danificar o alumínio</li></ul><h4>Passo a passo</h4><ol><li><strong>Separe componentes do mesmo sistema:</strong> Confirme que barras, cubos, cones e pinos são da mesma série e classe de carga.</li><li><strong>Monte sobre cavaletes:</strong> Apoie as barras alinhadas e una-as no solo, evitando trabalho em altura desnecessário (NR-35).</li><li><strong>Insira cones e trave pinos:</strong> Encaixe o cone, instale os DOIS pinos e prenda TODOS os contrapinos/clipes — confira um a um.</li><li><strong>Aperte parafusos ao torque:</strong> Em sistemas de flange, use o parafuso correto e o torque indicado pelo fabricante.</li><li><strong>Verifique alinhamento e orientação:</strong> Cheque que não há barra torta e que a face de maior carga está no sentido previsto pelo load chart.</li><li><strong>Inspeção dupla antes de içar:</strong> Um segundo profissional revisa todas as juntas; só então a estrutura sobe.</li></ol><p><strong>Na prática:</strong> Durante a montagem de um portal, o assistente esquece um contrapino numa junta no alto. Na conferência dupla (passo final), o líder de rigging percorre cada cone e detecta o clipe faltando antes do içamento. A junta é completada no chão. Sem essa rotina de dupla checagem, a falha só apareceria sob vibração, no pior momento.</p><h4>Resumo</h4><ul><li>As juntas transferem a carga; cubo, cone e pinos devem ser do mesmo sistema e classe.</li><li>Faltar contrapino ou usar parafuso errado anula o load chart e pode soltar a junta sob vibração.</li><li>Monte e confira no solo, marque a orientação e faça dupla checagem antes de içar.</li></ul>',25,3,true,false);
