insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('bbb499a2-56dd-48cd-b1e6-3ddcd176109e','1d22e854-0b74-4f7f-944e-6ea3b263ef36','O que significa WLL num sling ou manilha?','WLL é a carga de trabalho segura, já obtida dividindo a ruptura por um fator de segurança; nunca opere acima dela.',1,1);
