insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('4d14960b-db3f-4109-b97c-2b300d763c31','1d22e854-0b74-4f7f-944e-6ea3b263ef36','O que acontece com a carga em cada perna ao abrir o ângulo da linga?','Ângulos mais abertos elevam a força em cada perna do sling, podendo ultrapassar o WLL se ignorado.',2,1);
