insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('a1e992a5-0bcf-4e91-bd7d-2f082059a3d0','1d22e854-0b74-4f7f-944e-6ea3b263ef36','A redundância (cabo de segurança) sobre público é:','Em rigging sobre pessoas a redundância é exigida: se o caminho primário falha, o secundário segura a carga.',3,1);
