insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('c7308ede-4329-4148-a52e-fba98a1dad76','1d22e854-0b74-4f7f-944e-6ea3b263ef36','Qual manilha é aceitável em rigging de entretenimento?','Use manilhas de rigging marcadas com WLL (tipo Crosby/equivalente), com pino totalmente apertado.',5,1);
