insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('6bbea573-a7be-4071-af7b-c22726ad909d','5a20fb59-4b52-4da2-8ef8-644da0c58ffa','Ground support, voo e estabilidade da estrutura','texto','<p><strong>Para começar:</strong> Nem toda estrutura é pendurada. Muitas vezes você a ergue do chão — e aí o desafio é não deixar tombar.</p><p>Ground support são torres/colunas que sustentam a treliça a partir do solo, com cabeçotes (sleeve block) e motores que sobem o grid pela própria torre. Esta aula trata de bases, lastro (ballast), estais (guy wires), vento e a diferença prática entre voar (flown) e apoiar (ground). Estruturas externas têm o agravante do vento — sempre projeto de engenheiro.</p><ul><li><strong>Ground support: como funciona:</strong> Torres verticais de treliça (sleeve block + tower) recebem o grid horizontal e o elevam por motores internos. É usado quando não há ponto no teto, em arenas, ginásios e shows ao ar livre. As torres transferem toda a carga ao piso, que precisa suportar a reação.</li><li><strong>Base, sapata e distribuição de carga:</strong> Cada torre apoia numa base (base plate) que distribui a carga ao solo. Em pisos frágeis ou irregulares use placas de distribuição. A reação no pé inclui o peso da estrutura mais qualquer efeito de vento — verifique a capacidade do piso/solo.</li><li><strong>Lastro (ballast) e estabilidade:</strong> Para evitar tombamento, principalmente com vento, usa-se lastro (contrapeso) e/ou estais. A quantidade de lastro e o esquema de estaiamento são definidos por cálculo de engenheiro, considerando a área de vela (telão, banner, lona) e a velocidade de vento de projeto. Banner aumenta MUITO a força de vento.</li><li><strong>Estais (guy wires):</strong> Cabos tensionados que ancoram a estrutura ao solo, resistindo a forças laterais (vento). Ângulo, ponto de ancoragem e tensão fazem parte do projeto. Estais mal ancorados são tão perigosos quanto ausentes.</li><li><strong>Voar (flown) x apoiar (ground):</strong> Voar pendura no teto/ponto existente — depende da capacidade desse ponto. Apoiar (ground support) é independente do teto, mas exige torres, base e estabilidade contra tombamento. A escolha depende do local, da carga e da capacidade dos pontos disponíveis.</li><li><strong>Vento e ambiente externo:</strong> Ao ar livre, vento é a carga dominante e variável. Estruturas externas exigem projeto com plano de gerenciamento de vento: velocidades-limite para operar, parar o show e evacuar/abaixar a estrutura. Monitore com anemômetro. Não existe palco externo seguro sem plano de vento assinado por engenheiro.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Torres de ground support (sleeve block + tower):</strong> Erguer o grid a partir do solo sem depender do teto</li><li><strong>Base plates e placas de distribuição de carga:</strong> Distribuir a reação da torre em pisos frágeis ou irregulares</li><li><strong>Lastro / ballast (contrapesos):</strong> Estabilidade contra tombamento, dimensionado por engenheiro (SEGURANÇA)</li><li><strong>Estais (guy wires) e ancoragens:</strong> Resistir a forças laterais e de vento</li><li><strong>Anemômetro:</strong> Medir a velocidade do vento e acionar o plano de gerenciamento</li><li><strong>Projeto/ART de engenheiro para estrutura externa:</strong> Definir lastro, estais e limites de vento (SEGURANÇA)</li></ul><h4>Passo a passo</h4><ol><li><strong>Avalie o piso/solo:</strong> Confirme que o piso suporta a reação das torres; use placas de distribuição onde necessário.</li><li><strong>Monte torres aprumadas:</strong> Erga as torres niveladas e no prumo, conforme o manual do sistema de ground support.</li><li><strong>Instale lastro e estais conforme projeto:</strong> Aplique o contrapeso e o estaiamento exatamente como o engenheiro especificou para a área de vela e vento.</li><li><strong>Eleve o grid de forma sincronizada:</strong> Suba o grid pelos motores das torres de modo nivelado, observando estabilidade.</li><li><strong>Cheque prumo e tensões:</strong> Reverifique prumo das torres e tensão dos estais após o grid no lugar.</li><li><strong>Ative o plano de vento:</strong> Posicione o anemômetro e defina limites de operação, parada e descida da estrutura.</li></ol><p><strong>Na prática:</strong> Num palco ao ar livre com telão de 5 x 3 m, a área de vela aumenta a força do vento sobre as torres. O projeto do engenheiro pede 600 kg de lastro por torre e estais a 45°. No dia, o anemômetro marca rajadas crescentes; ao atingir o limite do plano, o produtor interrompe o show e a equipe abaixa o grid. A decisão salva a estrutura — vento não negocia.</p><h4>Resumo</h4><ul><li>Ground support ergue o grid do chão por torres; toda a carga vai ao piso, que precisa suportar.</li><li>Lastro e estais garantem estabilidade contra tombamento e devem ser dimensionados por engenheiro.</li><li>Em estruturas externas o vento manda: anemômetro, limites de operação e plano de descida são obrigatórios.</li></ul>',25,5,true,false);
