insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('0c0e0611-e8d7-4f4f-adc9-9aabd34e0a77','48a8d59c-58f0-4a3a-84a6-eee162f01e0e','No código IP65, o que significa o ''5'' e o ''5''?','No IP65: primeiro dígito 6 = totalmente protegido contra poeira; segundo 5 = protegido contra jatos d''água.',3,1);
