insert into public.quiz_questions (id,quiz_id,texto,explicacao,ordem,pontos) values ('f2cae12b-cd4b-49f1-9881-97d8e49f103f','48a8d59c-58f0-4a3a-84a6-eee162f01e0e','Qual padrão de plugue é robusto e típico para força de eventos?','IEC 60309/CEE é o padrão industrial com grau IP e travamento, ideal para força em eventos.',5,1);
