insert into public.lessons (id,module_id,titulo,tipo,conteudo_rico,duracao_min,ordem,tem_quiz,preview_gratis) values ('ec96974c-99a0-4c58-a54e-48eb385ad812','5a20fb59-4b52-4da2-8ef8-644da0c58ffa','Do improviso ao profissional: escolhendo soluções confiáveis','texto','<p><strong>Para começar:</strong> Existe sempre o jeito barato e rápido — e o jeito certo. Em estrutura e energia, a diferença entre os dois pode ser a diferença entre um show e uma tragédia.</p><p>Esta aula final junta tudo numa comparação prática: do básico ao profissional, em treliça, rigging e energia, mostrando onde o improviso é aceitável (com critério) e onde é simplesmente proibido. O fio condutor é a gestão de risco e a responsabilidade técnica.</p><ul><li><strong>Treliça: improviso x confiável:</strong> PROFISSIONAL: treliça de marca identificada, load chart, vão e cargas calculados, juntas completas. IMPROVISO PERIGOSO: tubo de andaime ou treliça sem identificação como suporte de carga sobre pessoas, vão ''no olho'', misturar sistemas. Estrutura sobre público nunca é improviso — é projeto.</li><li><strong>Rigging: improviso x confiável:</strong> PROFISSIONAL: motor certificado, slings e manilhas com WLL, redundância, equipe NR-35, célula de carga. IMPROVISO PERIGOSO: corda/arame, manilha de ferragem sem marcação, içar sobre público sem redundância, ninguém capacitado. Içamento sobre cabeças é a operação de maior consequência — zero improviso.</li><li><strong>Energia: improviso x confiável:</strong> PROFISSIONAL: quadro com disjuntor e DR, aterramento testado, fases balanceadas, cabo dimensionado, NR-10. IMPROVISO PERIGOSO: ''gambiarra'' com fio pelado, T''s empilhados, sem DR, sem terra, cabo subdimensionado esquentando. Energia mal feita é incêndio e choque esperando acontecer.</li><li><strong>Gestão de risco e responsabilidade técnica:</strong> Eventos de porte exigem responsáveis técnicos (engenheiro elétrico/estrutural com ART), APR, e em muitos casos AVCB/laudos do corpo de bombeiros e da prefeitura. Saber o limite da própria competência e chamar o profissional habilitado é marca do técnico maduro, não fraqueza.</li><li><strong>Quando dizer não:</strong> Há momentos em que a resposta certa é interromper: vento acima do limite, estrutura sem identificação para carga, ponto de içamento sem capacidade comprovada, instalação elétrica sem terra. Dizer ''não montamos assim'' protege vidas e protege você juridicamente. Segurança vem antes do show.</li><li><strong>Cultura de segurança e checklists:</strong> O profissional confiável padroniza: usa checklists, faz dupla checagem, documenta, inspeciona equipamentos periodicamente e treina a equipe. A segurança não é um ato isolado, é um hábito de equipe. Cada aula deste módulo trouxe um checklist — transforme-os em rotina.</li></ul><h4>Equipamentos / detalhes</h4><ul><li><strong>Equipamentos certificados e identificados (treliça, motor, slings, quadro):</strong> Garantir capacidade conhecida e rastreável (SEGURANÇA)</li><li><strong>Documentação: load charts, WLL, ART/RRT, APR, laudos:</strong> Comprovar dimensionamento e responsabilidade técnica</li><li><strong>Checklists das aulas anteriores:</strong> Padronizar a verificação e a dupla checagem</li><li><strong>EPI e instrumentos (anemômetro, célula de carga, alicate amperímetro):</strong> Operar e medir com segurança</li><li><strong>Responsável técnico habilitado (engenheiro):</strong> Assinar projetos e laudos de estrutura e energia (SEGURANÇA)</li></ul><h4>Passo a passo</h4><ol><li><strong>Classifique cada item como básico/pro:</strong> Para treliça, rigging e energia, avalie se a solução é confiável ou improviso perigoso.</li><li><strong>Elimine os improvisos proibidos:</strong> Estrutura/rigging sobre público e energia sem terra/DR não têm versão ''improvisada'' aceitável.</li><li><strong>Garanta a responsabilidade técnica:</strong> Para porte relevante, assegure ART/RRT, APR e laudos exigidos (bombeiros/prefeitura).</li><li><strong>Aplique os checklists:</strong> Use as listas de cada aula como rotina de conferência e dupla checagem.</li><li><strong>Exerça o direito de recusa:</strong> Diante de condição insegura (vento, ponto desconhecido, falta de terra), interrompa e corrija.</li><li><strong>Documente e melhore:</strong> Registre o que foi feito, inspecione equipamentos e treine a equipe continuamente.</li></ol><p><strong>Na prática:</strong> Um cliente pede para pendurar um telão pesado num ponto do teto ''que sempre aguentou''. O técnico maduro não aceita o ''sempre aguentou'': pede confirmação de capacidade ao engenheiro do prédio. Sem documento, propõe ground support com torres calculadas. Custa um pouco mais, mas a estrutura fica segura e respaldada. Dizer não ao improviso foi a decisão profissional.</p><h4>Resumo</h4><ul><li>Do básico ao pro: a diferença é capacidade conhecida, dimensionamento e responsabilidade técnica.</li><li>Carga sobre pessoas e energia sem terra/DR não têm versão improvisada aceitável — são proibidas.</li><li>Cultura de segurança é hábito: checklists, dupla checagem, documentação e o direito de dizer não.</li></ul>',25,9,true,false);
